const LESSONS = [{"num":0,"id":"lesson_00_ts_js_primer","filename":"lesson_00_ts_js_primer.tsx","title":"JS/TS Primer: The Syntax You'll See Constantly","subtitle":"Understand the request-response cycle first. Same as Python lessons -- logic before syntax. You already know Python logic (variables, loops, functions). This lesson maps that knowledge onto JS/TS syntax you'll reuse in EVERY React Native file from here on.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 00 -- JS/TS Primer: The Syntax You'll See Constantly\n//   Teaching philosophy: Understand the request-response cycle first.\n//                        Same as Python lessons -- logic before syntax.\n//   You already know Python logic (variables, loops, functions).\n//   This lesson maps that knowledge onto JS/TS syntax you'll reuse\n//   in EVERY React Native file from here on.\n// ================================================================\n\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python and JS/TS solve the same problems with different spelling.\n//\n//   Python:                          JS/TS:\n//   x = 5                            const x = 5;\n//   def greet(name):                 const greet = (name: string) => {\n//       return f\"Hi {name}\"              return `Hi ${name}`;\n//                                     }\n//   if x > 0:                        if (x > 0) {\n//       print(\"positive\")                console.log(\"positive\");\n//                                     }\n//\n//   Key differences that trip up Python developers:\n//   1. Every statement ends in a semicolon ; (optional but expected)\n//   2. Blocks use { } instead of indentation (indentation still\n//      matters for readability, but the { } is what actually scopes)\n//   3. No \"self\" -- methods use \"this\" and it behaves differently\n//   4. TypeScript adds TYPES on top of JS -- catches bugs before\n//      you even run the code (closer to type hints, but enforced)\n\n\n// ================================================================\n// PART 1 -- Variables: const vs let (Python has neither)\n// ================================================================\n//\n//   Python: x = 5          (x can always be reassigned)\n//   JS/TS:  const x = 5;   (x can NEVER be reassigned)\n//           let y = 5;     (y CAN be reassigned)\n//\n//   TRACE: why const is the default\n//   Step 1: You declare const total = 0;\n//   Step 2: Later you try: total = 10;\n//   Step 3: TypeScript ERRORS immediately -- \"Cannot assign to total\"\n//   Step 4: This is a FEATURE -- it stops accidental overwrites\n//\n//   Rule of thumb: use const unless you KNOW the value must change.\n\nconst appName = \"MyApp\";          // never reassigned -> const\nlet score = 0;                    // will change -> let\nscore = score + 10;\n\n// ── PREDICT before running ──────────────────────────────────────\n// const pi = 3.14;\n// pi = 3.15;                     // what happens here?            -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Functions: Arrow Functions (Python's def, reshaped)\n// ================================================================\n//\n//   Python:\n//   def add(a, b):\n//       return a + b\n//\n//   JS arrow function (same idea, different shape):\n//   const add = (a, b) => {\n//       return a + b;\n//   };\n//\n//   Short form -- no braces needed if it's just one return:\n//   const add = (a, b) => a + b;\n//\n//   TRACE: reading an arrow function out loud\n//   \"const add = \"        -> I'm storing a function in a variable\n//   \"(a, b) => \"           -> it takes a, b, and produces...\n//   \"a + b\"                -> ...this value, automatically returned\n\nconst add = (a: number, b: number): number => a + b;\n\nconst greet = (name: string): string => {\n    return `Hi, ${name}!`;        // template literal: `${}` = Python f\"\"\n};\n\nconsole.log(add(2, 3));\nconsole.log(greet(\"Sarath\"));\n\n\n// ================================================================\n// PART 3 -- TypeScript Types (Python's type hints, but ENFORCED)\n// ================================================================\n//\n//   Python type hint (a suggestion, not enforced at runtime):\n//   def add(a: int, b: int) -> int:\n//       return a + b\n//\n//   TypeScript type annotation (CHECKED before your code ever runs):\n//   const add = (a: number, b: number): number => a + b;\n//\n//   TRACE: what happens if you break a type\n//   Step 1: add(\"two\", 3)\n//   Step 2: TypeScript sees \"two\" is not a number\n//   Step 3: Red squiggly line in your editor -- BEFORE you run anything\n//   Step 4: This catches a whole category of bugs Python lets through\n\nlet age: number = 25;\nlet username: string = \"sarath\";\nlet isLoggedIn: boolean = true;\n\n// Arrays -- Python's list, with a declared item type\nlet scores: number[] = [10, 20, 30];\n\n// Objects -- Python's dict, but shape is fixed by an interface\ninterface User {\n    name: string;\n    age: number;\n    email?: string;             // ? means optional, like a dict.get() default\n}\n\nconst user: User = { name: \"Sarath\", age: 25 };\n\n\n// ================================================================\n// PART 4 -- Destructuring (Python's tuple unpacking, for objects)\n// ================================================================\n//\n//   Python:\n//   user = {\"name\": \"Sarath\", \"age\": 25}\n//   name = user[\"name\"]\n//   age = user[\"age\"]\n//\n//   JS/TS destructuring -- pull multiple keys out in one line:\n//   const { name, age } = user;\n//\n//   TRACE:\n//   Step 1: JS looks at user's keys: name, age\n//   Step 2: Creates a variable \"name\" = user.name\n//   Step 3: Creates a variable \"age\"  = user.age\n//   You'll see this CONSTANTLY when receiving props in components.\n\nconst { name, age: userAge } = user;     // renaming age -> userAge\nconsole.log(name, userAge);\n\n\n// ================================================================\n// PART 5 -- Imports (Python's import, same idea)\n// ================================================================\n//\n//   Python:                          JS/TS:\n//   import math                      import * as math from \"math\";\n//   from math import sqrt            import { sqrt } from \"math\";\n//\n//   You'll write this at the top of every React Native file:\n//   import { View, Text } from \"react-native\";\n//   import React, { useState } from \"react\";\n//\n//   \"import { X } from Y\" means: \"from Y, give me the named export X\"\n//   -- exactly like Python's \"from module import name\"","questionsCode":"// ================================================================\n// [QUESTIONS] -- const is the default. Types catch bugs early.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const price: number = 100;\n// const label: string = \"Total: \" + price;\n// console.log(label);             -> ?\n//\n// let count = 0;\n// const increment = () => { count = count + 1; };\n// increment();\n// increment();\n// console.log(count);             -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const greetUser = (name: string) => {\n//       return \"Hello \" + Name;\n//   }\n//   const user = { firstName: \"Sarath\" age: 25 };\n//   greetUser(user.firstname);\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Convert From Python\n//\n// Convert this Python function to a TypeScript arrow function\n// with proper type annotations:\n//\n//   def full_name(first, last):\n//       return first + \" \" + last\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Interface Design\n//\n// PLAN: what fields does a Product need? which are optional?\n//\n// Define an interface \"Product\" with: id (number), title (string),\n// price (number), and an OPTIONAL discount (number).\n// Create one const product of that type, with and without discount.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 5 -- Destructuring Practice\n//\n// PLAN: which keys do you need pulled out?\n//\n// Given: const movie = { title: \"Inception\", year: 2010, rating: 8.8 };\n// Destructure title and rating only (skip year) into separate\n// variables, then log: \"Inception (8.8)\" using a template literal.\n//\n// Write here:","takeaways":["const = default, never reassigned | let = will change","Arrow function: (params) => expression  OR  (params) => { ... }","TS types are CHECKED before code runs -- catches bugs early","Destructuring: const { key1, key2 } = object;","import { X } from \"Y\" = Python's \"from Y import X\""],"nextHint":"lesson_01_setup.tsx -- installing Expo and running on your phone","milestone":""},{"num":1,"id":"lesson_01_setup","filename":"lesson_01_setup.tsx","title":"Setup: Node, Expo CLI, and Your First Run","subtitle":"Understand the request-response cycle first. Get something running on your phone FIRST -- confidence before depth.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 01 -- Setup: Node, Expo CLI, and Your First Run\n//   Teaching philosophy: Understand the request-response cycle first.\n//                        Get something running on your phone FIRST --\n//                        confidence before depth.\n// ================================================================\n//   Before starting: install Node.js (LTS) from nodejs.org\n//   Install the \"Expo Go\" app on your phone (Play Store / App Store)\n\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   In Python, \"python my_script.py\" just runs on your machine.\n//   A phone app is different -- it needs to run INSIDE a phone's OS\n//   (Android or iOS), which your laptop cannot do directly.\n//\n//   Expo solves this gap:\n//\n//   Your laptop (writes code)\n//        |\n//        | Expo bundles your code + starts a dev server\n//        v\n//   QR code shown in terminal\n//        |\n//        | You scan it with the Expo Go app\n//        v\n//   Your phone (downloads the bundle, runs it LIVE)\n//\n//   Every time you save a file, the bundle updates and your phone\n//   refreshes automatically -- this is called \"Fast Refresh.\"\n//   No app store submission needed during development.\n\n\n// ================================================================\n// PART 1 -- Checking Node.js Is Installed\n// ================================================================\n//\n//   Node.js runs JavaScript outside a browser -- it's what powers\n//   the Expo CLI tool itself (the CLI is a JS program).\n//\n//   TRACE: verifying your install\n//   Step 1: Open a terminal\n//   Step 2: Run: node --version\n//   Step 3: Should print something like v20.11.0\n//   Step 4: Run: npm --version  (npm = Node's package manager,\n//           similar role to Python's pip)\n//\n//   node --version\n//   npm --version\n\n\n// ================================================================\n// PART 2 -- Creating Your First Expo Project\n// ================================================================\n//\n//   TRACE: npx create-expo-app\n//   Step 1: \"npx\" downloads and runs a tool WITHOUT installing it\n//           globally first -- like running \"pip install --temp X\"\n//   Step 2: \"create-expo-app\" is that tool -- it scaffolds a new\n//           project folder with all the boilerplate already wired up\n//   Step 3: It asks for a project name, then generates the folder\n//\n//   npx create-expo-app@latest my-first-app --template\n//\n//   Choose the \"Blank (TypeScript)\" template when prompted --\n//   matches the .tsx files you'll be writing in this course.\n\n// cd my-first-app\n\n\n// ================================================================\n// PART 3 -- Project Structure (What Got Generated)\n// ================================================================\n//\n//   my-first-app/\n//   |-- app/                  screens go here (file-based routing,\n//   |     |-- index.tsx       lesson 08 covers this in depth)\n//   |-- assets/                images, fonts\n//   |-- package.json           like requirements.txt + project config\n//   |-- tsconfig.json          TypeScript settings\n//   |-- node_modules/          installed packages (don't touch/commit)\n//\n//   package.json is the most important file to understand:\n//   - \"dependencies\" = packages your app needs (like pip-installed libs)\n//   - \"scripts\" = shortcuts, e.g. \"npm start\" runs the dev server\n\n\n// ================================================================\n// PART 4 -- Running the App on Your Phone\n// ================================================================\n//\n//   TRACE: npm start (or \"npx expo start\")\n//   Step 1: Expo bundles all your .tsx files into one JS bundle\n//   Step 2: Starts a local dev server (usually on port 8081)\n//   Step 3: Prints a QR code in the terminal\n//   Step 4: Open Expo Go on your phone, scan the QR code\n//   Step 5: Phone downloads the bundle over your WiFi and runs it\n//\n//   IMPORTANT: your phone and laptop must be on the SAME WiFi network.\n//\n//   npm start\n\n// Save any file while the app is running -> watch it update on your\n// phone within a second or two. This is Fast Refresh.\n\n\n// ================================================================\n// PART 5 -- Installing Extra Packages\n// ================================================================\n//\n//   Python: pip install requests\n//   Expo:   npx expo install some-package\n//\n//   Always prefer \"npx expo install X\" over plain \"npm install X\"\n//   for Expo-managed packages -- it picks the version that matches\n//   your exact Expo SDK version, avoiding compatibility bugs.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Get it running before moving on. Confidence first.\n// ================================================================\n\n// QUESTION 1 -- Predict\n//\n// You edit app/index.tsx and save the file while the app is running\n// on your phone via Expo Go.\n//\n// What do you expect to happen, and roughly how fast?       -> ?\n// What do you have to do if you instead close and reopen\n// Expo Go from scratch?                                     -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake in this plan)\n//\n//   1. Install Node.js\n//   2. Run: npm create-expo-app my-app\n//   3. Run: npm start\n//   4. Open Expo Go on phone connected to a DIFFERENT WiFi network\n//      than the laptop\n//   5. Scan QR code\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed plan:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Hands-On Checklist\n//\n// Actually do these steps on your machine and check them off:\n//   [ ] node --version runs successfully\n//   [ ] npx create-expo-app@latest rn-course --template runs\n//   [ ] Blank (TypeScript) template selected\n//   [ ] npm start shows a QR code\n//   [ ] Expo Go on your phone shows the default app screen\n//   [ ] Edit the text in app/index.tsx, save, see it update live\n//\n// Write here what you saw on screen after the final step:","takeaways":["Expo bundles your code -> QR code -> Expo Go runs it on your phone","npx create-expo-app@latest <name> --template -> scaffolds a project","npm start -> starts dev server + Fast Refresh on save","npx expo install <pkg> -> install Expo-compatible packages"],"nextHint":"lesson_02_jsx_components.tsx -- JSX vs HTML, your first component","milestone":""},{"num":2,"id":"lesson_02_jsx_components","filename":"lesson_02_jsx_components.tsx","title":"JSX & Components: Your First Screen","subtitle":"A component is just a function that returns \"what should be on screen.\"","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 02 -- JSX & Components: Your First Screen\n//   Teaching philosophy: A component is just a function that\n//                        returns \"what should be on screen.\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   In Python, a function returns data: a number, a string, a list.\n//   In React Native, a function can return UI -- a description of\n//   what should appear on the phone screen.\n//\n//   That description language is called JSX -- it LOOKS like HTML\n//   but it's actually JavaScript underneath. Every JSX tag becomes\n//   a function call that builds a tree of \"what to draw.\"\n//\n//   Python analogy:\n//   def describe_user(user):\n//       return f\"{user['name']} is {user['age']} years old\"\n//   -- returns a STRING describing data\n//\n//   React Native:\n//   const UserCard = () => {\n//       return <Text>Sarath is 25 years old</Text>;\n//   };\n//   -- returns a UI TREE describing what to draw\n//\n//   IMPORTANT: there is no <div>, <h1>, <p> here like web HTML.\n//   React Native has its OWN building blocks: View, Text, Image.\n\n\n// ================================================================\n// PART 1 -- View and Text: The Two Blocks You'll Use Most\n// ================================================================\n//\n//   View   = an invisible box / container (like a <div>)\n//   Text   = the ONLY way to show text (you cannot put raw text\n//            inside a View -- it must be wrapped in <Text>)\n//\n//   TRACE: rendering <View><Text>Hello</Text></View>\n//   Step 1: React Native sees a View -- creates an empty box\n//   Step 2: Inside it, sees a Text -- creates a text node\n//   Step 3: \"Hello\" is the CHILD of Text -- the actual string drawn\n//   Step 4: Final tree: Box -> contains -> \"Hello\"\n\nimport React from \"react\";\nimport { View, Text, StyleSheet } from \"react-native\";\n\nconst Greeting = () => {\n    return (\n        <View style={styles.container}>\n            <Text style={styles.title}>Hello, React Native!</Text>\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { padding: 20 },\n    title: { fontSize: 24, fontWeight: \"bold\" },\n});\n\nexport default Greeting;\n\n// ── PREDICT before running ──────────────────────────────────────\n// What happens if you write <View>Hello</View> WITHOUT <Text>?  -> ?\n// (Try it -- React Native will throw an error. Text needs <Text>.)\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- A Component IS a Function\n// ================================================================\n//\n//   Rule: a component is a function whose name starts with a\n//   CAPITAL letter, and which returns JSX.\n//\n//   const greeting = () => <Text>hi</Text>;   // lowercase -> NOT\n//                                              // treated as a component\n//   const Greeting = () => <Text>hi</Text>;   // capital -> IS one\n//\n//   TRACE: why capitalization matters\n//   Step 1: JSX sees <Greeting />\n//   Step 2: Capital letter -> \"this is a component, call its function\"\n//   Step 3: JSX sees <button />  (lowercase, web HTML tag -- doesn't\n//           even exist in RN, but the rule is the same idea)\n//   Step 4: Lowercase -> \"this is a built-in tag, not my function\"\n\nconst Subtitle = () => {\n    return <Text>I am a separate component.</Text>;\n};\n\n// Using one component inside another -- this is how whole apps\n// are built: small components, combined into bigger ones.\nconst Screen = () => {\n    return (\n        <View>\n            <Greeting />\n            <Subtitle />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Embedding JS Expressions with { }\n// ================================================================\n//\n//   Python f-string:   f\"Total: {price * 2}\"\n//   JSX equivalent:    <Text>Total: {price * 2}</Text>\n//\n//   Anything inside { } is regular JavaScript, evaluated and\n//   dropped into the UI tree as its result.\n\nconst price = 50;\nconst Receipt = () => {\n    return (\n        <View>\n            <Text>Price: {price}</Text>\n            <Text>With tax: {price * 1.18}</Text>\n            <Text>{price > 100 ? \"Expensive\" : \"Affordable\"}</Text>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- A Component Tree Mirrors a Nested Dict\n// ================================================================\n//\n//   Python nested dict:\n//   page = {\n//       \"header\": {\"title\": \"Home\"},\n//       \"body\": {\"text\": \"Welcome\"}\n//   }\n//\n//   JSX nested tree -- SAME shape, different notation:\n//   <View>                      // page\n//       <View>                  // header\n//           <Text>Home</Text>\n//       </View>\n//       <View>                  // body\n//           <Text>Welcome</Text>\n//       </View>\n//   </View>\n//\n//   Indentation in JSX is for humans only -- the { } and < /> tags\n//   are what actually define the structure, just like Python's\n//   { } and [ ] define dict/list structure regardless of spacing.","questionsCode":"// ================================================================\n// [QUESTIONS] -- A component = function that returns JSX.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const Box = () => {\n//     return (\n//         <View>\n//             <Text>Count: {2 + 2}</Text>\n//         </View>\n//     );\n// };\n//\n// What text appears on screen when <Box /> is rendered?   -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const card = () => {\n//       return (\n//           <View>\n//               Hello there\n//           </View>\n//       )\n//   }\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Profile Card\n//\n// PLAN: how many Text elements do you need? what data is static?\n//\n// Create a component ProfileCard that renders, inside one View:\n//   - A Text showing a name\n//   - A Text showing an age\n//   - A Text showing \"Status: Active\" only if a boolean\n//     isActive is true, otherwise \"Status: Inactive\"\n//     (hint: use the ternary {isActive ? \"...\" : \"...\"} pattern\n//     from PART 3)\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Compose Components\n//\n// PLAN: which small components combine into the bigger one?\n//\n// Create two small components: Header (renders a title Text) and\n// Footer (renders a copyright Text). Then create AppLayout that\n// renders Header, a body Text of your choice, and Footer -- all\n// inside one outer View.\n//\n// Write here:","takeaways":["JSX = HTML-looking syntax that's actually JavaScript","View = box/container | Text = only way to show text","Component = function, name starts with a CAPITAL letter","{expression} inside JSX = drop in any JS value, like an f-string"],"nextHint":"lesson_03_props.tsx -- passing data INTO components","milestone":""},{"num":3,"id":"lesson_03_props","filename":"lesson_03_props.tsx","title":"Props: Passing Data Into Components","subtitle":"Props are just function arguments. Nothing more mystical than that.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 03 -- Props: Passing Data Into Components\n//   Teaching philosophy: Props are just function arguments.\n//                        Nothing more mystical than that.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 02's components were hardcoded -- same output every time.\n//   Real apps need the SAME component to show DIFFERENT data:\n//   one ProfileCard for Sarath, another for Asha, another for Raj.\n//\n//   Python analogy -- this is just function parameters:\n//   def profile_card(name, age):\n//       return f\"{name}, {age} years old\"\n//\n//   profile_card(\"Sarath\", 25)\n//   profile_card(\"Asha\", 30)\n//\n//   React Native \"props\" = the SAME idea, but the argument arrives\n//   as ONE object, and the component is used as a JSX tag:\n//\n//   const ProfileCard = (props) => {\n//       return <Text>{props.name}, {props.age} years old</Text>;\n//   };\n//\n//   <ProfileCard name=\"Sarath\" age={25} />\n//   <ProfileCard name=\"Asha\" age={30} />\n\n\n// ================================================================\n// PART 1 -- Receiving Props (the object form)\n// ================================================================\n//\n//   TRACE: <ProfileCard name=\"Sarath\" age={25} />\n//   Step 1: JSX collects every attribute into ONE object:\n//           { name: \"Sarath\", age: 25 }\n//   Step 2: That object is passed as the function's single argument\n//   Step 3: Inside the component, you read props.name, props.age\n//   Step 4: Note: age={25} uses { } because 25 is a NUMBER, not a\n//           string -- \"25\" with quotes would pass the STRING \"25\"\n\nimport React from \"react\";\nimport { View, Text, StyleSheet } from \"react-native\";\n\ninterface ProfileCardProps {\n    name: string;\n    age: number;\n}\n\nconst ProfileCard = (props: ProfileCardProps) => {\n    return (\n        <View style={styles.card}>\n            <Text>{props.name}, {props.age} years old</Text>\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    card: { padding: 12, borderWidth: 1, borderRadius: 8, marginBottom: 8 },\n});\n\n\n// ================================================================\n// PART 2 -- Destructuring Props (what you'll actually write)\n// ================================================================\n//\n//   Remember lesson 00 PART 4 -- destructuring pulls keys straight\n//   out of an object. Almost all real RN code destructures props\n//   right in the function signature:\n//\n//   const ProfileCard = (props) => { ... props.name ... }   // verbose\n//   const ProfileCard = ({ name, age }) => { ... name ... }  // common\n\nconst ProfileCardV2 = ({ name, age }: ProfileCardProps) => {\n    return (\n        <View style={styles.card}>\n            <Text>{name}, {age} years old</Text>\n        </View>\n    );\n};\n\n// Using it with different data -- ONE component, MANY outputs:\nconst TeamScreen = () => {\n    return (\n        <View>\n            <ProfileCardV2 name=\"Sarath\" age={25} />\n            <ProfileCardV2 name=\"Asha\" age={30} />\n            <ProfileCardV2 name=\"Raj\" age={28} />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Optional Props and Defaults\n// ================================================================\n//\n//   Python: def greet(name, title=\"Mr.\"):   -- default value\n//   TS/RN equivalent uses a default right in destructuring:\n\ninterface BadgeProps {\n    label: string;\n    color?: string;            // ? = optional, from lesson 00 PART 3\n}\n\nconst Badge = ({ label, color = \"gray\" }: BadgeProps) => {\n    return (\n        <View style={[styles.card, { backgroundColor: color }]}>\n            <Text>{label}</Text>\n        </View>\n    );\n};\n\n// <Badge label=\"New\" />              -> uses default gray\n// <Badge label=\"Sale\" color=\"red\" /> -> overrides to red\n\n\n// ================================================================\n// PART 4 -- Props Are Read-Only (One-Way Data Flow)\n// ================================================================\n//\n//   A component must NEVER modify the props it receives -- exactly\n//   like you shouldn't mutate a function argument in place if the\n//   caller expects their original data untouched.\n//\n//   const ProfileCardV2 = ({ name, age }) => {\n//       age = age + 1;      // WRONG -- never reassign a prop\n//       return <Text>{name}</Text>;\n//   };\n//\n//   If a value needs to change over time (like a counter), that's\n//   STATE, not a prop -- covered next in lesson 04.\n\n\n// ================================================================\n// PART 5 -- children Prop (Wrapping Content)\n// ================================================================\n//\n//   Sometimes a component should wrap WHATEVER you put inside its\n//   tags, not fixed data. That's the special \"children\" prop.\n//\n//   <Card>\n//       <Text>Anything can go here</Text>\n//   </Card>\n//\n//   TRACE: how children arrives\n//   Step 1: Everything between <Card> and </Card> becomes one value\n//   Step 2: It's passed automatically as props.children\n//   Step 3: The component decides WHERE to place it\n\nimport { ReactNode } from \"react\";\n\ninterface CardProps {\n    children: ReactNode;       // ReactNode = \"any renderable JSX\"\n}\n\nconst Card = ({ children }: CardProps) => {\n    return <View style={styles.card}>{children}</View>;\n};\n\n// <Card>\n//     <Text>I'm wrapped by Card's border/padding</Text>\n// </Card>","questionsCode":"// ================================================================\n// [QUESTIONS] -- Props flow ONE way: parent -> child. Never reversed.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const Greet = ({ name }: { name: string }) => <Text>Hi {name}</Text>;\n//\n// <Greet name=\"Asha\" />\n// <Greet name={\"Raj\"} />\n//\n// Do both lines render the same thing? Why does the second one\n// use { } around a string that already has quotes?            -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const PriceTag = (props: { price: number }) => {\n//       props.price = props.price * 1.18;\n//       return <Text>Price: {props.Price}</Text>;\n//   };\n//\n//   <PriceTag price=\"100\" />\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Reusable Button Label\n//\n// PLAN: what props does this need, and which should be optional?\n//\n// Create a component InfoLine with props label (string, required)\n// and value (string, required) that renders \"Label: Value\" as one\n// Text. Use it three times with different label/value pairs inside\n// one View (e.g. \"Name: Sarath\", \"City: Chennai\", \"Role: Developer\").\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Optional Prop With Default\n//\n// PLAN: what's a sensible default for a \"size\" prop?\n//\n// Create a component Avatar with props initials (string, required)\n// and size (number, optional, default 40). Render a View styled\n// with width/height/borderRadius all equal to size, containing a\n// Text of the initials. Use it once with no size, once with size={80}.\n//\n// Write here:","takeaways":["Props = function arguments, passed as ONE object via JSX attributes","{name, age} destructuring in the signature = the common style","Props flow ONE way: parent -> child. NEVER mutate props.","children prop = whatever is nested between a component's tags"],"nextHint":"lesson_04_state.tsx -- values that change: useState","milestone":""},{"num":4,"id":"lesson_04_state","filename":"lesson_04_state.tsx","title":"State & useState: Values That Change","subtitle":"State is a variable, PLUS a promise that the screen redraws when it changes.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 04 -- State & useState: Values That Change\n//   Teaching philosophy: State is a variable, PLUS a promise that\n//                        the screen redraws when it changes.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Try this thought experiment: a counter screen with a regular\n//   \"let\" variable.\n//\n//   let count = 0;\n//   const increment = () => { count = count + 1; };\n//   -- pressing a button calls increment(). count DOES change in\n//   memory... but the SCREEN never updates. React has no idea the\n//   value changed, so it never re-draws.\n//\n//   Python analogy: imagine print()-ing a dashboard once at the\n//   top of a script. Changing a variable afterward doesn't make\n//   the ALREADY-PRINTED text update -- you'd have to print() again.\n//   useState is React's way of automatically \"print()-ing again\"\n//   (re-rendering) whenever that specific value changes.\n\n\n// ================================================================\n// PART 1 -- Your First useState\n// ================================================================\n//\n//   const [count, setCount] = useState(0);\n//                |       |              |\n//                |       |              starting value\n//                |       function to UPDATE count (and trigger\n//                |       a re-render)\n//                current value (read-only -- never assign to it\n//                directly, always go through setCount)\n//\n//   TRACE: pressing a \"+1\" button\n//   Step 1: onPress calls setCount(count + 1)\n//   Step 2: React stores the new value internally\n//   Step 3: React re-runs the WHOLE component function from the top\n//   Step 4: This time, useState(0) returns the NEW count, not 0\n//   Step 5: JSX re-renders with the updated number on screen\n\nimport React, { useState } from \"react\";\nimport { View, Text, Button, StyleSheet } from \"react-native\";\n\nconst Counter = () => {\n    const [count, setCount] = useState<number>(0);\n\n    return (\n        <View style={styles.container}>\n            <Text style={styles.count}>{count}</Text>\n            <Button title=\"+1\" onPress={() => setCount(count + 1)} />\n            <Button title=\"Reset\" onPress={() => setCount(0)} />\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { padding: 20, alignItems: \"center\" },\n    count: { fontSize: 40, marginBottom: 10 },\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you write \"count = count + 1\" instead of calling setCount,\n// does the number on screen change when you press +1?      -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Functional Updates (Safer When Using Old State)\n// ================================================================\n//\n//   setCount(count + 1) reads \"count\" from THIS render's snapshot.\n//   If multiple updates fire quickly, that snapshot can be stale.\n//   Safer pattern -- pass a FUNCTION that receives the latest value:\n//\n//   setCount((prevCount) => prevCount + 1);\n//\n//   TRACE: why this matters\n//   Step 1: setCount(count + 1) -- uses count CAPTURED at render time\n//   Step 2: setCount(prev => prev + 1) -- React hands you the\n//           TRUE latest value, no matter how many updates queued\n\nconst SafeCounter = () => {\n    const [count, setCount] = useState(0);\n    const incrementTwice = () => {\n        setCount((prev) => prev + 1);\n        setCount((prev) => prev + 1);   // both apply correctly -> +2\n    };\n    return (\n        <View>\n            <Text>{count}</Text>\n            <Button title=\"+2 (safe)\" onPress={incrementTwice} />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Toggling Booleans (Show/Hide Pattern)\n// ================================================================\n//\n//   A very common state shape: a boolean that flips visibility.\n\nconst Toggleable = () => {\n    const [isVisible, setIsVisible] = useState<boolean>(false);\n\n    return (\n        <View>\n            <Button\n                title={isVisible ? \"Hide\" : \"Show\"}\n                onPress={() => setIsVisible((prev) => !prev)}\n            />\n            {isVisible && <Text>Now you see me!</Text>}\n        </View>\n    );\n};\n//\n//   {isVisible && <Text>...</Text>} -- TRACE:\n//   Step 1: && evaluates left side first (isVisible)\n//   Step 2: if false -> stops there, JSX renders nothing\n//   Step 3: if true  -> moves to right side, renders the <Text>\n//   This is the standard \"conditionally render something\" pattern.\n\n\n// ================================================================\n// PART 4 -- State With Objects (Updating One Field at a Time)\n// ================================================================\n//\n//   Python: you'd just do user[\"age\"] += 1 on a dict in place.\n//   React state must be REPLACED, never mutated in place --\n//   spread the old object, then override the one field that changed.\n\ninterface FormState {\n    name: string;\n    age: number;\n}\n\nconst ProfileForm = () => {\n    const [form, setForm] = useState<FormState>({ name: \"\", age: 0 });\n\n    const updateName = (newName: string) => {\n        setForm({ ...form, name: newName });   // ...form = lesson 00's\n    };                                          // spread: copy old keys,\n                                                  // then override \"name\"\n\n    return <Text>{form.name || \"No name yet\"}</Text>;\n};\n//\n//   WRONG version (never do this):\n//   form.name = newName;   setForm(form);\n//   -- mutating in place means React can't tell the object \"changed\"\n//   (it's the same reference), so it may skip the re-render.","questionsCode":"// ================================================================\n// [QUESTIONS] -- State changes -> component re-renders automatically.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const [score, setScore] = useState(10);\n// const addFive = () => {\n//     setScore(score + 5);\n//     setScore(score + 5);\n// };\n// // addFive() is called ONCE.\n// What is \"score\" after this -- 15 or 20? Why?              -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const Likes = () => {\n//       let likes = useState(0);\n//       const handleLike = () => { likes = likes + 1; };\n//       return (\n//           <View>\n//               <Text>{likes}</Text>\n//               <Button title=\"Like\" onPress={handleLike} />\n//           </View>\n//       );\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Like/Unlike Button\n//\n// PLAN: what's the ONE piece of state you need?\n//\n// Create a component LikeButton with boolean state \"liked\"\n// (default false). Button title should read \"Like\" when not\n// liked, \"Liked!\" when liked, and pressing it should flip the\n// state using the functional-update pattern from PART 3.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Step Counter With Bounds\n//\n// PLAN: where do you check the bound -- before or inside setCount?\n//\n// Create a component BoundedCounter with number state \"value\"\n// (default 0). \"+1\" button increases it but NEVER above 10.\n// \"-1\" button decreases it but NEVER below 0. Display the value.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 5 -- Object State Update\n//\n// PLAN: which field changes -- name or age? what stays the same?\n//\n// Using the FormState shape from PART 4, create a component with\n// form state { name: \"Sarath\", age: 25 }. Add a button \"Birthday\"\n// that increases ONLY age by 1, keeping name unchanged, using the\n// spread pattern. Display \"name is age years old\".\n//\n// Write here:","takeaways":["const [value, setValue] = useState(initial)","NEVER mutate state directly -- always call the setter function","setValue(prev => ...) -- safest way to update based on old value","Objects/arrays: spread the old value, then override changed fields","{condition && <JSX/>} -- conditional rendering pattern"],"nextHint":"lesson_05_styling_flexbox.tsx -- layout with Flexbox","milestone":""},{"num":5,"id":"lesson_05_styling_flexbox","filename":"lesson_05_styling_flexbox.tsx","title":"Styling & Flexbox: Laying Out a Screen","subtitle":"Flexbox isn't CSS trivia -- it's a small set of rules for \"how do boxes share space.\"","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 05 -- Styling & Flexbox: Laying Out a Screen\n//   Teaching philosophy: Flexbox isn't CSS trivia -- it's a small\n//                        set of rules for \"how do boxes share space.\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   In Python you never had to ask \"where on screen does this go\" --\n//   print() just goes to the next line. A phone screen is 2D space,\n//   and EVERY View needs a layout rule: stacked vertically? side by\n//   side? centered? spaced out?\n//\n//   Flexbox answers these questions with a small vocabulary.\n//   IMPORTANT: in React Native, the DEFAULT direction is \"column\"\n//   (top to bottom) -- unlike CSS on web, where it's \"row\".\n\n\n// ================================================================\n// PART 1 -- StyleSheet.create (Not Inline CSS Strings)\n// ================================================================\n//\n//   Python analogy: a styles object is like a dict of settings you\n//   reuse across multiple widgets, instead of retyping every value.\n//\n//   StyleSheet.create({ ... }) takes a plain object of style objects\n//   and returns an optimized version React Native can reuse fast.\n\nimport React from \"react\";\nimport { View, Text, StyleSheet } from \"react-native\";\n\nconst styles = StyleSheet.create({\n    box: {\n        width: 100,\n        height: 100,\n        backgroundColor: \"tomato\",\n    },\n});\n\n// <View style={styles.box} />\n// Note: NO semicolons inside the style values, NO units like \"px\" --\n// numbers are treated as density-independent pixels automatically.\n\n\n// ================================================================\n// PART 2 -- flexDirection: The Most Important Property\n// ================================================================\n//\n//   flexDirection: \"column\"  -> children stack TOP to BOTTOM (default)\n//   flexDirection: \"row\"     -> children sit LEFT to RIGHT\n//\n//   TRACE: a row of 3 boxes\n//   Step 1: Parent View gets flexDirection: \"row\"\n//   Step 2: React Native lays children out left-to-right\n//   Step 3: Each child takes only the space IT needs, unless told\n//           otherwise (see flex: 1 below)\n\nconst RowExample = () => (\n    <View style={{ flexDirection: \"row\" }}>\n        <View style={[styles.box, { backgroundColor: \"red\", width: 50 }]} />\n        <View style={[styles.box, { backgroundColor: \"green\", width: 50 }]} />\n        <View style={[styles.box, { backgroundColor: \"blue\", width: 50 }]} />\n    </View>\n);\n// [styleA, styleB] -- an ARRAY of styles merges them, later ones\n// override earlier ones. This is how you combine a shared base\n// style with a one-off tweak.\n\n\n// ================================================================\n// PART 3 -- justifyContent & alignItems: The Two Axes\n// ================================================================\n//\n//   Every flex container has a MAIN axis and a CROSS axis:\n//   - flexDirection \"row\"    -> main axis = horizontal, cross = vertical\n//   - flexDirection \"column\" -> main axis = vertical, cross = horizontal\n//\n//   justifyContent -> positions children along the MAIN axis\n//     \"flex-start\" | \"center\" | \"flex-end\" | \"space-between\" | \"space-around\"\n//\n//   alignItems -> positions children along the CROSS axis\n//     \"flex-start\" | \"center\" | \"flex-end\" | \"stretch\"\n//\n//   TRACE: centering something on screen (the #1 question beginners ask)\n//   Step 1: container needs flex: 1 (fill all available space)\n//   Step 2: justifyContent: \"center\"  -> centers on the main axis\n//   Step 3: alignItems: \"center\"      -> centers on the cross axis\n//   Step 4: with both set, content is centered BOTH ways\n\nconst CenteredScreen = () => (\n    <View style={{ flex: 1, justifyContent: \"center\", alignItems: \"center\" }}>\n        <Text>I am centered, both horizontally and vertically.</Text>\n    </View>\n);\n\n\n// ================================================================\n// PART 4 -- flex: 1 (Sharing Available Space)\n// ================================================================\n//\n//   flex: 1 on a View means \"grow to fill whatever space is left,\n//   sharing fairly with siblings that also have flex set.\"\n//\n//   TRACE: two equal-height sections stacked vertically\n//   Step 1: Outer View: flex: 1 (fills the whole screen)\n//   Step 2: Top View:    flex: 1  -> takes HALF the remaining space\n//   Step 3: Bottom View: flex: 1  -> takes the OTHER half\n//   If Top had flex: 2 and Bottom flex: 1, Top would take 2/3.\n\nconst SplitScreen = () => (\n    <View style={{ flex: 1 }}>\n        <View style={{ flex: 1, backgroundColor: \"lightblue\" }} />\n        <View style={{ flex: 2, backgroundColor: \"lightgreen\" }} />\n    </View>\n);\n\n\n// ================================================================\n// PART 5 -- Spacing: margin, padding, gap\n// ================================================================\n//\n//   padding -> space INSIDE a box's border, pushing content inward\n//   margin  -> space OUTSIDE a box, pushing siblings away\n//   gap     -> space BETWEEN children of a flex container (modern,\n//              simpler than adding margin to every child)\n\nconst SpacedList = () => (\n    <View style={{ padding: 16, gap: 8 }}>\n        <View style={[styles.box, { height: 40 }]} />\n        <View style={[styles.box, { height: 40 }]} />\n        <View style={[styles.box, { height: 40 }]} />\n    </View>\n);","questionsCode":"// ================================================================\n// [QUESTIONS] -- Default direction is column. flex:1 fills space.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// <View style={{ flexDirection: \"row\", justifyContent: \"space-between\" }}>\n//     <Text>A</Text>\n//     <Text>B</Text>\n//     <Text>C</Text>\n// </View>\n//\n// Are A, B, C side by side or stacked? Where do they sit\n// relative to each other -- bunched together or spread out?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const styles = StyleSheet.create({\n//       row: { flexDirection: \"row\" margin: 10px }\n//   });\n//\n//   <View style=\"row\">\n//       <Text>Hi</Text>\n//   </View>\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Header Bar\n// PLAN: row or column? where does the title sit vs the icon?\n//\n// Build a header View with flexDirection \"row\", a title Text on\n// the left, and a \"⚙\" Text on the right, using justifyContent:\n// \"space-between\" so they sit at opposite ends.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a 3-Card Row\n// PLAN: how should the 3 cards share width equally?\n//\n// Build a row of 3 boxes, each with flex: 1 (so they split the\n// width evenly regardless of screen size), each a different color,\n// with a gap of 10 between them and 16 padding around the row.\n//\n// Write here:","takeaways":["StyleSheet.create({...}) -- define reusable styles, no units needed","flexDirection: \"column\" (default) | \"row\"","justifyContent -> main axis | alignItems -> cross axis","flex: 1 -> fill/share available space with siblings","[styleA, styleB] -- merge styles, later wins"],"nextHint":"lesson_06_user_input.tsx -- TextInput and Touchables","milestone":""},{"num":6,"id":"lesson_06_user_input","filename":"lesson_06_user_input.tsx","title":"User Input: TextInput & Touchables","subtitle":"Input fields are state, kept in sync by an event handler. Same loop, every time.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 06 -- User Input: TextInput & Touchables\n//   Teaching philosophy: Input fields are state, kept in sync by\n//                        an event handler. Same loop, every time.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python's input() BLOCKS your program until the user types and\n//   presses Enter -- it's a pause-and-wait.\n//\n//   A phone screen can't \"pause\" -- the user might tap, type, tap\n//   elsewhere, scroll, all without any fixed order. So instead of\n//   blocking, RN uses the \"controlled input\" pattern:\n//\n//   1. State holds the CURRENT text          useState(\"\")\n//   2. TextInput DISPLAYS that state          value={text}\n//   3. Every keystroke fires an event         onChangeText={...}\n//   4. The event handler updates the state    setText(newText)\n//   5. React re-renders, TextInput shows it   (loop back to 2)\n//\n//   This loop is called a \"controlled component\" -- the component's\n//   displayed value is always controlled BY state, never by the\n//   text input remembering things on its own.\n\n\n// ================================================================\n// PART 1 -- A Controlled TextInput\n// ================================================================\n//\n//   TRACE: typing the letter \"h\"\n//   Step 1: user presses \"h\" on the keyboard\n//   Step 2: TextInput fires onChangeText(\"h\")\n//   Step 3: your handler calls setText(\"h\")\n//   Step 4: component re-renders, value={text} is now \"h\"\n//   Step 5: TextInput visually shows \"h\" -- it never stored it\n//           itself, it just reflects whatever state says\n\nimport React, { useState } from \"react\";\nimport { View, Text, TextInput, StyleSheet, Pressable, Alert } from \"react-native\";\n\nconst NameInput = () => {\n    const [text, setText] = useState<string>(\"\");\n\n    return (\n        <View style={styles.container}>\n            <TextInput\n                style={styles.input}\n                placeholder=\"Enter your name\"\n                value={text}\n                onChangeText={setText}\n            />\n            <Text>You typed: {text}</Text>\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { padding: 20 },\n    input: {\n        borderWidth: 1,\n        borderColor: \"#ccc\",\n        borderRadius: 6,\n        padding: 10,\n        marginBottom: 10,\n    },\n    button: {\n        backgroundColor: \"#3478f6\",\n        padding: 12,\n        borderRadius: 8,\n        alignItems: \"center\",\n    },\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you remove value={text} but keep onChangeText={setText},\n// does typing still work? Why is value={text} still important?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Pressable: The Modern Touch Handler\n// ================================================================\n//\n//   Button (lesson 04) is simple but barely stylable. Pressable\n//   wraps ANY content and gives you full control over styling and\n//   press states -- it's what real apps use for custom buttons.\n//\n//   TRACE: a press\n//   Step 1: user touches the Pressable area\n//   Step 2: onPress fires -- runs your function, no arguments needed\n//   Step 3: (optional) style can be a FUNCTION receiving {pressed},\n//           letting you change appearance while held down\n\nconst CustomButton = () => {\n    return (\n        <Pressable\n            onPress={() => Alert.alert(\"Pressed!\", \"You tapped the button.\")}\n            style={({ pressed }) => [\n                styles.button,\n                { opacity: pressed ? 0.6 : 1 },   // dim while held\n            ]}\n        >\n            <Text style={{ color: \"white\" }}>Tap Me</Text>\n        </Pressable>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Numeric & Secure Input (keyboardType, secureTextEntry)\n// ================================================================\n//\n//   TextInput has props that change HOW the on-screen keyboard\n//   behaves -- this is configuration, not extra logic:\n//\n//   keyboardType=\"numeric\"     -> shows a number pad\n//   secureTextEntry={true}     -> masks characters, for passwords\n//   autoCapitalize=\"none\"      -> stops auto-capitalizing (emails!)\n//   multiline={true}           -> allows newlines, grows in height\n\nconst LoginFields = () => {\n    const [email, setEmail] = useState(\"\");\n    const [password, setPassword] = useState(\"\");\n\n    return (\n        <View style={styles.container}>\n            <TextInput\n                style={styles.input}\n                placeholder=\"Email\"\n                value={email}\n                onChangeText={setEmail}\n                autoCapitalize=\"none\"\n                keyboardType=\"email-address\"\n            />\n            <TextInput\n                style={styles.input}\n                placeholder=\"Password\"\n                value={password}\n                onChangeText={setPassword}\n                secureTextEntry\n            />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Combining Input + Button: A Tiny Form Flow\n// ================================================================\n//\n//   TRACE: submitting a name\n//   Step 1: text typed updates state (PART 1's loop)\n//   Step 2: user presses Submit (Pressable)\n//   Step 3: onPress reads the CURRENT state value (not the input\n//           directly -- state IS the source of truth)\n//   Step 4: you can validate, then act (e.g. clear the field)\n\nconst SubmitNameForm = () => {\n    const [name, setName] = useState(\"\");\n\n    const handleSubmit = () => {\n        if (name.trim() === \"\") {\n            Alert.alert(\"Error\", \"Name cannot be empty.\");\n            return;\n        }\n        Alert.alert(\"Submitted\", `Hello, ${name}!`);\n        setName(\"\");           // clear the field after submit\n    };\n\n    return (\n        <View style={styles.container}>\n            <TextInput\n                style={styles.input}\n                placeholder=\"Your name\"\n                value={name}\n                onChangeText={setName}\n            />\n            <Pressable style={styles.button} onPress={handleSubmit}>\n                <Text style={{ color: \"white\" }}>Submit</Text>\n            </Pressable>\n        </View>\n    );\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- value + onChangeText is the controlled-input loop.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const [age, setAge] = useState(\"\");\n// <TextInput value={age} onChangeText={setAge} keyboardType=\"numeric\" />\n//\n// Is \"age\" stored as a number or a string after typing \"25\"?  -> ?\n// (Hint: onChangeText always hands back a string, regardless\n// of keyboardType -- keyboardType only changes the KEYBOARD shown)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const SearchBox = () => {\n//       const [query, setQuery] = useState(\"\");\n//       return (\n//           <TextInput\n//               placeholder=\"Search\"\n//               onChangeText={() => setQuery}\n//           />\n//       );\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Character Counter\n//\n// PLAN: which piece of state changes on every keystroke?\n//\n// Create a component Bio with a multiline TextInput (max intended\n// 150 characters) and a Text below it showing \"{length}/150\".\n// If length exceeds 150, show the counter in red (conditional style).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Login Form With Validation\n//\n// PLAN: what counts as \"invalid\" for each field? when do you check?\n//\n// Using LoginFields as a base, add a Pressable \"Log In\" button.\n// On press: if email doesn't contain \"@\", or password length < 6,\n// show Alert.alert with a specific error message. Otherwise show\n// Alert.alert(\"Success\", \"Logged in!\").\n//\n// Write here:","takeaways":["Controlled input: value={state} + onChangeText={setState}","onChangeText always returns a STRING -- convert numbers yourself","Pressable -- modern touch handler, style can be a function of {pressed} for visual feedback","State is the source of truth -- read it, don't read the input"],"nextHint":"lesson_07_lists.tsx -- rendering arrays with FlatList","milestone":""},{"num":7,"id":"lesson_07_lists","filename":"lesson_07_lists.tsx","title":"Lists: Rendering Arrays with FlatList","subtitle":"Same logic as a Python for-loop -- \"for each item, draw something.\"","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 07 -- Lists: Rendering Arrays with FlatList\n//   Teaching philosophy: Same logic as a Python for-loop --\n//                        \"for each item, draw something.\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python:\n//   for user in users:\n//       print(user[\"name\"])\n//\n//   You already know how to loop over data. The only NEW idea here\n//   is: instead of printing text, each loop iteration produces a\n//   small piece of UI. Two ways to do this in React Native:\n//\n//   1. .map() -- fine for SHORT, fixed lists (a few items)\n//   2. FlatList -- built for LONG or DYNAMIC lists (efficient --\n//      only renders what's currently visible on screen)\n\n\n// ================================================================\n// PART 1 -- The .map() Approach (Small Lists)\n// ================================================================\n//\n//   Array.map() is JS's list comprehension -- it transforms each\n//   item into something else and returns a NEW array.\n//\n//   Python:  [f\"Hi {name}\" for name in names]\n//   JS:      names.map((name) => `Hi ${name}`)\n//\n//   TRACE: rendering 3 fruit names\n//   Step 1: fruits.map(...) runs once PER item\n//   Step 2: each call returns one <Text> element\n//   Step 3: .map() collects all of them into an array of elements\n//   Step 4: JSX renders that array as a list of items in order\n\nimport React, { useState } from \"react\";\nimport { View, Text, FlatList, StyleSheet } from \"react-native\";\n\nconst fruits = [\"Apple\", \"Banana\", \"Mango\"];\n\nconst SimpleFruitList = () => (\n    <View>\n        {fruits.map((fruit) => (\n            <Text key={fruit}>{fruit}</Text>\n        ))}\n    </View>\n);\n//\n//   key={fruit} -- TRACE: why every item needs a unique \"key\"\n//   Step 1: React needs to track WHICH item is which across re-renders\n//   Step 2: Without a key, React falls back to position (0, 1, 2...)\n//   Step 3: If the list reorders, React can misidentify items,\n//           causing wrong items to update/animate\n//   Step 4: A stable, unique key (id, not array index when avoidable)\n//           lets React track items correctly\n\n\n// ================================================================\n// PART 2 -- FlatList (The Real Tool for Real Lists)\n// ================================================================\n//\n//   .map() renders EVERY item immediately, even ones off-screen.\n//   For 1000 items, that's 1000 components built at once -- slow.\n//\n//   FlatList only renders what's near the visible screen area,\n//   recycling components as you scroll. Same end RESULT, much\n//   better performance for anything beyond a handful of items.\n//\n//   TRACE: how FlatList draws each row\n//   Step 1: you give it \"data\" -- an array\n//   Step 2: for each item, it calls your \"renderItem\" function\n//   Step 3: renderItem receives { item, index } -- you return JSX\n//   Step 4: \"keyExtractor\" tells FlatList how to get a unique key\n//           per item (instead of key={} on each row directly)\n\ninterface Product {\n    id: string;\n    name: string;\n    price: number;\n}\n\nconst products: Product[] = [\n    { id: \"1\", name: \"Keyboard\", price: 1500 },\n    { id: \"2\", name: \"Mouse\", price: 600 },\n    { id: \"3\", name: \"Monitor\", price: 9000 },\n];\n\nconst ProductList = () => {\n    return (\n        <FlatList\n            data={products}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => (\n                <View style={styles.row}>\n                    <Text>{item.name}</Text>\n                    <Text>₹{item.price}</Text>\n                </View>\n            )}\n        />\n    );\n};\n\nconst styles = StyleSheet.create({\n    row: {\n        flexDirection: \"row\",\n        justifyContent: \"space-between\",\n        padding: 12,\n        borderBottomWidth: 1,\n        borderBottomColor: \"#eee\",\n    },\n});\n\n\n// ================================================================\n// PART 3 -- Empty States and Headers\n// ================================================================\n//\n//   Real lists need to handle \"what if there's nothing to show yet.\"\n//\n//   ListEmptyComponent -> rendered when data=[] (empty array)\n//   ListHeaderComponent -> rendered once, above all items\n\nconst EmptyAwareList = ({ items }: { items: Product[] }) => {\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            ListHeaderComponent={<Text style={{ fontWeight: \"bold\" }}>Products</Text>}\n            ListEmptyComponent={<Text>No products yet.</Text>}\n            renderItem={({ item }) => <Text>{item.name}</Text>}\n        />\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Filtering Before Rendering (Search-as-you-type)\n// ================================================================\n//\n//   Combine lesson 06's controlled TextInput with a filtered list --\n//   this pattern shows up in almost every real app.\n//\n//   TRACE: typing \"mo\" into a search box\n//   Step 1: search state updates to \"mo\" (lesson 06's loop)\n//   Step 2: component re-renders\n//   Step 3: BEFORE rendering FlatList, filter products by name\n//   Step 4: FlatList receives the ALREADY-FILTERED array as data\n\nimport { TextInput } from \"react-native\";\n\nconst SearchableProductList = () => {\n    const [search, setSearch] = useState(\"\");\n\n    const filtered = products.filter((p) =>\n        p.name.toLowerCase().includes(search.toLowerCase())\n    );\n\n    return (\n        <View style={{ flex: 1 }}>\n            <TextInput\n                placeholder=\"Search products...\"\n                value={search}\n                onChangeText={setSearch}\n                style={{ borderWidth: 1, padding: 8, margin: 8 }}\n            />\n            <FlatList\n                data={filtered}\n                keyExtractor={(item) => item.id}\n                renderItem={({ item }) => <Text style={styles.row}>{item.name}</Text>}\n            />\n        </View>\n    );\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- FlatList for real lists. Always give a stable key.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const numbers = [1, 2, 3];\n// const doubled = numbers.map((n) => n * 2);\n// console.log(doubled);                       -> ?\n// console.log(numbers);                       -> ? (did it change?)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   <FlatList\n//       data={products}\n//       renderItem={(item) => <Text>{item.name}</Text>}\n//   />\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: renderItem's actual argument\n// shape, and what's missing entirely from this FlatList)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a To-Do List Renderer\n//\n// PLAN: what fields does each todo need? what shows when done?\n//\n// Given an array of { id: string, title: string, done: boolean },\n// render it with FlatList. Each row shows the title, struck through\n// (textDecorationLine: \"line-through\") style when done is true.\n// Show ListEmptyComponent text \"No todos!\" when the array is empty.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Live-Filtered Contact List\n//\n// PLAN: which field do you filter on -- name, phone, or both?\n//\n// Given contacts: { id, name, phone }[], build a screen with a\n// search TextInput that filters contacts whose name OR phone\n// contains the typed text (case-insensitive), rendered in a\n// FlatList showing \"name -- phone\" per row.\n//\n// Write here:","takeaways":[".map() -- fine for short, fixed lists; renders everything at once","FlatList -- for real/long lists; only renders visible items","data + renderItem({item}) + keyExtractor -- the 3 required props","Filter the array BEFORE passing it as \"data\", not inside renderItem"],"nextHint":"lesson_08_navigation_expo_router.tsx -- moving between screens","milestone":""},{"num":8,"id":"lesson_08_navigation_expo_router","filename":"lesson_08_navigation_expo_router.tsx","title":"Navigation: Expo Router (File-Based Routing)","subtitle":"A \"screen\" is just a component. Navigation is \"which component is currently showing.\" NOTE: this lesson describes FILES in the app/ folder, since Expo Router turns your folder structure into your app's routes. Read it like a guided tour -- you'll create these files for real in your own project.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 08 -- Navigation: Expo Router (File-Based Routing)\n//   Teaching philosophy: A \"screen\" is just a component. Navigation\n//                        is \"which component is currently showing.\"\n//   NOTE: this lesson describes FILES in the app/ folder, since\n//   Expo Router turns your folder structure into your app's routes.\n//   Read it like a guided tour -- you'll create these files for real\n//   in your own project.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   A website has URLs: /home, /profile, /settings -- each URL\n//   shows a different page. Expo Router brings that SAME idea to\n//   a phone app, except \"URLs\" are made from your FILE NAMES.\n//\n//   app/\n//   |-- index.tsx          -> route \"/\"        (the home screen)\n//   |-- profile.tsx        -> route \"/profile\"\n//   |-- settings.tsx       -> route \"/settings\"\n//   |-- products/\n//        |-- [id].tsx      -> route \"/products/123\" (dynamic!)\n//\n//   No manual route configuration -- the FILE PATH is the route.\n//   This is why Expo Router is the recommended default: it removes\n//   an entire category of setup code you'd otherwise write by hand.\n\n\n// ================================================================\n// PART 1 -- A Basic Two-Screen App\n// ================================================================\n//\n//   TRACE: tapping a \"Go to Profile\" button on the home screen\n//   Step 1: home screen calls router.push(\"/profile\")\n//   Step 2: Expo Router looks up app/profile.tsx\n//   Step 3: it renders that component, sliding it in\n//   Step 4: a back arrow appears automatically (stack navigation)\n//   Step 5: pressing back -> Expo Router pops back to index.tsx\n\n// ---- app/index.tsx ----\n//\n// import { View, Text, Button } from \"react-native\";\n// import { router } from \"expo-router\";\n//\n// export default function HomeScreen() {\n//     return (\n//         <View style={{ flex: 1, justifyContent: \"center\", alignItems: \"center\" }}>\n//             <Text>Home Screen</Text>\n//             <Button title=\"Go to Profile\" onPress={() => router.push(\"/profile\")} />\n//         </View>\n//     );\n// }\n\n// ---- app/profile.tsx ----\n//\n// import { View, Text, Button } from \"react-native\";\n// import { router } from \"expo-router\";\n//\n// export default function ProfileScreen() {\n//     return (\n//         <View style={{ flex: 1, justifyContent: \"center\", alignItems: \"center\" }}>\n//             <Text>Profile Screen</Text>\n//             <Button title=\"Go Back\" onPress={() => router.back()} />\n//         </View>\n//     );\n// }\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you rename app/profile.tsx to app/account.tsx, does\n// router.push(\"/profile\") still work? What URL DOES work now?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Link Component (Declarative Navigation)\n// ================================================================\n//\n//   router.push(...) is \"imperative\" -- you call a function.\n//   <Link> is \"declarative\" -- you describe WHERE it should go,\n//   similar to an <a href> on the web. Either works; Link is handy\n//   for things that are always tappable, like a list row.\n\n// import { Link } from \"expo-router\";\n//\n// <Link href=\"/profile\">\n//     <Text>Go to Profile</Text>\n// </Link>\n\n\n// ================================================================\n// PART 3 -- Dynamic Routes: Passing an ID Through the URL\n// ================================================================\n//\n//   Square brackets in a filename = \"this segment is a variable.\"\n//   app/products/[id].tsx matches /products/1, /products/2, etc.\n//\n//   TRACE: navigating to product 42\n//   Step 1: router.push(\"/products/42\")\n//   Step 2: Expo Router matches app/products/[id].tsx\n//   Step 3: inside that file, useLocalSearchParams() returns { id: \"42\" }\n//   Step 4: you use that id to look up/fetch the right product\n\n// ---- app/products/[id].tsx ----\n//\n// import { View, Text } from \"react-native\";\n// import { useLocalSearchParams } from \"expo-router\";\n//\n// export default function ProductDetail() {\n//     const { id } = useLocalSearchParams<{ id: string }>();\n//     return (\n//         <View>\n//             <Text>Showing details for product #{id}</Text>\n//         </View>\n//     );\n// }\n\n// Navigating to it from a list (lesson 07's FlatList + navigation):\n//\n// <FlatList\n//     data={products}\n//     keyExtractor={(item) => item.id}\n//     renderItem={({ item }) => (\n//         <Pressable onPress={() => router.push(`/products/${item.id}`)}>\n//             <Text>{item.name}</Text>\n//         </Pressable>\n//     )}\n// />\n\n\n// ================================================================\n// PART 4 -- Typed Navigation Params (TypeScript Safety)\n// ================================================================\n//\n//   useLocalSearchParams<{ id: string }>() -- the generic <{ id: string }>\n//   tells TypeScript exactly what shape to expect, so accessing\n//   params.wrongName gets caught at compile time, not at runtime.\n//\n//   For passing MORE than an id (e.g. extra query params), you can\n//   pass an object as the second argument to router.push:\n//\n//   router.push({ pathname: \"/products/[id]\", params: { id: \"42\", ref: \"home\" } });\n\n\n// ================================================================\n// PART 5 -- Layouts: Shared UI Across Screens (_layout.tsx)\n// ================================================================\n//\n//   A file named _layout.tsx wraps EVERY screen in that folder --\n//   used for shared headers, tab bars, or navigation containers.\n//\n//   app/_layout.tsx (wraps the whole app):\n//\n//   import { Stack } from \"expo-router\";\n//\n//   export default function RootLayout() {\n//       return <Stack />;\n//   }\n//\n//   This single line is what gives you the automatic back button\n//   and slide transitions you saw in PART 1 -- <Stack /> renders\n//   whichever screen route is currently active, with a navigation\n//   header wrapped around it.","questionsCode":"// ================================================================\n// [QUESTIONS] -- File path = route. [param].tsx = dynamic segment.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// Given this folder:\n//   app/index.tsx\n//   app/orders/index.tsx\n//   app/orders/[orderId].tsx\n//\n// What URL would show app/orders/index.tsx?                 -> ?\n// What URL would show app/orders/[orderId].tsx for order 9?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake)\n//\n//   File: app/profile.tsx\n//\n//   import { router } from \"expo-router\";\n//   <Button title=\"Go\" onPress={() => router.push(\"/Profile\")} />\n//\n// Bug -> ?  (hint: think about case-sensitivity in file paths)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Design a Route Structure\n//\n// PLAN: which screens are top-level? which need a dynamic segment?\n//\n// You're building a notes app with: a list of all notes, a screen\n// to view/edit ONE note by id, and a settings screen. Write out\n// the app/ folder structure (file names only) you would create,\n// and which URL each one corresponds to.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build It\n//\n// Actually create, in a real Expo Router project:\n//   app/index.tsx       -- list of 3 hardcoded note titles (FlatList)\n//   app/notes/[id].tsx  -- shows \"Note #{id}\" using useLocalSearchParams\n// Tapping a note in the list should navigate to its detail screen.\n//\n// Write here what you built and confirm it navigates correctly:","takeaways":["File path in app/ = the route -- no manual route config needed","router.push(\"/path\") / <Link href=\"/path\"> -- navigate","[id].tsx -- dynamic segment, read via useLocalSearchParams<{id: string}>()","_layout.tsx -- shared UI (Stack, headers, tabs) across a folder's screens"],"nextHint":"lesson_09_useeffect.tsx -- running code on mount / cleanup","milestone":""},{"num":9,"id":"lesson_09_useeffect","filename":"lesson_09_useeffect.tsx","title":"useEffect: Side Effects & Lifecycle","subtitle":"useEffect answers ONE question -- \"when should this code run?\"","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 09 -- useEffect: Side Effects & Lifecycle\n//   Teaching philosophy: useEffect answers ONE question --\n//                        \"when should this code run?\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   A Python script runs top to bottom, once, and exits. A React\n//   Native component doesn't work that way -- it RE-RUNS its\n//   function every time state or props change (lesson 04).\n//\n//   That creates a new problem: some actions should only happen\n//   ONCE (like fetching data when a screen first opens), not on\n//   every single re-render. useEffect is how you say \"run this\n//   code, but only when [these specific things] change.\"\n//\n//   const [data, setData] = useState(null);\n//   useEffect(() => {\n//       // this runs based on the dependency array below\n//   }, [/* dependency array */]);\n\n\n// ================================================================\n// PART 1 -- The Dependency Array: useEffect's Whole Personality\n// ================================================================\n//\n//   useEffect(fn, [])           -> runs ONCE, right after first render\n//   useEffect(fn, [count])      -> runs after first render, AND every\n//                                   time \"count\" changes\n//   useEffect(fn)                -> runs after EVERY render (rare, easy\n//                                   to cause infinite loops -- avoid)\n//\n//   TRACE: useEffect(fn, []) on screen open\n//   Step 1: component renders for the first time\n//   Step 2: screen appears on the phone\n//   Step 3: React then runs the effect function ONCE\n//   Step 4: because [] never changes, it never runs again\n\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text } from \"react-native\";\n\nconst WelcomeLogger = () => {\n    useEffect(() => {\n        console.log(\"Screen mounted -- this prints exactly once.\");\n    }, []);\n\n    return <Text>Check your console/terminal logs.</Text>;\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you change [] to [count] (with count from useState), and\n// then press a button that calls setCount, does the console.log\n// run again?                                                  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Reacting to a Specific Value Changing\n// ================================================================\n//\n//   TRACE: a search box that logs every time the query changes\n//   Step 1: user types \"m\" -> setQuery(\"m\") -> re-render\n//   Step 2: React checks: did \"query\" change since last render?\n//   Step 3: yes -> runs the effect again with the NEW query value\n//   Step 4: user types \"mo\" -> repeat\n\nconst SearchLogger = () => {\n    const [query, setQuery] = useState(\"\");\n\n    useEffect(() => {\n        console.log(\"Query changed to:\", query);\n    }, [query]);          // re-run ONLY when query changes\n\n    return <Text>{query}</Text>;\n};\n\n\n// ================================================================\n// PART 3 -- Cleanup Functions: Undoing Side Effects\n// ================================================================\n//\n//   Some effects set something up that must be torn down later --\n//   a timer, a subscription, an event listener. Return a function\n//   from useEffect, and React calls it automatically at the right time.\n//\n//   TRACE: a countdown timer\n//   Step 1: effect runs, starts setInterval, saves the timer id\n//   Step 2: every second, the interval fires, updates state\n//   Step 3: component unmounts (screen closes) OR dependencies change\n//   Step 4: React calls the CLEANUP function FIRST, clearing the\n//           old interval -- preventing it from running forever in\n//           the background after the screen is gone\n\nconst Countdown = () => {\n    const [seconds, setSeconds] = useState(10);\n\n    useEffect(() => {\n        const intervalId = setInterval(() => {\n            setSeconds((prev) => (prev > 0 ? prev - 1 : 0));\n        }, 1000);\n\n        return () => clearInterval(intervalId);   // cleanup\n    }, []);\n\n    return <Text>{seconds}</Text>;\n};\n//\n//   Without the cleanup return, the interval would keep running\n//   even after you navigate away -- a classic memory/bug leak.\n\n\n// ================================================================\n// PART 4 -- The #1 Real Use Case: Fetching Data on Screen Open\n// ================================================================\n//\n//   This is the pattern you'll use constantly, and lesson 10 goes\n//   deep on the fetch() part -- here, focus on the useEffect SHAPE.\n//\n//   TRACE: loading a user's profile when the screen opens\n//   Step 1: screen mounts, loading state starts as true\n//   Step 2: useEffect(fn, []) fires once\n//   Step 3: fn calls an (async) fetch function\n//   Step 4: when data arrives, setData(...) and setLoading(false)\n//   Step 5: re-render shows the data instead of a loading spinner\n\ninterface UserData {\n    name: string;\n}\n\nconst ProfileLoader = () => {\n    const [user, setUser] = useState<UserData | null>(null);\n    const [loading, setLoading] = useState(true);\n\n    useEffect(() => {\n        const loadUser = async () => {\n            // pretend this is a real API call (lesson 10 covers fetch)\n            await new Promise((resolve) => setTimeout(resolve, 1000));\n            setUser({ name: \"Sarath\" });\n            setLoading(false);\n        };\n        loadUser();\n    }, []);\n\n    if (loading) return <Text>Loading...</Text>;\n    return <Text>Welcome, {user?.name}</Text>;\n};\n//\n//   Note: useEffect's callback itself CANNOT be \"async\" directly --\n//   define an inner async function and call it, as shown above.","questionsCode":"// ================================================================\n// [QUESTIONS] -- [] = once. [value] = on that value's changes.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const [count, setCount] = useState(0);\n// useEffect(() => {\n//     console.log(\"Effect ran, count is\", count);\n// }, [count]);\n//\n// If a button calls setCount(count + 1) three times in a row\n// (three separate presses), how many times does the console.log\n// print in total, INCLUDING the first render?                -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const Clock = () => {\n//       const [time, setTime] = useState(new Date());\n//       useEffect(() => {\n//           setInterval(() => setTime(new Date()), 1000);\n//       });\n//       return <Text>{time.toString()}</Text>;\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: missing dependency array AND\n// missing cleanup -- what goes wrong from each, separately?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Window Focus Logger (Conceptual)\n//\n// PLAN: when should this effect run -- once, or on every render?\n//\n// Build a component that logs \"Screen opened\" once when it mounts,\n// and logs \"Screen closed\" once when it unmounts (use the cleanup\n// function for the second log). No state needed, just two console.logs.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Debounced Search Logger\n//\n// PLAN: why does this need BOTH a dependency array AND a cleanup?\n//\n// Build a search input (controlled, from lesson 06). Using\n// useEffect with [query] as the dependency, set a setTimeout that\n// logs \"Searching for: {query}\" after 500ms of no typing. In the\n// cleanup function, clearTimeout the previous timer -- this is\n// the standard \"debounce\" pattern (only fires after typing pauses).\n//\n// Write here:","takeaways":["useEffect(fn, []) -> runs once after first render","useEffect(fn, [value]) -> runs once, then again whenever value changes","return () => {...} inside the effect -- cleanup, runs before the next effect call AND when the component unmounts","Async work needs an inner async function -- the effect fn itself cannot be async"],"nextHint":"lesson_10_apis_fetch.tsx -- fetching real data from a server","milestone":""},{"num":10,"id":"lesson_10_apis_fetch","filename":"lesson_10_apis_fetch.tsx","title":"Fetching APIs in React Native","subtitle":"Same request-response cycle as Python's requests library -- different syntax, no new networking concepts.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 10 -- Fetching APIs in React Native\n//   Teaching philosophy: Same request-response cycle as Python's\n//                        requests library -- different syntax, no\n//                        new networking concepts.\n// ================================================================\n//   Before starting: npx expo install axios  (optional, see PART 3)\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python's lesson_23_apis.py taught: API = URL that returns JSON.\n//   GET = fetch data. POST = send data. Status codes summarize\n//   success/failure. NONE of that changes in React Native.\n//\n//   What's different is HOW you wait for the response, because a\n//   phone screen can never \"pause\" (no blocking input()-style call):\n//\n//   Python:  response = requests.get(url)        -- blocks here\n//   RN/TS:   const response = await fetch(url);   -- \"await\" pauses\n//            ONLY this async function, not the whole app/screen\n//\n//   \"async\" / \"await\" is JS's way of writing code that LOOKS\n//   sequential but doesn't freeze the UI while waiting.\n\n\n// ================================================================\n// PART 1 -- async/await: Reading It Like Python\n// ================================================================\n//\n//   async function someName() { ... }       -- marks a function as\n//                                                \"this can pause/wait\"\n//   await somePromise                        -- \"pause HERE until\n//                                                this resolves, then\n//                                                continue with the result\"\n//\n//   TRACE: fetching one user\n//   Step 1: fetch(url) immediately returns a \"Promise\" (an IOU for\n//           a future value) and starts the network request\n//   Step 2: await pauses this function until the Promise resolves\n//   Step 3: response.json() ALSO returns a Promise -- await it too\n//   Step 4: the parsed data is now a normal JS object\n\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, FlatList, ActivityIndicator } from \"react-native\";\n\ninterface ApiUser {\n    id: number;\n    name: string;\n    email: string;\n}\n\nconst fetchUser = async (id: number): Promise<ApiUser> => {\n    const response = await fetch(`https://jsonplaceholder.typicode.com/users/${id}`);\n    if (!response.ok) {\n        throw new Error(`HTTP error: ${response.status}`);\n    }\n    return response.json();\n};\n\nconst UserProfile = () => {\n    const [user, setUser] = useState<ApiUser | null>(null);\n    const [loading, setLoading] = useState(true);\n    const [error, setError] = useState<string | null>(null);\n\n    useEffect(() => {\n        const load = async () => {\n            try {\n                const data = await fetchUser(1);\n                setUser(data);\n            } catch (err) {\n                setError(err instanceof Error ? err.message : \"Unknown error\");\n            } finally {\n                setLoading(false);\n            }\n        };\n        load();\n    }, []);\n\n    if (loading) return <ActivityIndicator size=\"large\" />;\n    if (error) return <Text>Error: {error}</Text>;\n    return (\n        <View>\n            <Text>{user?.name}</Text>\n            <Text>{user?.email}</Text>\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// What does ActivityIndicator show, and for roughly how long,\n// before the name/email appear?                              -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Loading / Error / Data Pattern (Memorize This Shape)\n// ================================================================\n//\n//   ALMOST every screen that fetches data needs THREE states:\n//   1. loading  -- true while waiting, show a spinner\n//   2. error    -- set if something went wrong, show a message\n//   3. data     -- the actual result, show the real UI\n//\n//   try { ... } catch { ... } finally { ... } -- TRACE:\n//   Step 1: try block runs the risky network code\n//   Step 2: if it throws, catch block runs, captures the error\n//   Step 3: finally ALWAYS runs, success or failure -- perfect\n//           place to turn loading off no matter what happened\n\n\n// ================================================================\n// PART 3 -- Fetching a List and Rendering It\n// ================================================================\n//\n//   Combines lesson 07's FlatList with PART 1's fetch pattern --\n//   this exact combination is one of the most common screens you\n//   will ever build.\n\nconst fetchPosts = async (): Promise<{ id: number; title: string }[]> => {\n    const response = await fetch(\"https://jsonplaceholder.typicode.com/posts\");\n    return response.json();\n};\n\nconst PostList = () => {\n    const [posts, setPosts] = useState<{ id: number; title: string }[]>([]);\n    const [loading, setLoading] = useState(true);\n\n    useEffect(() => {\n        fetchPosts()\n            .then((data) => setPosts(data.slice(0, 10)))\n            .catch((err) => console.log(\"Failed to load posts:\", err))\n            .finally(() => setLoading(false));\n    }, []);\n    // .then/.catch/.finally -- the OLDER way to handle Promises,\n    // equivalent in effect to await + try/catch/finally. You'll\n    // see both styles in real codebases.\n\n    if (loading) return <ActivityIndicator />;\n\n    return (\n        <FlatList\n            data={posts}\n            keyExtractor={(item) => item.id.toString()}\n            renderItem={({ item }) => <Text style={{ padding: 8 }}>{item.title}</Text>}\n        />\n    );\n};\n\n\n// ================================================================\n// PART 4 -- POSTing Data (Sending, Not Just Fetching)\n// ================================================================\n//\n//   fetch(url, { method, headers, body }) -- TRACE:\n//   Step 1: method: \"POST\" -- tells the server you're creating data\n//   Step 2: headers tell the server the body is JSON\n//   Step 3: body must be a STRING -- JSON.stringify(obj) converts\n//           your JS object into that string (the reverse of .json())\n//   Step 4: server responds, usually with status 201 (Created)\n\nconst createPost = async (title: string, body: string) => {\n    const response = await fetch(\"https://jsonplaceholder.typicode.com/posts\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\" },\n        body: JSON.stringify({ title, body, userId: 1 }),\n    });\n    return response.json();\n};\n\n\n// ================================================================\n// PART 5 -- axios as an Alternative (Mentioned, Not Required)\n// ================================================================\n//\n//   axios wraps fetch with nicer defaults: automatic JSON parsing\n//   (no .json() call needed), and it throws on non-2xx automatically.\n//\n//   import axios from \"axios\";\n//   const response = await axios.get(url);\n//   console.log(response.data);          // already parsed\n//\n//   Either fetch or axios is fine -- fetch is built-in, axios is a\n//   popular convenience layer used in many production codebases.","questionsCode":"// ================================================================\n// [QUESTIONS] -- loading/error/data is the pattern. Memorize the shape.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const res = await fetch(\"https://jsonplaceholder.typicode.com/todos/1\");\n// const data = await res.json();\n// console.log(res.ok);              -> ?  (true/false)\n// console.log(typeof data);         -> ?\n// console.log(data.completed);      -> ?  (run it to confirm)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const loadData = () => {\n//       const res = fetch(\"https://jsonplaceholder.typicode.com/users\");\n//       const data = res.json();\n//       setUsers(data);\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Todo Screen\n//\n// PLAN: which 3 states do you need? what does each UI state show?\n//\n// Fetch https://jsonplaceholder.typicode.com/todos (first 20 only),\n// using the loading/error/data pattern from PART 2. Render with\n// FlatList: each row shows the title, with a \"✓\" prefix if completed.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a \"Create Post\" Form\n//\n// PLAN: which input state feeds the POST body?\n//\n// Build a form with title and body TextInputs (lesson 06) and a\n// Submit Pressable. On press, call createPost(title, body), show\n// an Alert with the new post's id on success, and an Alert with\n// the error message on failure.\n//\n// Write here:","takeaways":["async function + await -- pause THIS function, not the whole app","fetch(url) -> Promise<Response> | response.json() -> parsed data","ALWAYS structure data screens as: loading / error / data states","fetch(url, { method: \"POST\", headers, body: JSON.stringify(obj) })"],"nextHint":"lesson_11_forms_storage.tsx -- forms + AsyncStorage persistence","milestone":""},{"num":11,"id":"lesson_11_forms_storage","filename":"lesson_11_forms_storage.tsx","title":"Forms & AsyncStorage: Saving Data Locally","subtitle":"Same idea as Python's file_handling lesson -- write data out, read it back later.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 11 -- Forms & AsyncStorage: Saving Data Locally\n//   Teaching philosophy: Same idea as Python's file_handling lesson\n//                        -- write data out, read it back later.\n// ================================================================\n//   Before starting: npx expo install @react-native-async-storage/async-storage\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python's lesson_12_file_handling.py: open(\"data.txt\", \"w\") writes\n//   to disk so it survives the program ending. A phone app has the\n//   same need -- if the user closes the app, state (useState) is\n//   WIPED. AsyncStorage is the phone equivalent of writing to a file:\n//   simple key-value storage that survives app restarts.\n//\n//   Python:                          AsyncStorage:\n//   json.dump(data, file)            await AsyncStorage.setItem(key, json)\n//   json.load(file)                  await AsyncStorage.getItem(key)\n//\n//   IMPORTANT: AsyncStorage only stores STRINGS. Objects must be\n//   JSON.stringify()'d before saving, and JSON.parse()'d after\n//   reading back -- same round-trip as Python's json.dump/json.load.\n\n\n// ================================================================\n// PART 1 -- A Multi-Field Form (Combining Lesson 04 + 06)\n// ================================================================\n//\n//   Form state shape: ONE object holding every field, updated with\n//   the spread pattern from lesson 04 PART 4.\n\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, TextInput, Pressable, FlatList, Alert, StyleSheet } from \"react-native\";\nimport AsyncStorage from \"@react-native-async-storage/async-storage\";\n\ninterface Note {\n    id: string;\n    title: string;\n    body: string;\n}\n\nconst NoteForm = ({ onSubmit }: { onSubmit: (note: Note) => void }) => {\n    const [title, setTitle] = useState(\"\");\n    const [body, setBody] = useState(\"\");\n\n    const handleSubmit = () => {\n        if (title.trim() === \"\") {\n            Alert.alert(\"Title required\");\n            return;\n        }\n        onSubmit({ id: Date.now().toString(), title, body });\n        setTitle(\"\");\n        setBody(\"\");\n    };\n\n    return (\n        <View style={styles.form}>\n            <TextInput style={styles.input} placeholder=\"Title\" value={title} onChangeText={setTitle} />\n            <TextInput style={styles.input} placeholder=\"Body\" value={body} onChangeText={setBody} multiline />\n            <Pressable style={styles.button} onPress={handleSubmit}>\n                <Text style={{ color: \"white\" }}>Add Note</Text>\n            </Pressable>\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    form: { padding: 16, gap: 8 },\n    input: { borderWidth: 1, borderColor: \"#ccc\", borderRadius: 6, padding: 10 },\n    button: { backgroundColor: \"#3478f6\", padding: 12, borderRadius: 8, alignItems: \"center\" },\n});\n\n\n// ================================================================\n// PART 2 -- Writing to AsyncStorage\n// ================================================================\n//\n//   TRACE: saving an array of notes\n//   Step 1: you have notes: Note[] in state\n//   Step 2: JSON.stringify(notes) -> turns it into one big string\n//   Step 3: await AsyncStorage.setItem(\"notes\", thatString)\n//   Step 4: the device's local storage now has it, under key \"notes\"\n//   Step 5: this survives closing the app completely\n\nconst saveNotes = async (notes: Note[]) => {\n    await AsyncStorage.setItem(\"notes\", JSON.stringify(notes));\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you call AsyncStorage.setItem(\"notes\", notes) WITHOUT\n// JSON.stringify, what happens, given it only accepts strings?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 3 -- Reading From AsyncStorage (Usually in useEffect)\n// ================================================================\n//\n//   TRACE: loading saved notes when the screen opens\n//   Step 1: useEffect(fn, []) -- runs once, lesson 09's pattern\n//   Step 2: await AsyncStorage.getItem(\"notes\") -- returns a string\n//           OR null if nothing was ever saved under that key\n//   Step 3: if not null, JSON.parse(string) -> back to a real array\n//   Step 4: setNotes(parsedArray) -- now it's in state, ready to render\n\nconst loadNotes = async (): Promise<Note[]> => {\n    const raw = await AsyncStorage.getItem(\"notes\");\n    return raw ? JSON.parse(raw) : [];\n};\n\n\n// ================================================================\n// PART 4 -- Putting It Together: A Persisted Notes Screen\n// ================================================================\n//\n//   TRACE: the full read-modify-write cycle\n//   Step 1: on mount, load notes from storage into state\n//   Step 2: user adds a note -> update state with the new array\n//   Step 3: immediately ALSO save that new array back to storage\n//   Step 4: next time the app opens, step 1 picks up the saved data\n\nconst NotesScreen = () => {\n    const [notes, setNotes] = useState<Note[]>([]);\n\n    useEffect(() => {\n        loadNotes().then(setNotes);\n    }, []);\n\n    const addNote = async (note: Note) => {\n        const updated = [...notes, note];   // spread: copy + add new\n        setNotes(updated);\n        await saveNotes(updated);\n    };\n\n    const deleteNote = async (id: string) => {\n        const updated = notes.filter((n) => n.id !== id);   // exclude by id\n        setNotes(updated);\n        await saveNotes(updated);\n    };\n\n    return (\n        <View style={{ flex: 1 }}>\n            <NoteForm onSubmit={addNote} />\n            <FlatList\n                data={notes}\n                keyExtractor={(item) => item.id}\n                renderItem={({ item }) => (\n                    <Pressable onLongPress={() => deleteNote(item.id)} style={{ padding: 12 }}>\n                        <Text style={{ fontWeight: \"bold\" }}>{item.title}</Text>\n                        <Text>{item.body}</Text>\n                    </Pressable>\n                )}\n            />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 5 -- removeItem and clear (Cleanup Operations)\n// ================================================================\n//\n//   await AsyncStorage.removeItem(\"notes\");   -- deletes ONE key\n//   await AsyncStorage.clear();               -- wipes EVERYTHING\n//   (clear() affects the whole app's storage -- use removeItem for\n//   anything targeted, the same caution as Python's os.remove vs\n//   shutil.rmtree)","questionsCode":"// ================================================================\n// [QUESTIONS] -- AsyncStorage only stores strings. JSON round-trips objects.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// await AsyncStorage.setItem(\"count\", \"5\");\n// const value = await AsyncStorage.getItem(\"count\");\n// console.log(typeof value);            -> ?  (string or number?)\n// console.log(value + 1);               -> ?  (what does + do to a string?)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const saveUser = (user) => {\n//       AsyncStorage.setItem(\"user\", user);\n//   };\n//   const loadUser = () => {\n//       const data = AsyncStorage.getItem(\"user\");\n//       return JSON.parse(data);\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Settings Screen\n//\n// PLAN: what's the key? what shape is the saved value?\n//\n// Build a screen with a boolean \"darkMode\" toggle (Pressable that\n// flips state) that SAVES to AsyncStorage under key \"settings\"\n// immediately on change, and LOADS the saved value on mount so the\n// toggle reflects the last-saved state after an app restart.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Extend the Notes App\n//\n// PLAN: which note changes -- and how do you find it in the array?\n//\n// Add an \"edit\" feature to NotesScreen: tapping a note (not long\n// press) should let you change its title via a second TextInput\n// and a \"Save Edit\" button, updating ONLY that note in the array\n// (use .map() to return a new array with one item changed), then\n// persist with saveNotes.\n//\n// Write here:","takeaways":["AsyncStorage only stores STRINGS -- JSON.stringify before saving, JSON.parse after reading","setItem/getItem are async -- always await them","Pattern: load on mount (useEffect) -> update state -> save on change","removeItem(key) for one key | clear() wipes everything (be careful)"],"nextHint":"lesson_12_device_features.tsx -- camera, location, permissions","milestone":""},{"num":12,"id":"lesson_12_device_features","filename":"lesson_12_device_features.tsx","title":"Device Features: Camera, Location, Permissions","subtitle":"Hardware access ALWAYS follows the same 3-step shape -- ask, check, use.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 12 -- Device Features: Camera, Location, Permissions\n//   Teaching philosophy: Hardware access ALWAYS follows the same\n//                        3-step shape -- ask, check, use.\n// ================================================================\n//   Before starting:\n//   npx expo install expo-camera expo-location expo-image-picker\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python scripts on your laptop run with whatever access your\n//   user account has. A PHONE is different -- the OS protects\n//   sensitive hardware (camera, GPS, contacts) behind PERMISSIONS\n//   that the USER must explicitly grant, one app at a time.\n//\n//   Every device feature in Expo follows the SAME 3-step shape:\n//   1. ASK   -- request permission (shows the OS's popup)\n//   2. CHECK -- did the user grant it, or deny it?\n//   3. USE   -- only if granted, actually access the hardware\n//\n//   Skipping step 2 and using the feature anyway will crash or\n//   silently fail -- ALWAYS check the permission result first.\n\n\n// ================================================================\n// PART 1 -- Location: Ask, Check, Use\n// ================================================================\n//\n//   TRACE: getting the user's current GPS position\n//   Step 1: requestForegroundPermissionsAsync() -- shows OS popup\n//           (\"Allow MyApp to access your location?\")\n//   Step 2: result.status is either \"granted\" or \"denied\"\n//   Step 3: if granted, getCurrentPositionAsync() reads real GPS\n//   Step 4: if denied, show a message -- DO NOT attempt to read GPS\n\nimport React, { useState } from \"react\";\nimport { View, Text, Button } from \"react-native\";\nimport * as Location from \"expo-location\";\n\nconst LocationScreen = () => {\n    const [coords, setCoords] = useState<{ lat: number; lon: number } | null>(null);\n    const [error, setError] = useState<string | null>(null);\n\n    const getLocation = async () => {\n        const { status } = await Location.requestForegroundPermissionsAsync();\n        if (status !== \"granted\") {\n            setError(\"Location permission denied.\");\n            return;\n        }\n        const position = await Location.getCurrentPositionAsync({});\n        setCoords({\n            lat: position.coords.latitude,\n            lon: position.coords.longitude,\n        });\n    };\n\n    return (\n        <View style={{ padding: 20 }}>\n            <Button title=\"Get My Location\" onPress={getLocation} />\n            {coords && <Text>Lat: {coords.lat}, Lon: {coords.lon}</Text>}\n            {error && <Text>{error}</Text>}\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If the user denies permission once, then you press the button\n// again, does the OS popup show again automatically, or do they\n// need to enable it manually in phone Settings?              -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Camera & Image Picker\n// ================================================================\n//\n//   Two related but different tools:\n//   expo-camera        -- build a CUSTOM live camera screen\n//   expo-image-picker  -- simplest option: open the OS's OWN\n//                         camera/gallery UI and just get back a result\n//\n//   For most apps, image-picker is enough -- you don't need to\n//   reinvent the camera interface.\n\nimport * as ImagePicker from \"expo-image-picker\";\nimport { Image } from \"react-native\";\n\nconst PhotoPicker = () => {\n    const [imageUri, setImageUri] = useState<string | null>(null);\n\n    const pickImage = async () => {\n        const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();\n        if (status !== \"granted\") {\n            console.log(\"Gallery permission denied.\");\n            return;\n        }\n        const result = await ImagePicker.launchImageLibraryAsync({\n            mediaTypes: ImagePicker.MediaTypeOptions.Images,\n            quality: 0.7,\n        });\n        if (!result.canceled) {\n            setImageUri(result.assets[0].uri);\n        }\n    };\n\n    return (\n        <View style={{ padding: 20 }}>\n            <Button title=\"Pick a Photo\" onPress={pickImage} />\n            {imageUri && <Image source={{ uri: imageUri }} style={{ width: 200, height: 200 }} />}\n        </View>\n    );\n};\n//\n//   TRACE: result.canceled\n//   Step 1: user either picks a photo OR backs out of the picker\n//   Step 2: result.canceled tells you which happened\n//   Step 3: only read result.assets[0].uri when canceled is false\n\n\n// ================================================================\n// PART 3 -- A Live Camera Preview (expo-camera)\n// ================================================================\n//\n//   For a CUSTOM camera screen (e.g. a barcode scanner UI), you\n//   render <CameraView> directly and control it with a ref\n//   (refs are covered properly in lesson 16 -- here, just the shape).\n\n// import { CameraView, useCameraPermissions } from \"expo-camera\";\n//\n// const CameraScreen = () => {\n//     const [permission, requestPermission] = useCameraPermissions();\n//\n//     if (!permission) return <Text>Loading permissions...</Text>;\n//     if (!permission.granted) {\n//         return (\n//             <View>\n//                 <Text>We need camera access.</Text>\n//                 <Button title=\"Grant Permission\" onPress={requestPermission} />\n//             </View>\n//         );\n//     }\n//     return <CameraView style={{ flex: 1 }} />;\n// };\n\n\n// ================================================================\n// PART 4 -- Why Permissions Can FAIL Even After \"Granted\"\n// ================================================================\n//\n//   Real apps must handle ALL of these cases, not just the happy path:\n//   - user denies the permission popup\n//   - user previously denied it PERMANENTLY (\"don't ask again\")\n//   - user grants it, then revokes it later in phone Settings\n//   - the device has no GPS signal / no camera hardware at all\n//\n//   This is why every device-feature function in this lesson checks\n//   status before touching the hardware -- never assume access.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Ask, check, use. Never skip the check.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const { status } = await Location.requestForegroundPermissionsAsync();\n// if (status !== \"granted\") {\n//     // do nothing else, just return\n// }\n// const position = await Location.getCurrentPositionAsync({});\n//\n// What's wrong with this code even though it CHECKS status?  -> ?\n// (hint: look closely at the if block's body)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const takePhoto = () => {\n//       const result = ImagePicker.launchImageLibraryAsync();\n//       setImage(result.uri);\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Permission-Gated Button\n//\n// PLAN: what are the 3 visual states this button can be in?\n//\n// Build a component that shows \"Check Location Permission\" initially.\n// On press, request permission. If granted, replace the button with\n// the lat/lon text (PART 1's pattern). If denied, show \"Permission\n// denied -- enable it in Settings\" instead of the button.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Profile Photo Uploader\n//\n// PLAN: where is the \"no photo yet\" state shown vs the picked photo?\n//\n// Build a profile screen: a circular placeholder (gray View,\n// borderRadius half of width/height) that says \"Add Photo\" when no\n// image is picked, and shows the actual picked image once one is\n// chosen via ImagePicker, replacing the placeholder.\n//\n// Write here:","takeaways":["Every device feature: ASK permission -> CHECK status -> USE hardware","requestForegroundPermissionsAsync() / requestMediaLibraryPermissionsAsync()","status !== \"granted\" -> stop, don't touch the hardware","expo-image-picker -- simplest path for photo selection","expo-camera -- for a fully custom live camera UI"],"nextHint":"lesson_13_project.tsx -- build a small app combining lessons 00-12","milestone":""},{"num":13,"id":"lesson_13_project","filename":"lesson_13_project.tsx","title":"Project: Build a Weather Notes App","subtitle":"A project lesson has NO new concepts -- it's where lessons 00-12 combine into one real, working screen. Read it, then REBUILD it yourself from the QUESTIONS, not by copying.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 13 -- Project: Build a Weather Notes App\n//   Teaching philosophy: A project lesson has NO new concepts --\n//                        it's where lessons 00-12 combine into one\n//                        real, working screen. Read it, then REBUILD\n//                        it yourself from the QUESTIONS, not by copying.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- What We're Building\n// ================================================================\n//\n//   A small app: search a city name, fetch its current weather\n//   (lesson 10), and save it to a personal list of \"watched cities\"\n//   (lesson 11) that persists across app restarts.\n//\n//   Concepts combined:\n//   - useState for form input, list, loading, error      (04, 06)\n//   - FlatList to render the watched cities                (07)\n//   - useEffect to load saved cities on mount               (09)\n//   - fetch() to call a weather API                         (10)\n//   - AsyncStorage to persist the watched list               (11)\n//   - Flexbox to lay out the search bar + list               (05)\n//\n//   We use https://wttr.in/{city}?format=j1 -- a free weather API\n//   that needs no API key, good for learning without signup friction.\n\n\n// ================================================================\n// PART 1 -- Types and Storage Key (Plan the Shape First)\n// ================================================================\n//\n//   Before writing any UI, decide what ONE saved city looks like --\n//   exactly like sketching a dict shape in Python before coding.\n\nimport React, { useState, useEffect } from \"react\";\nimport {\n    View, Text, TextInput, Pressable, FlatList,\n    ActivityIndicator, StyleSheet, Alert,\n} from \"react-native\";\nimport AsyncStorage from \"@react-native-async-storage/async-storage\";\n\ninterface WatchedCity {\n    id: string;\n    name: string;\n    tempC: number;\n    condition: string;\n}\n\nconst STORAGE_KEY = \"watched_cities\";\n\n\n// ================================================================\n// PART 2 -- The Fetch Function (Isolated, Testable)\n// ================================================================\n//\n//   Keeping fetch logic in its own function (not inline in a\n//   component) makes it reusable and easier to reason about --\n//   same instinct as Python's \"small functions, each doing one thing.\"\n\nconst fetchWeather = async (city: string): Promise<WatchedCity> => {\n    const response = await fetch(`https://wttr.in/${encodeURIComponent(city)}?format=j1`);\n    if (!response.ok) throw new Error(\"City not found.\");\n    const data = await response.json();\n    const current = data.current_condition[0];\n    return {\n        id: Date.now().toString(),\n        name: city,\n        tempC: parseInt(current.temp_C, 10),\n        condition: current.weatherDesc[0].value,\n    };\n};\n//\n//   encodeURIComponent(city) -- TRACE: why this matters\n//   Step 1: a user might type \"New York\" (contains a space)\n//   Step 2: URLs can't contain raw spaces\n//   Step 3: encodeURIComponent turns it into \"New%20York\"\n//   Step 4: the server correctly decodes it back to \"New York\"\n\n\n// ================================================================\n// PART 3 -- Storage Helpers (Load/Save, From Lesson 11)\n// ================================================================\n\nconst loadCities = async (): Promise<WatchedCity[]> => {\n    const raw = await AsyncStorage.getItem(STORAGE_KEY);\n    return raw ? JSON.parse(raw) : [];\n};\n\nconst saveCities = async (cities: WatchedCity[]) => {\n    await AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(cities));\n};\n\n\n// ================================================================\n// PART 4 -- The Screen: Wiring Everything Together\n// ================================================================\n//\n//   TRACE: the full user flow\n//   Step 1: screen mounts -> useEffect loads saved cities (PART 3)\n//   Step 2: user types a city name into the TextInput (state: query)\n//   Step 3: user presses \"Add\" -> loading=true, fetchWeather runs\n//   Step 4: on success -> new city appended to list, saved, query cleared\n//   Step 5: on failure -> error shown, list untouched\n//   Step 6: FlatList renders every watched city with its weather\n\nconst WeatherNotesApp = () => {\n    const [query, setQuery] = useState(\"\");\n    const [cities, setCities] = useState<WatchedCity[]>([]);\n    const [loading, setLoading] = useState(false);\n    const [error, setError] = useState<string | null>(null);\n\n    useEffect(() => {\n        loadCities().then(setCities);\n    }, []);\n\n    const handleAdd = async () => {\n        if (query.trim() === \"\") return;\n        setLoading(true);\n        setError(null);\n        try {\n            const newCity = await fetchWeather(query.trim());\n            const updated = [...cities, newCity];\n            setCities(updated);\n            await saveCities(updated);\n            setQuery(\"\");\n        } catch (err) {\n            setError(err instanceof Error ? err.message : \"Something went wrong.\");\n        } finally {\n            setLoading(false);\n        }\n    };\n\n    const handleRemove = async (id: string) => {\n        const updated = cities.filter((c) => c.id !== id);\n        setCities(updated);\n        await saveCities(updated);\n    };\n\n    return (\n        <View style={styles.container}>\n            <View style={styles.searchRow}>\n                <TextInput\n                    style={styles.input}\n                    placeholder=\"City name\"\n                    value={query}\n                    onChangeText={setQuery}\n                />\n                <Pressable style={styles.addButton} onPress={handleAdd}>\n                    <Text style={{ color: \"white\" }}>Add</Text>\n                </Pressable>\n            </View>\n\n            {loading && <ActivityIndicator />}\n            {error && <Text style={styles.error}>{error}</Text>}\n\n            <FlatList\n                data={cities}\n                keyExtractor={(item) => item.id}\n                ListEmptyComponent={<Text>No cities watched yet.</Text>}\n                renderItem={({ item }) => (\n                    <Pressable onLongPress={() => handleRemove(item.id)} style={styles.cityRow}>\n                        <Text style={styles.cityName}>{item.name}</Text>\n                        <Text>{item.tempC}°C -- {item.condition}</Text>\n                    </Pressable>\n                )}\n            />\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { flex: 1, padding: 16 },\n    searchRow: { flexDirection: \"row\", gap: 8, marginBottom: 12 },\n    input: { flex: 1, borderWidth: 1, borderColor: \"#ccc\", borderRadius: 6, padding: 10 },\n    addButton: { backgroundColor: \"#3478f6\", padding: 12, borderRadius: 8, justifyContent: \"center\" },\n    error: { color: \"red\", marginBottom: 8 },\n    cityRow: { padding: 12, borderBottomWidth: 1, borderBottomColor: \"#eee\" },\n    cityName: { fontWeight: \"bold\", fontSize: 16 },\n});\n\nexport default WeatherNotesApp;","questionsCode":"// ================================================================\n// [QUESTIONS] -- Rebuild this from scratch. Don't copy-paste.\n// ================================================================\n\n// QUESTION 1 -- Trace the Flow\n//\n// Without looking back at PART 4, write out the 6 steps that\n// happen from typing a city name to seeing it appear in the list,\n// in your own words.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Add a Refresh Feature\n//\n// PLAN: which existing function already fetches fresh weather data?\n//\n// Add a \"Refresh All\" button above the list that re-fetches the\n// weather for EVERY watched city (keeping the same id and name,\n// updating tempC/condition) and re-saves the updated list.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Add Duplicate Prevention\n//\n// PLAN: how do you check if a city is already in the list, by name?\n//\n// Modify handleAdd so that if a city with the same name (case\n// insensitive) is already in \"cities\", it shows an Alert\n// (\"Already watching this city\") instead of adding a duplicate.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build It for Real\n//\n// Actually run this in a real Expo project (lesson 01's setup).\n// Confirm: adding a real city works, closing and reopening the app\n// (or Expo Go) keeps your watched cities, and long-pressing removes\n// one. Note any errors you hit and how you fixed them.\n//\n// Write here:","takeaways":["A project = combining small, already-known pieces -- no new syntax","Isolate fetch/storage logic into plain functions, outside components","Always wire: load on mount -> update state -> persist on change"],"nextHint":"lesson_14_build_share.tsx -- previewing and sharing your app","milestone":""},{"num":14,"id":"lesson_14_build_share","filename":"lesson_14_build_share.tsx","title":"Build & Share: From Your Laptop to Someone Else's Phone","subtitle":"\"It works on my phone via Expo Go\" and \"it's a real, shareable app\" are TWO different milestones. This lesson is the bridge between them, conceptually -- lessons 48-49 cover full store deployment.","section":"Fundamentals","color":"blue","mainCode":"// ================================================================\n//   LESSON 14 -- Build & Share: From Your Laptop to Someone Else's Phone\n//   Teaching philosophy: \"It works on my phone via Expo Go\" and\n//                        \"it's a real, shareable app\" are TWO\n//                        different milestones. This lesson is the\n//                        bridge between them, conceptually --\n//                        lessons 48-49 cover full store deployment.\n// ================================================================\n//   Before starting: an Expo account (free) -- npx expo login\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Everything so far ran through Expo Go: your phone downloads\n//   the JS bundle live from your laptop's dev server. That's GREAT\n//   for development, but it has limits:\n//   - your laptop must be running and on the same network\n//   - the other person needs the Expo Go app installed\n//   - some native features behave slightly differently than a\n//     real standalone build\n//\n//   EAS (Expo Application Services) builds a REAL standalone app\n//   file -- one you can install directly, with no laptop or Expo\n//   Go required, exactly like any app from the Play Store/App Store.\n\n\n// ================================================================\n// PART 1 -- Preview Sharing Without a Build (Fastest Option)\n// ================================================================\n//\n//   TRACE: sharing a live preview link\n//   Step 1: npx expo start --tunnel  (tunnel = works across\n//           different networks, not just the same WiFi)\n//   Step 2: Expo prints a shareable link/QR code\n//   Step 3: anyone with Expo Go installed can open that link\n//   Step 4: they see your app live, updating as you save files --\n//           same Fast Refresh behavior, just over the internet\n//\n//   npx expo start --tunnel\n//\n//   Good for: quick demos, friends/testers trying it NOW. Not a\n//   substitute for a real installable build.\n\n\n// ================================================================\n// PART 2 -- EAS Build: Producing a Real App File\n// ================================================================\n//\n//   TRACE: building a standalone Android app\n//   Step 1: npm install -g eas-cli   (install the build tool once)\n//   Step 2: eas login                (sign in to your Expo account)\n//   Step 3: eas build:configure       (generates eas.json -- build\n//           profiles: development, preview, production)\n//   Step 4: eas build --platform android --profile preview\n//   Step 5: Expo's servers build the app in the cloud (you don't\n//           need Android Studio installed locally for this)\n//   Step 6: you get a DOWNLOAD LINK to a real .apk file when done\n//\n//   npm install -g eas-cli\n//   eas login\n//   eas build:configure\n//   eas build --platform android --profile preview\n\n\n// ================================================================\n// PART 3 -- Installing the Built App (No Store Needed Yet)\n// ================================================================\n//\n//   The \"preview\" profile produces an .apk -- Android's installable\n//   package format. Anyone can:\n//   1. open the download link EAS gives you, on their Android phone\n//   2. download the .apk\n//   3. tap it to install (Android may ask to \"allow installs from\n//      unknown sources\" the first time -- that's expected/normal)\n//\n//   iOS is more locked down -- a preview build for iOS typically\n//   needs the tester's device registered via TestFlight (covered\n//   properly in lesson 49's deployment lesson, since it ties\n//   directly into Apple's App Store process).\n\n\n// ================================================================\n// PART 4 -- app.json / app.config.ts: Your App's Identity\n// ================================================================\n//\n//   Before building, your app needs identifying info -- think of\n//   this like a project's setup.py/pyproject.toml metadata.\n//\n//   // app.json\n//   {\n//     \"expo\": {\n//       \"name\": \"Weather Notes\",\n//       \"slug\": \"weather-notes\",\n//       \"version\": \"1.0.0\",\n//       \"icon\": \"./assets/icon.png\",\n//       \"android\": { \"package\": \"com.yourname.weathernotes\" },\n//       \"ios\": { \"bundleIdentifier\": \"com.yourname.weathernotes\" }\n//     }\n//   }\n//\n//   \"package\"/\"bundleIdentifier\" -- a GLOBALLY unique id for your\n//   app (reverse-domain style). Once published, this can't easily\n//   change -- pick it deliberately, even for a learning project.\n\n\n// ================================================================\n// PART 5 -- Build Profiles: Dev vs Preview vs Production\n// ================================================================\n//\n//   eas.json typically defines three profiles:\n//\n//   \"development\" -- includes dev tools, for your own testing,\n//                    can still connect to a local dev server\n//   \"preview\"      -- a real standalone build, but NOT optimized\n//                    for store submission -- for sharing with\n//                    testers (PART 3's use case)\n//   \"production\"   -- the fully optimized build you submit to the\n//                    Play Store / App Store (lessons 48-49)\n//\n//   eas build --platform android --profile production","questionsCode":"// ================================================================\n// [QUESTIONS] -- Expo Go = live dev tool. EAS Build = real app file.\n// ================================================================\n\n// QUESTION 1 -- Predict\n//\n// You run \"npx expo start --tunnel\" and share the link with a\n// friend on a different WiFi network, in a different city.\n// Does it work? What does your friend need installed first?  -> ?\n// What happens to the shared preview if you close your laptop?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake in this plan)\n//\n//   1. Write the app\n//   2. Run: eas build --platform android --profile preview\n//   3. Send the .apk download link to an iPhone user\n//   4. They tap the link expecting it to install\n//\n// Bug -> ?  (hint: think about which platform an .apk targets)\n// Fixed plan:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Hands-On: Share a Live Preview\n//\n// Actually run \"npx expo start --tunnel\" on your Weather Notes\n// app from lesson 13. Share the link/QR with one other device\n// (or a friend) NOT on your home WiFi. Confirm it loads.\n//\n// Write here what happened (or what error you hit):\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Plan Your App's Identity\n//\n// PLAN: what name/slug/bundle id would you choose, and why?\n//\n// Write the app.json values you would use for the Weather Notes\n// app -- name, slug, version, android package, and ios bundleIdentifier.\n// Keep the reverse-domain id consistent across both platforms.\n//\n// Write here:","takeaways":["Expo Go = fast live dev tool, needs the app + laptop running","EAS Build = produces a real, standalone, installable app file","\"preview\" profile -- for sharing with testers, no store needed","\"production\" profile -- for actual store submission","app.json / eas.json -- your app's identity and build configuration"],"nextHint":"lesson_15_usememo_usecallback.tsx -- Advanced Hooks begin","milestone":"FUNDAMENTALS SECTION COMPLETE -- you can build, run, fetch, persist, and share a real React Native + Expo app."},{"num":15,"id":"lesson_15_usememo_usecallback","filename":"lesson_15_usememo_usecallback.tsx","title":"useMemo & useCallback: Avoiding Wasted Work","subtitle":"Both hooks answer ONE question -- \"do I really need to redo this right now?\"","section":"Advanced Hooks","color":"purple","mainCode":"// ================================================================\n//   LESSON 15 -- useMemo & useCallback: Avoiding Wasted Work\n//   Teaching philosophy: Both hooks answer ONE question --\n//                        \"do I really need to redo this right now?\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Recall lesson 04: ANY state change re-runs the WHOLE component\n//   function. That means every variable, every function defined\n//   inside it, gets recreated from scratch on every single re-render\n//   -- even ones that don't depend on what changed.\n//\n//   Python analogy: imagine a function that recalculates a slow\n//   report EVERY time it's called, even when the underlying data\n//   hasn't changed since the last call. You'd cache the result.\n//   useMemo and useCallback are React's built-in caches:\n//\n//   useMemo     -> caches a COMPUTED VALUE\n//   useCallback -> caches a FUNCTION itself\n//\n//   Both take the SAME shape as useEffect: a function, and a\n//   dependency array deciding when to throw the cache away.\n\n\n// ================================================================\n// PART 1 -- useMemo: Caching an Expensive Calculation\n// ================================================================\n//\n//   TRACE: filtering a large product list on every re-render\n//   Step 1: WITHOUT useMemo -- every re-render re-runs the filter,\n//           even if \"products\" and \"search\" haven't changed (e.g.\n//           re-rendering because an unrelated piece of state changed)\n//   Step 2: WITH useMemo -- React remembers the last result\n//   Step 3: on the next render, React checks the dependency array\n//   Step 4: if nothing in it changed, it reuses the CACHED result\n//           instead of re-running the function at all\n\nimport React, { useState, useMemo, useCallback } from \"react\";\nimport { View, Text, TextInput, FlatList, Pressable } from \"react-native\";\n\ninterface Product {\n    id: string;\n    name: string;\n    price: number;\n}\n\nconst products: Product[] = [\n    { id: \"1\", name: \"Keyboard\", price: 1500 },\n    { id: \"2\", name: \"Mouse\", price: 600 },\n    { id: \"3\", name: \"Monitor\", price: 9000 },\n];\n\nconst ProductSearchScreen = () => {\n    const [search, setSearch] = useState(\"\");\n    const [theme, setTheme] = useState(\"light\");   // unrelated state\n\n    const filtered = useMemo(() => {\n        console.log(\"Filtering ran\");   // watch how OFTEN this prints\n        return products.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()));\n    }, [search]);   // only recompute when \"search\" changes\n\n    return (\n        <View style={{ padding: 16 }}>\n            <TextInput placeholder=\"Search\" value={search} onChangeText={setSearch} />\n            <Pressable onPress={() => setTheme(theme === \"light\" ? \"dark\" : \"light\")}>\n                <Text>Toggle theme ({theme})</Text>\n            </Pressable>\n            <FlatList data={filtered} keyExtractor={(p) => p.id} renderItem={({ item }) => <Text>{item.name}</Text>} />\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Press \"Toggle theme\" several times without touching search.\n// Does \"Filtering ran\" print in the console each time?       -> ?\n// Why, given that the component DOES re-render each press?   -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- useCallback: Caching a Function Reference\n// ================================================================\n//\n//   Every render normally creates a BRAND NEW function object, even\n//   if the code inside looks identical. That matters because:\n//   - a child component receiving that function as a prop sees a\n//     \"different\" prop every render (new reference), which can\n//     cause unnecessary re-renders of the child (lesson 17 covers\n//     why -- this lesson focuses on the caching mechanism itself)\n//\n//   useCallback caches the FUNCTION reference itself, the same way\n//   useMemo caches a VALUE.\n//\n//   const handlePress = useCallback(() => {\n//       console.log(\"pressed\");\n//   }, []);   // same function reference across re-renders\n\nconst ParentScreen = () => {\n    const [count, setCount] = useState(0);\n\n    const handleReset = useCallback(() => {\n        setCount(0);\n    }, []);   // never needs to change -- setCount is always stable\n\n    return (\n        <View>\n            <Text>{count}</Text>\n            <Pressable onPress={() => setCount((c) => c + 1)}>\n                <Text>+1</Text>\n            </Pressable>\n            <ResetButton onReset={handleReset} />\n        </View>\n    );\n};\n\nconst ResetButton = React.memo(({ onReset }: { onReset: () => void }) => {\n    console.log(\"ResetButton rendered\");   // lesson 17 explains React.memo\n    return (\n        <Pressable onPress={onReset}>\n            <Text>Reset</Text>\n        </Pressable>\n    );\n});\n\n\n// ================================================================\n// PART 3 -- When NOT to Use Them (Most of the Time!)\n// ================================================================\n//\n//   useMemo/useCallback are NOT free -- they cost a tiny bit of\n//   memory and comparison work every render. For simple values or\n//   functions, that overhead can be MORE expensive than just\n//   recreating them plainly.\n//\n//   Rule of thumb -- reach for these ONLY when:\n//   1. the calculation is genuinely slow (big loops, big lists), OR\n//   2. you're passing a function to a memoized child (lesson 17),\n//      and reference stability actually matters\n//\n//   Don't wrap every single function \"just in case\" -- that's\n//   premature optimization, and it makes code harder to read for\n//   no real benefit.\n\n\n// ================================================================\n// PART 4 -- useRef Teaser: A Third Kind of \"Persisting\" Value\n// ================================================================\n//\n//   useMemo/useCallback persist a VALUE/FUNCTION across renders but\n//   still RECOMPUTE when dependencies change. Sometimes you want a\n//   box that just holds a value, mutable, with NO re-render at all\n//   when it changes -- that's useRef, covered fully in lesson 16.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Cache the expensive thing, not everything.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const slow = useMemo(() => {\n//     console.log(\"computing\");\n//     return a + b;\n// }, [a]);     // note: only \"a\" is listed, NOT \"b\"\n//\n// If \"b\" changes but \"a\" stays the same, does \"computing\" print?  -> ?\n// Is this a bug? What's the risk of an incomplete dependency array?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const total = useMemo(() => {\n//       return prices.reduce((sum, p) => sum + p, 0);\n//   });\n//\n//   const handleSubmit = useCallback(() => {\n//       submitOrder(cartId);\n//   }, []);\n//   // cartId is used inside, but never listed as a dependency\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Memoized Total\n//\n// PLAN: what should trigger a recalculation -- and what shouldn't?\n//\n// Build a cart screen with an array of { id, price, qty } items in\n// state, and an unrelated \"notifications enabled\" boolean toggle.\n// Use useMemo to compute the total price (sum of price * qty),\n// recomputing ONLY when the items array changes, NOT when the\n// toggle changes. Add a console.log inside to prove it.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Identify the Real Need\n//\n// For each scenario, decide: useMemo, useCallback, or NEITHER\n// (just write it plainly)? Justify each in one sentence.\n//   a) Filtering a 5000-item list by search text\n//   b) A function that just calls console.log(\"clicked\")\n//   c) A function passed to a React.memo-wrapped child component\n//   d) Adding two numbers from state\n//\n// Write here:","takeaways":["useMemo(fn, deps) -- caches a COMPUTED VALUE","useCallback(fn, deps) -- caches a FUNCTION REFERENCE","Both skip re-running unless something in \"deps\" actually changed","Don't overuse -- only when the work is genuinely expensive, or reference stability matters for a memoized child"],"nextHint":"lesson_16_useref.tsx -- mutable values that don't trigger renders","milestone":""},{"num":16,"id":"lesson_16_useref","filename":"lesson_16_useref.tsx","title":"useRef: A Mutable Box That Skips Re-Renders","subtitle":"useState says \"remember this AND redraw the screen.\" useRef says \"just remember this -- don't redraw anything.\"","section":"Advanced Hooks","color":"purple","mainCode":"// ================================================================\n//   LESSON 16 -- useRef: A Mutable Box That Skips Re-Renders\n//   Teaching philosophy: useState says \"remember this AND redraw\n//                        the screen.\" useRef says \"just remember\n//                        this -- don't redraw anything.\"\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Two real needs that useState is the WRONG tool for:\n//   1. \"I need to grab a handle to an actual on-screen element\"\n//      (e.g. tell a TextInput to focus itself programmatically)\n//   2. \"I need to remember a value across renders, but changing it\n//      should NOT cause a re-render\" (e.g. counting renders for\n//      debugging, or storing a timer id from lesson 09)\n//\n//   const myRef = useRef(initialValue);\n//   myRef.current        -- read or write here directly\n//\n//   TRACE: the key difference from useState\n//   Step 1: useState's setter -> triggers a re-render\n//   Step 2: ref.current = newValue -> does NOT trigger a re-render\n//   Step 3: the NEXT time the component re-renders for some OTHER\n//           reason, ref.current will have the latest value -- but\n//           changing it alone never CAUSES that re-render\n\n\n// ================================================================\n// PART 1 -- Referencing a Real Component (Imperative Focus)\n// ================================================================\n//\n//   TRACE: focusing a TextInput when a button is pressed\n//   Step 1: const inputRef = useRef<TextInput>(null);\n//   Step 2: <TextInput ref={inputRef} /> -- React attaches the\n//           actual native input instance to inputRef.current\n//   Step 3: pressing a button calls inputRef.current?.focus()\n//   Step 4: the OS keyboard pops up, cursor lands in that field --\n//           no state, no re-render involved at all\n\nimport React, { useRef, useState, useEffect } from \"react\";\nimport { View, Text, TextInput, Pressable } from \"react-native\";\n\nconst FocusableForm = () => {\n    const inputRef = useRef<TextInput>(null);\n\n    return (\n        <View style={{ padding: 20, gap: 10 }}>\n            <TextInput ref={inputRef} placeholder=\"Tap the button to focus me\" style={{ borderWidth: 1, padding: 10 }} />\n            <Pressable onPress={() => inputRef.current?.focus()}>\n                <Text>Focus the Input</Text>\n            </Pressable>\n        </View>\n    );\n};\n//\n//   inputRef.current?.focus() -- the \"?.\" is OPTIONAL CHAINING:\n//   if inputRef.current is null (not attached yet), it just skips\n//   the call instead of crashing -- same safety idea as Python's\n//   \"if obj is not None: obj.method()\", in one line.\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why is useRef(null) the starting value, instead of useRef(\"\")\n// like you might expect for a text field?                    -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Storing a Mutable Value That Doesn't Trigger Renders\n// ================================================================\n//\n//   TRACE: counting how many times a component re-rendered, WITHOUT\n//   causing infinite extra re-renders by tracking it with useState\n//   Step 1: renderCount.current starts at 0\n//   Step 2: every render, you increment it directly: renderCount.current += 1\n//   Step 3: this does NOT cause another render -- it just updates\n//           silently, ready to read whenever the NEXT render happens\n\nconst RenderCounter = () => {\n    const [text, setText] = useState(\"\");\n    const renderCount = useRef(0);\n    renderCount.current += 1;\n\n    return (\n        <View style={{ padding: 20 }}>\n            <TextInput value={text} onChangeText={setText} style={{ borderWidth: 1, padding: 10 }} />\n            <Text>This component has rendered {renderCount.current} times.</Text>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Storing Timer IDs (Replacing a Plain Variable)\n// ================================================================\n//\n//   Recall lesson 09's Countdown -- it used a LOCAL variable\n//   (intervalId) inside useEffect, which worked because it never\n//   needed to be READ from outside that effect. When a timer ID\n//   needs to be accessed or cleared from a DIFFERENT function\n//   (like a \"Stop\" button), useRef is what holds it.\n\nconst StoppableTimer = () => {\n    const [seconds, setSeconds] = useState(0);\n    const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);\n\n    const start = () => {\n        if (intervalRef.current) return;   // already running\n        intervalRef.current = setInterval(() => {\n            setSeconds((s) => s + 1);\n        }, 1000);\n    };\n\n    const stop = () => {\n        if (intervalRef.current) {\n            clearInterval(intervalRef.current);\n            intervalRef.current = null;\n        }\n    };\n\n    useEffect(() => stop, []);   // cleanup on unmount, lesson 09's pattern\n\n    return (\n        <View style={{ padding: 20, gap: 10 }}>\n            <Text>{seconds}s</Text>\n            <Pressable onPress={start}><Text>Start</Text></Pressable>\n            <Pressable onPress={stop}><Text>Stop</Text></Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- useState vs useRef: The Decision Rule\n// ================================================================\n//\n//   Ask: \"if this value changes, does the SCREEN need to look\n//   different?\"\n//   - YES -> useState (it must trigger a re-render to show the change)\n//   - NO  -> useRef (a silent value, or a handle to a real element)\n//\n//   Common useRef use cases: focus management, scroll position,\n//   timer/interval ids, \"previous value\" tracking, measuring\n//   render counts for debugging, holding a FlatList ref to call\n//   .scrollToIndex() programmatically.","questionsCode":"// ================================================================\n// [QUESTIONS] -- useRef never triggers a re-render on its own.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const countRef = useRef(0);\n// const handlePress = () => {\n//     countRef.current += 1;\n//     console.log(countRef.current);\n// };\n// // Button calls handlePress 3 times.\n//\n// Does the screen show an updated number anywhere automatically?  -> ?\n// What does the console.log show after each of the 3 presses?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const Timer = () => {\n//       const seconds = useRef(0);\n//       useEffect(() => {\n//           setInterval(() => { seconds.current += 1; }, 1000);\n//       }, []);\n//       return <Text>{seconds.current}</Text>;\n//   };\n//\n// Bug -> ?  (hint: the interval IS updating seconds.current correctly\n// every second -- so why does the screen never visually change?)\n// Fixed code (what would you ADD to make the number visible?):\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build an Auto-Focus Search Bar\n//\n// PLAN: when should focus() get called -- on mount, or on press?\n//\n// Build a search screen where the TextInput automatically receives\n// focus the moment the screen appears (hint: combine useRef with\n// useEffect(fn, []) from lesson 09 -- call .focus() inside the effect).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Track \"Previous Value\" With useRef\n//\n// PLAN: when do you UPDATE the ref -- before or after reading it?\n//\n// Build a component with a number input (controlled state \"value\").\n// Below it, show \"Previous: {previousValue}\" -- using a useRef that\n// stores the value from the LAST render (updated inside a useEffect\n// that runs after every change to \"value\").\n//\n// Write here:","takeaways":["const ref = useRef(initial) -- ref.current holds the value","Changing ref.current does NOT trigger a re-render","<Component ref={myRef} /> -- attach a handle to a real element","useState: screen must change | useRef: silent value or element handle"],"nextHint":"lesson_17_custom_hooks.tsx -- extracting your own reusable logic","milestone":""},{"num":17,"id":"lesson_17_custom_hooks","filename":"lesson_17_custom_hooks.tsx","title":"Custom Hooks: Extracting Your Own Reusable Logic","subtitle":"A custom hook is just a regular function that happens to call OTHER hooks inside it.","section":"Advanced Hooks","color":"purple","mainCode":"// ================================================================\n//   LESSON 17 -- Custom Hooks: Extracting Your Own Reusable Logic\n//   Teaching philosophy: A custom hook is just a regular function\n//                        that happens to call OTHER hooks inside it.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Python: when the SAME few lines of logic show up in multiple\n//   functions, you extract a helper function. You've already done\n//   this instinct in lesson 13 (fetchWeather, loadCities as\n//   standalone functions).\n//\n//   But what about logic that involves useState/useEffect TOGETHER\n//   -- like the entire loading/error/data pattern from lesson 10?\n//   You can't extract THAT into a plain function, because plain\n//   functions can't call useState. The fix: a CUSTOM HOOK -- a\n//   function whose name starts with \"use\", that calls other hooks\n//   inside it, and RETURNS whatever the component needs.\n//\n//   Rule: a function is a hook (and can call useState/useEffect/etc)\n//   ONLY if its name starts with \"use\". This isn't just a style\n//   preference -- React's tooling relies on this naming pattern.\n\n\n// ================================================================\n// PART 1 -- Extracting the Loading/Error/Data Pattern\n// ================================================================\n//\n//   Lesson 10 wrote this shape inline, inside ONE component. Real\n//   apps fetch dozens of different things -- repeating loading/\n//   error/data state every time is exactly the kind of repetition\n//   a custom hook removes.\n//\n//   TRACE: how useFetch is used\n//   Step 1: a component calls useFetch(url)\n//   Step 2: INSIDE useFetch, useState/useEffect run exactly like\n//           they would if written directly in the component\n//   Step 3: useFetch returns { data, loading, error } as an object\n//   Step 4: the calling component destructures whatever it needs\n\nimport { useState, useEffect } from \"react\";\nimport { View, Text, ActivityIndicator } from \"react-native\";\n\nfunction useFetch<T>(url: string) {\n    const [data, setData] = useState<T | null>(null);\n    const [loading, setLoading] = useState(true);\n    const [error, setError] = useState<string | null>(null);\n\n    useEffect(() => {\n        let cancelled = false;     // see PART 3 for why this exists\n        setLoading(true);\n        fetch(url)\n            .then((res) => res.json())\n            .then((json) => { if (!cancelled) setData(json); })\n            .catch((err) => { if (!cancelled) setError(err.message); })\n            .finally(() => { if (!cancelled) setLoading(false); });\n        return () => { cancelled = true; };\n    }, [url]);\n\n    return { data, loading, error };\n}\n\n// Using it -- compare this to lesson 10's UserProfile component:\ninterface ApiUser { name: string; email: string; }\n\nconst UserProfileScreen = () => {\n    const { data: user, loading, error } = useFetch<ApiUser>(\n        \"https://jsonplaceholder.typicode.com/users/1\"\n    );\n\n    if (loading) return <ActivityIndicator />;\n    if (error) return <Text>Error: {error}</Text>;\n    return <Text>{user?.name} -- {user?.email}</Text>;\n};\n\n// A SECOND component reuses the exact same hook, zero repeated code:\ninterface Post { title: string; }\n\nconst PostScreen = () => {\n    const { data: post, loading } = useFetch<Post>(\n        \"https://jsonplaceholder.typicode.com/posts/1\"\n    );\n    if (loading) return <ActivityIndicator />;\n    return <Text>{post?.title}</Text>;\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If useFetch is called twice in the SAME component with two\n// different URLs, do the two calls' states interfere with each\n// other? Why or why not?                                      -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- A Simpler Custom Hook: Toggling a Boolean\n// ================================================================\n//\n//   Not every custom hook needs to be complex -- extracting even a\n//   TINY repeated pattern (lesson 04's toggle) is worthwhile once\n//   you use it in 3+ places.\n\nfunction useToggle(initial: boolean = false) {\n    const [value, setValue] = useState(initial);\n    const toggle = () => setValue((prev) => !prev);\n    return [value, toggle] as const;\n    // \"as const\" keeps the tuple's exact order/types, so\n    // destructuring as [isOn, toggleOn] works correctly in TS\n}\n\nconst Switcher = () => {\n    const [isDarkMode, toggleDarkMode] = useToggle(false);\n    return (\n        <View>\n            <Text onPress={toggleDarkMode}>\n                {isDarkMode ? \"Dark Mode ON\" : \"Dark Mode OFF\"}\n            </Text>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Why the \"cancelled\" Flag in useFetch Matters\n// ================================================================\n//\n//   TRACE: a race condition without it\n//   Step 1: component calls useFetch(\"/users/1\")\n//   Step 2: BEFORE that finishes, the url prop changes to \"/users/2\"\n//   Step 3: effect's cleanup runs, a NEW fetch starts for /users/2\n//   Step 4: the OLD /users/1 request finally resolves LATE\n//   Step 5: without the flag, it would overwrite data with STALE\n//           /users/1 results, even though the screen has moved on\n//   Step 6: the \"cancelled\" flag, set true in cleanup, stops the\n//           OLD request from calling setData at all\n\n\n// ================================================================\n// PART 4 -- The Rule That Makes All of This Work\n// ================================================================\n//\n//   Hooks (built-in OR custom) must be called:\n//   1. At the TOP LEVEL of a component or another hook (never\n//      inside an if statement, loop, or nested function)\n//   2. In the SAME ORDER every single render\n//\n//   This is because React tracks hook state by the ORDER they're\n//   called in, not by name. Conditionally skipping a useState call\n//   would shift every hook after it out of sync with its stored data.","questionsCode":"// ================================================================\n// [QUESTIONS] -- A custom hook = a function starting with \"use\".\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// function useCounter(start: number) {\n//     const [count, setCount] = useState(start);\n//     return { count, increment: () => setCount((c) => c + 1) };\n// }\n//\n// const a = useCounter(0);   // used in ComponentA\n// const b = useCounter(100); // used in ComponentB\n//\n// If ComponentA calls a.increment(), does b.count change at all?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the rule violation)\n//\n//   const Profile = ({ showExtra }: { showExtra: boolean }) => {\n//       if (showExtra) {\n//           const [extra, setExtra] = useState(\"\");\n//       }\n//       const [name, setName] = useState(\"\");\n//       return <Text>{name}</Text>;\n//   };\n//\n// Bug -> ?  (which rule from PART 4 does this break?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build useAsyncStorage\n//\n// PLAN: what does the hook need to return for a component to use it?\n//\n// Combine lesson 11's AsyncStorage load/save logic into a custom\n// hook useAsyncStorage<T>(key: string, initialValue: T) that\n// returns [value, setValue] -- where setValue updates BOTH the\n// in-memory state AND writes to AsyncStorage automatically.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build useDebouncedValue\n//\n// PLAN: which lesson's pattern does this reuse internally?\n//\n// Build a custom hook useDebouncedValue(value: string, delayMs:\n// number) that returns a debounced version of \"value\" -- it only\n// updates after \"delayMs\" has passed with no further changes\n// (reuse lesson 09's QUESTION 4 debounce idea, but as a hook).\n//\n// Write here:","takeaways":["Custom hook = a function named \"use...\" that calls other hooks","Extract repeated useState/useEffect patterns once 2-3 components","need the same shape (loading/error/data, toggles, debouncing...)","Hooks must be called at the top level, same order, every render"],"nextHint":"lesson_18_context_api.tsx -- sharing state without prop drilling","milestone":""},{"num":18,"id":"lesson_18_context_api","filename":"lesson_18_context_api.tsx","title":"Context API: Sharing State Without Prop Drilling","subtitle":"Context is a \"global variable,\" scoped to a part of your component tree, that any descendant can read without it being passed down manually through every level.","section":"Advanced Hooks","color":"purple","mainCode":"// ================================================================\n//   LESSON 18 -- Context API: Sharing State Without Prop Drilling\n//   Teaching philosophy: Context is a \"global variable,\" scoped to\n//                        a part of your component tree, that any\n//                        descendant can read without it being\n//                        passed down manually through every level.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Imagine a logged-in user's name needs to show in a header,\n//   AND in a settings screen, AND in a profile card -- all nested\n//   several components deep. Without Context, you'd pass \"user\"\n//   as a prop through EVERY layer in between, even components that\n//   don't use it themselves, just to relay it downward:\n//\n//   App -> Screen -> Layout -> Header -> Avatar  (needs \"user\")\n//\n//   Each arrow means: pass \"user\" as a prop, just to relay it.\n//   This is called \"prop drilling\" -- it works, but becomes painful\n//   as the tree grows. Context lets Avatar read \"user\" DIRECTLY,\n//   skipping Screen, Layout, and Header entirely.\n//\n//   Python analogy: prop drilling is like passing a config object\n//   through 5 function calls just so the 6th one can read it.\n//   Context is closer to a module-level variable any function in\n//   that module can import and read directly.\n\n\n// ================================================================\n// PART 1 -- Creating a Context\n// ================================================================\n//\n//   TRACE: setting up a UserContext\n//   Step 1: createContext(defaultValue) -- makes a Context object.\n//           The default is ONLY used if no Provider wraps the reader.\n//   Step 2: a Provider component wraps part of your tree, given a\n//           \"value\" -- everything inside it can now read that value\n//   Step 3: useContext(MyContext) -- any descendant reads the\n//           CURRENT value, no matter how deeply nested\n\nimport React, { createContext, useContext, useState, ReactNode } from \"react\";\nimport { View, Text, Pressable } from \"react-native\";\n\ninterface User {\n    name: string;\n    email: string;\n}\n\nconst UserContext = createContext<User | null>(null);\n\nconst App = () => {\n    const [user] = useState<User>({ name: \"Sarath\", email: \"sarath@example.com\" });\n\n    return (\n        <UserContext.Provider value={user}>\n            <Screen />\n        </UserContext.Provider>\n    );\n};\n\nconst Screen = () => <Layout />;        // doesn't touch \"user\" at all\nconst Layout = () => <Header />;        // doesn't touch \"user\" at all\n\nconst Header = () => {\n    const user = useContext(UserContext);   // reads it DIRECTLY\n    return <Text>Welcome, {user?.name}</Text>;\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If <Header /> were rendered OUTSIDE of <UserContext.Provider>\n// entirely, what would useContext(UserContext) return?       -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- A Theme Context (The Most Common Real Example)\n// ================================================================\n//\n//   Context shines for app-wide settings: theme, logged-in user,\n//   language/locale -- things MANY unrelated components need.\n//\n//   TRACE: toggling dark mode from deep in the tree\n//   Step 1: ThemeContext's value is an OBJECT: { isDark, toggle }\n//   Step 2: ANY descendant can call toggle() -- it updates the\n//           Provider's state (via useState, lesson 04)\n//   Step 3: React re-renders every component reading this Context\n\ninterface ThemeContextValue {\n    isDark: boolean;\n    toggleTheme: () => void;\n}\n\nconst ThemeContext = createContext<ThemeContextValue | null>(null);\n\nconst ThemeProvider = ({ children }: { children: ReactNode }) => {\n    const [isDark, setIsDark] = useState(false);\n    const toggleTheme = () => setIsDark((prev) => !prev);\n\n    return (\n        <ThemeContext.Provider value={{ isDark, toggleTheme }}>\n            {children}\n        </ThemeContext.Provider>\n    );\n};\n\n// A custom hook (lesson 17!) that wraps useContext for convenience\n// AND guards against using it outside a Provider by mistake:\nconst useTheme = () => {\n    const context = useContext(ThemeContext);\n    if (!context) throw new Error(\"useTheme must be used inside a ThemeProvider\");\n    return context;\n};\n\nconst ThemedButton = () => {\n    const { isDark, toggleTheme } = useTheme();\n    return (\n        <Pressable onPress={toggleTheme} style={{ backgroundColor: isDark ? \"#222\" : \"#eee\", padding: 12 }}>\n            <Text style={{ color: isDark ? \"white\" : \"black\" }}>\n                {isDark ? \"Dark Mode\" : \"Light Mode\"}\n            </Text>\n        </Pressable>\n    );\n};\n\nconst ThemedApp = () => (\n    <ThemeProvider>\n        <View style={{ flex: 1 }}>\n            <ThemedButton />\n        </View>\n    </ThemeProvider>\n);\n\n\n// ================================================================\n// PART 3 -- When Context Is the WRONG Tool\n// ================================================================\n//\n//   Context re-renders EVERY consumer whenever its value changes --\n//   there's no built-in way to subscribe to just \"part\" of it.\n//   For frequently-changing, performance-sensitive global state\n//   (e.g. live data updating many times per second across a large\n//   app), Redux Toolkit or Zustand (next lessons) scale better.\n//\n//   Rule of thumb: Context is great for state that changes\n//   INFREQUENTLY (user, theme, locale) and is read WIDELY. For\n//   state that changes OFTEN and is read widely, look at the\n//   state management options coming up next.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Provider wraps, useContext reads, anywhere inside.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// <UserContext.Provider value={{ name: \"Asha\", email: \"a@x.com\" }}>\n//     <UserContext.Provider value={{ name: \"Raj\", email: \"r@x.com\" }}>\n//         <Header />\n//     </UserContext.Provider>\n// </UserContext.Provider>\n//\n// Header calls useContext(UserContext) -- whose name does it see,\n// Asha's or Raj's? (hint: think about which Provider is CLOSEST)  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const CartContext = createContext();\n//\n//   const CartScreen = () => {\n//       const cart = useContext(CartContext);\n//       return <Text>{cart.items.length}</Text>;\n//   };\n//\n//   const App = () => <CartScreen />;   // no Provider anywhere!\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build an Auth Context\n//\n// PLAN: what value shape does every screen need -- user + functions?\n//\n// Build an AuthContext providing { user: User | null, login: (u:\n// User) => void, logout: () => void }. Write an AuthProvider\n// wrapping useState, and a useAuth() hook (like useTheme above)\n// that throws if used outside the Provider. Build a LoginScreen\n// that calls login() and a ProfileScreen that reads user and shows\n// a \"Log Out\" button calling logout().\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Refactor Away From Prop Drilling\n//\n// PLAN: which existing prop chain could Context replace?\n//\n// Take any 3-level-deep component chain you've built in a previous\n// lesson where a prop was passed through a middle component that\n// never used it itself. Rewrite it using Context so the middle\n// component no longer needs to know about that data at all.\n//\n// Write here:","takeaways":["createContext(default) -> Context object","<MyContext.Provider value={...}> -- wraps a subtree, supplies the value","useContext(MyContext) -- read it from ANY descendant, any depth","Wrap useContext in a custom hook to add a \"must be inside Provider\" guard","Best for state that changes INFREQUENTLY but is read WIDELY"],"nextHint":"lesson_19_redux_toolkit.tsx -- State Management begins","milestone":""},{"num":19,"id":"lesson_19_redux_toolkit","filename":"lesson_19_redux_toolkit.tsx","title":"Redux Toolkit: Centralized State for Real Apps","subtitle":"Redux is Context's state-changing rules, made explicit and centralized -- ONE place defines HOW state is allowed to change.","section":"State Management","color":"pink","mainCode":"// ================================================================\n//   LESSON 19 -- Redux Toolkit: Centralized State for Real Apps\n//   Teaching philosophy: Redux is Context's state-changing rules,\n//                        made explicit and centralized -- ONE place\n//                        defines HOW state is allowed to change.\n// ================================================================\n//   Before starting: npx expo install @reduxjs/toolkit react-redux\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 18's Context works well for a FEW pieces of global state.\n//   Once an app has carts, auth, notifications, settings, and more\n//   -- all changing often, all read in many places -- managing it\n//   all with separate Contexts gets messy, and EVERY consumer\n//   re-renders on EVERY change (lesson 18 PART 3's limitation).\n//\n//   Redux's core idea, in Python terms: imagine ONE big dict\n//   (the \"store\") that holds your ENTIRE app's shared state, and\n//   the ONLY way to change it is by calling specific, named\n//   functions (\"reducers\") -- never by mutating the dict directly.\n//   This makes changes predictable and traceable.\n//\n//   Redux Toolkit (RTK) is the modern, recommended way to write\n//   Redux -- it removes almost all of the old boilerplate.\n\n\n// ================================================================\n// PART 1 -- A Slice: State + the Functions That Can Change It\n// ================================================================\n//\n//   A \"slice\" = one chunk of your store, plus the actions allowed\n//   to modify it. Counter example -- the simplest possible slice:\n//\n//   TRACE: dispatching an action\n//   Step 1: a component calls dispatch(increment())\n//   Step 2: Redux runs the counterSlice's \"increment\" reducer\n//   Step 3: the reducer function MUTATES \"state\" directly INSIDE\n//           Redux Toolkit's createSlice (this is the ONE place RTK\n//           allows it, using a library called Immer behind the\n//           scenes -- it looks like mutation but is actually safe)\n//   Step 4: the store updates, every subscribed component re-renders\n\n// ---- store/counterSlice.ts ----\nimport { createSlice, PayloadAction } from \"@reduxjs/toolkit\";\n\ninterface CounterState {\n    value: number;\n}\n\nconst initialState: CounterState = { value: 0 };\n\nconst counterSlice = createSlice({\n    name: \"counter\",\n    initialState,\n    reducers: {\n        increment: (state) => { state.value += 1; },\n        decrement: (state) => { state.value -= 1; },\n        incrementByAmount: (state, action: PayloadAction<number>) => {\n            state.value += action.payload;\n        },\n    },\n});\n\nexport const { increment, decrement, incrementByAmount } = counterSlice.actions;\n// export default counterSlice.reducer;   // counterSlice.ts would export\n// its reducer like this; reused directly below since this lesson keeps\n// everything in one file\n\n// ── PREDICT before running ──────────────────────────────────────\n// incrementByAmount needs an argument when called, but increment\n// doesn't. Looking at the reducers above, why?               -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Store: Combining Slices\n// ================================================================\n//\n//   configureStore wires all your slices together into ONE store --\n//   like registering every blueprint's dict into one root dict.\n\n// ---- store/store.ts ----\nimport { configureStore } from \"@reduxjs/toolkit\";\n// import counterReducer from \"./counterSlice\";   // a real, separate\n// file -- counterSlice's reducer above is reused directly here since\n// this lesson keeps everything in one file\nconst counterReducer = counterSlice.reducer;\n\nexport const store = configureStore({\n    reducer: {\n        counter: counterReducer,\n        // cart: cartReducer, auth: authReducer, ... as the app grows\n    },\n});\n\nexport type RootState = ReturnType<typeof store.getState>;\nexport type AppDispatch = typeof store.dispatch;\n\n\n// ================================================================\n// PART 3 -- Connecting React: Provider, useSelector, useDispatch\n// ================================================================\n//\n//   Provider here plays the SAME role as Context's Provider\n//   (lesson 18) -- it makes the store available to the whole tree.\n//\n//   useSelector(fn) -- reads a SLICE of state, re-renders the\n//                      component ONLY when that specific slice changes\n//   useDispatch()   -- gives you the dispatch function to send actions\n\n// ---- App.tsx ----\nimport React from \"react\";\nimport { Provider, useSelector, useDispatch } from \"react-redux\";\nimport { View, Text, Pressable } from \"react-native\";\n// import { store, RootState } from \"./store/store\";\n// import { increment, decrement } from \"./store/counterSlice\";\n\nconst CounterScreen = () => {\n    // const count = useSelector((state: RootState) => state.counter.value);\n    // const dispatch = useDispatch();\n    return (\n        <View style={{ padding: 20, alignItems: \"center\" }}>\n            {/* <Text>{count}</Text>\n            <Pressable onPress={() => dispatch(increment())}><Text>+1</Text></Pressable>\n            <Pressable onPress={() => dispatch(decrement())}><Text>-1</Text></Pressable> */}\n        </View>\n    );\n};\n\n// const RootApp = () => (\n//     <Provider store={store}>\n//         <CounterScreen />\n//     </Provider>\n// );\n\n\n// ================================================================\n// PART 4 -- Async Logic: createAsyncThunk (Fetching Into the Store)\n// ================================================================\n//\n//   Combines lesson 10's fetch pattern with Redux -- instead of\n//   loading/error/data living in ONE component's useState, they\n//   live in the STORE, shared by anyone who needs them.\n//\n//   TRACE: dispatching an async thunk\n//   Step 1: dispatch(fetchUser(1)) -- starts the request\n//   Step 2: RTK auto-dispatches a \"pending\" action -- you set\n//           loading = true in extraReducers for that case\n//   Step 3: on success, a \"fulfilled\" action carries the result\n//   Step 4: on failure, a \"rejected\" action carries the error\n\nimport { createAsyncThunk } from \"@reduxjs/toolkit\";\n\ninterface ApiUser { id: number; name: string; }\n\nexport const fetchUser = createAsyncThunk(\"user/fetchUser\", async (userId: number) => {\n    const response = await fetch(`https://jsonplaceholder.typicode.com/users/${userId}`);\n    return (await response.json()) as ApiUser;\n});\n\ninterface UserState {\n    data: ApiUser | null;\n    loading: boolean;\n    error: string | null;\n}\n\nconst userSlice = createSlice({\n    name: \"user\",\n    initialState: { data: null, loading: false, error: null } as UserState,\n    reducers: {},\n    extraReducers: (builder) => {\n        builder\n            .addCase(fetchUser.pending, (state) => { state.loading = true; state.error = null; })\n            .addCase(fetchUser.fulfilled, (state, action) => { state.loading = false; state.data = action.payload; })\n            .addCase(fetchUser.rejected, (state, action) => { state.loading = false; state.error = action.error.message ?? \"Failed\"; });\n    },\n});\n\nexport default userSlice.reducer;","questionsCode":"// ================================================================\n// [QUESTIONS] -- One store, named actions, predictable updates.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// dispatch(increment());\n// dispatch(increment());\n// dispatch(decrement());\n//\n// Starting from value: 0, what is state.counter.value after all\n// three dispatches run, in order?                             -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const cartSlice = createSlice({\n//       name: \"cart\",\n//       initialState: { items: [] },\n//       reducers: {\n//           addItem: (state, action) => {\n//               state.items = state.items.push(action.payload);\n//           },\n//       },\n//   });\n//\n// Bug -> ?  (hint: what does Array.prototype.push() actually RETURN,\n// versus what it does to the array in place?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Cart Slice\n//\n// PLAN: what actions does a cart need -- add, remove, clear?\n//\n// Create a cartSlice with state { items: {id: string, qty: number}[] }\n// and reducers addItem, removeItem(by id), and clearCart. Wire it\n// into the store alongside counterSlice. Build a screen using\n// useSelector/useDispatch to add a hardcoded item and display the\n// item count.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build an Async User List Slice\n//\n// PLAN: which 3 states does extraReducers need to handle?\n//\n// Using createAsyncThunk, build a thunk fetchAllUsers that fetches\n// https://jsonplaceholder.typicode.com/users. Build a usersSlice\n// with state { list: ApiUser[], loading: boolean, error: string|null }\n// handling pending/fulfilled/rejected. Build a screen that dispatches\n// it on mount (useEffect + dispatch) and renders the list with FlatList.\n//\n// Write here:","takeaways":["createSlice({name, initialState, reducers}) -- state + the only allowed ways to change it","configureStore({reducer: {...}}) -- combines all slices into one store","useSelector(fn) -- read a slice | useDispatch() -- send an action","createAsyncThunk -- async logic that dispatches pending/fulfilled/rejected"],"nextHint":"lesson_20_zustand.tsx -- a lighter-weight alternative to Redux","milestone":""},{"num":20,"id":"lesson_20_zustand","filename":"lesson_20_zustand.tsx","title":"Zustand: State Management Without the Ceremony","subtitle":"same GOAL as Redux Toolkit (one shared store, predictable updates) -- far less setup to get there.","section":"State Management","color":"pink","mainCode":"// ================================================================\n//   LESSON 20 -- Zustand: State Management Without the Ceremony\n//   Teaching philosophy: same GOAL as Redux Toolkit (one shared\n//                        store, predictable updates) -- far less\n//                        setup to get there.\n// ================================================================\n//   Before starting: npx expo install zustand\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Redux Toolkit (lesson 19) needed: a slice file, a store file,\n//   a Provider wrapping the app, useSelector, useDispatch -- several\n//   moving pieces working together.\n//\n//   Zustand collapses ALL of that into: define a store as a single\n//   function call, then import and use it directly in ANY\n//   component -- no Provider needed at all.\n//\n//   Priority order recap from your curriculum: Context API (great\n//   for simple, infrequent global state) -> Redux Toolkit (the\n//   industry-standard, structured choice for large apps) ->\n//   Zustand (a lighter alternative many teams now prefer for the\n//   SAME problems Redux solves, with less boilerplate).\n\n\n// ================================================================\n// PART 1 -- Creating a Store\n// ================================================================\n//\n//   TRACE: create(...)\n//   Step 1: create() takes a function receiving \"set\" (and \"get\")\n//   Step 2: you return an object -- THAT object IS your store's\n//           shape: state values AND the functions that update them,\n//           all together (unlike Redux's separate state/reducers)\n//   Step 3: \"set\" merges whatever you give it into the store,\n//           similar to setState merging -- you don't need to\n//           manually spread the rest of the state\n\n// ---- store/counterStore.ts ----\nimport { create } from \"zustand\";\n\ninterface CounterStore {\n    count: number;\n    increment: () => void;\n    decrement: () => void;\n    reset: () => void;\n}\n\nconst useCounterStore = create<CounterStore>((set) => ({\n    count: 0,\n    increment: () => set((state) => ({ count: state.count + 1 })),\n    decrement: () => set((state) => ({ count: state.count - 1 })),\n    reset: () => set({ count: 0 }),\n}));\n\n// ── PREDICT before running ──────────────────────────────────────\n// Compare this file to lesson 19's counterSlice.ts -- which one\n// needed a SEPARATE store-combining file (store.ts) to work?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Using the Store: No Provider Required\n// ================================================================\n//\n//   TRACE: reading and updating from a component\n//   Step 1: useCounterStore() is just a HOOK -- call it directly\n//   Step 2: pass a SELECTOR function to read only what you need:\n//           useCounterStore((state) => state.count)\n//   Step 3: this component re-renders ONLY when \"count\" changes --\n//           even if other fields in the store change, it won't\n//   Step 4: actions (increment, etc.) are read the SAME way\n\nimport React from \"react\";\nimport { View, Text, Pressable } from \"react-native\";\n\nconst CounterScreen = () => {\n    const count = useCounterStore((state) => state.count);\n    const increment = useCounterStore((state) => state.increment);\n    const decrement = useCounterStore((state) => state.decrement);\n\n    return (\n        <View style={{ padding: 20, alignItems: \"center\" }}>\n            <Text style={{ fontSize: 32 }}>{count}</Text>\n            <Pressable onPress={increment}><Text>+1</Text></Pressable>\n            <Pressable onPress={decrement}><Text>-1</Text></Pressable>\n        </View>\n    );\n};\n\n// A SECOND, totally unrelated component reads from the SAME store,\n// no Provider wiring needed anywhere in the tree above either one:\nconst CounterBadge = () => {\n    const count = useCounterStore((state) => state.count);\n    return <Text>Current count: {count}</Text>;\n};\n\n\n// ================================================================\n// PART 3 -- A Cart Store (A More Realistic Shape)\n// ================================================================\n//\n//   TRACE: addItem using \"get\" to read current state inside an action\n//   Step 1: set((state) => ...) -- the function form receives the\n//           LATEST state, just like useState's functional updates\n//           (lesson 04 PART 2) -- same safety reasoning applies\n\ninterface CartItem { id: string; name: string; price: number; }\n\ninterface CartStore {\n    items: CartItem[];\n    addItem: (item: CartItem) => void;\n    removeItem: (id: string) => void;\n    total: () => number;\n}\n\nconst useCartStore = create<CartStore>((set, get) => ({\n    items: [],\n    addItem: (item) => set((state) => ({ items: [...state.items, item] })),\n    removeItem: (id) => set((state) => ({ items: state.items.filter((i) => i.id !== id) })),\n    total: () => get().items.reduce((sum, i) => sum + i.price, 0),\n    // \"total\" isn't state itself -- it's a plain function reading\n    // CURRENT state via get(), computed on demand when called\n}));\n\n\n// ================================================================\n// PART 4 -- Async Actions (No Special Thunk Syntax Needed)\n// ================================================================\n//\n//   Unlike Redux's createAsyncThunk (lesson 19 PART 4), Zustand\n//   actions can just BE async functions directly -- there's no\n//   separate \"thunk\" concept to learn.\n\ninterface ApiUser { id: number; name: string; }\n\ninterface UserStore {\n    user: ApiUser | null;\n    loading: boolean;\n    error: string | null;\n    fetchUser: (id: number) => Promise<void>;\n}\n\nconst useUserStore = create<UserStore>((set) => ({\n    user: null,\n    loading: false,\n    error: null,\n    fetchUser: async (id) => {\n        set({ loading: true, error: null });\n        try {\n            const response = await fetch(`https://jsonplaceholder.typicode.com/users/${id}`);\n            const data = await response.json();\n            set({ user: data, loading: false });\n        } catch (err) {\n            set({ error: \"Failed to load user\", loading: false });\n        }\n    },\n}));\n\n\n// ================================================================\n// PART 5 -- Zustand vs Redux Toolkit: When to Reach for Which\n// ================================================================\n//\n//   Redux Toolkit -- more structure, more tooling (Redux DevTools,\n//   middleware ecosystem), often expected in larger teams/companies\n//   with established conventions. Worth knowing because many\n//   existing codebases already use it.\n//\n//   Zustand -- much less boilerplate, easier to learn and read,\n//   great for small-to-medium apps or teams that want Redux-level\n//   power without Redux-level ceremony.\n//\n//   Both solve the SAME underlying problem this course's curriculum\n//   flagged: \"companies rarely use only useState\" once an app grows\n//   past a handful of screens sharing data.","questionsCode":"// ================================================================\n// [QUESTIONS] -- create() returns a hook. No Provider needed.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const useStore = create((set) => ({ a: 1, b: 2 }));\n//\n// const ComponentA = () => useStore((state) => state.a);\n// const ComponentB = () => useStore((state) => state.b);\n//\n// If a future action only changes \"a\", does ComponentB re-render?  -> ?\n// Why does selecting JUST the field you need matter here?     -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const useStore = create((set) => ({\n//       items: [],\n//       addItem: (item) => {\n//           state.items.push(item);\n//       },\n//   }));\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: where does \"state\" even come\n// from inside addItem, and is .push() the right approach here?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Favorites Store\n//\n// PLAN: what's the simplest way to check \"is this id favorited\"?\n//\n// Build useFavoritesStore with state { ids: string[] }, an action\n// toggleFavorite(id: string) that adds the id if absent or removes\n// it if present, and a helper isFavorite(id: string) => boolean.\n// Build a ProductRow component using this store to show a filled\n// or empty heart and toggle it on press.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Migrate the Cart Slice\n//\n// PLAN: which pieces from lesson 19's Redux cartSlice carry over?\n//\n// Take the cartSlice you (or this lesson) designed in lesson 19's\n// QUESTION 3, and rewrite it as a Zustand store instead -- same\n// addItem/removeItem/clearCart behavior, no slice/store-file split,\n// no Provider.\n//\n// Write here:","takeaways":["create<T>((set, get) => ({...})) -- state AND actions together","useStore((state) => state.field) -- selector, re-renders ONLY on that field changing","No Provider needed -- import the hook and call it anywhere","Async actions: just write async functions directly, no thunk syntax"],"nextHint":"lesson_21_rest_apis_deep_dive.tsx -- Backend Integration begins","milestone":"STATE MANAGEMENT SECTION COMPLETE."},{"num":21,"id":"lesson_21_rest_apis_deep_dive","filename":"lesson_21_rest_apis_deep_dive.tsx","title":"REST APIs in Depth: Headers, Status, and Structure","subtitle":"lesson 10 taught the basic GET/POST shape. This lesson fills in everything real backends expect that a toy API doesn't.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 21 -- REST APIs in Depth: Headers, Status, and Structure\n//   Teaching philosophy: lesson 10 taught the basic GET/POST shape.\n//                        This lesson fills in everything real\n//                        backends expect that a toy API doesn't.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   jsonplaceholder (used since lesson 10) doesn't need auth, doesn't\n//   validate input strictly, and pretends to save data it never\n//   really stores. A REAL backend (Node.js/Django, which you've\n//   touched before) expects MORE structure on every request:\n//   - WHO is making this request? (Authorization header)\n//   - WHAT shape is the data? (Content-Type header)\n//   - WHICH operation, precisely? (HTTP method conventions)\n//\n//   REST is a set of CONVENTIONS for organizing these. Following\n//   them means any backend speaks the same basic \"shape\" of API.\n\n\n// ================================================================\n// PART 1 -- The Five HTTP Methods and Their Meaning\n// ================================================================\n//\n//   GET     -- read data, never changes anything on the server\n//   POST    -- create something new\n//   PUT     -- replace an existing resource ENTIRELY\n//   PATCH   -- update PART of an existing resource\n//   DELETE  -- remove a resource\n//\n//   TRACE: PUT vs PATCH on a user record\n//   Step 1: PUT /users/5 with { name: \"Sarath\" } -- REPLACES the\n//           whole user record with just { name: \"Sarath\" } --\n//           any other fields (email, age) may be WIPED depending\n//           on the backend's implementation\n//   Step 2: PATCH /users/5 with { name: \"Sarath\" } -- updates ONLY\n//           the name field, leaving email/age untouched\n//\n//   Most apps use PATCH far more often than PUT for this reason --\n//   you rarely want to accidentally erase fields you didn't send.\n\n\n// ================================================================\n// PART 2 -- Headers: Metadata About the Request\n// ================================================================\n//\n//   Headers are key-value pairs sent ALONGSIDE the request body --\n//   Python analogy: like passing extra keyword arguments that\n//   describe the request itself, not the data inside it.\n//\n//   \"Content-Type\": \"application/json\"   -- \"my body is JSON\"\n//   \"Authorization\": \"Bearer <token>\"     -- \"here's proof of who I am\"\n//                                             (lesson 22 covers tokens)\n//   \"Accept\": \"application/json\"          -- \"send the response as JSON\"\n\nconst apiRequest = async (url: string, token?: string) => {\n    const headers: Record<string, string> = {\n        \"Content-Type\": \"application/json\",\n        \"Accept\": \"application/json\",\n    };\n    if (token) {\n        headers[\"Authorization\"] = `Bearer ${token}`;\n    }\n    const response = await fetch(url, { headers });\n    return response.json();\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If a backend REQUIRES Authorization but you call apiRequest(url)\n// with no token argument, what status code would you expect back\n// (recall lesson 10/Python lesson 23's status code list)?    -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 3 -- A Reusable API Client (Centralizing Fetch Logic)\n// ================================================================\n//\n//   Repeating headers/error handling in every screen is exactly the\n//   kind of duplication lesson 17 (custom hooks) and basic function\n//   extraction both fight against. Real apps centralize this into\n//   ONE small client module.\n\nconst BASE_URL = \"https://api.example.com\";\n\ninterface RequestOptions {\n    method?: \"GET\" | \"POST\" | \"PUT\" | \"PATCH\" | \"DELETE\";\n    body?: unknown;\n    token?: string;\n}\n\nasync function apiClient<T>(path: string, options: RequestOptions = {}): Promise<T> {\n    const { method = \"GET\", body, token } = options;\n    const headers: Record<string, string> = { \"Content-Type\": \"application/json\" };\n    if (token) headers[\"Authorization\"] = `Bearer ${token}`;\n\n    const response = await fetch(`${BASE_URL}${path}`, {\n        method,\n        headers,\n        body: body ? JSON.stringify(body) : undefined,\n    });\n\n    if (!response.ok) {\n        const errorBody = await response.json().catch(() => null);\n        throw new Error(errorBody?.message ?? `Request failed: ${response.status}`);\n    }\n    return response.json();\n}\n\n// Usage anywhere in the app -- ONE line per call, all the header/\n// error logic stays in one place:\n// const products = await apiClient<Product[]>(\"/products\");\n// const created = await apiClient<Product>(\"/products\", { method: \"POST\", body: { name: \"Mouse\" } });\n\n\n// ================================================================\n// PART 4 -- Reading Error Responses Properly\n// ================================================================\n//\n//   A real backend usually sends a JSON body even on FAILURE,\n//   describing what went wrong:\n//\n//   { \"message\": \"Email already in use\", \"field\": \"email\" }\n//\n//   TRACE: PART 3's error handling\n//   Step 1: response.ok is false (4xx/5xx status)\n//   Step 2: try to parse a JSON error body (it might not exist,\n//           so .catch(() => null) prevents a SECOND crash)\n//   Step 3: throw a real Error with the backend's message if present,\n//           otherwise fall back to a generic message with the status\n\n\n// ================================================================\n// PART 5 -- Pagination (Real Lists Are Rarely \"Everything at Once\")\n// ================================================================\n//\n//   Real APIs return PAGES of data, not the entire table -- exactly\n//   why FlatList (lesson 07) matters: you fetch a page, render it,\n//   and fetch the NEXT page as the user scrolls near the bottom\n//   (FlatList's onEndReached prop, used in lesson 26's project).\n//\n//   GET /products?page=1&limit=20\n//   { \"data\": [...20 items...], \"page\": 1, \"totalPages\": 8 }","questionsCode":"// ================================================================\n// [QUESTIONS] -- Headers describe the request. Status codes describe the result.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// apiClient(\"/orders\", { method: \"PATCH\", body: { status: \"shipped\" } });\n//\n// Does this REPLACE the whole order, or just update its status\n// field, assuming the backend follows REST conventions?      -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const updateUser = async (id, data) => {\n//       const res = fetch(`/users/${id}`, {\n//           method: \"POST\",\n//           body: data,\n//       });\n//       return res.json();\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?   (hint: method choice for\n// an UPDATE, missing await, and body format)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Extend apiClient With Query Params\n//\n// PLAN: how do query params get appended to a URL safely?\n//\n// Add an optional \"params\" field to RequestOptions (a Record<string,\n// string>), and build the final URL using URLSearchParams to append\n// them (e.g. { page: \"2\", limit: \"20\" } -> \"?page=2&limit=20\").\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Design a Paginated Fetch Hook\n//\n// PLAN: what state does this need beyond the lesson 17 useFetch shape?\n//\n// Build a custom hook usePaginatedList<T>(path: string) returning\n// { items: T[], loadMore: () => void, loading: boolean, hasMore:\n// boolean } -- loadMore increments an internal page number and\n// APPENDS new results to \"items\" rather than replacing them.\n//\n// Write here:","takeaways":["GET (read) | POST (create) | PUT (replace) | PATCH (partial update) | DELETE","Headers describe the REQUEST -- Content-Type, Authorization, Accept","Centralize fetch logic in ONE client function/module","Always parse and surface the backend's actual error message"],"nextHint":"lesson_22_jwt_auth.tsx -- how token-based authentication works","milestone":""},{"num":22,"id":"lesson_22_jwt_auth","filename":"lesson_22_jwt_auth.tsx","title":"JWT Authentication: Proving Who You Are","subtitle":"a JWT is just a signed, tamper-proof string -- understand WHY it works before writing any login code.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 22 -- JWT Authentication: Proving Who You Are\n//   Teaching philosophy: a JWT is just a signed, tamper-proof\n//                        string -- understand WHY it works before\n//                        writing any login code.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   HTTP is \"stateless\" -- the server doesn't remember you between\n//   requests by default. Every request must prove WHO is making it.\n//\n//   Old approach: server-side sessions (a session id in a cookie,\n//   server keeps a matching record in memory/DB). Common in\n//   traditional Django apps.\n//\n//   JWT (JSON Web Token) approach: the SERVER signs a token\n//   containing your identity, and hands it to you. On every future\n//   request, you ATTACH that token -- the server verifies the\n//   signature (without needing to look anything up in a database)\n//   to confirm it's genuine and unmodified.\n//\n//   Python analogy: imagine a tamper-evident wristband at a concert.\n//   Security doesn't keep a guest list to check your name against\n//   every time -- they just check the wristband's seal is intact.\n//   A JWT is that wristband, in string form.\n\n\n// ================================================================\n// PART 1 -- The Anatomy of a JWT\n// ================================================================\n//\n//   A JWT looks like: xxxxx.yyyyy.zzzzz -- three parts, separated\n//   by dots, each base64-encoded:\n//\n//   HEADER.PAYLOAD.SIGNATURE\n//\n//   HEADER    -- which algorithm was used to sign it\n//   PAYLOAD   -- the actual DATA: { userId: 5, email: \"...\", exp: ... }\n//                \"exp\" = expiry timestamp -- after this, the token\n//                is considered invalid even if the signature is fine\n//   SIGNATURE -- proof the payload hasn't been tampered with,\n//                created using a SECRET KEY only the server knows\n//\n//   IMPORTANT: the payload is NOT encrypted, only encoded -- anyone\n//   can READ it (paste a JWT into jwt.io to see). NEVER put\n//   passwords or sensitive secrets inside the payload itself.\n\n\n// ================================================================\n// PART 2 -- The Login Flow, Step by Step\n// ================================================================\n//\n//   TRACE: logging in\n//   Step 1: app sends POST /login with { email, password }\n//   Step 2: server checks credentials against its database\n//   Step 3: if valid, server creates a JWT containing { userId, exp }\n//           and SIGNS it with a secret key (this signing is what\n//           makes it tamper-proof -- changing even one character\n//           of the payload invalidates the signature)\n//   Step 4: server sends the JWT back to the app\n//   Step 5: app stores the JWT (AsyncStorage, lesson 11 -- proper\n//           secure storage covered in lesson 23)\n//   Step 6: every future request attaches it: \"Authorization: Bearer <jwt>\"\n//   Step 7: server verifies the signature on each request --\n//           NO database lookup needed to confirm identity\n\ninterface LoginResponse {\n    token: string;\n    user: { id: number; email: string };\n}\n\nconst login = async (email: string, password: string): Promise<LoginResponse> => {\n    const response = await fetch(\"https://api.example.com/login\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\" },\n        body: JSON.stringify({ email, password }),\n    });\n    if (!response.ok) throw new Error(\"Invalid email or password\");\n    return response.json();\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If someone copies your JWT string and pastes it into THEIR app,\n// can the server tell the difference between you and them?   -> ?\n// (This is why tokens must be stored/transmitted carefully --\n// lesson 23 covers WHERE to store them.)\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 3 -- Attaching the Token to Every Request\n// ================================================================\n//\n//   This connects directly to lesson 21's apiClient -- the \"token\"\n//   parameter you saw there is exactly the JWT from login.\n\nasync function authedRequest<T>(path: string, token: string): Promise<T> {\n    const response = await fetch(`https://api.example.com${path}`, {\n        headers: { \"Authorization\": `Bearer ${token}` },\n    });\n    if (response.status === 401) {\n        throw new Error(\"Session expired -- please log in again\");\n    }\n    return response.json();\n}\n//\n//   status === 401 -- TRACE: why this specific code matters\n//   Step 1: 401 means \"Unauthorized\" -- your token is missing,\n//           expired, or invalid\n//   Step 2: this is DIFFERENT from 403 (\"Forbidden\" -- you ARE\n//           known, but not ALLOWED to do this specific thing)\n//   Step 3: a 401 is your app's signal to log the user out and\n//           send them back to the login screen\n\n\n// ================================================================\n// PART 4 -- Why Expiry (exp) Exists\n// ================================================================\n//\n//   If a JWT never expired, a stolen token would work FOREVER.\n//   Short expiry (e.g. 15 minutes) limits the damage window if a\n//   token is ever leaked -- but logging in every 15 minutes would\n//   be a terrible user experience. The fix is REFRESH TOKENS,\n//   covered fully in lesson 24 -- a longer-lived token used ONLY\n//   to silently obtain a fresh short-lived one, without re-entering\n//   a password.","questionsCode":"// ================================================================\n// [QUESTIONS] -- A JWT proves identity via signature, not secrecy of contents.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A JWT's payload contains: { \"userId\": 5, \"role\": \"user\", \"exp\": 123 }\n// Someone edits the base64 text directly to change \"role\" to \"admin\"\n// and sends the modified token to the server.\n//\n// Does the server accept this modified token as valid? Why?   -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const fetchProfile = async () => {\n//       const res = await fetch(\"/profile\");\n//       return res.json();\n//   };\n//   // App is supposed to be logged in, calling a protected endpoint.\n//\n// Bug -> ?  (hint: compare this to authedRequest above -- what's\n// completely missing from this call?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Trace a Full Login + Protected Request\n//\n// Write out, in your own words, the COMPLETE sequence of network\n// requests and what each side (app vs server) does, for: a user\n// logging in, then immediately fetching their own order history\n// from a protected endpoint.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Handle a 401 Globally\n//\n// PLAN: where should \"log the user out\" logic actually live --\n// in every single screen, or in one shared place?\n//\n// Modify authedRequest (or apiClient from lesson 21) so that on a\n// 401 response, it calls a passed-in onUnauthorized() callback\n// (e.g. one that clears AsyncStorage and navigates to /login via\n// Expo Router) BEFORE throwing the error.\n//\n// Write here:","takeaways":["JWT = HEADER.PAYLOAD.SIGNATURE -- payload is READABLE, not secret","Signature proves the token wasn't tampered with -- it's not encryption","Authorization: Bearer <token> -- sent on every protected request","401 = your token is missing/invalid/expired -- log out and redirect","exp = short-lived on purpose -- limits damage from a leaked token"],"nextHint":"lesson_23_login_register.tsx -- building the actual login UI + flow","milestone":""},{"num":23,"id":"lesson_23_login_register","filename":"lesson_23_login_register.tsx","title":"Login & Register: Building the Actual Flow","subtitle":"this is forms (lesson 06/11) + fetch (lesson 10) + JWT (lesson 22), wired into one real screen-to-screen flow.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 23 -- Login & Register: Building the Actual Flow\n//   Teaching philosophy: this is forms (lesson 06/11) + fetch\n//                        (lesson 10) + JWT (lesson 22), wired into\n//                        one real screen-to-screen flow.\n// ================================================================\n//   Before starting: npx expo install expo-secure-store\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 11 used AsyncStorage for notes -- fine for non-sensitive\n//   data. A JWT (lesson 22) is effectively a temporary password --\n//   if a malicious app on the same device could read it, they could\n//   impersonate the user. expo-secure-store encrypts what it stores\n//   using the OS's own secure storage (Keychain on iOS, Keystore on\n//   Android) -- the right tool specifically for tokens/secrets.\n//\n//   AsyncStorage  -- general app data (notes, settings, drafts)\n//   SecureStore   -- tokens, passwords, anything sensitive\n\n\n// ================================================================\n// PART 1 -- Storing and Reading the Token Securely\n// ================================================================\n//\n//   Same API shape as AsyncStorage (lesson 11) -- the ONLY change\n//   is the import and WHERE it physically stores the data.\n\nimport * as SecureStore from \"expo-secure-store\";\n\nconst saveToken = async (token: string) => {\n    await SecureStore.setItemAsync(\"auth_token\", token);\n};\n\nconst getToken = async (): Promise<string | null> => {\n    return await SecureStore.getItemAsync(\"auth_token\");\n};\n\nconst clearToken = async () => {\n    await SecureStore.deleteItemAsync(\"auth_token\");\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you uninstall and reinstall the app, does SecureStore's saved\n// token usually survive? (Hint: think about what \"secure, OS-level\n// storage\" implies about its lifecycle vs the app itself.)     -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Login Screen\n// ================================================================\n//\n//   TRACE: pressing \"Log In\"\n//   Step 1: validate fields aren't empty (lesson 06's pattern)\n//   Step 2: call the login API function (lesson 22)\n//   Step 3: on success -- save the token (PART 1), update the\n//           AuthContext (lesson 18's useAuth) so the WHOLE app\n//           knows the user is now logged in\n//   Step 4: navigate to the home screen (lesson 08's router)\n//   Step 5: on failure -- show the error, leave the user on this screen\n\nimport React, { useState } from \"react\";\nimport { View, Text, TextInput, Pressable, ActivityIndicator, StyleSheet } from \"react-native\";\n// import { router } from \"expo-router\";\n// import { useAuth } from \"../context/AuthContext\";   // lesson 18's pattern\n\nconst LoginScreen = () => {\n    const [email, setEmail] = useState(\"\");\n    const [password, setPassword] = useState(\"\");\n    const [loading, setLoading] = useState(false);\n    const [error, setError] = useState<string | null>(null);\n    // const { login } = useAuth();\n\n    const handleLogin = async () => {\n        if (!email.includes(\"@\") || password.length < 6) {\n            setError(\"Enter a valid email and a password of at least 6 characters.\");\n            return;\n        }\n        setLoading(true);\n        setError(null);\n        try {\n            // const { token, user } = await loginApi(email, password);\n            // await saveToken(token);\n            // login(user);          // updates AuthContext -> whole app re-renders\n            // router.replace(\"/home\");\n        } catch (err) {\n            setError(err instanceof Error ? err.message : \"Login failed\");\n        } finally {\n            setLoading(false);\n        }\n    };\n\n    return (\n        <View style={styles.container}>\n            <TextInput style={styles.input} placeholder=\"Email\" value={email} onChangeText={setEmail} autoCapitalize=\"none\" />\n            <TextInput style={styles.input} placeholder=\"Password\" value={password} onChangeText={setPassword} secureTextEntry />\n            {error && <Text style={styles.error}>{error}</Text>}\n            <Pressable style={styles.button} onPress={handleLogin} disabled={loading}>\n                {loading ? <ActivityIndicator color=\"white\" /> : <Text style={{ color: \"white\" }}>Log In</Text>}\n            </Pressable>\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { flex: 1, padding: 20, justifyContent: \"center\", gap: 10 },\n    input: { borderWidth: 1, borderColor: \"#ccc\", borderRadius: 6, padding: 12 },\n    button: { backgroundColor: \"#3478f6\", padding: 14, borderRadius: 8, alignItems: \"center\" },\n    error: { color: \"red\" },\n});\n//\n//   router.replace(\"/home\") vs router.push(\"/home\") -- TRACE:\n//   Step 1: push ADDS a new screen to the stack -- back button\n//           would return to the login screen\n//   Step 2: replace SWAPS the current screen -- back button\n//           skips login entirely. After logging in, you almost\n//           always want \"replace\" -- nobody should navigate BACK\n//           into a login screen after authenticating.\n\n\n// ================================================================\n// PART 3 -- The Register Screen (Same Shape, Different Endpoint)\n// ================================================================\n//\n//   Register usually collects MORE fields, and on success often\n//   logs the user in immediately (some backends return a token\n//   right from the register endpoint; others require a separate\n//   login call afterward -- check your specific backend's behavior).\n\nconst registerApi = async (name: string, email: string, password: string) => {\n    const response = await fetch(\"https://api.example.com/register\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\" },\n        body: JSON.stringify({ name, email, password }),\n    });\n    if (!response.ok) {\n        const body = await response.json().catch(() => null);\n        throw new Error(body?.message ?? \"Registration failed\");\n    }\n    return response.json();\n};\n\n\n// ================================================================\n// PART 4 -- Checking Login Status on App Start\n// ================================================================\n//\n//   TRACE: reopening the app after closing it\n//   Step 1: app starts, AuthContext's Provider mounts\n//   Step 2: useEffect(fn, []) (lesson 09) checks SecureStore for\n//           a saved token\n//   Step 3: if found, optionally verify it's not expired (or just\n//           try a protected request and handle a 401, lesson 22)\n//   Step 4: if valid, restore the logged-in state immediately --\n//           user skips the login screen entirely\n//   Step 5: if missing/invalid, route to the login screen\n\nconst checkSavedLogin = async (): Promise<string | null> => {\n    const token = await getToken();\n    return token;   // a real app would also validate it here\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- SecureStore for tokens. router.replace after login.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A user logs in successfully, the app calls router.replace(\"/home\").\n// They then press the phone's hardware back button.\n//\n// Do they land back on the login screen, or somewhere else?  -> ?\n// What if router.push had been used instead of replace?       -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const handleLogin = () => {\n//       const result = loginApi(email, password);\n//       AsyncStorage.setItem(\"token\", result.token);\n//       router.push(\"/login\");\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?   (hint: missing await,\n// wrong storage choice for a token, and wrong navigation target)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build the Register Screen\n//\n// PLAN: which fields, which validations, what happens on success?\n//\n// Build a RegisterScreen with name/email/password/confirmPassword\n// TextInputs. Validate: all fields non-empty, password === confirm\n// Password, password length >= 6. On success, call registerApi,\n// then navigate to /login with router.replace so they log in fresh.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build the Startup Auth Check\n//\n// PLAN: while checking, what should the user SEE on screen?\n//\n// Build a root component that, on mount, calls checkSavedLogin().\n// While checking (loading state), show an ActivityIndicator.\n// If a token exists, router.replace(\"/home\"); if not, router.replace\n// (\"/login\"). This is the \"splash/auth gate\" pattern real apps use.\n//\n// Write here:","takeaways":["expo-secure-store -- for tokens/secrets, NOT AsyncStorage","Login flow: validate -> call API -> save token -> update auth state -> router.replace (never push) into the app","Register: same shape, usually more fields, different endpoint","On app start, check SecureStore BEFORE deciding which screen to show"],"nextHint":"lesson_24_refresh_tokens.tsx -- staying logged in safely","milestone":""},{"num":24,"id":"lesson_24_refresh_tokens","filename":"lesson_24_refresh_tokens.tsx","title":"Refresh Tokens: Staying Logged In Safely","subtitle":"this lesson solves the EXACT tension named in lesson 22 PART 4 -- short expiry is safer, but re-logging in constantly is bad UX. Refresh tokens resolve both.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 24 -- Refresh Tokens: Staying Logged In Safely\n//   Teaching philosophy: this lesson solves the EXACT tension\n//                        named in lesson 22 PART 4 -- short expiry\n//                        is safer, but re-logging in constantly\n//                        is bad UX. Refresh tokens resolve both.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   TWO tokens, two very different jobs:\n//\n//   ACCESS TOKEN  -- short-lived (minutes), sent on EVERY API\n//                    request, proves \"who you are right now\"\n//   REFRESH TOKEN -- long-lived (days/weeks), sent ONLY to one\n//                    specific endpoint, used to get a NEW access\n//                    token without asking for a password again\n//\n//   Python analogy: the access token is a day pass that expires\n//   quickly. The refresh token is the membership card that lets\n//   you print a NEW day pass at the front desk, without re-applying\n//   for membership every single day.\n//\n//   TRACE: the full lifecycle\n//   Step 1: login returns BOTH an access token and a refresh token\n//   Step 2: app uses the access token for normal requests\n//   Step 3: access token expires -- a request comes back 401\n//   Step 4: app sends the refresh token to POST /refresh\n//   Step 5: server verifies the refresh token, issues a NEW access\n//           token (and sometimes a new refresh token too)\n//   Step 6: app retries the ORIGINAL failed request with the new\n//           access token -- the user never noticed any of this\n\n\n// ================================================================\n// PART 1 -- Storing Both Tokens\n// ================================================================\n//\n//   Both are sensitive -- both belong in SecureStore (lesson 23),\n//   never AsyncStorage.\n\nimport * as SecureStore from \"expo-secure-store\";\n\ninterface TokenPair {\n    accessToken: string;\n    refreshToken: string;\n}\n\nconst saveTokens = async ({ accessToken, refreshToken }: TokenPair) => {\n    await SecureStore.setItemAsync(\"access_token\", accessToken);\n    await SecureStore.setItemAsync(\"refresh_token\", refreshToken);\n};\n\nconst getAccessToken = () => SecureStore.getItemAsync(\"access_token\");\nconst getRefreshToken = () => SecureStore.getItemAsync(\"refresh_token\");\n\nconst clearTokens = async () => {\n    await SecureStore.deleteItemAsync(\"access_token\");\n    await SecureStore.deleteItemAsync(\"refresh_token\");\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If the refresh token itself expires (say, after 30 days of the\n// app never being opened), what should happen on the NEXT attempt\n// to refresh?                                                 -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Refresh Function\n// ================================================================\n\nconst refreshAccessToken = async (): Promise<string> => {\n    const refreshToken = await getRefreshToken();\n    if (!refreshToken) throw new Error(\"No refresh token -- must log in again\");\n\n    const response = await fetch(\"https://api.example.com/refresh\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\" },\n        body: JSON.stringify({ refreshToken }),\n    });\n\n    if (!response.ok) {\n        await clearTokens();\n        throw new Error(\"Refresh token invalid -- must log in again\");\n    }\n\n    const data: TokenPair = await response.json();\n    await saveTokens(data);\n    return data.accessToken;\n};\n\n\n// ================================================================\n// PART 3 -- An Auto-Retrying API Client (Interceptor Pattern)\n// ================================================================\n//\n//   This is the piece that makes the whole flow INVISIBLE to the\n//   user. It wraps lesson 21's apiClient idea with one extra rule:\n//   \"if a request fails with 401, refresh, then try ONCE more.\"\n//\n//   TRACE: a request that hits an expired token\n//   Step 1: requestWithRefresh calls the real endpoint\n//   Step 2: server says 401 (access token expired)\n//   Step 3: function calls refreshAccessToken() (PART 2)\n//   Step 4: gets a NEW access token, retries the ORIGINAL request\n//           with it attached\n//   Step 5: this time it succeeds -- caller never sees the 401 at all\n\nasync function requestWithRefresh<T>(path: string, options: RequestInit = {}): Promise<T> {\n    let accessToken = await getAccessToken();\n\n    const doFetch = (token: string | null) =>\n        fetch(`https://api.example.com${path}`, {\n            ...options,\n            headers: {\n                ...options.headers,\n                \"Content-Type\": \"application/json\",\n                ...(token ? { Authorization: `Bearer ${token}` } : {}),\n            },\n        });\n\n    let response = await doFetch(accessToken);\n\n    if (response.status === 401) {\n        accessToken = await refreshAccessToken();   // throws if refresh fails too\n        response = await doFetch(accessToken);       // retry ONCE\n    }\n\n    if (!response.ok) throw new Error(`Request failed: ${response.status}`);\n    return response.json();\n}\n//\n//   \"retry ONCE\" matters -- without a limit, a permanently broken\n//   refresh token could cause an infinite retry loop (request fails\n//   -> refresh fails silently in some buggy version -> retry ->\n//   fails again -> forever). Always cap retries at exactly one.\n\n\n// ================================================================\n// PART 4 -- Logging Out Fully\n// ================================================================\n//\n//   TRACE: a complete logout\n//   Step 1: (optional, good practice) tell the server to invalidate\n//           the refresh token: POST /logout with the refresh token\n//   Step 2: clearTokens() -- wipe both tokens from SecureStore\n//   Step 3: clear any in-memory user state (AuthContext, lesson 18)\n//   Step 4: router.replace(\"/login\") -- never push, same reasoning\n//           as lesson 23 PART 2","questionsCode":"// ================================================================\n// [QUESTIONS] -- Access token = short-lived & frequent. Refresh = rare & guarded.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// requestWithRefresh(\"/orders\") is called. The access token is\n// expired, AND the refresh token has ALSO expired.\n//\n// Walk through PART 3's steps -- what does the function ultimately\n// do: return data, retry forever, or throw an error?          -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const fetchData = async (path) => {\n//       const res = await fetch(path);\n//       if (res.status === 401) {\n//           await refreshAccessToken();\n//           return fetchData(path);   // retry\n//       }\n//       return res.json();\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: no Authorization header is EVER\n// attached, and what happens if refresh ALSO keeps failing?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build the Logout Flow\n//\n// PLAN: what order do the 4 steps from PART 4 need to happen in?\n//\n// Build a logout() function combining: an optional server call,\n// clearTokens(), clearing AuthContext's user state (lesson 18),\n// and navigating to /login with router.replace. Wire it to a\n// \"Log Out\" button on a ProfileScreen.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Add a Refresh Queue (Harder, Optional)\n//\n// PLAN: what goes wrong if 3 requests ALL get a 401 at the same\n// moment -- how many refresh calls would PART 3's code trigger?\n//\n// Modify requestWithRefresh so that if a refresh is ALREADY in\n// progress when another request hits a 401, the second request\n// WAITS for the first refresh to finish instead of triggering its\n// own separate refresh call (hint: store the in-flight refresh\n// Promise in a module-level variable, reuse it if it exists).\n//\n// Write here:","takeaways":["Access token: short-lived, sent on every request","Refresh token: long-lived, sent ONLY to the refresh endpoint","On 401: refresh once, retry the original request once, then give up","Both tokens live in SecureStore, both cleared together on logout"],"nextHint":"lesson_25_file_upload.tsx -- sending images/files to a server","milestone":""},{"num":25,"id":"lesson_25_file_upload","filename":"lesson_25_file_upload.tsx","title":"File Upload: Sending Images to a Server","subtitle":"uploading is just a SPECIAL kind of POST body -- multipart/form-data instead of JSON.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 25 -- File Upload: Sending Images to a Server\n//   Teaching philosophy: uploading is just a SPECIAL kind of POST\n//                        body -- multipart/form-data instead of JSON.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every POST so far (lessons 10, 21-24) sent JSON: a string of\n//   text. A photo is BINARY data -- you can't just JSON.stringify\n//   an image. The standard solution is \"multipart/form-data\" --\n//   a request body that can carry BOTH text fields AND binary file\n//   data together, each clearly separated.\n//\n//   Python analogy: requests.post(url, files={\"photo\": open(...)})\n//   does this exact same thing under the hood -- React Native's\n//   FormData class is the equivalent builder.\n\n\n// ================================================================\n// PART 1 -- Picking an Image (Recap From Lesson 12)\n// ================================================================\n\nimport * as ImagePicker from \"expo-image-picker\";\n\nconst pickImage = async (): Promise<string | null> => {\n    const { status } = await ImagePicker.requestMediaLibraryPermissionsAsync();\n    if (status !== \"granted\") return null;\n\n    const result = await ImagePicker.launchImageLibraryAsync({\n        mediaTypes: ImagePicker.MediaTypeOptions.Images,\n        quality: 0.7,\n    });\n    return result.canceled ? null : result.assets[0].uri;\n};\n\n\n// ================================================================\n// PART 2 -- Building a FormData Upload\n// ================================================================\n//\n//   TRACE: FormData.append for a file\n//   Step 1: new FormData() -- an empty \"form\" you build piece by piece\n//   Step 2: formData.append(\"photo\", { uri, name, type }) -- in\n//           React Native specifically, a file is described as an\n//           OBJECT with uri/name/type, NOT a raw File object like\n//           on web\n//   Step 3: formData.append(\"caption\", \"My new photo\") -- regular\n//           text fields can sit alongside the file in the SAME form\n//   Step 4: fetch(url, { method: \"POST\", body: formData }) --\n//           IMPORTANT: do NOT manually set \"Content-Type\" yourself\n//           here -- fetch sets the correct multipart boundary header\n//           automatically, and overriding it usually BREAKS the upload\n\ninterface UploadResult { url: string; }\n\nconst uploadPhoto = async (uri: string, caption: string, token: string): Promise<UploadResult> => {\n    const formData = new FormData();\n    formData.append(\"photo\", {\n        uri,\n        name: \"photo.jpg\",\n        type: \"image/jpeg\",\n    } as any);\n    formData.append(\"caption\", caption);\n\n    const response = await fetch(\"https://api.example.com/upload\", {\n        method: \"POST\",\n        headers: {\n            Authorization: `Bearer ${token}`,\n            // NOTE: no Content-Type here -- see explanation above\n        },\n        body: formData,\n    });\n\n    if (!response.ok) throw new Error(\"Upload failed\");\n    return response.json();\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// What do you expect to happen if you manually set headers:\n// { \"Content-Type\": \"multipart/form-data\" } yourself, instead of\n// letting fetch generate it?                                  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 3 -- A Full Upload Screen With Progress Feedback\n// ================================================================\n//\n//   Combines: lesson 12 (picking), lesson 04 (state), lesson 10's\n//   loading/error pattern, and PART 2's upload function.\n\nimport React, { useState } from \"react\";\nimport { View, Text, Image, Pressable, ActivityIndicator, Alert } from \"react-native\";\n\nconst PhotoUploadScreen = () => {\n    const [imageUri, setImageUri] = useState<string | null>(null);\n    const [uploading, setUploading] = useState(false);\n\n    const handlePick = async () => {\n        const uri = await pickImage();\n        if (uri) setImageUri(uri);\n    };\n\n    const handleUpload = async () => {\n        if (!imageUri) return;\n        setUploading(true);\n        try {\n            // const result = await uploadPhoto(imageUri, \"My photo\", token);\n            Alert.alert(\"Success\", \"Photo uploaded!\");\n        } catch (err) {\n            Alert.alert(\"Error\", \"Upload failed. Try again.\");\n        } finally {\n            setUploading(false);\n        }\n    };\n\n    return (\n        <View style={{ padding: 20, gap: 12 }}>\n            {imageUri && <Image source={{ uri: imageUri }} style={{ width: 200, height: 200 }} />}\n            <Pressable onPress={handlePick}><Text>Pick a Photo</Text></Pressable>\n            <Pressable onPress={handleUpload} disabled={!imageUri || uploading}>\n                {uploading ? <ActivityIndicator /> : <Text>Upload</Text>}\n            </Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Tracking Real Upload Progress (XMLHttpRequest)\n// ================================================================\n//\n//   Plain fetch() has NO built-in progress events -- for a progress\n//   BAR (not just a spinner), apps fall back to the older\n//   XMLHttpRequest API, which DOES support an upload progress event.\n//\n//   TRACE: xhr.upload.onprogress\n//   Step 1: event.loaded -- bytes sent so far\n//   Step 2: event.total  -- total bytes to send\n//   Step 3: (event.loaded / event.total) * 100 -- percentage complete\n\nconst uploadWithProgress = (uri: string, onProgress: (percent: number) => void) => {\n    return new Promise<void>((resolve, reject) => {\n        const xhr = new XMLHttpRequest();\n        const formData = new FormData();\n        formData.append(\"photo\", { uri, name: \"photo.jpg\", type: \"image/jpeg\" } as any);\n\n        xhr.upload.onprogress = (event) => {\n            if (event.lengthComputable) {\n                onProgress(Math.round((event.loaded / event.total) * 100));\n            }\n        };\n        xhr.onload = () => (xhr.status === 200 ? resolve() : reject(new Error(\"Upload failed\")));\n        xhr.onerror = () => reject(new Error(\"Network error\"));\n\n        xhr.open(\"POST\", \"https://api.example.com/upload\");\n        xhr.send(formData);\n    });\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- FormData carries files. Let fetch set its own Content-Type.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const formData = new FormData();\n// formData.append(\"name\", \"Sarath\");\n// formData.append(\"photo\", { uri: \"file://...\", name: \"a.jpg\", type: \"image/jpeg\" });\n//\n// console.log(formData);          -> ?  (can you read its contents\n// directly like a normal object? what's the right way to inspect it?)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const upload = async (uri) => {\n//       const formData = new FormData();\n//       formData.append(\"photo\", uri);\n//       const res = await fetch(url, {\n//           method: \"POST\",\n//           headers: { \"Content-Type\": \"multipart/form-data\" },\n//           body: formData,\n//       });\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: what shape does \"photo\" need to\n// be, and what's wrong with the manually-set header?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Progress Bar\n//\n// PLAN: which state updates on every onprogress event?\n//\n// Build a component using uploadWithProgress that shows a simple\n// View \"bar\" whose width style is `${percent}%`, updating live as\n// the upload progresses, and a Text showing \"{percent}%\".\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Multi-Field Upload Form\n//\n// PLAN: which fields are text, which is the file?\n//\n// Build a \"Submit Report\" form: a title TextInput, a description\n// TextInput, and an attached photo (PART 1's picker). On submit,\n// build ONE FormData with all three fields and upload it in a\n// single request.\n//\n// Write here:","takeaways":["new FormData() + .append(key, value) -- mixes text fields and files","RN files: { uri, name, type } object, NOT a raw File/Blob","NEVER manually set Content-Type for multipart -- let fetch do it","XMLHttpRequest -- needed only when you want real upload progress %"],"nextHint":"lesson_26_project_auth_app.tsx -- the full Authentication App","milestone":""},{"num":26,"id":"lesson_26_project_auth_app","filename":"lesson_26_project_auth_app.tsx","title":"Project: A Complete Authentication App","subtitle":"same rule as lesson 13 -- no new concepts. Lessons 18, 21-25 combine into one real, working auth flow. Rebuild it yourself from the QUESTIONS, don't just copy it.","section":"Backend Integration","color":"green","mainCode":"// ================================================================\n//   LESSON 26 -- Project: A Complete Authentication App\n//   Teaching philosophy: same rule as lesson 13 -- no new concepts.\n//                        Lessons 18, 21-25 combine into one real,\n//                        working auth flow. Rebuild it yourself\n//                        from the QUESTIONS, don't just copy it.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- What We're Building\n// ================================================================\n//\n//   Screens: Login, Register, Home (protected), Profile (protected,\n//   with a photo upload). Behavior:\n//   - app remembers login across restarts (SecureStore, lesson 23)\n//   - access token auto-refreshes on expiry (lesson 24)\n//   - logged-out users can never reach Home/Profile\n//   - AuthContext (lesson 18) is the single source of truth for\n//     \"who is logged in right now,\" read by any screen that needs it\n//\n//   Concepts combined: Context API (18), REST client (21), JWT (22),\n//   login/register forms (23), refresh tokens (24), file upload (25),\n//   navigation (08), useEffect (09)\n\n\n// ================================================================\n// PART 1 -- AuthContext: The Center of the Whole App\n// ================================================================\n//\n//   TRACE: how every other screen relates to this file\n//   Step 1: AuthProvider wraps the entire app (in app/_layout.tsx,\n//           lesson 08 PART 5)\n//   Step 2: on mount, it checks SecureStore for saved tokens\n//   Step 3: it exposes { user, login, register, logout, isLoading }\n//   Step 4: EVERY screen reads from this via useAuth() -- no prop\n//           drilling, no separate fetch logic duplicated per screen\n\nimport React, { createContext, useContext, useState, useEffect, ReactNode } from \"react\";\nimport * as SecureStore from \"expo-secure-store\";\n\ninterface User { id: number; name: string; email: string; }\n\ninterface AuthContextValue {\n    user: User | null;\n    isLoading: boolean;\n    login: (email: string, password: string) => Promise<void>;\n    register: (name: string, email: string, password: string) => Promise<void>;\n    logout: () => Promise<void>;\n}\n\nconst AuthContext = createContext<AuthContextValue | null>(null);\n\nconst BASE_URL = \"https://api.example.com\";\n\nconst AuthProvider = ({ children }: { children: ReactNode }) => {\n    const [user, setUser] = useState<User | null>(null);\n    const [isLoading, setIsLoading] = useState(true);\n\n    useEffect(() => {\n        const restoreSession = async () => {\n            const token = await SecureStore.getItemAsync(\"access_token\");\n            if (token) {\n                try {\n                    const res = await fetch(`${BASE_URL}/me`, { headers: { Authorization: `Bearer ${token}` } });\n                    if (res.ok) setUser(await res.json());\n                } catch {\n                    // silently fall through to logged-out state\n                }\n            }\n            setIsLoading(false);\n        };\n        restoreSession();\n    }, []);\n\n    const login = async (email: string, password: string) => {\n        const res = await fetch(`${BASE_URL}/login`, {\n            method: \"POST\",\n            headers: { \"Content-Type\": \"application/json\" },\n            body: JSON.stringify({ email, password }),\n        });\n        if (!res.ok) throw new Error(\"Invalid email or password\");\n        const data = await res.json();\n        await SecureStore.setItemAsync(\"access_token\", data.accessToken);\n        await SecureStore.setItemAsync(\"refresh_token\", data.refreshToken);\n        setUser(data.user);\n    };\n\n    const register = async (name: string, email: string, password: string) => {\n        const res = await fetch(`${BASE_URL}/register`, {\n            method: \"POST\",\n            headers: { \"Content-Type\": \"application/json\" },\n            body: JSON.stringify({ name, email, password }),\n        });\n        if (!res.ok) throw new Error(\"Registration failed\");\n        await login(email, password);   // log in right after registering\n    };\n\n    const logout = async () => {\n        await SecureStore.deleteItemAsync(\"access_token\");\n        await SecureStore.deleteItemAsync(\"refresh_token\");\n        setUser(null);\n    };\n\n    return (\n        <AuthContext.Provider value={{ user, isLoading, login, register, logout }}>\n            {children}\n        </AuthContext.Provider>\n    );\n};\n\nconst useAuth = () => {\n    const ctx = useContext(AuthContext);\n    if (!ctx) throw new Error(\"useAuth must be used inside AuthProvider\");\n    return ctx;\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why does restoreSession call GET /me instead of just trusting\n// that \"a token exists in SecureStore\" means the user is logged in?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Login & Register Screens\n// ================================================================\n\nimport { View, Text, TextInput, Pressable, ActivityIndicator, StyleSheet } from \"react-native\";\n// import { router } from \"expo-router\";\n\nconst LoginScreen = () => {\n    const { login } = useAuth();\n    const [email, setEmail] = useState(\"\");\n    const [password, setPassword] = useState(\"\");\n    const [error, setError] = useState<string | null>(null);\n    const [loading, setLoading] = useState(false);\n\n    const handleLogin = async () => {\n        setLoading(true);\n        setError(null);\n        try {\n            await login(email, password);\n            // router.replace(\"/home\");\n        } catch (err) {\n            setError(err instanceof Error ? err.message : \"Login failed\");\n        } finally {\n            setLoading(false);\n        }\n    };\n\n    return (\n        <View style={styles.container}>\n            <TextInput style={styles.input} placeholder=\"Email\" value={email} onChangeText={setEmail} autoCapitalize=\"none\" />\n            <TextInput style={styles.input} placeholder=\"Password\" value={password} onChangeText={setPassword} secureTextEntry />\n            {error && <Text style={styles.error}>{error}</Text>}\n            <Pressable style={styles.button} onPress={handleLogin}>\n                {loading ? <ActivityIndicator color=\"white\" /> : <Text style={{ color: \"white\" }}>Log In</Text>}\n            </Pressable>\n            {/* <Link href=\"/register\"><Text>Need an account? Register</Text></Link> */}\n        </View>\n    );\n};\n\nconst styles = StyleSheet.create({\n    container: { flex: 1, padding: 20, justifyContent: \"center\", gap: 10 },\n    input: { borderWidth: 1, borderColor: \"#ccc\", borderRadius: 6, padding: 12 },\n    button: { backgroundColor: \"#3478f6\", padding: 14, borderRadius: 8, alignItems: \"center\" },\n    error: { color: \"red\" },\n});\n\n\n// ================================================================\n// PART 3 -- A Route Guard (Protecting Home/Profile)\n// ================================================================\n//\n//   TRACE: a user tries to open /home without being logged in\n//   Step 1: HomeScreen renders inside a <RequireAuth> wrapper\n//   Step 2: RequireAuth reads { user, isLoading } from useAuth()\n//   Step 3: while isLoading -- show a spinner (don't redirect yet,\n//           we don't know the answer until the SecureStore check\n//           from PART 1 finishes)\n//   Step 4: if NOT loading and user is null -- redirect to /login\n//   Step 5: if NOT loading and user exists -- render the real children\n\nconst RequireAuth = ({ children }: { children: ReactNode }) => {\n    const { user, isLoading } = useAuth();\n\n    if (isLoading) return <ActivityIndicator style={{ flex: 1 }} />;\n    if (!user) {\n        // router.replace(\"/login\");\n        return null;\n    }\n    return <>{children}</>;\n};\n\n\n// ================================================================\n// PART 4 -- Profile Screen With Photo Upload (Lesson 25)\n// ================================================================\n\nconst ProfileScreen = () => {\n    const { user, logout } = useAuth();\n\n    return (\n        <RequireAuth>\n            <View style={{ padding: 20, gap: 12 }}>\n                <Text>Name: {user?.name}</Text>\n                <Text>Email: {user?.email}</Text>\n                {/* PhotoUploadScreen from lesson 25 would render here */}\n                <Pressable onPress={logout}><Text>Log Out</Text></Pressable>\n            </View>\n        </RequireAuth>\n    );\n};\n\n\n// ================================================================\n// PART 5 -- Wiring the Root Layout\n// ================================================================\n//\n//   ---- app/_layout.tsx ----\n//\n//   import { Stack } from \"expo-router\";\n//   // import { AuthProvider } from \"../context/AuthContext\";\n//\n//   export default function RootLayout() {\n//       return (\n//           <AuthProvider>\n//               <Stack />\n//           </AuthProvider>\n//       );\n//   }\n//\n//   Because AuthProvider wraps <Stack />, EVERY screen in the app,\n//   no matter how deeply routed, can call useAuth().","questionsCode":"// ================================================================\n// [QUESTIONS] -- Rebuild this from scratch, in a real project.\n// ================================================================\n\n// QUESTION 1 -- Trace the Cold-Start Flow\n//\n// Without re-reading PART 1-3, describe what happens, in order,\n// from the moment the app process starts to the moment a\n// PREVIOUSLY logged-in user sees the Home screen.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Add Refresh-Token Logic\n//\n// PLAN: where does lesson 24's requestWithRefresh plug into this?\n//\n// Modify the \"/me\" call inside restoreSession (and any future\n// protected calls) to use lesson 24's requestWithRefresh pattern,\n// so an expired (but refreshable) access token doesn't log the\n// user out unnecessarily.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Add Field Validation to Register\n//\n// PLAN: which checks happen BEFORE calling the API at all?\n//\n// Build the RegisterScreen (referenced but not shown in PART 5)\n// with name/email/password/confirmPassword fields, validating all\n// of them client-side (lesson 23's approach) before calling register().\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build It for Real\n//\n// Set up a real Expo Router project with app/_layout.tsx,\n// app/login.tsx, app/register.tsx, app/home.tsx, app/profile.tsx.\n// Wire AuthProvider, RequireAuth, and all four screens together.\n// You'll need a real or mock backend exposing /login, /register,\n// /me, /refresh -- note what you used and any issues you hit.\n//\n// Write here:","takeaways":["AuthContext = single source of truth for \"who is logged in\"","Always restore + VERIFY session on app start, don't just trust storage","RequireAuth wrapper -- gate protected screens behind { user, isLoading }","AuthProvider wraps the root layout -- every screen can useAuth()"],"nextHint":"lesson_27_asyncstorage_deep_dive.tsx -- Database section begins","milestone":"BACKEND INTEGRATION SECTION COMPLETE."},{"num":27,"id":"lesson_27_asyncstorage_deep_dive","filename":"lesson_27_asyncstorage_deep_dive.tsx","title":"AsyncStorage Deep Dive: Patterns Beyond One Key","subtitle":"lesson 11 taught the basic API. This lesson covers the patterns real apps need once they have MORE than one saved thing.","section":"Database","color":"amber","mainCode":"// ================================================================\n//   LESSON 27 -- AsyncStorage Deep Dive: Patterns Beyond One Key\n//   Teaching philosophy: lesson 11 taught the basic API. This\n//                        lesson covers the patterns real apps need\n//                        once they have MORE than one saved thing.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 11 saved ONE key (\"notes\"). Real apps accumulate many:\n//   settings, drafts, cached lists, onboarding flags, recent\n//   searches. AsyncStorage is a flat key-value store -- like a\n//   single-level Python dict that's always strings -- so you need\n//   DELIBERATE key naming and batching strategies as it grows.\n\n\n// ================================================================\n// PART 1 -- Namespacing Keys (Avoiding Collisions)\n// ================================================================\n//\n//   Python analogy: instead of a flat dict with keys like \"name\",\n//   \"title\", \"id\" that might collide between different features,\n//   you'd nest them: settings[\"theme\"], cache[\"posts\"]. AsyncStorage\n//   has no nesting, so the CONVENTION is to prefix keys by feature.\n//\n//   \"settings:theme\"\n//   \"settings:notifications\"\n//   \"cache:posts\"\n//   \"draft:new_post\"\n\nimport AsyncStorage from \"@react-native-async-storage/async-storage\";\n\nconst KEYS = {\n    THEME: \"settings:theme\",\n    NOTIFICATIONS: \"settings:notifications\",\n    POSTS_CACHE: \"cache:posts\",\n} as const;\n\n// ── PREDICT before running ──────────────────────────────────────\n// If TWO different features both used the plain key \"data\" without\n// any prefix, what would happen when both try to save to it?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- multiGet / multiSet (Batch Operations)\n// ================================================================\n//\n//   Calling getItem 5 times in a row works, but each call is a\n//   separate trip to the native storage layer. multiGet/multiSet\n//   batch several keys into ONE call -- faster, especially on\n//   app startup when you're restoring multiple settings at once.\n//\n//   TRACE: loading all settings at once\n//   Step 1: AsyncStorage.multiGet([key1, key2, key3])\n//   Step 2: returns an ARRAY of [key, value] pairs, in the SAME\n//           order you asked for them\n//   Step 3: you destructure/map over it to rebuild a settings object\n\nconst loadAllSettings = async () => {\n    const pairs = await AsyncStorage.multiGet([KEYS.THEME, KEYS.NOTIFICATIONS]);\n    const settings: Record<string, string | null> = {};\n    pairs.forEach(([key, value]) => { settings[key] = value; });\n    return settings;\n};\n\nconst saveAllSettings = async (theme: string, notifications: boolean) => {\n    await AsyncStorage.multiSet([\n        [KEYS.THEME, theme],\n        [KEYS.NOTIFICATIONS, JSON.stringify(notifications)],\n    ]);\n};\n\n\n// ================================================================\n// PART 3 -- getAllKeys (Discovering What's Stored)\n// ================================================================\n//\n//   Useful for debugging, or building a \"clear cache but keep\n//   settings\" feature -- you need to know WHAT keys exist before\n//   deciding what to remove.\n\nconst clearAllCaches = async () => {\n    const allKeys = await AsyncStorage.getAllKeys();\n    const cacheKeys = allKeys.filter((key) => key.startsWith(\"cache:\"));\n    await AsyncStorage.multiRemove(cacheKeys);\n};\n\n\n// ================================================================\n// PART 4 -- Caching API Responses With an Expiry Timestamp\n// ================================================================\n//\n//   Combines lesson 10 (fetch) with AsyncStorage to avoid\n//   re-fetching the SAME data every time a screen opens, while\n//   still refreshing it periodically.\n//\n//   TRACE: cache-or-fetch logic\n//   Step 1: check AsyncStorage for a cached entry with a saved timestamp\n//   Step 2: if found AND (now - savedTimestamp) < maxAgeMs, USE the\n//           cached data, skip the network call entirely\n//   Step 3: otherwise, fetch fresh data, save it WITH a new timestamp\n\ninterface CacheEntry<T> { data: T; savedAt: number; }\n\nasync function getCachedOrFetch<T>(key: string, maxAgeMs: number, fetchFn: () => Promise<T>): Promise<T> {\n    const raw = await AsyncStorage.getItem(key);\n    if (raw) {\n        const cached: CacheEntry<T> = JSON.parse(raw);\n        if (Date.now() - cached.savedAt < maxAgeMs) {\n            return cached.data;   // still fresh -- skip the network\n        }\n    }\n    const fresh = await fetchFn();\n    const entry: CacheEntry<T> = { data: fresh, savedAt: Date.now() };\n    await AsyncStorage.setItem(key, JSON.stringify(entry));\n    return fresh;\n}\n\n// Usage:\n// const posts = await getCachedOrFetch(KEYS.POSTS_CACHE, 5 * 60 * 1000, fetchPosts);\n// -- reuses cached posts if fetched less than 5 minutes ago\n\n\n// ================================================================\n// PART 5 -- Limits of AsyncStorage (Why Lessons 28-29 Exist)\n// ================================================================\n//\n//   AsyncStorage is great for: settings, flags, small cached lists,\n//   tokens-adjacent metadata (not the tokens themselves -- lesson 23).\n//\n//   It struggles with: LARGE datasets, data you need to QUERY\n//   (e.g. \"all orders over ₹500, sorted by date\" -- AsyncStorage\n//   has no query language, you'd load everything and filter in JS),\n//   or data that needs to sync across devices in real time.\n//\n//   Those needs are exactly what SQLite (lesson 28) and Firestore\n//   (lesson 29) solve.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Namespace keys. Batch reads/writes. Cache with expiry.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// await AsyncStorage.multiSet([[\"a\", \"1\"], [\"b\", \"2\"]]);\n// const result = await AsyncStorage.multiGet([\"a\", \"b\", \"c\"]);\n// console.log(result);            -> ?  (what does the entry for\n// \"c\" look like, given it was never set?)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const clearCache = async () => {\n//       const keys = AsyncStorage.getAllKeys();\n//       const cacheKeys = keys.filter((k) => k.startsWith(\"cache\"));\n//       AsyncStorage.multiRemove(cacheKeys);\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Recent Searches Feature\n//\n// PLAN: how many recent searches should be kept -- and in what order?\n//\n// Build addRecentSearch(term: string) that prepends a new search\n// term to a \"search:recent\" array (most recent first), keeping\n// only the last 10, persisted via AsyncStorage. Build\n// getRecentSearches() to read it back.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Cache-Aware Product List\n//\n// PLAN: how stale is \"too stale\" for a product catalog?\n//\n// Using getCachedOrFetch, build a ProductListScreen that loads\n// products via a 10-minute cache, showing a small \"Updated Xs ago\"\n// Text computed from the cache entry's savedAt timestamp.\n//\n// Write here:","takeaways":["Namespace keys by feature: \"feature:key\" -- avoids collisions","multiGet/multiSet/multiRemove -- batch operations, fewer round trips","getAllKeys() -- discover what's stored, useful for selective clearing","Cache pattern: store {data, savedAt}, compare Date.now() - savedAt","AsyncStorage doesn't scale to querying large/relational data"],"nextHint":"lesson_28_sqlite.tsx -- a real embedded database on-device","milestone":""},{"num":28,"id":"lesson_28_sqlite","filename":"lesson_28_sqlite.tsx","title":"SQLite: A Real Database, On the Device","subtitle":"this is SQL, the exact same language family as any relational DB you've touched from Django -- just running locally on the phone.","section":"Database","color":"amber","mainCode":"// ================================================================\n//   LESSON 28 -- SQLite: A Real Database, On the Device\n//   Teaching philosophy: this is SQL, the exact same language\n//                        family as any relational DB you've touched\n//                        from Django -- just running locally on the phone.\n// ================================================================\n//   Before starting: npx expo install expo-sqlite\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 27 showed AsyncStorage's limit: no querying. SQLite is a\n//   full relational database that ships INSIDE your app -- no\n//   server, no network, but with real SQL: WHERE, ORDER BY, JOIN,\n//   indexes. If you've used Django's ORM or raw SQL before, the\n//   query language here is the SAME -- only the connection setup\n//   is React-Native-specific.\n//\n//   Use SQLite when: data is structured (rows/columns), you need\n//   to QUERY/filter/sort it, or the dataset is too big to comfortably\n//   hold in memory as one big JS array.\n\n\n// ================================================================\n// PART 1 -- Opening a Database and Creating a Table\n// ================================================================\n//\n//   TRACE: setting up storage for a todo list\n//   Step 1: openDatabaseSync(\"app.db\") -- creates the file if it\n//           doesn't exist yet, opens a connection to it\n//   Step 2: execSync runs a CREATE TABLE statement -- \"IF NOT EXISTS\"\n//           means this is safe to run every app launch without\n//           wiping existing data\n//   Step 3: the table now persists across app restarts, just like\n//           a real database table would\n\nimport { useState, useEffect } from \"react\";\nimport * as SQLite from \"expo-sqlite\";\n\nconst db = SQLite.openDatabaseSync(\"app.db\");\n\nconst setupDatabase = () => {\n    db.execSync(`\n        CREATE TABLE IF NOT EXISTS todos (\n            id INTEGER PRIMARY KEY AUTOINCREMENT,\n            title TEXT NOT NULL,\n            done INTEGER NOT NULL DEFAULT 0\n        );\n    `);\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why does \"done\" use INTEGER (0 or 1) instead of a BOOLEAN type?\n// (Hint: think about SQLite's actual supported column types.)  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Inserting and Querying Rows\n// ================================================================\n//\n//   TRACE: runSync vs getAllSync\n//   Step 1: runSync -- for INSERT/UPDATE/DELETE, statements that\n//           change data but don't return rows\n//   Step 2: getAllSync -- for SELECT, statements that return rows\n//           back, as an array of plain objects\n//   Step 3: the \"?\" placeholders prevent SQL injection -- NEVER\n//           build SQL strings by directly inserting user input\n\ninterface Todo { id: number; title: string; done: number; }\n\nconst addTodo = (title: string) => {\n    db.runSync(\"INSERT INTO todos (title, done) VALUES (?, ?);\", [title, 0]);\n};\n\nconst getAllTodos = (): Todo[] => {\n    return db.getAllSync<Todo>(\"SELECT * FROM todos ORDER BY id DESC;\");\n};\n\nconst toggleTodo = (id: number, done: boolean) => {\n    db.runSync(\"UPDATE todos SET done = ? WHERE id = ?;\", [done ? 1 : 0, id]);\n};\n\nconst deleteTodo = (id: number) => {\n    db.runSync(\"DELETE FROM todos WHERE id = ?;\", [id]);\n};\n//\n//   \"?\" placeholders -- TRACE: why this matters\n//   Step 1: WRONG: `INSERT INTO todos (title) VALUES ('${title}')`\n//   Step 2: if title contained `'); DROP TABLE todos; --`, that\n//           string would be executed AS SQL, not stored as data\n//   Step 3: placeholders (?) + a separate values array tell SQLite\n//           \"treat this strictly as DATA, never as code\"\n\n\n// ================================================================\n// PART 3 -- A Todo Screen Backed by SQLite\n// ================================================================\n\nimport { View, Text, TextInput, Pressable, FlatList } from \"react-native\";\n\nconst TodoScreen = () => {\n    const [todos, setTodos] = useState<Todo[]>([]);\n    const [title, setTitle] = useState(\"\");\n\n    const refresh = () => setTodos(getAllTodos());\n\n    useEffect(() => {\n        setupDatabase();\n        refresh();\n    }, []);\n\n    const handleAdd = () => {\n        if (title.trim() === \"\") return;\n        addTodo(title.trim());\n        setTitle(\"\");\n        refresh();        // re-query after every write -- keeps UI in sync\n    };\n\n    return (\n        <View style={{ padding: 16, gap: 8 }}>\n            <TextInput value={title} onChangeText={setTitle} placeholder=\"New todo\" style={{ borderWidth: 1, padding: 8 }} />\n            <Pressable onPress={handleAdd}><Text>Add</Text></Pressable>\n            <FlatList\n                data={todos}\n                keyExtractor={(item) => item.id.toString()}\n                renderItem={({ item }) => (\n                    <Pressable onPress={() => { toggleTodo(item.id, !item.done); refresh(); }}>\n                        <Text style={{ textDecorationLine: item.done ? \"line-through\" : \"none\" }}>\n                            {item.title}\n                        </Text>\n                    </Pressable>\n                )}\n            />\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Filtering and Sorting With Real SQL\n// ================================================================\n//\n//   This is exactly what AsyncStorage (lesson 27) couldn't do\n//   efficiently -- a real WHERE clause, evaluated by the database\n//   engine itself, not by looping through a JS array.\n\nconst getPendingTodos = (): Todo[] => {\n    return db.getAllSync<Todo>(\"SELECT * FROM todos WHERE done = 0 ORDER BY id DESC;\");\n};\n\nconst searchTodos = (term: string): Todo[] => {\n    return db.getAllSync<Todo>(\"SELECT * FROM todos WHERE title LIKE ?;\", [`%${term}%`]);\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- Real SQL, on-device. Always use ? placeholders.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// db.runSync(\"INSERT INTO todos (title, done) VALUES (?, ?);\", [\"Buy milk\", 0]);\n// db.runSync(\"INSERT INTO todos (title, done) VALUES (?, ?);\", [\"Walk dog\", 1]);\n// const result = db.getAllSync(\"SELECT * FROM todos WHERE done = 1;\");\n//\n// How many rows does \"result\" contain, and what's the title?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the security bug)\n//\n//   const addComment = (text: string) => {\n//       db.runSync(`INSERT INTO comments (text) VALUES ('${text}');`);\n//   };\n//\n// Bug -> ?  (what specific attack does this enable, and what's the fix?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build an Expense Tracker Table\n//\n// PLAN: what columns does one expense need?\n//\n// Create a table \"expenses\" with id, title (TEXT), amount (REAL),\n// category (TEXT), created_at (TEXT, store as an ISO date string).\n// Write addExpense, getExpensesByCategory(category), and\n// getTotalSpent() (using SQL's SUM aggregate function).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Searchable Notes Screen\n//\n// PLAN: which lesson's UI pattern does this reuse -- 07's filtering,\n// or a real SQL WHERE clause this time?\n//\n// Build a \"notes\" table (id, title, body) and a screen with a\n// search TextInput that calls a SQL LIKE query (PART 4's pattern)\n// on every keystroke, rendering matching notes with FlatList.\n//\n// Write here:","takeaways":["openDatabaseSync(name) -- opens/creates a local .db file","execSync -- run setup SQL (CREATE TABLE) | runSync -- INSERT/UPDATE/DELETE","getAllSync<T>(sql, params) -- SELECT, returns typed rows","ALWAYS use ? placeholders -- never interpolate raw strings into SQL"],"nextHint":"lesson_29_firestore.tsx -- a cloud database that syncs in real time","milestone":""},{"num":29,"id":"lesson_29_firestore","filename":"lesson_29_firestore.tsx","title":"Firebase Firestore: A Cloud Database That Syncs","subtitle":"SQLite (lesson 28) lives ONLY on one device. Firestore lives in the cloud -- every device sees the SAME data, live.","section":"Database","color":"amber","mainCode":"// ================================================================\n//   LESSON 29 -- Firebase Firestore: A Cloud Database That Syncs\n//   Teaching philosophy: SQLite (lesson 28) lives ONLY on one\n//                        device. Firestore lives in the cloud --\n//                        every device sees the SAME data, live.\n// ================================================================\n//   Before starting: npx expo install firebase\n//   (and create a free Firebase project at the Firebase console)\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   SQLite answers \"store structured data on THIS device.\" But a\n//   chat app, a shared todo list, or any \"multiple people see the\n//   same data\" feature needs a database that lives SOMEWHERE\n//   central, reachable from every device. Firestore is Google's\n//   managed cloud database, built specifically around two ideas:\n//\n//   1. Documents, not rows -- closer to a Python dict/JSON object\n//      than a SQL table row. No fixed schema required.\n//   2. Real-time listeners -- you don't have to manually re-fetch;\n//      Firestore PUSHES updates to your app the instant the data\n//      changes anywhere, on anyone's device.\n//\n//   Structure: Collections contain Documents. Documents can contain\n//   Sub-collections. Roughly: collection ≈ a table's worth of\n//   records, document ≈ one record (as a flexible dict).\n\n\n// ================================================================\n// PART 1 -- Connecting to Firestore\n// ================================================================\n\nimport { initializeApp } from \"firebase/app\";\nimport {\n    getFirestore, collection, addDoc, getDocs,\n    onSnapshot, query, orderBy, doc, updateDoc, deleteDoc,\n} from \"firebase/firestore\";\n\nconst firebaseConfig = {\n    apiKey: \"YOUR_API_KEY\",\n    projectId: \"your-project-id\",\n    // ...rest of your config, from the Firebase console\n};\n\nconst app = initializeApp(firebaseConfig);\nconst dbFirestore = getFirestore(app);\n\n// ── PREDICT before running ──────────────────────────────────────\n// Unlike SQLite's table with fixed columns (lesson 28), a Firestore\n// document has NO required schema. What's one upside, and one\n// risk, of that flexibility?                                  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Writing and Reading Documents\n// ================================================================\n//\n//   TRACE: adding a document\n//   Step 1: collection(dbFirestore, \"posts\") -- a reference to the\n//           \"posts\" collection (created automatically on first write)\n//   Step 2: addDoc(collectionRef, data) -- Firestore generates a\n//           unique document id for you automatically\n//   Step 3: getDocs(collectionRef) -- a ONE-TIME read, returns a\n//           snapshot of documents AT THIS MOMENT (not live-updating)\n\ninterface Post { title: string; body: string; createdAt: number; }\n\nconst addPost = async (title: string, body: string) => {\n    await addDoc(collection(dbFirestore, \"posts\"), {\n        title, body, createdAt: Date.now(),\n    });\n};\n\nconst fetchPostsOnce = async (): Promise<(Post & { id: string })[]> => {\n    const snapshot = await getDocs(collection(dbFirestore, \"posts\"));\n    return snapshot.docs.map((d) => ({ id: d.id, ...(d.data() as Post) }));\n};\n\n\n// ================================================================\n// PART 3 -- onSnapshot: Real-Time Listening (The Big Difference)\n// ================================================================\n//\n//   This is the feature SQLite/AsyncStorage simply can't offer --\n//   live updates pushed from the server, with no polling/refetching.\n//\n//   TRACE: subscribing to live updates\n//   Step 1: onSnapshot(query, callback) -- callback fires IMMEDIATELY\n//           with current data, AND again every time it changes\n//   Step 2: this returns an UNSUBSCRIBE function -- exactly the\n//           cleanup pattern from lesson 09's useEffect\n//   Step 3: if ANY user, on ANY device, adds a post, your callback\n//           fires again automatically -- no manual refresh needed\n\nimport { useState, useEffect } from \"react\";\nimport { View, Text, FlatList, TextInput, Pressable } from \"react-native\";\n\nconst LivePostList = () => {\n    const [posts, setPosts] = useState<(Post & { id: string })[]>([]);\n\n    useEffect(() => {\n        const postsQuery = query(collection(dbFirestore, \"posts\"), orderBy(\"createdAt\", \"desc\"));\n        const unsubscribe = onSnapshot(postsQuery, (snapshot) => {\n            const data = snapshot.docs.map((d) => ({ id: d.id, ...(d.data() as Post) }));\n            setPosts(data);\n        });\n        return unsubscribe;   // lesson 09's cleanup pattern, exactly\n    }, []);\n\n    return (\n        <FlatList\n            data={posts}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => <Text>{item.title}</Text>}\n        />\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Updating and Deleting a Specific Document\n// ================================================================\n//\n//   doc(dbFirestore, \"posts\", postId) -- a reference to ONE\n//   specific document, by its id (similar to SQLite's WHERE id = ?)\n\nconst editPost = async (postId: string, newTitle: string) => {\n    await updateDoc(doc(dbFirestore, \"posts\", postId), { title: newTitle });\n};\n\nconst removePost = async (postId: string) => {\n    await deleteDoc(doc(dbFirestore, \"posts\", postId));\n};\n\n\n// ================================================================\n// PART 5 -- SQLite vs Firestore: When to Reach for Which\n// ================================================================\n//\n//   SQLite   -- single device, offline-first, complex relational\n//               queries, no ongoing cost, data nobody else needs to see\n//   Firestore -- multi-device sync, real-time collaboration (chat,\n//               shared lists, live dashboards), needs internet,\n//               usage-based pricing past a free tier\n//\n//   Many real apps use BOTH: Firestore for shared/live data, SQLite\n//   or AsyncStorage for purely local caches/preferences.","questionsCode":"// ================================================================\n// [QUESTIONS] -- onSnapshot pushes updates. getDocs is a one-time read.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// Two phones both have LivePostList open. Phone A calls addPost(...).\n//\n// Does Phone B's screen update automatically, and roughly how\n// quickly, assuming both have internet?                       -> ?\n// What would happen on Phone B if it had used fetchPostsOnce()\n// inside a useEffect(fn, []) instead of onSnapshot?            -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   useEffect(() => {\n//       onSnapshot(collection(dbFirestore, \"posts\"), (snapshot) => {\n//           setPosts(snapshot.docs.map((d) => d.data()));\n//       });\n//   }, []);\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: what's missing from the return,\n// and what's missing from each mapped post object compared to PART 2/3)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Live Comment Feed\n//\n// PLAN: which field determines the display order?\n//\n// Build a \"comments\" collection with { text, author, createdAt }.\n// Build a screen with a TextInput + Pressable to add a comment,\n// and a live FlatList (onSnapshot, ordered newest-first) showing\n// \"{author}: {text}\" for each.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build an Edit/Delete UI\n//\n// PLAN: which document id does each row need to remember?\n//\n// Extend the comment feed: long-pressing a comment shows a delete\n// confirmation (Alert) calling removePost-style logic for that\n// specific document id; tapping it opens an inline edit TextInput\n// calling updateDoc with the new text.\n//\n// Write here:","takeaways":["Collections contain Documents -- flexible, schema-less records","addDoc -- create | getDocs -- one-time read | onSnapshot -- live updates","onSnapshot returns an unsubscribe function -- ALWAYS return it from useEffect","doc(db, collection, id) -- reference ONE document for update/delete"],"nextHint":"lesson_30_mongodb_atlas.tsx -- a cloud database reached via your own backend","milestone":""},{"num":30,"id":"lesson_30_mongodb_atlas","filename":"lesson_30_mongodb_atlas.tsx","title":"MongoDB Atlas: A Cloud Database Behind Your Own Backend","subtitle":"this lesson is as much about ARCHITECTURE as about MongoDB itself -- understanding WHERE the database boundary should sit.","section":"Database","color":"amber","mainCode":"// ================================================================\n//   LESSON 30 -- MongoDB Atlas: A Cloud Database Behind Your Own Backend\n//   Teaching philosophy: this lesson is as much about ARCHITECTURE\n//                        as about MongoDB itself -- understanding\n//                        WHERE the database boundary should sit.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Firestore (lesson 29) is DESIGNED to be talked to directly from\n//   a phone app -- Google built client SDKs and security rules for\n//   exactly that. MongoDB Atlas is different: it's normally meant\n//   to be accessed from a SERVER (your Node.js/Django backend, which\n//   you already know), NOT directly from a phone app.\n//\n//   Why does this matter? If your React Native app held MongoDB\n//   connection credentials directly, ANYONE could extract them from\n//   the app bundle and connect to your ENTIRE database with full\n//   access. A backend sits in between, controlling exactly what the\n//   app is allowed to read/write -- this is the architecture\n//   pattern lessons 21-26 already built (apiClient + JWT auth).\n//\n//   Phone App  --(REST API + JWT)-->  Your Backend  -->  MongoDB Atlas\n//\n//   (Atlas does offer a \"Data API\" for direct HTTPS access without\n//   a custom backend -- mentioned in PART 4 -- but for anything\n//   beyond a prototype, the backend-in-the-middle pattern is the\n//   one used in production apps.)\n\n\n// ================================================================\n// PART 1 -- The Backend Side (Context, Not RN Code)\n// ================================================================\n//\n//   On your Node.js/Express backend (outside this RN project),\n//   you'd connect to Atlas roughly like this:\n//\n//   // backend/db.js (Node.js, NOT React Native)\n//   const { MongoClient } = require(\"mongodb\");\n//   const client = new MongoClient(process.env.MONGODB_URI);\n//   await client.connect();\n//   const db = client.db(\"myAppDb\");\n//   const products = db.collection(\"products\");\n//\n//   // backend/routes/products.js\n//   app.get(\"/products\", authenticate, async (req, res) => {\n//       const all = await products.find({}).toArray();\n//       res.json(all);\n//   });\n//\n//   The RN app NEVER sees process.env.MONGODB_URI -- it only ever\n//   talks to YOUR backend's /products endpoint.\n\n\n// ================================================================\n// PART 2 -- The React Native Side: Just Another REST Endpoint\n// ================================================================\n//\n//   From the app's perspective, this is IDENTICAL to everything in\n//   lesson 21 -- it has no idea MongoDB is involved at all. That's\n//   the whole point of the backend boundary: the app only knows\n//   \"REST API,\" never \"which database.\"\n\ninterface Product { _id: string; name: string; price: number; }\n\nconst fetchProducts = async (token: string): Promise<Product[]> => {\n    const response = await fetch(\"https://your-backend.com/products\", {\n        headers: { Authorization: `Bearer ${token}` },\n    });\n    if (!response.ok) throw new Error(\"Failed to load products\");\n    return response.json();\n};\n\nconst createProduct = async (name: string, price: number, token: string) => {\n    const response = await fetch(\"https://your-backend.com/products\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\", Authorization: `Bearer ${token}` },\n        body: JSON.stringify({ name, price }),\n    });\n    return response.json();\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If your backend's /products route forgot the \"authenticate\"\n// middleware from PART 1, what could go wrong, given the app's\n// fetchProducts function still sends a token regardless?      -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 3 -- MongoDB's Query Style vs SQLite's (Conceptual Comparison)\n// ================================================================\n//\n//   SQLite (lesson 28):  SELECT * FROM products WHERE price > 100;\n//   MongoDB (backend):    products.find({ price: { $gt: 100 } })\n//\n//   Both express the SAME idea -- \"filter by a condition\" -- with\n//   different syntax. MongoDB documents are JSON-like (no fixed\n//   columns, similar flexibility to Firestore's documents), while\n//   SQLite is strictly tabular. This is backend knowledge, but\n//   understanding it helps you design the RIGHT REST endpoints for\n//   your app to call (e.g. /products?minPrice=100).\n\n\n// ================================================================\n// PART 4 -- The Atlas Data API (A Direct-Access Alternative)\n// ================================================================\n//\n//   For learning/prototyping ONLY, MongoDB offers a \"Data API\" --\n//   HTTPS endpoints you CAN call directly from the app, no custom\n//   backend needed. It still requires an API key, which carries the\n//   SAME risk as embedding any secret in a phone app -- treat this\n//   as a prototyping shortcut, not a production pattern.\n//\n//   const response = await fetch(\"https://data.mongodb-api.com/app/.../action/find\", {\n//       method: \"POST\",\n//       headers: { \"api-key\": \"YOUR_DATA_API_KEY\", \"Content-Type\": \"application/json\" },\n//       body: JSON.stringify({ dataSource: \"Cluster0\", database: \"myAppDb\", collection: \"products\" }),\n//   });","questionsCode":"// ================================================================\n// [QUESTIONS] -- The backend is the real database boundary, not the app.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// If a backend endpoint /products has NO authentication check at\n// all, and your MongoDB connection string is ONLY ever stored on\n// the backend server (never in the app)...\n//\n// Can an attacker who decompiles your RN app extract the MongoDB\n// credentials directly from it?                               -> ?\n// Can they still cause damage another way? How?               -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the architecture mistake)\n//\n//   // Inside a React Native component:\n//   const client = new MongoClient(\"mongodb+srv://user:pass@cluster...\");\n//   await client.connect();\n//   const data = await client.db(\"app\").collection(\"products\").find().toArray();\n//\n// Bug -> ?  (this is a CONCEPTUAL bug about WHERE this code should\n// even live, not a syntax bug)\n// Fixed approach:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Design the Endpoints\n//\n// PLAN: which HTTP method (lesson 21) fits each action?\n//\n// You're building a backend-and-app pair for a bookmarking app\n// storing bookmarks in MongoDB Atlas. List the REST endpoints\n// (method + path) the backend should expose for: listing a user's\n// bookmarks, adding one, deleting one, and updating its title.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build the App Side\n//\n// PLAN: which lesson's apiClient pattern can you reuse directly?\n//\n// Using the endpoints you designed in QUESTION 3, write the RN\n// fetch functions (reuse lesson 21's apiClient helper) for all\n// four operations, plus a BookmarksScreen using FlatList to display\n// them.\n//\n// Write here:","takeaways":["MongoDB Atlas is normally reached THROUGH a backend, not directly","The app talks REST + JWT (lessons 21-22) -- it never sees DB credentials","The backend, not the phone, is where database security actually lives","Atlas Data API exists for prototyping, with the same secret-exposure risk"],"nextHint":"lesson_31_websockets.tsx -- Real-Time Features begin","milestone":"DATABASE SECTION COMPLETE."},{"num":31,"id":"lesson_31_websockets","filename":"lesson_31_websockets.tsx","title":"WebSockets: A Connection That Stays Open","subtitle":"every API call so far has been a single question-and-answer. WebSockets are a standing phone line, open in both directions.","section":"Real-Time","color":"cyan","mainCode":"// ================================================================\n//   LESSON 31 -- WebSockets: A Connection That Stays Open\n//   Teaching philosophy: every API call so far has been a single\n//                        question-and-answer. WebSockets are a\n//                        standing phone line, open in both directions.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every fetch() so far (lessons 10, 21-26, 29-30) follows the\n//   SAME shape: app asks a question, server answers ONCE, the\n//   connection closes. Great for \"give me the product list\" --\n//   useless for \"tell me the INSTANT a new chat message arrives,\"\n//   because the server has no way to push anything to you\n//   unprompted over plain HTTP.\n//\n//   A WebSocket flips this: the app and server open ONE connection\n//   and keep it alive. EITHER side can send a message at ANY time,\n//   with no new \"request\" needed for each one.\n//\n//   HTTP (fetch):     Question -> Answer -> connection closes\n//   WebSocket:         Connection opens -> stays open -> either\n//                       side sends messages, whenever, until closed\n//\n//   Firestore's onSnapshot (lesson 29) is BUILT on similar real-time\n//   plumbing -- this lesson goes one level lower, to the raw protocol.\n\n\n// ================================================================\n// PART 1 -- Opening a Connection\n// ================================================================\n//\n//   TRACE: the WebSocket lifecycle\n//   Step 1: new WebSocket(url) -- starts connecting (note: \"ws://\"\n//           or \"wss://\" -- the secure version -- NOT \"http://\")\n//   Step 2: onopen fires once the connection is established\n//   Step 3: onmessage fires EVERY time the server sends something\n//   Step 4: onerror / onclose fire if something goes wrong or the\n//           connection ends\n\nimport { useEffect, useRef, useState } from \"react\";\nimport { View, Text, TextInput, Pressable, FlatList } from \"react-native\";\n\nconst useEchoSocket = () => {\n    const [connected, setConnected] = useState(false);\n    const [messages, setMessages] = useState<string[]>([]);\n    const socketRef = useRef<WebSocket | null>(null);\n\n    useEffect(() => {\n        const socket = new WebSocket(\"wss://echo.websocket.org\");\n        socketRef.current = socket;\n\n        socket.onopen = () => setConnected(true);\n        socket.onmessage = (event) => setMessages((prev) => [...prev, event.data]);\n        socket.onclose = () => setConnected(false);\n        socket.onerror = (err) => console.log(\"Socket error:\", err);\n\n        return () => socket.close();   // lesson 09's cleanup pattern\n    }, []);\n\n    const send = (text: string) => socketRef.current?.send(text);\n\n    return { connected, messages, send };\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you call send() BEFORE onopen has fired (connection still\n// connecting), what do you expect to happen?                  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- A Minimal Chat-Style Screen\n// ================================================================\n\nconst EchoChatScreen = () => {\n    const { connected, messages, send } = useEchoSocket();\n    const [text, setText] = useState(\"\");\n\n    const handleSend = () => {\n        if (text.trim() === \"\") return;\n        send(text);\n        setText(\"\");\n    };\n\n    return (\n        <View style={{ flex: 1, padding: 16 }}>\n            <Text>{connected ? \"Connected\" : \"Connecting...\"}</Text>\n            <FlatList data={messages} renderItem={({ item }) => <Text>{item}</Text>} keyExtractor={(_, i) => i.toString()} />\n            <TextInput value={text} onChangeText={setText} placeholder=\"Type a message\" style={{ borderWidth: 1, padding: 8 }} />\n            <Pressable onPress={handleSend} disabled={!connected}><Text>Send</Text></Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Sending and Receiving Structured Data (JSON)\n// ================================================================\n//\n//   Raw WebSocket messages are just strings -- exactly like fetch's\n//   body (lesson 10/21), JSON.stringify before sending, JSON.parse\n//   after receiving, to work with real objects instead of raw text.\n\ninterface ChatMessage { user: string; text: string; sentAt: number; }\n\nconst sendChatMessage = (socket: WebSocket, user: string, text: string) => {\n    const payload: ChatMessage = { user, text, sentAt: Date.now() };\n    socket.send(JSON.stringify(payload));\n};\n\n// inside onmessage:\n// socket.onmessage = (event) => {\n//     const message: ChatMessage = JSON.parse(event.data);\n//     setMessages((prev) => [...prev, message]);\n// };\n\n\n// ================================================================\n// PART 4 -- Reconnecting When the Connection Drops\n// ================================================================\n//\n//   Mobile networks are unreliable -- tunnels, elevators, weak\n//   signal all close sockets unexpectedly. Production apps almost\n//   always implement reconnect-with-backoff (similar spirit to\n//   lesson 23's QUESTION on retry logic for fetch).\n//\n//   TRACE: a simple reconnect loop\n//   Step 1: onclose fires unexpectedly (not because YOU called close())\n//   Step 2: wait a short delay (e.g. 2 seconds)\n//   Step 3: create a NEW WebSocket to the same url\n//   Step 4: if it closes again, repeat -- often with INCREASING\n//           delay each time (\"exponential backoff\") to avoid\n//           hammering a server that's still recovering","questionsCode":"// ================================================================\n// [QUESTIONS] -- One connection, both directions, until closed.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const socket = new WebSocket(\"wss://example.com\");\n// socket.send(\"hello\");     // called IMMEDIATELY, on the next line\n//\n// Given that connecting takes some time, does the server reliably\n// receive \"hello\"? What's the safer place to put this send call?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   useEffect(() => {\n//       const socket = new WebSocket(url);\n//       socket.onmessage = (e) => setMessages([...messages, e.data]);\n//   }, []);\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: one is about stale state inside\n// a closure, the other is about resource cleanup)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Live Counter\n//\n// PLAN: what message shape does the server send for this to work?\n//\n// Assume a WebSocket server broadcasts { type: \"count\", value:\n// number } every second to all connected clients. Build a screen\n// that connects, parses incoming JSON messages, and displays the\n// current value, updating live with no fetch/polling involved.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Add Reconnection Logic\n//\n// PLAN: how do you avoid an infinite reconnect storm if the server\n// is down for a long time?\n//\n// Extend useEchoSocket so that if onclose fires UNEXPECTEDLY (the\n// component is still mounted), it waits 2 seconds and creates a\n// new WebSocket automatically, up to a max of 5 attempts, doubling\n// the wait each time (2s, 4s, 8s...).\n//\n// Write here:","takeaways":["new WebSocket(url) -- ws:// or wss://, opens a persistent connection","onopen / onmessage / onerror / onclose -- the 4 lifecycle events","socket.send(string) -- JSON.stringify objects before sending","ALWAYS socket.close() in a useEffect cleanup","Real apps add reconnect-with-backoff for dropped connections"],"nextHint":"lesson_32_socketio.tsx -- a higher-level library built on this","milestone":""},{"num":32,"id":"lesson_32_socketio","filename":"lesson_32_socketio.tsx","title":"Socket.io: WebSockets With Convenience Built In","subtitle":"Socket.io solves the rough edges lesson 31 left exposed -- reconnection, named events, rooms -- without you hand-rolling each one.","section":"Real-Time","color":"cyan","mainCode":"// ================================================================\n//   LESSON 32 -- Socket.io: WebSockets With Convenience Built In\n//   Teaching philosophy: Socket.io solves the rough edges lesson 31\n//                        left exposed -- reconnection, named events,\n//                        rooms -- without you hand-rolling each one.\n// ================================================================\n//   Before starting: npx expo install socket.io-client\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 31's raw WebSocket required YOU to: parse every message\n//   manually, reconnect manually, and invent your own \"message\n//   type\" system (since raw sockets only send plain strings/JSON\n//   blobs with no built-in routing). Socket.io is a library\n//   (server AND client side) that adds:\n//\n//   1. NAMED EVENTS -- send/receive specific event types, like\n//      Python's event-driven libraries (think: on(\"new_message\", fn)\n//      instead of manually checking a \"type\" field yourself)\n//   2. Automatic reconnection -- built in, no manual backoff needed\n//   3. Rooms -- group connected clients (e.g. \"chat_room_5\") so a\n//      message only reaches the relevant people, not EVERYONE\n//\n//   IMPORTANT: Socket.io's client can only talk to a Socket.io\n//   SERVER -- it isn't a drop-in replacement for talking to ANY\n//   raw WebSocket server (unlike lesson 31's WebSocket, which is\n//   a universal browser/RN built-in).\n\n\n// ================================================================\n// PART 1 -- Connecting\n// ================================================================\n//\n//   TRACE: io(url)\n//   Step 1: io(url) immediately starts connecting (similar to\n//           lesson 31's `new WebSocket(url)`)\n//   Step 2: socket.on(\"connect\", fn) -- fires once connected\n//           (equivalent to onopen)\n//   Step 3: socket.on(\"disconnect\", fn) -- fires on disconnect\n//           (equivalent to onclose) -- but Socket.io will try to\n//           RECONNECT automatically afterward, by default\n\nimport { useEffect, useRef, useState } from \"react\";\nimport { View, Text, TextInput, Pressable, FlatList } from \"react-native\";\nimport { io, Socket } from \"socket.io-client\";\n\nconst SERVER_URL = \"https://your-backend.com\";\n\nconst useChatSocket = (username: string) => {\n    const socketRef = useRef<Socket | null>(null);\n    const [connected, setConnected] = useState(false);\n    const [messages, setMessages] = useState<{ user: string; text: string }[]>([]);\n\n    useEffect(() => {\n        const socket = io(SERVER_URL);\n        socketRef.current = socket;\n\n        socket.on(\"connect\", () => setConnected(true));\n        socket.on(\"disconnect\", () => setConnected(false));\n\n        // a NAMED event -- only fires for messages the server\n        // specifically tagged as \"new_message\", unlike lesson 31's\n        // generic onmessage that fires for EVERYTHING\n        socket.on(\"new_message\", (msg: { user: string; text: string }) => {\n            setMessages((prev) => [...prev, msg]);\n        });\n\n        return () => { socket.disconnect(); };\n    }, []);\n\n    const sendMessage = (text: string) => {\n        socketRef.current?.emit(\"new_message\", { user: username, text });\n    };\n\n    return { connected, messages, sendMessage };\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Compare socket.on(\"new_message\", fn) here to lesson 31's\n// socket.onmessage. If the server ALSO sends a \"user_typing\" event\n// on the same connection, does your \"new_message\" handler get\n// called for that too?                                        -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- emit and on: The Two Verbs You'll Use Constantly\n// ================================================================\n//\n//   socket.emit(\"eventName\", data)   -- SEND a named event\n//   socket.on(\"eventName\", callback) -- LISTEN for a named event\n//\n//   This pair fully replaces lesson 31's send()/onmessage with a\n//   ROUTER built in -- many event types can share one connection\n//   cleanly, the same way one Express/Django app can have many\n//   different URL routes on one server.\n\n\n// ================================================================\n// PART 3 -- A Chat Screen\n// ================================================================\n\nconst ChatScreen = ({ username }: { username: string }) => {\n    const { connected, messages, sendMessage } = useChatSocket(username);\n    const [text, setText] = useState(\"\");\n\n    const handleSend = () => {\n        if (text.trim() === \"\") return;\n        sendMessage(text);\n        setText(\"\");\n    };\n\n    return (\n        <View style={{ flex: 1, padding: 16 }}>\n            <Text>{connected ? \"Online\" : \"Connecting...\"}</Text>\n            <FlatList\n                data={messages}\n                keyExtractor={(_, i) => i.toString()}\n                renderItem={({ item }) => <Text><Text style={{ fontWeight: \"bold\" }}>{item.user}: </Text>{item.text}</Text>}\n            />\n            <TextInput value={text} onChangeText={setText} placeholder=\"Message\" style={{ borderWidth: 1, padding: 8 }} />\n            <Pressable onPress={handleSend}><Text>Send</Text></Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Rooms: Targeting a Subset of Connected Users\n// ================================================================\n//\n//   Without rooms, EVERY connected client gets EVERY message --\n//   fine for a single global chat, wrong for \"group chat #5\" where\n//   only its members should see messages.\n//\n//   TRACE (server-side concept, shown for context):\n//   Step 1: client emits \"join_room\" with a room id\n//   Step 2: server (Node.js + socket.io) calls socket.join(roomId)\n//   Step 3: server sends future messages with io.to(roomId).emit(...)\n//   Step 4: ONLY clients who joined that specific room receive it\n//\n//   From the RN side, you just emit \"join_room\" once when entering\n//   a specific chat screen:\n//\n//   useEffect(() => {\n//       socketRef.current?.emit(\"join_room\", roomId);\n//   }, [roomId]);\n\n\n// ================================================================\n// PART 5 -- Authenticating a Socket Connection\n// ================================================================\n//\n//   Just like REST requests need a JWT (lesson 22), sockets need a\n//   way to identify the connecting user too -- usually passed at\n//   connection time, not as a header (sockets don't use HTTP headers\n//   the same way after the initial handshake).\n//\n//   const socket = io(SERVER_URL, { auth: { token: accessToken } });\n//\n//   The server reads socket.handshake.auth.token to verify identity\n//   before allowing the connection to proceed.","questionsCode":"// ================================================================\n// [QUESTIONS] -- emit sends, on listens, by NAMED event.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// socket.on(\"new_message\", handlerA);\n// socket.emit(\"join_room\", \"room5\");\n// socket.emit(\"new_message\", { user: \"Sarath\", text: \"hi\" });\n//\n// Does emitting \"new_message\" trigger handlerA on THIS same client,\n// or only on OTHER clients connected to the server?            -> ?\n// (Hint: think about who the SERVER decides to broadcast/echo to.)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const socket = io(SERVER_URL);\n//   socket.send(\"new_message\", { text: \"hi\" });\n//   const ChatScreen = () => {\n//       socket.on(\"new_message\", (msg) => setMessages([...messages, msg]));\n//       return <Text>{messages.length}</Text>;\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?   (hint: wrong method name,\n// where the listener is registered, and stale closure again)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Typing Indicator\n//\n// PLAN: which event fires on keystroke, and which on send?\n//\n// Add a \"user_typing\" emit fired (debounced, lesson 09's pattern)\n// whenever the TextInput's text changes, and a \"user_typing\"\n// listener that shows \"{user} is typing...\" for 2 seconds after\n// receiving it.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build Room-Based Chat\n//\n// PLAN: when should join_room fire -- on mount, or on every render?\n//\n// Build a ChatScreen that takes a roomId prop, emits \"join_room\"\n// once on mount (useEffect, lesson 09), and only displays messages\n// tagged with that same roomId in their payload.\n//\n// Write here:","takeaways":["io(url) -- connects to a Socket.io SERVER specifically","socket.emit(event, data) -- send | socket.on(event, fn) -- listen","Automatic reconnection built in -- no manual backoff needed","Rooms -- target a subset of clients, not a global broadcast","auth: { token } at connection time -- the socket equivalent of a JWT header"],"nextHint":"lesson_33_firebase_realtime_db.tsx -- Google's real-time alternative","milestone":""},{"num":33,"id":"lesson_33_firebase_realtime_db","filename":"lesson_33_firebase_realtime_db.tsx","title":"Firebase Realtime Database","subtitle":"same real-time PROMISE as Firestore (lesson 29) and Socket.io (lesson 32), but a different underlying data SHAPE: one big live-synced JSON tree, not collections/documents.","section":"Real-Time","color":"cyan","mainCode":"// ================================================================\n//   LESSON 33 -- Firebase Realtime Database\n//   Teaching philosophy: same real-time PROMISE as Firestore\n//                        (lesson 29) and Socket.io (lesson 32), but\n//                        a different underlying data SHAPE: one big\n//                        live-synced JSON tree, not collections/documents.\n// ================================================================\n//   Before starting: same `firebase` package as lesson 29\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   You now know THREE different ways to get real-time updates:\n//   - lesson 31/32: raw WebSockets / Socket.io -- YOU run the server\n//   - lesson 29: Firestore -- collections of documents, rich queries\n//   - this lesson: Realtime Database -- ONE giant JSON tree, simpler\n//     queries, often cheaper/simpler for things like live location\n//     or presence (\"who's online right now\")\n//\n//   Python analogy: Realtime Database is like one enormous nested\n//   dict, fully synced live across every connected client -- you\n//   read/write specific PATHS into that tree, like dict[\"a\"][\"b\"][\"c\"].\n\n\n// ================================================================\n// PART 1 -- Connecting and Writing to a Path\n// ================================================================\n//\n//   TRACE: the tree shape for a live location feature\n//   locations/\n//     user_1/ { lat: 12.9, lon: 77.6, updatedAt: 169... }\n//     user_2/ { lat: 13.0, lon: 77.5, updatedAt: 169... }\n//\n//   Each \"ref\" is a path INTO that tree -- set() replaces whatever\n//   is at that path entirely.\n\nimport { initializeApp } from \"firebase/app\";\nimport { getDatabase, ref, set, onValue, off, push, remove } from \"firebase/database\";\n\nconst firebaseConfig = {\n    apiKey: \"YOUR_API_KEY\",\n    databaseURL: \"https://your-project.firebaseio.com\",\n    projectId: \"your-project-id\",\n};\n\nconst app = initializeApp(firebaseConfig);\nconst rtdb = getDatabase(app);\n\nconst updateMyLocation = (userId: string, lat: number, lon: number) => {\n    set(ref(rtdb, `locations/${userId}`), { lat, lon, updatedAt: Date.now() });\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you call set() on \"locations/user_1\" a SECOND time with only\n// { lat: 13.0 }, does \"lon\" from the first write still exist\n// afterward, or is it wiped? (Hint: compare to PATCH vs PUT,\n// lesson 21 PART 1.)                                          -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- onValue: Subscribing to a Live Path\n// ================================================================\n//\n//   TRACE: watching one user's location update live\n//   Step 1: onValue(ref(rtdb, path), callback) -- fires immediately\n//           with the current value, then again on EVERY change to\n//           that exact path\n//   Step 2: snapshot.val() -- pulls the actual data out of the\n//           snapshot object Firebase gives you\n//   Step 3: off(reference) -- the cleanup call, equivalent to\n//           Firestore's unsubscribe function (lesson 29 PART 3) or\n//           a WebSocket's close() (lesson 31 PART 1)\n\nimport { useEffect, useState } from \"react\";\nimport { View, Text } from \"react-native\";\n\ninterface Location { lat: number; lon: number; updatedAt: number; }\n\nconst useLiveLocation = (userId: string) => {\n    const [location, setLocation] = useState<Location | null>(null);\n\n    useEffect(() => {\n        const locationRef = ref(rtdb, `locations/${userId}`);\n        onValue(locationRef, (snapshot) => {\n            setLocation(snapshot.val());\n        });\n        return () => off(locationRef);\n    }, [userId]);\n\n    return location;\n};\n\nconst LiveLocationScreen = ({ userId }: { userId: string }) => {\n    const location = useLiveLocation(userId);\n    if (!location) return <Text>Waiting for location...</Text>;\n    return <Text>Lat: {location.lat}, Lon: {location.lon}</Text>;\n};\n\n\n// ================================================================\n// PART 3 -- push(): Auto-Generated Keys for Lists\n// ================================================================\n//\n//   A \"list\" in Realtime Database is really just an object whose\n//   keys happen to be auto-generated, sortable-by-time ids --\n//   push() generates one for you, similar in spirit to SQLite's\n//   AUTOINCREMENT (lesson 28) or Firestore's auto document ids\n//   (lesson 29).\n\ninterface ChatMessage { user: string; text: string; sentAt: number; }\n\nconst sendMessage = (roomId: string, message: ChatMessage) => {\n    const messagesRef = ref(rtdb, `rooms/${roomId}/messages`);\n    push(messagesRef, message);\n    // resulting tree: rooms/room5/messages/-Nabc123/{user, text, sentAt}\n};\n\nconst removeMessage = (roomId: string, messageKey: string) => {\n    remove(ref(rtdb, `rooms/${roomId}/messages/${messageKey}`));\n};\n\n\n// ================================================================\n// PART 4 -- Presence: \"Who's Online Right Now\"\n// ================================================================\n//\n//   A classic Realtime Database use case, because it pairs well\n//   with onDisconnect() -- the server detects a dropped connection\n//   and AUTOMATICALLY runs a cleanup write, even if the app crashed\n//   and never got a chance to say \"I'm leaving\" itself.\n//\n//   import { onDisconnect } from \"firebase/database\";\n//\n//   const myStatusRef = ref(rtdb, `status/${userId}`);\n//   set(myStatusRef, { online: true });\n//   onDisconnect(myStatusRef).set({ online: false, lastSeen: Date.now() });\n//\n//   TRACE: why onDisconnect matters\n//   Step 1: you set online: true when the app opens\n//   Step 2: you ALSO register what should happen on disconnect,\n//           immediately -- the SERVER remembers this instruction\n//   Step 3: if the app crashes/loses signal with no warning, the\n//           server still runs that cleanup write on your behalf","questionsCode":"// ================================================================\n// [QUESTIONS] -- One JSON tree, paths in, live updates out.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// push(ref(rtdb, \"rooms/room5/messages\"), { user: \"A\", text: \"hi\" });\n// push(ref(rtdb, \"rooms/room5/messages\"), { user: \"B\", text: \"hey\" });\n//\n// Are the two messages stored under the SAME key, or different\n// auto-generated keys? Can you predict the keys in advance?    -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   useEffect(() => {\n//       onValue(ref(rtdb, `locations/${userId}`), (snap) => {\n//           setLocation(snap.val());\n//       });\n//   }, []);\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: missing dependency AND missing cleanup)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Live Group Chat\n//\n// PLAN: which path holds the messages -- by room, or all together?\n//\n// Build a chat screen for a given roomId using push() to send and\n// onValue() to listen at `rooms/${roomId}/messages`. Render\n// messages sorted by sentAt (snapshot.val() returns an object\n// keyed by push-id -- convert it to a sorted array before rendering).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build Online Presence\n//\n// PLAN: when does \"online: true\" get set, and when does the\n// disconnect cleanup get REGISTERED (not just triggered)?\n//\n// Build a hook useOnlineStatus(userId) that sets status/{userId}\n// to online on mount, registers onDisconnect to mark them offline\n// with a lastSeen timestamp, and returns the LIVE online/offline\n// status of a DIFFERENT given userId by subscribing to their path.\n//\n// Write here:","takeaways":["ref(rtdb, \"path/to/data\") -- a reference into ONE big JSON tree","set() replaces a path entirely | push() adds a list item with an auto-generated key","onValue(ref, callback) -- live updates | off(ref) -- unsubscribe","onDisconnect(ref).set(...) -- server-side cleanup on connection loss","REAL-TIME CONCEPTS COMPLETE."],"nextHint":"lesson_34_project_chat_app.tsx -- the full Chat App project","milestone":""},{"num":34,"id":"lesson_34_project_chat_app","filename":"lesson_34_project_chat_app.tsx","title":"Project: A Complete Chat App","subtitle":"same rule as lessons 13/26 -- no new concepts. Auth (18, 22-23), Socket.io (32), and lists (07) combine into one real, working multi-room chat. Rebuild it yourself from the QUESTIONS, don't copy it.","section":"Real-Time","color":"cyan","mainCode":"// ================================================================\n//   LESSON 34 -- Project: A Complete Chat App\n//   Teaching philosophy: same rule as lessons 13/26 -- no new\n//                        concepts. Auth (18, 22-23), Socket.io (32),\n//                        and lists (07) combine into one real,\n//                        working multi-room chat. Rebuild it\n//                        yourself from the QUESTIONS, don't copy it.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- What We're Building\n// ================================================================\n//\n//   Screens: a Room List (pick which chat to join) and a Chat Room\n//   (live messages, join_room/leave_room events). Behavior:\n//   - the logged-in user's name (from AuthContext, lesson 26) is\n//     attached to every message automatically -- no re-typing a name\n//   - joining a NEW room leaves the PREVIOUS one cleanly\n//   - messages persist for the session (server-side, conceptually --\n//     this lesson focuses on the RN side talking to that server)\n//\n//   Concepts combined: AuthContext (18/26), Socket.io (32),\n//   FlatList (07), useEffect cleanup (09), navigation (08)\n\n\n// ================================================================\n// PART 1 -- The Socket Connection, Authenticated\n// ================================================================\n//\n//   TRACE: connecting once, reusing everywhere\n//   Step 1: a SINGLE socket connection is created when the user\n//           logs in (or when the chat section of the app mounts),\n//           NOT recreated every time a room screen opens\n//   Step 2: the connection is authenticated using the JWT from\n//           AuthContext (lesson 22's auth token, lesson 32 PART 5's\n//           auth option)\n//   Step 3: individual room screens REUSE this same connection,\n//           only emitting join_room/leave_room as the user navigates\n\nimport { io, Socket } from \"socket.io-client\";\n\nlet socket: Socket | null = null;\n\nconst connectChatSocket = (token: string): Socket => {\n    if (socket) return socket;   // reuse if already connected\n    socket = io(\"https://your-backend.com\", { auth: { token } });\n    return socket;\n};\n\nconst disconnectChatSocket = () => {\n    socket?.disconnect();\n    socket = null;\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why is connectChatSocket designed to REUSE an existing connection\n// instead of creating a new one every time it's called?       -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Room List Screen\n// ================================================================\n\nimport React, { useState, useEffect } from \"react\";\nimport { View, Text, FlatList, Pressable, TextInput, StyleSheet } from \"react-native\";\n// import { router } from \"expo-router\";\n// import { useAuth } from \"../context/AuthContext\";   // lesson 26\n\ninterface Room { id: string; name: string; }\n\nconst ROOMS: Room[] = [\n    { id: \"general\", name: \"General\" },\n    { id: \"tech\", name: \"Tech Talk\" },\n    { id: \"random\", name: \"Random\" },\n];\n\nconst RoomListScreen = () => {\n    return (\n        <FlatList\n            data={ROOMS}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => (\n                <Pressable\n                    style={styles.roomRow}\n                    onPress={() => {/* router.push(`/chat/${item.id}`) */}}\n                >\n                    <Text style={styles.roomName}>{item.name}</Text>\n                </Pressable>\n            )}\n        />\n    );\n};\n\nconst styles = StyleSheet.create({\n    roomRow: { padding: 16, borderBottomWidth: 1, borderBottomColor: \"#eee\" },\n    roomName: { fontSize: 16, fontWeight: \"bold\" },\n    container: { flex: 1 },\n    inputRow: { flexDirection: \"row\", padding: 8, gap: 8, borderTopWidth: 1, borderTopColor: \"#eee\" },\n    input: { flex: 1, borderWidth: 1, borderColor: \"#ccc\", borderRadius: 6, padding: 10 },\n    message: { padding: 8 },\n});\n\n\n// ================================================================\n// PART 3 -- The Chat Room Screen: Join, Listen, Send, Leave\n// ================================================================\n//\n//   TRACE: the full room lifecycle (lesson 08's [id].tsx pattern\n//   would normally read roomId from useLocalSearchParams)\n//   Step 1: screen mounts -> emit \"join_room\" with this roomId\n//   Step 2: socket.on(\"room_message\", ...) starts collecting\n//           messages for THIS room only\n//   Step 3: user types and sends -> emit \"room_message\" with\n//           { roomId, user, text }\n//   Step 4: screen unmounts (user navigates away) -> emit\n//           \"leave_room\", AND remove the \"room_message\" listener --\n//           otherwise messages from a room you've LEFT would still\n//           pile into state for a screen no longer showing them\n\ninterface ChatMessage { user: string; text: string; sentAt: number; }\n\nconst ChatRoomScreen = ({ roomId }: { roomId: string }) => {\n    const [messages, setMessages] = useState<ChatMessage[]>([]);\n    const [text, setText] = useState(\"\");\n    // const { user } = useAuth();\n    const username = \"Sarath\";   // would come from useAuth() in a real app\n\n    useEffect(() => {\n        if (!socket) return;\n        socket.emit(\"join_room\", roomId);\n\n        const handleMessage = (msg: ChatMessage) => {\n            setMessages((prev) => [...prev, msg]);\n        };\n        socket.on(\"room_message\", handleMessage);\n\n        return () => {\n            socket?.emit(\"leave_room\", roomId);\n            socket?.off(\"room_message\", handleMessage);\n        };\n    }, [roomId]);\n\n    const handleSend = () => {\n        if (text.trim() === \"\" || !socket) return;\n        socket.emit(\"room_message\", { roomId, user: username, text, sentAt: Date.now() });\n        setText(\"\");\n    };\n\n    return (\n        <View style={styles.container}>\n            <FlatList\n                data={messages}\n                keyExtractor={(_, i) => i.toString()}\n                renderItem={({ item }) => (\n                    <Text style={styles.message}>\n                        <Text style={{ fontWeight: \"bold\" }}>{item.user}: </Text>{item.text}\n                    </Text>\n                )}\n            />\n            <View style={styles.inputRow}>\n                <TextInput style={styles.input} value={text} onChangeText={setText} placeholder=\"Message\" />\n                <Pressable onPress={handleSend}><Text>Send</Text></Pressable>\n            </View>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Connecting It to Login (App-Wide Lifecycle)\n// ================================================================\n//\n//   The socket connection's lifetime should match the LOGIN\n//   session, not any one screen's lifetime -- connect right after\n//   a successful login (lesson 26's AuthContext login function),\n//   disconnect on logout:\n//\n//   const login = async (email, password) => {\n//       // ...existing login logic from lesson 26...\n//       connectChatSocket(data.accessToken);\n//   };\n//\n//   const logout = async () => {\n//       disconnectChatSocket();\n//       // ...existing logout logic...\n//   };","questionsCode":"// ================================================================\n// [QUESTIONS] -- Rebuild this from scratch, in a real project.\n// ================================================================\n\n// QUESTION 1 -- Trace the Room-Switching Flow\n//\n// A user is in the \"General\" room, then taps back and opens \"Tech\n// Talk\" instead. Walk through, in order, every join_room/leave_room\n// emit and listener attach/detach that should happen.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Add Typing Indicators\n//\n// PLAN: which lesson's debounce idea controls how OFTEN you emit?\n//\n// Add a \"typing\" emit (debounced to fire at most once per second\n// while the user types) and a \"user_typing\" listener showing\n// \"{user} is typing...\" for 2 seconds after the last event received.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Add a Message History Fetch\n//\n// PLAN: which lesson's REST pattern fetches PAST messages, versus\n// which part of this lesson handles NEW live ones?\n//\n// On mounting a ChatRoomScreen, before listening for live messages,\n// fetch the last 50 messages for that room via a REST endpoint\n// (lesson 21's apiClient) and seed the initial \"messages\" state\n// with them, THEN start listening for new ones via the socket.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build It for Real\n//\n// Set up a real project with RoomListScreen and a dynamic\n// app/chat/[roomId].tsx (lesson 08) rendering ChatRoomScreen. You'll\n// need a Socket.io server (Node.js) handling join_room/leave_room/\n// room_message events, broadcasting only to clients in that room.\n// Note what you built and any issues you hit.\n//\n// Write here:","takeaways":["ONE socket connection per login session -- not one per screen","join_room/leave_room on mount/unmount -- always paired in cleanup","socket.off(event, handler) -- remove a SPECIFIC listener, not all of them","Connect the socket on login, disconnect on logout -- match auth lifecycle"],"nextHint":"lesson_35_push_notifications.tsx -- Native Features begin","milestone":"REAL-TIME SECTION COMPLETE."},{"num":35,"id":"lesson_35_push_notifications","filename":"lesson_35_push_notifications.tsx","title":"Push Notifications: Reaching a Closed App","subtitle":"this solves a problem NOTHING else in this course can -- reaching the user when your app isn't even running.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 35 -- Push Notifications: Reaching a Closed App\n//   Teaching philosophy: this solves a problem NOTHING else in\n//                        this course can -- reaching the user when\n//                        your app isn't even running.\n// ================================================================\n//   Before starting: npx expo install expo-notifications expo-device\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every real-time tool so far (lessons 31-33) needs the app OPEN\n//   and CONNECTED to work. Push notifications are different -- the\n//   OS itself (Android/iOS) keeps a connection to Apple/Google's\n//   notification servers running AT ALL TIMES, even when your app\n//   is fully closed. Your backend sends a message to THAT service,\n//   which delivers it to the device regardless of your app's state.\n//\n//   Your Backend -> Expo's Push Service -> Apple/Google -> Device\n//                                                              |\n//                                                    shows a notification\n//                                                    even if your app\n//                                                    isn't running at all\n//\n//   Expo's push service is a convenience layer so you don't have\n//   to integrate with Apple's and Google's notification systems\n//   separately -- you send ONE request format, Expo routes it correctly.\n\n\n// ================================================================\n// PART 1 -- Requesting Permission and Getting a Push Token\n// ================================================================\n//\n//   TRACE: registering a device for push notifications\n//   Step 1: ask permission (lesson 12's ask/check/use shape, same\n//           idea as camera/location)\n//   Step 2: if granted, getExpoPushTokenAsync() returns a UNIQUE\n//           token identifying THIS specific device installation\n//   Step 3: send that token to YOUR backend, associated with the\n//           logged-in user (lesson 26's AuthContext user)\n//   Step 4: backend stores it -- later, it uses this token to tell\n//           Expo's push service WHERE to deliver a notification\n\nimport * as Notifications from \"expo-notifications\";\nimport * as Device from \"expo-device\";\nimport { useEffect, useState } from \"react\";\n\nconst registerForPushNotifications = async (): Promise<string | null> => {\n    if (!Device.isDevice) {\n        console.log(\"Push notifications need a real device, not a simulator.\");\n        return null;\n    }\n    const { status } = await Notifications.requestPermissionsAsync();\n    if (status !== \"granted\") return null;\n\n    const tokenData = await Notifications.getExpoPushTokenAsync();\n    return tokenData.data;   // looks like \"ExponentPushToken[xxxxxxxx]\"\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why does this check Device.isDevice before requesting permission?\n// What's different about push notifications on a simulator/emulator?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Sending the Token to Your Backend\n// ================================================================\n//\n//   Same REST pattern as everything since lesson 21 -- the push\n//   token is just another field your backend stores, alongside\n//   the user's id.\n\nconst savePushToken = async (token: string, authToken: string) => {\n    await fetch(\"https://your-backend.com/push-token\", {\n        method: \"POST\",\n        headers: { \"Content-Type\": \"application/json\", Authorization: `Bearer ${authToken}` },\n        body: JSON.stringify({ pushToken: token }),\n    });\n};\n\n\n// ================================================================\n// PART 3 -- Triggering a Notification (Backend's Job, Shown for Context)\n// ================================================================\n//\n//   This part runs on YOUR SERVER, not in the RN app -- shown so\n//   you understand the full picture, the same way lesson 30 showed\n//   backend-side MongoDB code for context.\n//\n//   // backend (Node.js)\n//   await fetch(\"https://exp.host/--/api/v2/push/send\", {\n//       method: \"POST\",\n//       headers: { \"Content-Type\": \"application/json\" },\n//       body: JSON.stringify({\n//           to: storedPushToken,\n//           title: \"New message\",\n//           body: \"Sarath sent you a message\",\n//           data: { roomId: \"general\" },\n//       }),\n//   });\n\n\n// ================================================================\n// PART 4 -- Handling a Received Notification, on Every App State\n// ================================================================\n//\n//   A notification can arrive while the app is: in the FOREGROUND\n//   (open and visible), in the BACKGROUND (open but not visible),\n//   or fully CLOSED. Each case needs slightly different handling.\n//\n//   TRACE: foreground behavior\n//   Step 1: by default, iOS/Android may NOT show a visible banner\n//           if the app is already open and in the foreground\n//   Step 2: setNotificationHandler tells Expo HOW to handle that --\n//           e.g. still show an alert even while the app is open\n//\n//   TRACE: tapping a notification (any app state)\n//   Step 1: addNotificationResponseReceivedListener fires when the\n//           user TAPS a notification\n//   Step 2: you read notification.request.content.data (the \"data\"\n//           field from PART 3) to decide where to navigate --\n//           e.g. straight into the specific chat room mentioned\n\nNotifications.setNotificationHandler({\n    handleNotification: async () => ({\n        shouldShowAlert: true,\n        shouldPlaySound: true,\n        shouldSetBadge: false,\n    }),\n});\n\nconst useNotificationListener = () => {\n    useEffect(() => {\n        const receivedSub = Notifications.addNotificationReceivedListener((notification) => {\n            console.log(\"Notification received:\", notification.request.content.title);\n        });\n\n        const responseSub = Notifications.addNotificationResponseReceivedListener((response) => {\n            const data = response.notification.request.content.data;\n            console.log(\"User tapped notification, data:\", data);\n            // router.push(`/chat/${data.roomId}`)  -- lesson 08's navigation\n        });\n\n        return () => {\n            receivedSub.remove();\n            responseSub.remove();\n        };\n    }, []);\n};\n\n\n// ================================================================\n// PART 5 -- Local Notifications (No Server Involved At All)\n// ================================================================\n//\n//   Sometimes you want a notification scheduled entirely ON-DEVICE\n//   -- a reminder, a timer finishing -- with no backend round trip.\n\nconst scheduleLocalReminder = async (title: string, secondsFromNow: number) => {\n    await Notifications.scheduleNotificationAsync({\n        content: { title, body: \"Reminder!\" },\n        trigger: { seconds: secondsFromNow },\n    });\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- Push token identifies a DEVICE. Backend sends. OS delivers.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A user logs into the SAME account on two different phones.\n//\n// Should your backend store ONE push token per user, or potentially\n// MULTIPLE? What happens if you only store the most recent one?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const register = async () => {\n//       const token = Notifications.getExpoPushTokenAsync();\n//       fetch(\"/push-token\", { method: \"POST\", body: token });\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   Bug 3 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build the Full Registration Flow\n//\n// PLAN: when should this run -- on every screen, or once after login?\n//\n// Combine registerForPushNotifications and savePushToken into one\n// function called ONCE, right after a successful login (lesson 26's\n// AuthContext), storing the push token against the now-known user.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build Tap-to-Navigate\n//\n// PLAN: which field in the notification payload tells you WHERE to go?\n//\n// Using useNotificationListener's responseSub, implement actual\n// navigation: if data.type === \"chat_message\", navigate to\n// /chat/{data.roomId}; if data.type === \"friend_request\", navigate\n// to /profile/{data.fromUserId}.\n//\n// Write here:","takeaways":["Push notifications work even when the app is fully closed","getExpoPushTokenAsync() -- identifies THIS device, send it to your backend","Your backend calls Expo's push API -- the RN app never sends notifications itself","addNotificationResponseReceivedListener -- handle TAPS, read the \"data\" payload","scheduleNotificationAsync -- local, on-device, no backend needed"],"nextHint":"lesson_36_bluetooth_ble.tsx -- talking to nearby hardware","milestone":""},{"num":36,"id":"lesson_36_bluetooth_ble","filename":"lesson_36_bluetooth_ble.tsx","title":"Bluetooth Low Energy (BLE): Talking to Nearby Hardware","subtitle":"you already know BLE/IoT concepts from hands-on experience -- this lesson maps that knowledge onto React Native's specific API shape, not BLE fundamentals from zero.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 36 -- Bluetooth Low Energy (BLE): Talking to Nearby Hardware\n//   Teaching philosophy: you already know BLE/IoT concepts from\n//                        hands-on experience -- this lesson maps\n//                        that knowledge onto React Native's specific\n//                        API shape, not BLE fundamentals from zero.\n// ================================================================\n//   Before starting: npx expo install react-native-ble-plx\n//   IMPORTANT: BLE needs native code Expo Go does NOT include --\n//   you must build a \"development build\" (covered in lesson 41 /\n//   conceptually: npx expo run:android or eas build --profile development)\n\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   You already know the core BLE vocabulary: peripherals,\n//   services, characteristics, advertising, GATT. What's NEW here\n//   is purely the React Native plumbing around that, plus ONE\n//   important platform fact:\n//\n//   Expo Go (the app you've used for every previous lesson) is a\n//   pre-built binary that does NOT include BLE's native modules.\n//   react-native-ble-plx needs native (Java/Kotlin + Swift/Obj-C)\n//   code, so from this lesson onward, you need a \"development\n//   build\" -- your OWN compiled version of Expo Go, with the BLE\n//   library baked in. This is the FIRST time in the course this\n//   distinction actually matters.\n\n\n// ================================================================\n// PART 1 -- Permissions (Android Is Stricter Than You'd Expect)\n// ================================================================\n//\n//   TRACE: BLE permissions on Android 12+\n//   Step 1: BLUETOOTH_SCAN and BLUETOOTH_CONNECT are runtime\n//           permissions (lesson 12's ask/check/use shape applies\n//           here too, just with BLE-specific permission names)\n//   Step 2: on OLDER Android versions, BLE scanning ALSO required\n//           ACCESS_FINE_LOCATION -- because, historically, scan\n//           results could reveal a user's approximate location via\n//           nearby beacons\n//   Step 3: app.json needs these permissions declared under\n//           \"android\": { \"permissions\": [...] } for a custom build\n\nimport { PermissionsAndroid, Platform } from \"react-native\";\n\nconst requestBlePermissions = async (): Promise<boolean> => {\n    if (Platform.OS !== \"android\") return true;   // iOS prompts differently\n\n    const granted = await PermissionsAndroid.requestMultiple([\n        PermissionsAndroid.PERMISSIONS.BLUETOOTH_SCAN,\n        PermissionsAndroid.PERMISSIONS.BLUETOOTH_CONNECT,\n        PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,\n    ]);\n\n    return Object.values(granted).every((result) => result === PermissionsAndroid.RESULTS.GRANTED);\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If a user denies BLUETOOTH_CONNECT but grants BLUETOOTH_SCAN,\n// can you discover devices? Can you actually connect to one?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Scanning for Devices\n// ================================================================\n//\n//   TRACE: scanning, the RN-specific shape\n//   Step 1: new BleManager() -- ONE instance for the whole app's\n//           lifetime, similar to lesson 34's single socket instance\n//   Step 2: manager.startDeviceScan(serviceUUIDs, options, callback)\n//           -- callback fires for EVERY advertisement packet seen\n//           (the same device may fire repeatedly while in range)\n//   Step 3: ALWAYS call stopDeviceScan() -- scanning continuously\n//           drains battery fast, exactly the concern you already\n//           know from prior BLE/IoT work\n\nimport { BleManager, Device } from \"react-native-ble-plx\";\nimport { useEffect, useRef, useState } from \"react\";\nimport { View, Text, FlatList, Pressable } from \"react-native\";\n\nconst bleManager = new BleManager();\n\nconst useBleScan = () => {\n    const [devices, setDevices] = useState<Device[]>([]);\n    const [scanning, setScanning] = useState(false);\n\n    const startScan = async () => {\n        const ok = await requestBlePermissions();\n        if (!ok) return;\n\n        setDevices([]);\n        setScanning(true);\n        bleManager.startDeviceScan(null, null, (error, device) => {\n            if (error) { console.log(\"Scan error:\", error); return; }\n            if (device) {\n                setDevices((prev) =>\n                    prev.some((d) => d.id === device.id) ? prev : [...prev, device]\n                );\n            }\n        });\n\n        setTimeout(() => {\n            bleManager.stopDeviceScan();\n            setScanning(false);\n        }, 10000);   // auto-stop after 10 seconds -- never scan forever\n    };\n\n    useEffect(() => {\n        return () => { bleManager.stopDeviceScan(); };   // cleanup on unmount\n    }, []);\n\n    return { devices, scanning, startScan };\n};\n\n\n// ================================================================\n// PART 3 -- Connecting and Discovering Services/Characteristics\n// ================================================================\n//\n//   TRACE: the connection handshake (same GATT concepts you know,\n//   spelled in this library's API)\n//   Step 1: device.connect() -- establishes the BLE connection\n//   Step 2: device.discoverAllServicesAndCharacteristics() --\n//           populates the device object with its full GATT table\n//   Step 3: you now know which characteristic UUIDs are readable/\n//           writable/notifiable, exactly as you'd inspect from a\n//           BLE scanner tool\n\nconst connectToDevice = async (deviceId: string): Promise<Device> => {\n    const device = await bleManager.connectToDevice(deviceId);\n    await device.discoverAllServicesAndCharacteristics();\n    return device;\n};\n\n\n// ================================================================\n// PART 4 -- Reading, Writing, and Subscribing to Notifications\n// ================================================================\n//\n//   TRACE: the 3 ways you interact with a characteristic\n//   Step 1: READ -- one-time pull, e.g. a battery level characteristic\n//   Step 2: WRITE -- send a command, e.g. turn an LED on\n//   Step 3: MONITOR (notify) -- subscribe to live updates, e.g. a\n//           heart-rate sensor pushing new readings continuously --\n//           this is the BLE equivalent of lesson 31-33's real-time\n//           listeners, just over Bluetooth instead of the internet\n//\n//   Values transfer as BASE64-encoded byte strings -- decoding them\n//   into real numbers is YOUR app's job, based on the device's\n//   documented data format (exactly like parsing a sensor's raw\n//   byte payload in any other BLE/IoT context).\n\nimport { Buffer } from \"buffer\";\n\nconst readBatteryLevel = async (device: Device): Promise<number> => {\n    const characteristic = await device.readCharacteristicForService(\n        \"0000180f-0000-1000-8000-00805f9b34fb\",   // standard Battery Service UUID\n        \"00002a19-0000-1000-8000-00805f9b34fb\"    // Battery Level characteristic\n    );\n    const bytes = Buffer.from(characteristic.value ?? \"\", \"base64\");\n    return bytes[0];   // battery level is a single byte, 0-100\n};\n\nconst subscribeToHeartRate = (device: Device, onReading: (bpm: number) => void) => {\n    return device.monitorCharacteristicForService(\n        \"0000180d-0000-1000-8000-00805f9b34fb\",\n        \"00002a37-0000-1000-8000-00805f9b34fb\",\n        (error, characteristic) => {\n            if (error || !characteristic?.value) return;\n            const bytes = Buffer.from(characteristic.value, \"base64\");\n            onReading(bytes[1]);   // heart rate value is typically byte index 1\n        }\n    );\n    // returns a Subscription -- call .remove() in cleanup, same pattern\n    // as every other listener this section has used (lessons 29, 31-33)\n};\n\n\n// ================================================================\n// PART 5 -- A Scan-and-Connect Screen\n// ================================================================\n\nconst BleScanScreen = () => {\n    const { devices, scanning, startScan } = useBleScan();\n\n    return (\n        <View style={{ padding: 16 }}>\n            <Pressable onPress={startScan} disabled={scanning}>\n                <Text>{scanning ? \"Scanning...\" : \"Scan for Devices\"}</Text>\n            </Pressable>\n            <FlatList\n                data={devices}\n                keyExtractor={(item) => item.id}\n                renderItem={({ item }) => (\n                    <Pressable onPress={() => connectToDevice(item.id)}>\n                        <Text>{item.name ?? \"Unnamed device\"} ({item.id})</Text>\n                    </Pressable>\n                )}\n            />\n        </View>\n    );\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- Same GATT concepts, react-native-ble-plx's specific API.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// startDeviceScan runs with no setTimeout-based stop, and the\n// screen displaying it is left open for 20 minutes.\n//\n// What happens to the device's battery over that time, and why\n// is an explicit stopDeviceScan() (or a timeout) important?    -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const connect = async (id) => {\n//       const device = await bleManager.connectToDevice(id);\n//       const characteristic = await device.readCharacteristicForService(\n//           serviceUUID, charUUID\n//       );\n//       console.log(characteristic.value);\n//   };\n//\n// Bug -> ?  (hint: what MUST happen between connecting and reading\n// any characteristic, per PART 3?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Device List With Connection State\n//\n// PLAN: what UI state shows \"scanning,\" \"connecting,\" \"connected\"?\n//\n// Extend BleScanScreen so each row shows its own connection status\n// (idle / connecting / connected), updating live as the user taps\n// to connect, using per-device state (an object keyed by device id).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Live Sensor Reading Screen\n//\n// PLAN: which lesson's \"subscribe + cleanup\" shape does this reuse?\n//\n// Using subscribeToHeartRate's pattern, build a screen that connects\n// to a chosen device, subscribes to a characteristic, displays live\n// readings in a Text, and properly calls .remove() on the\n// subscription when the screen unmounts (lesson 09's cleanup pattern).\n//\n// Write here:","takeaways":["BLE needs a development build -- Expo Go cannot run native BLE code","Always request BLUETOOTH_SCAN + BLUETOOTH_CONNECT (+ location on older Android) before scanning","ALWAYS stop scanning -- timeout or explicit stopDeviceScan()","discoverAllServicesAndCharacteristics() BEFORE any read/write/monitor","monitorCharacteristicForService -- BLE's version of a real-time listener"],"nextHint":"lesson_37_camera_advanced.tsx -- beyond basic photo picking","milestone":""},{"num":37,"id":"lesson_37_camera_advanced","filename":"lesson_37_camera_advanced.tsx","title":"Camera: Building a Live, Custom Camera Screen","subtitle":"lesson 12 used the OS's OWN camera UI via image-picker. This lesson builds YOUR OWN camera screen -- live preview, custom controls, barcode scanning.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 37 -- Camera: Building a Live, Custom Camera Screen\n//   Teaching philosophy: lesson 12 used the OS's OWN camera UI via\n//                        image-picker. This lesson builds YOUR OWN\n//                        camera screen -- live preview, custom\n//                        controls, barcode scanning.\n// ================================================================\n//   Before starting: npx expo install expo-camera\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 12's launchImageLibraryAsync/launchCameraAsync hand\n//   control to the OS entirely -- you get a result back, nothing\n//   more. That's PERFECT for \"let the user pick/take one photo.\"\n//   It's the WRONG tool when you need a LIVE camera feed inside\n//   your own screen -- e.g. a barcode/QR scanner, a custom photo\n//   filter preview, or showing a live feed with custom overlay UI.\n//   expo-camera gives you that raw, embeddable live feed.\n\n\n// ================================================================\n// PART 1 -- A Live Camera Preview\n// ================================================================\n//\n//   TRACE: rendering a live feed\n//   Step 1: useCameraPermissions() -- a hook, returns [permission,\n//           requestPermission] -- SAME ask/check/use shape from\n//           lesson 12, just packaged as a hook this time\n//   Step 2: <CameraView> renders the ACTUAL live camera feed as a\n//           normal RN component -- style it with Flexbox (lesson 05)\n//           like anything else\n//   Step 3: \"facing\" prop -- \"back\" or \"front\" camera\n\nimport React, { useState, useRef } from \"react\";\nimport { View, Text, Pressable, StyleSheet } from \"react-native\";\nimport { CameraView, useCameraPermissions, BarcodeScanningResult } from \"expo-camera\";\n\nconst LiveCameraScreen = () => {\n    const [permission, requestPermission] = useCameraPermissions();\n\n    if (!permission) return <Text>Loading permissions...</Text>;\n    if (!permission.granted) {\n        return (\n            <View style={styles.center}>\n                <Text>We need camera access to continue.</Text>\n                <Pressable onPress={requestPermission}><Text>Grant Permission</Text></Pressable>\n            </View>\n        );\n    }\n\n    return (\n        <CameraView style={{ flex: 1 }} facing=\"back\" />\n    );\n};\n\nconst styles = StyleSheet.create({\n    center: { flex: 1, justifyContent: \"center\", alignItems: \"center\" },\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// Compare useCameraPermissions() to lesson 36's manual\n// requestBlePermissions(). What's the practical difference between\n// a permission HOOK and a permission FUNCTION you call yourself?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Taking a Photo (Via a Ref, Like Lesson 16)\n// ================================================================\n//\n//   TRACE: capturing a still photo from the live feed\n//   Step 1: useRef<CameraView>(null) -- lesson 16's pattern, gives\n//           you a handle to the actual camera instance\n//   Step 2: cameraRef.current?.takePictureAsync() -- captures\n//           exactly what's on screen RIGHT NOW\n//   Step 3: the result includes a \"uri\" -- usable anywhere lesson 12\n//           or lesson 25's upload code expected a picked image's uri\n\nconst PhotoCaptureScreen = () => {\n    const [permission, requestPermission] = useCameraPermissions();\n    const cameraRef = useRef<CameraView>(null);\n    const [photoUri, setPhotoUri] = useState<string | null>(null);\n\n    const takePhoto = async () => {\n        const photo = await cameraRef.current?.takePictureAsync();\n        if (photo) setPhotoUri(photo.uri);\n    };\n\n    if (!permission?.granted) return <Pressable onPress={requestPermission}><Text>Grant Permission</Text></Pressable>;\n\n    return (\n        <View style={{ flex: 1 }}>\n            <CameraView ref={cameraRef} style={{ flex: 1 }} />\n            <Pressable style={{ padding: 20, alignItems: \"center\" }} onPress={takePhoto}>\n                <Text>Take Photo</Text>\n            </Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Switching Between Front and Back Camera\n// ================================================================\n//\n//   \"facing\" is just a piece of state (lesson 04) -- toggling it\n//   re-renders CameraView with the new value, switching cameras live.\n\nconst SwitchableCameraScreen = () => {\n    const [facing, setFacing] = useState<\"front\" | \"back\">(\"back\");\n\n    return (\n        <View style={{ flex: 1 }}>\n            <CameraView style={{ flex: 1 }} facing={facing} />\n            <Pressable\n                style={{ padding: 20 }}\n                onPress={() => setFacing((prev) => (prev === \"back\" ? \"front\" : \"back\"))}\n            >\n                <Text>Flip Camera</Text>\n            </Pressable>\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Barcode/QR Scanning (A Common Real Use Case)\n// ================================================================\n//\n//   TRACE: live barcode detection\n//   Step 1: \"onBarcodeScanned\" fires automatically whenever a\n//           recognizable barcode/QR code is in view -- no manual\n//           capture button needed\n//   Step 2: result.data -- the decoded text content\n//   Step 3: result.type -- which barcode format was detected\n//   Step 4: a common bug: this fires REPEATEDLY for the same code\n//           while it's still in frame -- guard with a \"scanned\"\n//           flag so you don't process the same code 30 times a second\n\nconst QrScannerScreen = () => {\n    const [permission, requestPermission] = useCameraPermissions();\n    const [scanned, setScanned] = useState(false);\n    const [result, setResult] = useState<string | null>(null);\n\n    const handleScan = (scan: BarcodeScanningResult) => {\n        if (scanned) return;   // ignore repeat detections of the same code\n        setScanned(true);\n        setResult(scan.data);\n    };\n\n    if (!permission?.granted) return <Pressable onPress={requestPermission}><Text>Grant Permission</Text></Pressable>;\n\n    return (\n        <View style={{ flex: 1 }}>\n            <CameraView\n                style={{ flex: 1 }}\n                onBarcodeScanned={handleScan}\n                barcodeScannerSettings={{ barcodeTypes: [\"qr\"] }}\n            />\n            {result && (\n                <View style={{ padding: 16 }}>\n                    <Text>Scanned: {result}</Text>\n                    <Pressable onPress={() => { setScanned(false); setResult(null); }}>\n                        <Text>Scan Again</Text>\n                    </Pressable>\n                </View>\n            )}\n        </View>\n    );\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- CameraView is live and embeddable. Guard repeat scans.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// In QrScannerScreen, what happens if you REMOVE the\n// \"if (scanned) return;\" guard, while pointing the camera at one\n// QR code continuously for 5 seconds?                          -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const PhotoScreen = () => {\n//       const cameraRef = useRef(null);\n//       const takePhoto = () => {\n//           const photo = cameraRef.takePictureAsync();\n//           setUri(photo.uri);\n//       };\n//       return <CameraView ref={cameraRef} style={{ flex: 1 }} />;\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: where does .current go, and is\n// takePictureAsync awaited?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Photo Review Screen\n//\n// PLAN: what 2 states does this screen need -- before and after capture?\n//\n// Extend PhotoCaptureScreen: after taking a photo, show it full-screen\n// with two buttons, \"Retake\" (clears photoUri, shows the live camera\n// again) and \"Use Photo\" (would proceed to upload, lesson 25).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Multi-Format Scanner\n//\n// PLAN: which barcode types does a real-world product scanner need?\n//\n// Extend QrScannerScreen's barcodeScannerSettings to accept both\n// \"qr\" and \"ean13\" (common product barcodes), and show the\n// detected result.type alongside result.data so the user can see\n// WHICH format was recognized.\n//\n// Write here:","takeaways":["CameraView -- a live, embeddable camera feed, styled like any View","useCameraPermissions() -- the hook form of ask/check/use","ref + takePictureAsync() -- capture exactly what's on screen","onBarcodeScanned -- fires repeatedly while a code is in view -- always guard against duplicate processing"],"nextHint":"lesson_38_gps_location.tsx -- tracking, not just one-time reads","milestone":""},{"num":38,"id":"lesson_38_gps_location","filename":"lesson_38_gps_location.tsx","title":"GPS & Location: Tracking, Not Just One-Time Reads","subtitle":"lesson 12 read location ONCE. This lesson covers WATCHING it continuously -- the real building block behind live location tracking projects.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 38 -- GPS & Location: Tracking, Not Just One-Time Reads\n//   Teaching philosophy: lesson 12 read location ONCE. This lesson\n//                        covers WATCHING it continuously -- the\n//                        real building block behind live location\n//                        tracking projects.\n// ================================================================\n//   Before starting: same expo-location package from lesson 12\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   getCurrentPositionAsync() (lesson 12) is a SNAPSHOT -- one GPS\n//   read, then done. A delivery-tracking app, a running tracker, or\n//   a \"find nearby friends\" feature needs a STREAM of updates as\n//   the device physically moves. watchPositionAsync gives you\n//   exactly that -- the GPS equivalent of lesson 31-33's real-time\n//   listeners, except the \"events\" are produced by hardware\n//   movement instead of a server pushing data.\n\n\n// ================================================================\n// PART 1 -- Foreground vs Background Location (A Critical Distinction)\n// ================================================================\n//\n//   FOREGROUND permission -- location updates work ONLY while your\n//   app is open and visible on screen.\n//   BACKGROUND permission -- updates continue even if the user\n//   switches to another app or locks the phone -- needed for things\n//   like a fitness tracker recording a run while the screen is off.\n//\n//   Background location is a MUCH more sensitive permission --\n//   both Android and iOS show extra warnings to the user, and app\n//   stores scrutinize apps requesting it. Only ask for it if your\n//   feature genuinely cannot work without it.\n\nimport * as Location from \"expo-location\";\n\nconst requestForegroundAccess = async (): Promise<boolean> => {\n    const { status } = await Location.requestForegroundPermissionsAsync();\n    return status === \"granted\";\n};\n\nconst requestBackgroundAccess = async (): Promise<boolean> => {\n    // on most platforms, foreground permission must be granted FIRST\n    const { status } = await Location.requestBackgroundPermissionsAsync();\n    return status === \"granted\";\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If your app only needs location to show a \"you are here\" pin\n// while the map screen is open, do you need background permission\n// at all?                                                      -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- watchPositionAsync: A Live Subscription\n// ================================================================\n//\n//   TRACE: the subscription shape (same family as lesson 09's\n//   useEffect cleanup, lesson 29's onSnapshot, lesson 33's onValue)\n//   Step 1: watchPositionAsync(options, callback) starts watching\n//   Step 2: callback fires every time the device moves (or on an\n//           interval, depending on \"options\")\n//   Step 3: it returns a SUBSCRIPTION object with a .remove() method\n//   Step 4: ALWAYS call .remove() in your cleanup -- forgetting\n//           this keeps the GPS radio running and draining battery\n//           even after the screen closes\n\nimport { useEffect, useState } from \"react\";\nimport { View, Text } from \"react-native\";\n\ninterface Coords { latitude: number; longitude: number; }\n\nconst useLiveLocation = () => {\n    const [coords, setCoords] = useState<Coords | null>(null);\n\n    useEffect(() => {\n        let subscription: Location.LocationSubscription | null = null;\n\n        const start = async () => {\n            const granted = await requestForegroundAccess();\n            if (!granted) return;\n\n            subscription = await Location.watchPositionAsync(\n                {\n                    accuracy: Location.Accuracy.High,\n                    timeInterval: 3000,     // at most every 3 seconds\n                    distanceInterval: 10,   // OR after moving 10 meters\n                },\n                (location) => {\n                    setCoords({\n                        latitude: location.coords.latitude,\n                        longitude: location.coords.longitude,\n                    });\n                }\n            );\n        };\n        start();\n\n        return () => subscription?.remove();\n    }, []);\n\n    return coords;\n};\n\nconst LiveMapScreen = () => {\n    const coords = useLiveLocation();\n    if (!coords) return <Text>Waiting for GPS signal...</Text>;\n    return <Text>Lat: {coords.latitude.toFixed(5)}, Lon: {coords.longitude.toFixed(5)}</Text>;\n};\n\n\n// ================================================================\n// PART 3 -- timeInterval vs distanceInterval (Battery Trade-off)\n// ================================================================\n//\n//   TRACE: how the two settings interact\n//   Step 1: timeInterval -- \"don't fire more often than every N ms,\n//           EVEN if the device is moving constantly\"\n//   Step 2: distanceInterval -- \"don't fire unless the device moved\n//           at least N meters since the last update\"\n//   Step 3: BOTH conditions apply together -- an update only fires\n//           once EITHER threshold passes, whichever provides the\n//           better balance for your use case\n//\n//   Higher accuracy + shorter intervals = more precise tracking,\n//   but drains battery faster -- the same trade-off you've weighed\n//   in prior BLE/IoT sensor work, just expressed through GPS settings.\n\n\n// ================================================================\n// PART 4 -- Sending Live Location Over a Socket (Connecting to Lesson 32)\n// ================================================================\n//\n//   A \"live location tracking\" feature combines THIS lesson with\n//   real-time transport from lessons 31-33 -- GPS produces updates,\n//   a socket (or Realtime Database) broadcasts them to whoever is\n//   watching.\n\nimport { Socket } from \"socket.io-client\";\n\nconst broadcastLocation = (socket: Socket, coords: Coords) => {\n    socket.emit(\"location_update\", coords);\n};\n// Combine this with useLiveLocation's callback -- every time coords\n// change, emit it. A watcher's screen subscribes via socket.on\n// (\"location_update\", ...) exactly like lesson 32's chat messages.","questionsCode":"// ================================================================\n// [QUESTIONS] -- watchPositionAsync streams. ALWAYS .remove() it.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// watchPositionAsync is started with timeInterval: 5000 and\n// distanceInterval: 0. The device is sitting still on a table.\n//\n// Does the callback keep firing every 5 seconds anyway, or does it\n// stop once the device stops moving?                          -> ?\n// (Hint: re-read PART 3's \"EITHER threshold\" rule carefully.)\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   useEffect(() => {\n//       Location.watchPositionAsync({}, (loc) => setCoords(loc.coords));\n//   }, []);\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: watchPositionAsync RETURNS a\n// promise resolving to a subscription -- is that handled here? and\n// is there a cleanup?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Distance Traveled Tracker\n//\n// PLAN: how do you compute distance between two lat/lon points?\n//\n// Build a hook that, using watchPositionAsync, keeps a running\n// total of distance traveled (you can use a simple haversine\n// formula function, or approximate with expo-location's built-in\n// helpers if available) since the screen opened, displayed in meters.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build Live Location Sharing\n//\n// PLAN: which lesson's socket pattern receives the broadcasted updates?\n//\n// Combine useLiveLocation with broadcastLocation: every time coords\n// update, emit \"location_update\" over a Socket.io connection\n// (lesson 32). On a SECOND screen/device, listen for that event and\n// display the latest received coordinates.\n//\n// Write here:","takeaways":["getCurrentPositionAsync -- one-time | watchPositionAsync -- a stream","Foreground permission -- only while app is visible | Background -- needs separate permission, more scrutiny, use sparingly","timeInterval / distanceInterval -- battery vs precision trade-off","ALWAYS subscription.remove() in cleanup"],"nextHint":"lesson_39_sensors.tsx -- accelerometer, gyroscope, and motion","milestone":""},{"num":39,"id":"lesson_39_sensors","filename":"lesson_39_sensors.tsx","title":"Sensors: Accelerometer, Gyroscope, and Motion","subtitle":"every sensor in this lesson follows the EXACT SAME subscribe/listen/cleanup shape you've now seen four times (lessons 29, 31-33, 38) -- recognize the pattern, not memorize each API separately.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 39 -- Sensors: Accelerometer, Gyroscope, and Motion\n//   Teaching philosophy: every sensor in this lesson follows the\n//                        EXACT SAME subscribe/listen/cleanup shape\n//                        you've now seen four times (lessons 29,\n//                        31-33, 38) -- recognize the pattern, not\n//                        memorize each API separately.\n// ================================================================\n//   Before starting: npx expo install expo-sensors\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   A phone is full of small physical sensors, constantly measuring\n//   the real world:\n//   - Accelerometer -- measures acceleration force (gravity, shakes,\n//     tilting) along x/y/z axes\n//   - Gyroscope -- measures ROTATION rate around x/y/z axes\n//   - Magnetometer -- measures magnetic field (compass direction)\n//   - Barometer -- measures air pressure (altitude estimation)\n//\n//   Each one in expo-sensors exposes the SAME shape: set an update\n//   interval, addListener for a stream of readings, remove() the\n//   listener when done. Once you've learned ONE, you've learned all of them.\n\n\n// ================================================================\n// PART 1 -- The Accelerometer\n// ================================================================\n//\n//   TRACE: subscribing to motion readings\n//   Step 1: Accelerometer.setUpdateInterval(ms) -- how often readings\n//           arrive (similar trade-off to lesson 38's timeInterval --\n//           more frequent = more responsive, more battery used)\n//   Step 2: Accelerometer.addListener(callback) -- fires repeatedly\n//           with { x, y, z } values (in units of gravitational force, g)\n//   Step 3: the RETURNED subscription has a .remove() method --\n//           the same cleanup shape as every other listener so far\n\nimport { Accelerometer } from \"expo-sensors\";\nimport { useEffect, useState } from \"react\";\nimport { View, Text } from \"react-native\";\n\ninterface Vector3 { x: number; y: number; z: number; }\n\nconst useAccelerometer = () => {\n    const [data, setData] = useState<Vector3>({ x: 0, y: 0, z: 0 });\n\n    useEffect(() => {\n        Accelerometer.setUpdateInterval(200);   // 5 readings per second\n        const subscription = Accelerometer.addListener(setData);\n        return () => subscription.remove();\n    }, []);\n\n    return data;\n};\n\nconst TiltScreen = () => {\n    const { x, y, z } = useAccelerometer();\n    return (\n        <View style={{ padding: 20 }}>\n            <Text>x: {x.toFixed(2)}</Text>\n            <Text>y: {y.toFixed(2)}</Text>\n            <Text>z: {z.toFixed(2)}</Text>\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// With the phone lying flat, face up, on a table, which axis (x,\n// y, or z) would you expect to read close to 1.0 (representing\n// gravity), and which two close to 0?                          -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Gyroscope (Rotation Rate, Not Orientation)\n// ================================================================\n//\n//   IMPORTANT distinction: the gyroscope reports how FAST something\n//   is rotating right now (radians/second), NOT the device's\n//   current absolute orientation. To track actual orientation over\n//   time, you'd integrate gyroscope readings (or use a higher-level\n//   sensor fusion API) -- this lesson covers the raw reading only.\n\nimport { Gyroscope } from \"expo-sensors\";\n\nconst useGyroscope = () => {\n    const [rotation, setRotation] = useState<Vector3>({ x: 0, y: 0, z: 0 });\n\n    useEffect(() => {\n        Gyroscope.setUpdateInterval(200);\n        const subscription = Gyroscope.addListener(setRotation);\n        return () => subscription.remove();\n    }, []);\n\n    return rotation;\n};\n\n\n// ================================================================\n// PART 3 -- Detecting a Shake Gesture (A Practical Pattern)\n// ================================================================\n//\n//   TRACE: turning raw accelerometer noise into a \"shake\" EVENT\n//   Step 1: compute the total magnitude of the acceleration vector:\n//           sqrt(x^2 + y^2 + z^2)\n//   Step 2: at rest, magnitude is close to 1.0 (just gravity)\n//   Step 3: a sharp shake spikes magnitude well above a threshold\n//           (e.g. > 1.8)\n//   Step 4: trigger your \"shake detected\" logic only on that spike,\n//           with a short cooldown so one shake doesn't fire 10 times\n\nconst useShakeDetector = (onShake: () => void) => {\n    useEffect(() => {\n        Accelerometer.setUpdateInterval(100);\n        let lastShakeTime = 0;\n\n        const subscription = Accelerometer.addListener(({ x, y, z }) => {\n            const magnitude = Math.sqrt(x * x + y * y + z * z);\n            const now = Date.now();\n            if (magnitude > 1.8 && now - lastShakeTime > 1000) {\n                lastShakeTime = now;\n                onShake();\n            }\n        });\n\n        return () => subscription.remove();\n    }, [onShake]);\n};\n\n\n// ================================================================\n// PART 4 -- Checking Sensor Availability\n// ================================================================\n//\n//   Not every device has every sensor (especially on some Android\n//   models, or in emulators). Always check before relying on one\n//   for a critical feature -- the same defensive habit as lesson 12\n//   PART 4's \"ask, check, use\" for hardware permissions.\n\nconst checkAccelerometerAvailable = async (): Promise<boolean> => {\n    return await Accelerometer.isAvailableAsync();\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- Same shape every time: interval, listener, remove().\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// Accelerometer.setUpdateInterval(1000);\n// const sub = Accelerometer.addListener((data) => console.log(data));\n// // ...5 seconds later...\n// sub.remove();\n//\n// Roughly how many times does console.log fire, total, across\n// those 5 seconds?                                            -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const TiltScreen = () => {\n//       const [data, setData] = useState({ x: 0, y: 0, z: 0 });\n//       Accelerometer.addListener(setData);\n//       return <Text>{data.x}</Text>;\n//   };\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: WHERE is addListener being\n// called from, and what happens on every re-render as a result?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Level/Bubble Tool\n//\n// PLAN: which two axes determine \"tilted left/right\" vs \"tilted\n// forward/back,\" with the phone held flat?\n//\n// Build a screen using useAccelerometer that shows \"Flat\" when x\n// and y are both close to 0 (within some small tolerance), and\n// otherwise shows \"Tilted\" plus the direction (e.g. \"Tilted right\").\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a \"Shake to Undo\" Feature\n//\n// PLAN: what should happen on shake -- and how do you prevent it\n// firing repeatedly while the user keeps shaking?\n//\n// Using useShakeDetector, build a simple counter screen (lesson 04)\n// where shaking the phone resets the counter to 0, with an Alert\n// confirming \"Reset by shake!\" -- confirm the 1-second cooldown\n// prevents multiple resets from one continuous shake motion.\n//\n// Write here:","takeaways":["Every sensor: setUpdateInterval -> addListener -> subscription.remove()","Accelerometer -- acceleration force (gravity, tilt, shakes)","Gyroscope -- rotation RATE, not absolute orientation","magnitude = sqrt(x^2+y^2+z^2) -- the standard \"how much force\" calculation","isAvailableAsync() -- check before depending on a sensor existing"],"nextHint":"lesson_40_background_tasks.tsx -- running code while the app is closed","milestone":""},{"num":40,"id":"lesson_40_background_tasks","filename":"lesson_40_background_tasks.tsx","title":"Background Tasks: Running Code While the App Is Closed","subtitle":"this is the LAST piece needed to fully explain lesson 35's push notifications and lesson 38's location tracking working even when the app isn't open.","section":"Native Features","color":"red","mainCode":"// ================================================================\n//   LESSON 40 -- Background Tasks: Running Code While the App Is Closed\n//   Teaching philosophy: this is the LAST piece needed to fully\n//                        explain lesson 35's push notifications and\n//                        lesson 38's location tracking working even\n//                        when the app isn't open.\n// ================================================================\n//   Before starting: npx expo install expo-background-fetch expo-task-manager\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every useEffect in this course (lesson 09 onward) only runs\n//   while your COMPONENT is mounted -- which means only while the\n//   app is open and that screen is showing. Background tasks are\n//   different: you register a task ONCE, by name, and the OS itself\n//   decides when to wake your app briefly to run it -- even if the\n//   user closed the app entirely.\n//\n//   IMPORTANT, and different from everything else in this course:\n//   the OS, NOT your code, decides exactly WHEN a background task\n//   runs. You can request \"roughly every 15 minutes,\" but Android/\n//   iOS may delay, batch, or skip runs to save battery -- you\n//   cannot rely on background tasks for split-second timing.\n\n\n// ================================================================\n// PART 1 -- Defining a Task (Outside Any Component)\n// ================================================================\n//\n//   TRACE: TaskManager.defineTask\n//   Step 1: a task is registered by a STRING NAME, at the TOP\n//           LEVEL of a file -- NOT inside a component, because it\n//           must be defined even when no screen is rendering at all\n//   Step 2: the task function runs in the background, with NO\n//           access to your component tree, state, or UI -- it's\n//           closer to a standalone script that wakes up periodically\n//   Step 3: it must return a Result telling the OS what happened --\n//           NewData (found something), NoData (nothing new), or\n//           Failed (something went wrong)\n\nimport * as TaskManager from \"expo-task-manager\";\nimport * as BackgroundFetch from \"expo-background-fetch\";\n\nconst SYNC_TASK_NAME = \"background-sync\";\n\nTaskManager.defineTask(SYNC_TASK_NAME, async () => {\n    try {\n        const response = await fetch(\"https://your-backend.com/check-updates\");\n        const data = await response.json();\n        if (data.hasNewContent) {\n            // e.g. schedule a local notification (lesson 35 PART 5)\n            return BackgroundFetch.BackgroundFetchResult.NewData;\n        }\n        return BackgroundFetch.BackgroundFetchResult.NoData;\n    } catch (error) {\n        return BackgroundFetch.BackgroundFetchResult.Failed;\n    }\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// Since the task function has no access to React state or a\n// component's props, how would it show the user something (e.g.\n// \"new content available\")? (Hint: think back to lesson 35.)  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Registering the Task to Actually Run\n// ================================================================\n//\n//   Defining a task (PART 1) just teaches the app WHAT to do when\n//   asked. Registering it tells the OS to actually SCHEDULE it.\n//\n//   TRACE: registerTaskAsync\n//   Step 1: minimumInterval -- your REQUESTED interval, in seconds\n//           (the OS treats this as a suggestion, not a guarantee --\n//           see BEFORE CODE)\n//   Step 2: stopOnTerminate: false -- keep trying to run even after\n//           the user fully closes/swipes away the app (Android)\n//   Step 3: startOnBoot: true -- resume scheduling after the device\n//           restarts, without the user needing to reopen the app first\n\nconst registerBackgroundSync = async () => {\n    await BackgroundFetch.registerTaskAsync(SYNC_TASK_NAME, {\n        minimumInterval: 15 * 60,   // ~15 minutes, OS treats as a floor\n        stopOnTerminate: false,\n        startOnBoot: true,\n    });\n};\n\nconst unregisterBackgroundSync = async () => {\n    await BackgroundFetch.unregisterTaskAsync(SYNC_TASK_NAME);\n};\n\n\n// ================================================================\n// PART 3 -- Background Location (Connecting Lessons 38 and 40)\n// ================================================================\n//\n//   Lesson 38's watchPositionAsync only works while the screen is\n//   open. For TRUE background location tracking (a fitness app\n//   recording a run with the screen off), expo-location has its\n//   OWN background task integration, layered on this same\n//   TaskManager mechanism:\n\nconst LOCATION_TASK_NAME = \"background-location-task\";\n\nimport * as Location from \"expo-location\";\n\nTaskManager.defineTask(LOCATION_TASK_NAME, ({ data, error }) => {\n    if (error) { console.log(\"Background location error:\", error); return; }\n    if (data) {\n        const { locations } = data as { locations: Location.LocationObject[] };\n        console.log(\"Background location update:\", locations[0]?.coords);\n        // send to backend, save to SQLite (lesson 28), etc.\n    }\n});\n\nconst startBackgroundLocationTracking = async () => {\n    const { status } = await Location.requestBackgroundPermissionsAsync();\n    if (status !== \"granted\") return;\n\n    await Location.startLocationUpdatesAsync(LOCATION_TASK_NAME, {\n        accuracy: Location.Accuracy.Balanced,\n        timeInterval: 60000,        // request updates roughly every minute\n        showsBackgroundLocationIndicator: true,   // iOS requires user-visible indicator\n    });\n};\n\n\n// ================================================================\n// PART 4 -- Checking Status and Limits\n// ================================================================\n//\n//   Background execution is heavily restricted by BOTH platforms\n//   to protect battery life -- this is intentional, not a bug to\n//   work around. Use it ONLY for genuinely necessary periodic\n//   checks (sync, content refresh) -- never as a substitute for\n//   real-time delivery (that's what push notifications, lesson 35,\n//   and sockets, lessons 31-33, are actually for).\n\nconst checkBackgroundFetchStatus = async () => {\n    const status = await BackgroundFetch.getStatusAsync();\n    // status can indicate: Available, Denied, or Restricted (e.g.\n    // user disabled Background App Refresh in iOS Settings)\n    return status;\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- The OS decides WHEN. Define outside components. Always cleanup.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// You register a background task with minimumInterval: 60 (1\n// minute), expecting frequent updates. After a day of testing, you\n// notice it sometimes only ran once every 30-45 minutes.\n//\n// Is this a bug in your code? Why might the OS behave this way?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake)\n//\n//   const HomeScreen = () => {\n//       TaskManager.defineTask(\"sync\", async () => {\n//           await fetch(\"/sync\");\n//       });\n//       return <Text>Home</Text>;\n//   };\n//\n// Bug -> ?  (hint: re-read PART 1's \"must be defined at the top\n// level\" rule, and think about what happens every time HomeScreen renders)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Background Content Checker\n//\n// PLAN: what should the task do when it finds new content, given\n// it has no direct way to update a currently-open screen's UI?\n//\n// Define and register a background task that checks an endpoint\n// for new content every ~20 minutes, and if found, schedules a\n// local notification (lesson 35 PART 5) saying \"New content available!\"\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Toggle for Background Tracking\n//\n// PLAN: what permission must be checked/requested before starting?\n//\n// Build a settings screen with a toggle (lesson 04's pattern):\n// turning it ON calls startBackgroundLocationTracking, turning it\n// OFF calls Location.stopLocationUpdatesAsync(LOCATION_TASK_NAME).\n// Persist the toggle's state with AsyncStorage (lesson 11) so it's\n// remembered across app restarts.\n//\n// Write here:","takeaways":["TaskManager.defineTask(name, fn) -- defined at the TOP LEVEL, not inside a component","registerTaskAsync -- requests scheduling; the OS decides actual timing","minimumInterval is a FLOOR, not a guarantee -- the OS may delay/skip","Background location needs separate background permission (lesson 38)","Use sparingly -- push notifications/sockets are the right tool for anything time-sensitive"],"nextHint":"lesson_41_memoization.tsx -- Performance section begins","milestone":"NATIVE FEATURES SECTION COMPLETE."},{"num":41,"id":"lesson_41_memoization","filename":"lesson_41_memoization.tsx","title":"Memoization: Stopping Unnecessary Re-Renders","subtitle":"lesson 15 cached VALUES and FUNCTIONS. This lesson caches an entire COMPONENT's rendered output -- React.memo.","section":"Performance","color":"orange","mainCode":"// ================================================================\n//   LESSON 41 -- Memoization: Stopping Unnecessary Re-Renders\n//   Teaching philosophy: lesson 15 cached VALUES and FUNCTIONS.\n//                        This lesson caches an entire COMPONENT's\n//                        rendered output -- React.memo.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Recall the core re-render rule from lesson 04: when a parent\n//   re-renders, EVERY child it renders re-renders too, by default\n//   -- even children whose props didn't actually change.\n//\n//   For a list of 5 items, that's rarely a problem. For a FlatList\n//   of 500 complex rows, re-rendering ALL of them every time\n//   unrelated state changes (like a search box's text) can visibly\n//   slow the app down. React.memo lets a component SKIP\n//   re-rendering if its props are the same as last time.\n\n\n// ================================================================\n// PART 1 -- React.memo: Skipping Re-Renders With Unchanged Props\n// ================================================================\n//\n//   TRACE: a parent with an expensive child\n//   Step 1: WITHOUT memo -- every time \"search\" changes, BOTH the\n//           search box AND every ProductRow re-render, even though\n//           a single ProductRow's OWN props (item) never changed\n//   Step 2: WITH React.memo -- React compares the new props to the\n//           previous props (a shallow comparison, field by field)\n//   Step 3: if they're considered EQUAL, React reuses the PREVIOUS\n//           render output entirely, skipping the function call\n\nimport React, { useState } from \"react\";\nimport { View, Text, TextInput, FlatList } from \"react-native\";\n\ninterface Product { id: string; name: string; price: number; }\n\nconst ProductRow = React.memo(({ item }: { item: Product }) => {\n    console.log(\"Rendering row:\", item.name);   // watch how often this fires\n    return (\n        <View style={{ padding: 12 }}>\n            <Text>{item.name} -- ₹{item.price}</Text>\n        </View>\n    );\n});\n\nconst products: Product[] = [\n    { id: \"1\", name: \"Keyboard\", price: 1500 },\n    { id: \"2\", name: \"Mouse\", price: 600 },\n];\n\nconst ProductScreen = () => {\n    const [search, setSearch] = useState(\"\");   // unrelated to the rows themselves\n\n    return (\n        <View>\n            <TextInput value={search} onChangeText={setSearch} placeholder=\"Search (try typing)\" />\n            <FlatList data={products} keyExtractor={(p) => p.id} renderItem={({ item }) => <ProductRow item={item} />} />\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Type into the search box several times. Do the \"Rendering row\"\n// logs print again each time, or only on the FIRST render?    -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- The Function-Prop Trap (Why Lesson 15 Matters Here)\n// ================================================================\n//\n//   React.memo's shallow comparison checks if each prop is THE\n//   SAME VALUE as before. Objects and functions are compared by\n//   REFERENCE -- a brand new function created on every render\n//   (even with identical code inside) counts as \"different,\" which\n//   defeats React.memo entirely.\n//\n//   TRACE: a memo that DOESN'T actually skip anything\n//   Step 1: parent re-renders for any reason\n//   Step 2: onPress={() => handlePress(item.id)} creates a NEW\n//           function object every single render\n//   Step 3: ProductRow's \"onPress\" prop is now \"different\" by\n//           reference, even though it does the same thing\n//   Step 4: React.memo's comparison fails -> re-renders anyway\n\nconst BrokenMemoExample = ({ items }: { items: Product[] }) => {\n    const [count, setCount] = useState(0);\n    const handlePress = (id: string) => console.log(\"pressed\", id);\n\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => (\n                // NEW function every render -- breaks memoization below\n                <ProductRow item={item} />\n            )}\n        />\n    );\n};\n//\n//   The FIX: wrap handlePress in useCallback (lesson 15), so the\n//   SAME function reference is reused across renders -- THEN\n//   React.memo's comparison can actually succeed.\n\n\n// ================================================================\n// PART 3 -- A Custom Comparison Function (When Shallow Isn't Enough)\n// ================================================================\n//\n//   By default, React.memo does a SHALLOW comparison -- fine for\n//   primitives (strings, numbers, booleans) but NOT for nested\n//   objects, where two DIFFERENT object references might still\n//   contain the SAME data. React.memo accepts a second argument: a\n//   custom comparison function for exactly this case.\n\ninterface RowProps { item: Product; isSelected: boolean; }\n\nconst SelectableRow = React.memo(\n    ({ item, isSelected }: RowProps) => (\n        <View style={{ backgroundColor: isSelected ? \"#eef\" : \"white\", padding: 12 }}>\n            <Text>{item.name}</Text>\n        </View>\n    ),\n    (prevProps, nextProps) => {\n        // return true if props are EQUAL (skip re-render)\n        return prevProps.item.id === nextProps.item.id && prevProps.isSelected === nextProps.isSelected;\n    }\n);\n\n\n// ================================================================\n// PART 4 -- When NOT to Reach for React.memo\n// ================================================================\n//\n//   Same caution as lesson 15 PART 3 -- React.memo isn't free. It\n//   adds a comparison check on EVERY render. For simple, cheap\n//   components (a single Text, a small icon), the comparison can\n//   cost MORE than just re-rendering would have. Reach for it when:\n//   1. the component is genuinely expensive to render (complex\n//      layout, many children), AND\n//   2. it re-renders often with props that usually DON'T change\n//      (a classic case: rows in a long FlatList -- lesson 42 builds\n//      directly on this)","questionsCode":"// ================================================================\n// [QUESTIONS] -- React.memo compares props. Functions need useCallback too.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const Child = React.memo(({ value }: { value: number }) => {\n//     console.log(\"Child rendered\");\n//     return <Text>{value}</Text>;\n// });\n//\n// const Parent = () => {\n//     const [a, setA] = useState(0);\n//     const [b, setB] = useState(0);\n//     return (\n//         <View>\n//             <Child value={a} />\n//             <Pressable onPress={() => setB(b + 1)}><Text>Change B</Text></Pressable>\n//         </View>\n//     );\n// };\n//\n// Pressing \"Change B\" several times -- does \"Child rendered\" print\n// again each time? Why or why not, given Child only depends on \"a\"?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const Row = React.memo(({ item, onPress }) => (\n//       <Pressable onPress={onPress}><Text>{item.name}</Text></Pressable>\n//   ));\n//\n//   const List = ({ items }) => {\n//       const [count, setCount] = useState(0);\n//       return items.map((item) => (\n//           <Row key={item.id} item={item} onPress={() => handleSelect(item.id)} />\n//       ));\n//   };\n//\n// Bug -> ?  (hint: is Row's memoization actually doing anything\n// useful here, given how onPress is created?)\n// Fixed code (what would you wrap, and with what hook?):\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Memoized Cart Row\n//\n// PLAN: which props change rarely, and which (if any) change often?\n//\n// Build a CartRow component (showing name, qty, price * qty) wrapped\n// in React.memo, used inside a FlatList of 50+ hardcoded items.\n// Add an unrelated counter elsewhere on the same screen and confirm\n// (via console.log) that incrementing it does NOT re-render every row.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Fix a Broken Memoization\n//\n// PLAN: which two things need to change together for this to work?\n//\n// Take BrokenMemoExample from PART 2 and fix it properly: wrap\n// handlePress in useCallback (lesson 15) AND pass it down to\n// ProductRow as a prop, confirming via console.log that rows no\n// longer re-render when an unrelated piece of state changes.\n//\n// Write here:","takeaways":["React.memo(Component) -- skips re-rendering if props are shallow-equal","Functions/objects passed as props need useCallback/useMemo (lesson 15) to actually benefit from memoization -- otherwise it's a no-op","A custom (prevProps, nextProps) => boolean comparator handles deeper equality checks when shallow isn't enough","Only memo components that are BOTH expensive AND re-render often"],"nextHint":"lesson_42_flatlist_optimization.tsx -- applying this to real lists","milestone":""},{"num":42,"id":"lesson_42_flatlist_optimization","filename":"lesson_42_flatlist_optimization.tsx","title":"FlatList Optimization: Making Long Lists Smooth","subtitle":"lesson 07 taught FlatList's basic shape. This lesson tunes it for lists with hundreds or thousands of real items.","section":"Performance","color":"orange","mainCode":"// ================================================================\n//   LESSON 42 -- FlatList Optimization: Making Long Lists Smooth\n//   Teaching philosophy: lesson 07 taught FlatList's basic shape.\n//                        This lesson tunes it for lists with\n//                        hundreds or thousands of real items.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 07 explained FlatList already only renders what's near\n//   the visible screen, recycling rows as you scroll -- that's the\n//   BASELINE optimization, automatic. This lesson covers the\n//   SETTINGS and PATTERNS that matter once a list gets genuinely\n//   large (hundreds-to-thousands of rows) or rows get complex.\n\n\n// ================================================================\n// PART 1 -- keyExtractor and React.memo, Together\n// ================================================================\n//\n//   Lesson 07 already required keyExtractor (helps React track\n//   WHICH row is which across re-renders). Lesson 41's React.memo\n//   on the row component is the SINGLE highest-impact change for a\n//   long list -- combine both, always.\n\nimport React, { useState, useCallback } from \"react\";\nimport { View, Text, FlatList, Pressable } from \"react-native\";\n\ninterface Item { id: string; title: string; }\n\nconst Row = React.memo(({ item, onPress }: { item: Item; onPress: (id: string) => void }) => {\n    return (\n        <Pressable onPress={() => onPress(item.id)} style={{ padding: 12, borderBottomWidth: 1, borderColor: \"#eee\" }}>\n            <Text>{item.title}</Text>\n        </Pressable>\n    );\n});\n\nconst BigList = ({ items }: { items: Item[] }) => {\n    // useCallback (lesson 15) -- keeps the SAME function reference\n    // across renders, so Row's React.memo actually has a chance to work\n    const handlePress = useCallback((id: string) => {\n        console.log(\"pressed\", id);\n    }, []);\n\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => <Row item={item} onPress={handlePress} />}\n        />\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If handlePress were defined WITHOUT useCallback (a plain const\n// inside the component), would Row's React.memo still help at all?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- getItemLayout: Skipping Measurement Work\n// ================================================================\n//\n//   By default, FlatList measures each row's size AS it renders,\n//   to figure out scroll positions. If every row is the SAME fixed\n//   height, you can tell FlatList that size UP FRONT -- it skips\n//   the measurement step entirely, making scroll position\n//   calculations (like jumping to a specific index) instant.\n//\n//   TRACE: getItemLayout's three return values\n//   Step 1: length -- the row's height (must be FIXED/known ahead\n//           of time for this optimization to apply)\n//   Step 2: offset -- how far from the top this row starts --\n//           simply length * index, for a uniform list\n//   Step 3: index -- echoed back, matching the row being described\n\nconst ROW_HEIGHT = 56;\n\nconst FixedHeightList = ({ items }: { items: Item[] }) => {\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => (\n                <View style={{ height: ROW_HEIGHT, justifyContent: \"center\", padding: 12 }}>\n                    <Text>{item.title}</Text>\n                </View>\n            )}\n            getItemLayout={(data, index) => ({\n                length: ROW_HEIGHT,\n                offset: ROW_HEIGHT * index,\n                index,\n            })}\n        />\n    );\n};\n\n\n// ================================================================\n// PART 3 -- Tuning Render Windows (windowSize, initialNumToRender)\n// ================================================================\n//\n//   These props control HOW MUCH FlatList renders ahead of/behind\n//   the visible area -- a direct trade-off between \"smoother fast\n//   scrolling\" and \"more memory/CPU used at once.\"\n//\n//   initialNumToRender -- how many rows render on FIRST mount,\n//                         before any scrolling happens (lower = app\n//                         feels like it opens faster)\n//   windowSize          -- how many \"screens\" worth of content to\n//                         keep rendered around the visible area\n//                         (default 21 -- 10 above, 10 below, 1 visible)\n//   removeClippedSubviews -- detaches off-screen views from the\n//                         native view hierarchy entirely (Android\n//                         benefit mainly; test before/after, it can\n//                         occasionally cause visual glitches)\n\nconst TunedList = ({ items }: { items: Item[] }) => {\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => <Row item={item} onPress={() => {}} />}\n            initialNumToRender={10}\n            windowSize={5}\n            removeClippedSubviews\n        />\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Infinite Scroll: onEndReached (From Lesson 21's Pagination)\n// ================================================================\n//\n//   TRACE: loading more data as the user nears the bottom\n//   Step 1: onEndReachedThreshold: 0.5 -- fire onEndReached when\n//           the user scrolls within 50% of a screen's height from\n//           the bottom (a fraction of the list's visible length)\n//   Step 2: onEndReached calls your \"load next page\" function\n//           (lesson 21's pagination pattern)\n//   Step 3: NEW items get APPENDED to \"data,\" not replacing it\n//   Step 4: ListFooterComponent shows a spinner while loading more\n\nconst PaginatedList = ({\n    items, onLoadMore, loadingMore,\n}: { items: Item[]; onLoadMore: () => void; loadingMore: boolean }) => {\n    return (\n        <FlatList\n            data={items}\n            keyExtractor={(item) => item.id}\n            renderItem={({ item }) => <Text style={{ padding: 12 }}>{item.title}</Text>}\n            onEndReachedThreshold={0.5}\n            onEndReached={onLoadMore}\n            ListFooterComponent={loadingMore ? <Text style={{ padding: 12 }}>Loading more...</Text> : null}\n        />\n    );\n};","questionsCode":"// ================================================================\n// [QUESTIONS] -- memo the row, fix the height, tune the window, paginate the data.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A FlatList renders rows whose height varies wildly (some 40px,\n// some 200px depending on content length).\n//\n// Can you safely use getItemLayout for this list? Why or why not?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   <FlatList\n//       data={items}\n//       renderItem={({ item }) => <ExpensiveRow item={item} onPress={() => select(item.id)} />}\n//       getItemLayout={(data, index) => ({ length: 56, offset: index, index })}\n//   />\n//   // ExpensiveRow is wrapped in React.memo\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: check the offset math, and check\n// whether onPress actually lets React.memo do anything useful here)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Optimize an Existing List\n//\n// PLAN: which of this lesson's 4 techniques actually apply here?\n//\n// Take lesson 13's WeatherNotesApp's FlatList (watched cities) and\n// apply: a memoized row component, getItemLayout (assume a fixed\n// row height), and explain in a comment WHY onEndReached/pagination\n// would NOT be needed for this particular list.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Paginated API List\n//\n// PLAN: which lesson's fetch pattern feeds new pages into this list?\n//\n// Using lesson 21's apiClient and PaginatedList's shape, build a\n// screen fetching https://jsonplaceholder.typicode.com/posts with\n// a simulated page size of 10 (slice the full response), appending\n// 10 more posts each time onEndReached fires, up to the full 100.\n//\n// Write here:","takeaways":["keyExtractor + React.memo'd rows -- the highest-impact baseline combo","getItemLayout -- skip measurement, ONLY for fixed-height rows","initialNumToRender / windowSize -- tune render volume vs smoothness","onEndReached + onEndReachedThreshold -- the standard infinite-scroll pattern"],"nextHint":"lesson_43_lazy_loading.tsx -- loading code only when it's needed","milestone":""},{"num":43,"id":"lesson_43_lazy_loading","filename":"lesson_43_lazy_loading.tsx","title":"Lazy Loading: Don't Load What You're Not Showing Yet","subtitle":"lessons 41-42 made RENDERING cheaper. This lesson makes the initial APP STARTUP cheaper, by delaying work until it's needed.","section":"Performance","color":"orange","mainCode":"// ================================================================\n//   LESSON 43 -- Lazy Loading: Don't Load What You're Not Showing Yet\n//   Teaching philosophy: lessons 41-42 made RENDERING cheaper.\n//                        This lesson makes the initial APP STARTUP\n//                        cheaper, by delaying work until it's needed.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   By default, EVERY component/module you import gets bundled and\n//   loaded when the app starts -- even a settings screen, an admin\n//   panel, or a rarely-used feature the user might never open this\n//   session. For a small app this is invisible; for a large app,\n//   it can noticeably slow down the FIRST screen appearing.\n//\n//   Python analogy: importing a heavy library (e.g. pandas) at the\n//   TOP of a script makes the script slow to even START, even if\n//   that import is only used in one rarely-called function. You'd\n//   move the import INSIDE that function instead -- \"lazy import.\"\n//   React's lazy loading is the same idea, for components.\n\n\n// ================================================================\n// PART 1 -- React.lazy + Suspense: Loading a Component on Demand\n// ================================================================\n//\n//   TRACE: lazily loading a heavy screen\n//   Step 1: React.lazy(() => import(\"./HeavyScreen\")) -- this does\n//           NOT load HeavyScreen immediately. It creates a special\n//           component that loads it ONLY when first RENDERED\n//   Step 2: <Suspense fallback={<Spinner />}> wraps anywhere a lazy\n//           component might appear -- while it's loading, the\n//           fallback shows instead\n//   Step 3: once loaded, React swaps the fallback for the real\n//           component automatically -- no manual loading state needed\n\nimport React, { Suspense, useState } from \"react\";\nimport { View, Text, Pressable, ActivityIndicator } from \"react-native\";\n\n// const HeavyAnalyticsScreen = React.lazy(() => import(\"./HeavyAnalyticsScreen\"));\n// \"./HeavyAnalyticsScreen\" is a real, separate file in your project --\n// shown as a string path here purely to illustrate the import boundary\nconst HeavyAnalyticsScreen = () => <Text>Analytics data...</Text>;\n\nconst Dashboard = () => {\n    const [showAnalytics, setShowAnalytics] = useState(false);\n\n    return (\n        <View style={{ flex: 1 }}>\n            <Pressable onPress={() => setShowAnalytics(true)}>\n                <Text>Show Analytics</Text>\n            </Pressable>\n            {showAnalytics && (\n                <Suspense fallback={<ActivityIndicator />}>\n                    <HeavyAnalyticsScreen />\n                </Suspense>\n            )}\n        </View>\n    );\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Compare this to importing HeavyAnalyticsScreen normally at the\n// top of the file. WHEN does each version actually load that\n// screen's code -- app startup, or the moment \"Show Analytics\" is\n// pressed?                                                     -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Where Expo Router Already Does This For You\n// ================================================================\n//\n//   Good news: Expo Router (lesson 08) already lazy-loads screens\n//   by FILE, automatically -- each route in app/ is its own bundle\n//   chunk, loaded when first navigated to. You generally don't\n//   need React.lazy for whole SCREENS in an Expo Router app; this\n//   technique matters most for:\n//   - a heavy COMPONENT used conditionally within an already-loaded\n//     screen (e.g. PART 1's analytics panel, shown only on demand)\n//   - a heavy third-party library only needed for one feature\n\n\n// ================================================================\n// PART 3 -- Lazy-Loading a Heavy Library (Not Just a Component)\n// ================================================================\n//\n//   TRACE: deferring a heavy import until it's actually used\n//   Step 1: a chart-rendering library might be large -- importing\n//           it at the top of EVERY screen's file slows down\n//           startup for users who never view a chart\n//   Step 2: a DYNAMIC import() (note: a function call, not the\n//           static \"import X from Y\" syntax) returns a Promise,\n//           resolved only when called\n//   Step 3: call it inside an event handler or useEffect, only\n//           when the chart is actually about to be shown\n\nconst loadChartLibrary = async () => {\n    // const ChartModule = await import(\"some-chart-library\");\n    // \"some-chart-library\" is a real, heavy third-party package --\n    // shown as a string path here purely to illustrate dynamic import()\n    await new Promise((resolve) => setTimeout(resolve, 500));   // stand-in for the load\n};\n\nconst ChartButton = () => {\n    const [ready, setReady] = useState(false);\n\n    const handleShowChart = async () => {\n        await loadChartLibrary();   // only downloaded/parsed NOW\n        setReady(true);\n    };\n\n    return (\n        <View>\n            <Pressable onPress={handleShowChart}><Text>Load Chart</Text></Pressable>\n            {ready && <Text>Chart library loaded!</Text>}\n        </View>\n    );\n};\n\n\n// ================================================================\n// PART 4 -- Lazy Loading vs the Performance Work From Lessons 41-42\n// ================================================================\n//\n//   These are solving DIFFERENT bottlenecks -- know which one\n//   applies to a given slowness you're investigating:\n//\n//   Slow APP STARTUP / slow first screen     -> lazy loading (this lesson)\n//   Slow/janky SCROLLING through a long list -> FlatList tuning (lesson 42)\n//   Wasted RE-RENDERS on unrelated state      -> memoization (lesson 41)\n//\n//   Applying the WRONG fix (e.g. React.memo-ing a startup-time\n//   problem) won't help -- diagnose which bottleneck you actually have.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Delay loading until something is actually shown/used.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const Heavy = React.lazy(() => import(\"./Heavy\"));\n//\n// <Suspense fallback={<Text>Loading...</Text>}>\n//     {someCondition && <Heavy />}\n// </Suspense>\n//\n// If someCondition is false on initial render, does Heavy's module\n// get downloaded/loaded at all yet?                            -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the bug)\n//\n//   const Settings = React.lazy(() => import(\"./Settings\"));\n//\n//   const App = () => (\n//       <View>\n//           <Settings />\n//       </View>\n//   );\n//\n// Bug -> ?  (hint: what's REQUIRED around any lazy component?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Identify the Right Tool\n//\n// For each scenario, name which lesson's technique (41 memoization,\n// 42 FlatList tuning, or 43 lazy loading) actually addresses it,\n// and why the other two wouldn't help:\n//   a) The app takes 4 seconds to show its first screen\n//   b) Scrolling a 2000-row list stutters noticeably\n//   c) Typing in an unrelated search box re-renders 50 list rows\n//      that didn't change\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Lazy-Loaded Modal Feature\n//\n// PLAN: what's shown WHILE the heavy modal's code is loading?\n//\n// Build a \"Report a Bug\" feature: a button that, when pressed,\n// lazily loads a (conceptually) heavy BugReportModal component\n// (with a Suspense fallback spinner), rather than bundling it with\n// the main screen from the start.\n//\n// Write here:","takeaways":["React.lazy(() => import(...)) -- loads a component on first render","<Suspense fallback={...}> -- REQUIRED wrapper, shown while loading","Expo Router already lazy-loads whole screens by file automatically","Dynamic import() -- defers loading a heavy LIBRARY, not just a component","Match the fix to the bottleneck: startup vs scrolling vs re-renders"],"nextHint":"lesson_44_image_optimization.tsx -- the most common real culprit","milestone":""},{"num":44,"id":"lesson_44_image_optimization","filename":"lesson_44_image_optimization.tsx","title":"Image Optimization: The Most Common Real Culprit","subtitle":"in real apps, unoptimized IMAGES cause more visible slowness than almost anything else covered in lessons 41-43 combined.","section":"Performance","color":"orange","mainCode":"// ================================================================\n//   LESSON 44 -- Image Optimization: The Most Common Real Culprit\n//   Teaching philosophy: in real apps, unoptimized IMAGES cause\n//                        more visible slowness than almost anything\n//                        else covered in lessons 41-43 combined.\n// ================================================================\n//   Before starting: npx expo install expo-image\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   A 4000x3000 pixel photo straight from a camera, displayed in a\n//   100x100 thumbnail, still costs the DEVICE memory and decode\n//   time as if it were full-size -- React Native doesn't \"shrink\"\n//   the underlying decoded image just because you styled it smaller.\n//   This is the single most common performance issue in real apps:\n//   loading images far larger than they're ever displayed at.\n\n\n// ================================================================\n// PART 1 -- expo-image vs the Built-In Image Component\n// ================================================================\n//\n//   React Native's built-in <Image> works, but expo-image is a\n//   drop-in replacement with MUCH better defaults: automatic\n//   caching (memory AND disk), smoother loading transitions, and\n//   better large-image handling out of the box.\n\nimport { Image } from \"expo-image\";\nimport { View, Text } from \"react-native\";\n\nconst ProfilePhoto = ({ uri }: { uri: string }) => {\n    return (\n        <Image\n            source={{ uri }}\n            style={{ width: 80, height: 80, borderRadius: 40 }}\n            contentFit=\"cover\"\n            transition={200}     // smooth fade-in once loaded\n        />\n    );\n};\n//\n//   contentFit=\"cover\" -- TRACE: how this differs from \"contain\"\n//   Step 1: \"cover\" -- fills the given width/height entirely,\n//           cropping overflow (most common choice for avatars/thumbnails)\n//   Step 2: \"contain\" -- fits the WHOLE image inside the given\n//           size, may leave empty space (better for logos, diagrams)\n\n// ── PREDICT before running ──────────────────────────────────────\n// If a 4000x3000 photo is requested with style width:80, height:80,\n// does expo-image automatically request a SMALLER version from a\n// remote server, or does it download the full original?       -> ?\n// (Hint: this depends on what URL you actually pass it -- see PART 2.)\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Requesting an Appropriately-Sized Image From the Server\n// ================================================================\n//\n//   The single biggest win: don't make the DEVICE resize a huge\n//   image -- ask the SERVER for an already-small one. Many image\n//   hosting services (Cloudinary, Imgix, and similar) support\n//   resizing via URL parameters.\n//\n//   Original:  https://images.example.com/photo123.jpg\n//   Resized:   https://images.example.com/photo123.jpg?w=200&h=200\n//\n//   TRACE: why this matters more than any client-side technique\n//   Step 1: WITHOUT resizing -- device downloads 4MB, decodes a\n//           huge bitmap, THEN displays it shrunk to 80x80\n//   Step 2: WITH server resizing -- device downloads ~10KB,\n//           decodes a small bitmap that's ALREADY close to 80x80\n//   Step 3: massive savings in network data, memory, and decode time\n\nconst buildResizedUrl = (baseUrl: string, width: number, height: number) => {\n    return `${baseUrl}?w=${width}&h=${height}`;\n};\n\nconst Thumbnail = ({ baseUrl }: { baseUrl: string }) => (\n    <Image source={{ uri: buildResizedUrl(baseUrl, 100, 100) }} style={{ width: 50, height: 50 }} contentFit=\"cover\" />\n);\n\n\n// ================================================================\n// PART 3 -- Caching Policy\n// ================================================================\n//\n//   expo-image caches by default, but you can be explicit about\n//   the strategy depending on the use case.\n//\n//   cachePolicy=\"memory-disk\" (default) -- fastest repeat loads,\n//                              survives app restarts (disk)\n//   cachePolicy=\"memory\"                -- faster than network, but\n//                              cleared when the app closes\n//   cachePolicy=\"none\"                  -- always re-fetch (rare;\n//                              only for content that changes every load)\n\nconst CachedAvatar = ({ uri }: { uri: string }) => (\n    <Image source={{ uri }} style={{ width: 60, height: 60 }} cachePolicy=\"memory-disk\" />\n);\n\n\n// ================================================================\n// PART 4 -- Placeholders: Perceived Speed Matters Too\n// ================================================================\n//\n//   A blank space while loading FEELS slower than a placeholder,\n//   even if the actual load time is identical. expo-image supports\n//   a low-res \"blurhash\" placeholder -- a tiny encoded string\n//   representing a blurred preview, shown instantly while the real\n//   image loads in.\n\nconst ImageWithPlaceholder = ({ uri }: { uri: string }) => (\n    <Image\n        source={{ uri }}\n        placeholder={{ blurhash: \"L6PZfSi_.AyE_3t7t7R**0o#DgR4\" }}\n        style={{ width: 300, height: 200 }}\n        contentFit=\"cover\"\n        transition={300}\n    />\n);\n\n\n// ================================================================\n// PART 5 -- FlatList of Images: Combining With Lesson 42\n// ================================================================\n//\n//   A photo gallery FlatList combines EVERYTHING from this section:\n//   memoized rows (lesson 41), getItemLayout for fixed thumbnail\n//   sizes (lesson 42), AND appropriately-sized image URLs (this lesson).\n\nimport React from \"react\";\nimport { FlatList } from \"react-native\";\n\ninterface Photo { id: string; thumbUrl: string; }\n\nconst PhotoRow = React.memo(({ photo }: { photo: Photo }) => (\n    <Image source={{ uri: photo.thumbUrl }} style={{ width: 100, height: 100, margin: 4 }} contentFit=\"cover\" />\n));\n\nconst Gallery = ({ photos }: { photos: Photo[] }) => (\n    <FlatList\n        data={photos}\n        keyExtractor={(p) => p.id}\n        numColumns={3}\n        renderItem={({ item }) => <PhotoRow photo={item} />}\n    />\n);","questionsCode":"// ================================================================\n// [QUESTIONS] -- Ask the server for the right size. Cache deliberately.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A gallery screen shows 100 photos, each requested at full\n// original resolution (several MB each) but displayed as 80x80\n// thumbnails.\n//\n// What 2 specific costs does this impose on the device, beyond\n// just \"it's slower\"?                                          -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the missed optimization)\n//\n//   const Avatar = ({ uri }) => (\n//       <Image source={{ uri }} style={{ width: 40, height: 40 }} />\n//   );\n//   // \"uri\" always points at the user's full original uploaded photo\n//\n// Bug -> ?  (not a syntax bug -- a missed opportunity from PART 2)\n// Fixed approach:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Resized Avatar Component\n//\n// PLAN: which prop determines the actual size requested from the server?\n//\n// Build an Avatar component taking { baseUrl, size } props, using\n// buildResizedUrl to request an image at exactly \"size x size\"\n// (times maybe 2 for retina screens), styled at \"size\" points.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Photo Gallery With Placeholders\n//\n// PLAN: what should show INSTANTLY, before any real image has loaded?\n//\n// Build Gallery (PART 5) so each PhotoRow shows a blurhash\n// placeholder while loading, uses cachePolicy=\"memory-disk\", and\n// requests a properly small size via buildResizedUrl rather than\n// each photo's full original URL.\n//\n// Write here:","takeaways":["expo-image -- better defaults than the built-in Image: caching, transitions, placeholders","Request an appropriately SIZED image from the server -- the single biggest win, bigger than any client-side trick","cachePolicy=\"memory-disk\" -- avoid re-downloading the same image","blurhash placeholders -- improve PERCEIVED speed while loading"],"nextHint":"lesson_45_jest_basics.tsx -- Testing section begins","milestone":"PERFORMANCE SECTION COMPLETE."},{"num":45,"id":"lesson_45_jest_basics","filename":"lesson_45_jest_basics.tsx","title":"Jest Basics: Automated Checking, Not Manual Tapping","subtitle":"a test is just a function that runs your code and CHECKS the result, automatically -- the same instinct as your \"PREDICT\" exercises throughout this course, but verified by the computer instead of by you.","section":"Testing","color":"lime","mainCode":"// ================================================================\n//   LESSON 45 -- Jest Basics: Automated Checking, Not Manual Tapping\n//   Teaching philosophy: a test is just a function that runs your\n//                        code and CHECKS the result, automatically\n//                        -- the same instinct as your \"PREDICT\"\n//                        exercises throughout this course, but\n//                        verified by the computer instead of by you.\n// ================================================================\n//   Before starting: npx expo install jest-expo jest --save-dev\n//   (Expo projects come with a working jest preset, \"jest-expo\")\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every \"PREDICT before running\" box in this course asked you to\n//   guess an output, then verify it by actually running the code.\n//   Doing that manually, every time, for every function, in a real\n//   app with hundreds of functions, doesn't scale. Jest automates\n//   exactly that loop:\n//\n//   1. Run a piece of code with known inputs\n//   2. Assert what the output SHOULD be\n//   3. Jest tells you PASS or FAIL, instantly, for the whole\n//      codebase, every time you make a change\n//\n//   Python analogy: this is the same role as Python's unittest/\n//   pytest -- arrange inputs, act (call the function), assert the\n//   result matches expectations.\n\n\n// ================================================================\n// PART 1 -- Your First Test: describe, it, expect\n// ================================================================\n//\n//   TRACE: the anatomy of a test file\n//   Step 1: describe(\"group name\", fn) -- groups related tests\n//           together (purely organizational, like a class in unittest)\n//   Step 2: it(\"description\", fn) -- ONE individual test case\n//           (also written as test(...) -- both work identically)\n//   Step 3: expect(actual).toBe(expected) -- the actual assertion --\n//           Jest compares the two and reports pass/fail\n\n// ---- utils/math.ts ----\nexport const add = (a: number, b: number): number => a + b;\nexport const isEven = (n: number): boolean => n % 2 === 0;\n\n// ---- utils/math.test.ts ----\n// import { add, isEven } from \"./math\";   // a real, separate file --\n// the functions are defined above only so this lesson is self-contained\n\ndescribe(\"add\", () => {\n    it(\"adds two positive numbers\", () => {\n        expect(add(2, 3)).toBe(5);\n    });\n\n    it(\"handles negative numbers\", () => {\n        expect(add(-1, -1)).toBe(-2);\n    });\n});\n\ndescribe(\"isEven\", () => {\n    it(\"returns true for even numbers\", () => {\n        expect(isEven(4)).toBe(true);\n    });\n    it(\"returns false for odd numbers\", () => {\n        expect(isEven(7)).toBe(false);\n    });\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you wrote expect(add(2, 3)).toBe(6) (a WRONG expectation),\n// what would running these tests show -- a runtime crash in your\n// app, or something else entirely?                             -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Common Matchers (Beyond toBe)\n// ================================================================\n//\n//   toBe(value)          -- exact equality (===), for primitives\n//   toEqual(value)        -- deep equality, for objects/arrays\n//                           (toBe would fail on two DIFFERENT\n//                           object references holding the same data)\n//   toBeNull() / toBeUndefined()\n//   toBeTruthy() / toBeFalsy()\n//   toThrow()             -- asserts a function throws an error\n//   toContain(item)        -- array/string contains a value\n\nconst formatUser = (name: string, age: number) => ({ name, age });\n\ntest(\"formatUser returns the right shape\", () => {\n    expect(formatUser(\"Sarath\", 25)).toEqual({ name: \"Sarath\", age: 25 });\n    // NOT toBe -- two separately-created objects are never === equal,\n    // even with identical contents (same reasoning as lesson 04's\n    // \"never mutate state in place\" object comparison rules)\n});\n\nconst divide = (a: number, b: number) => {\n    if (b === 0) throw new Error(\"Cannot divide by zero\");\n    return a / b;\n};\n\ntest(\"divide throws on zero\", () => {\n    expect(() => divide(10, 0)).toThrow(\"Cannot divide by zero\");\n    // note the () => -- you pass a FUNCTION to toThrow, so Jest can\n    // call it itself and catch the error; calling divide(10, 0)\n    // directly inside expect() would throw BEFORE Jest can check it\n});\n\n\n// ================================================================\n// PART 3 -- Testing Async Code (Connects to Lesson 10)\n// ================================================================\n//\n//   Just like your component code, test functions can be async --\n//   await the same way you would anywhere else.\n\nconst fetchUserName = async (id: number): Promise<string> => {\n    const response = await fetch(`https://jsonplaceholder.typicode.com/users/${id}`);\n    const data = await response.json();\n    return data.name;\n};\n\ntest(\"fetchUserName returns a string\", async () => {\n    const name = await fetchUserName(1);\n    expect(typeof name).toBe(\"string\");\n});\n//\n//   NOTE: hitting a REAL network in tests is usually discouraged in\n//   real projects (slow, flaky, costs quota) -- production test\n//   suites typically MOCK fetch instead. This example keeps things\n//   simple and consistent with lesson 10's real API; mocking is a\n//   natural next step once you're comfortable with the basics here.\n\n\n// ================================================================\n// PART 4 -- beforeEach: Resetting State Between Tests\n// ================================================================\n//\n//   TRACE: why shared setup needs to be isolated per test\n//   Step 1: WITHOUT beforeEach -- if test A modifies some shared\n//           object, test B might unexpectedly see A's leftover changes\n//   Step 2: beforeEach(fn) runs FRESH before EVERY single test in\n//           its describe block -- guaranteeing a clean starting point\n\nlet cart: { items: string[] };\n\nbeforeEach(() => {\n    cart = { items: [] };\n});\n\nconst addToCart = (item: string) => cart.items.push(item);\n\ntest(\"cart starts empty\", () => {\n    expect(cart.items).toEqual([]);\n});\n\ntest(\"addToCart adds an item\", () => {\n    addToCart(\"Keyboard\");\n    expect(cart.items).toContain(\"Keyboard\");\n});\n// Without beforeEach resetting cart, the second test would start\n// with whatever leftover state the FIRST test left behind.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Tests verify behavior automatically, every time.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// test(\"string check\", () => {\n//     expect(\"5\" + 5).toBe(55);\n// });\n//\n// Does this test PASS or FAIL? What does \"5\" + 5 actually evaluate\n// to in JS (recall lesson 06's note about onChangeText)?       -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   test(\"user object matches\", () => {\n//       const user = { name: \"Asha\", age: 30 };\n//       expect(user).toBe({ name: \"Asha\", age: 30 });\n//   });\n//\n//   test(\"throws on bad input\", () => {\n//       expect(divide(5, 0)).toThrow();\n//   });\n//\n// Bug 1 -> ?   Bug 2 -> ?\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Write Tests for a Pure Function\n//\n// PLAN: what are the EDGE cases worth testing, not just the happy path?\n//\n// Write a function isValidEmail(email: string): boolean (simple\n// check: contains \"@\" and a \".\" after it). Write at least 4 tests:\n// a valid email, a missing \"@\", an empty string, and an email with\n// no \".\" after the \"@\".\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Write Tests for the Cart Logic\n//\n// PLAN: which behaviors of a cart matter enough to lock in with a test?\n//\n// Building on PART 4's cart, add a removeFromCart(item) function\n// and a getTotal(prices: Record<string, number>) function. Write\n// tests (with beforeEach resetting cart) covering: adding multiple\n// items, removing an item that exists, removing one that doesn't,\n// and computing a correct total.\n//\n// Write here:","takeaways":["describe -- groups tests | it/test -- one test case | expect -- the assertion","toBe -- exact equality (primitives) | toEqual -- deep equality (objects)","expect(() => fn()).toThrow() -- wrap in a function so Jest can catch it","beforeEach -- fresh, isolated state before every test"],"nextHint":"lesson_46_react_native_testing_library.tsx -- testing components, not just functions","milestone":""},{"num":46,"id":"lesson_46_react_native_testing_library","filename":"lesson_46_react_native_testing_library.tsx","title":"React Native Testing Library: Testing Components","subtitle":"lesson 45 tested plain functions. RNTL tests components the way a USER experiences them -- what's on screen, what happens when you tap something -- not internal implementation.","section":"Testing","color":"lime","mainCode":"// ================================================================\n//   LESSON 46 -- React Native Testing Library: Testing Components\n//   Teaching philosophy: lesson 45 tested plain functions. RNTL\n//                        tests components the way a USER experiences\n//                        them -- what's on screen, what happens when\n//                        you tap something -- not internal implementation.\n// ================================================================\n//   Before starting: npx expo install @testing-library/react-native --save-dev\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   You COULD test a component by inspecting its internal state\n//   directly -- but that ties your tests to implementation details\n//   that might change even when the user-visible BEHAVIOR doesn't\n//   (e.g. renaming a state variable). RNTL's philosophy: query the\n//   screen the way a real user would (find text, find a button by\n//   its label) and interact with it the way a user would (press,\n//   type) -- exactly mirroring how YOU manually tested every\n//   component throughout this course, just automated.\n\n\n// ================================================================\n// PART 1 -- render and screen Queries\n// ================================================================\n//\n//   TRACE: testing a simple counter (lesson 04's Counter)\n//   Step 1: render(<Counter />) -- mounts the component in a test\n//           environment, similar to what Expo Go does on a real device\n//   Step 2: screen.getByText(...) -- finds an element by its visible\n//           text, throwing a clear error if it's not found at all\n//   Step 3: fireEvent.press(button) -- simulates a real tap\n//   Step 4: re-query AFTER the press, to confirm the UI actually updated\n\nimport React, { useState } from \"react\";\nimport { View, Text, Pressable } from \"react-native\";\nimport { render, screen, fireEvent } from \"@testing-library/react-native\";\n\nconst Counter = () => {\n    const [count, setCount] = useState(0);\n    return (\n        <View>\n            <Text>Count: {count}</Text>\n            <Pressable onPress={() => setCount(count + 1)}>\n                <Text>Increment</Text>\n            </Pressable>\n        </View>\n    );\n};\n\ntest(\"Counter starts at 0 and increments on press\", () => {\n    render(<Counter />);\n\n    expect(screen.getByText(\"Count: 0\")).toBeTruthy();\n\n    fireEvent.press(screen.getByText(\"Increment\"));\n\n    expect(screen.getByText(\"Count: 1\")).toBeTruthy();\n});\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you pressed \"Increment\" TWICE in this test before the final\n// expect, what text would you need to query for instead of\n// \"Count: 1\"?                                                  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Querying Inputs (Connecting to Lesson 06)\n// ================================================================\n//\n//   getByPlaceholderText -- finds a TextInput by its placeholder,\n//                           the same way a user visually identifies one\n//   fireEvent.changeText -- simulates typing, calling onChangeText\n//                           exactly like a real keystroke would\n\nconst NameForm = () => {\n    const [name, setName] = useState(\"\");\n    return (\n        <View>\n            <Text>{name === \"\" ? \"No name yet\" : `Hello, ${name}`}</Text>\n            <Text accessibilityRole=\"none\">{/* placeholder for layout */}</Text>\n            <TextInputStub value={name} onChangeText={setName} />\n        </View>\n    );\n};\nimport { TextInput } from \"react-native\";\nconst TextInputStub = TextInput;   // alias for clarity in this lesson's example\n\ntest(\"typing a name updates the greeting\", () => {\n    render(<NameForm />);\n\n    expect(screen.getByText(\"No name yet\")).toBeTruthy();\n\n    fireEvent.changeText(screen.getByDisplayValue(\"\"), \"Sarath\");\n\n    expect(screen.getByText(\"Hello, Sarath\")).toBeTruthy();\n});\n\n\n// ================================================================\n// PART 3 -- Testing Conditional Rendering (Connecting to Lesson 04)\n// ================================================================\n//\n//   queryByText (note: \"query\", not \"get\") -- returns NULL if not\n//   found, instead of throwing an error. Use \"get\" when you EXPECT\n//   something to exist (failing loudly if it's missing is useful),\n//   use \"query\" when you're specifically checking something does\n//   NOT exist -- \"get\" would crash the test before you even reach\n//   your assertion in that case.\n\nconst Toggleable = () => {\n    const [visible, setVisible] = useState(false);\n    return (\n        <View>\n            <Pressable onPress={() => setVisible((v) => !v)}>\n                <Text>{visible ? \"Hide\" : \"Show\"}</Text>\n            </Pressable>\n            {visible && <Text>Secret message</Text>}\n        </View>\n    );\n};\n\ntest(\"secret message only shows after pressing Show\", () => {\n    render(<Toggleable />);\n\n    expect(screen.queryByText(\"Secret message\")).toBeNull();\n\n    fireEvent.press(screen.getByText(\"Show\"));\n\n    expect(screen.getByText(\"Secret message\")).toBeTruthy();\n});\n\n\n// ================================================================\n// PART 4 -- Mocking fetch (Testing Components That Load Data)\n// ================================================================\n//\n//   Lesson 45 noted real network calls in tests are usually\n//   avoided. jest.fn() creates a FAKE function you control\n//   completely -- here, replacing global.fetch so the test runs\n//   instantly and predictably, without any real network involved.\n//\n//   TRACE: mocking a fetch-based component (lesson 10's pattern)\n//   Step 1: global.fetch = jest.fn(() => Promise.resolve(fakeResponse))\n//   Step 2: the component calls fetch exactly like it would for real\n//           -- it has NO idea it's talking to a fake\n//   Step 3: findByText (note: \"find\", not \"get\") -- WAITS for async\n//           UI updates, since the component needs a moment to fetch\n//           and re-render after loading=false (lesson 10's pattern)\n\nconst UserGreeting = () => {\n    const [name, setName] = useState<string | null>(null);\n    React.useEffect(() => {\n        fetch(\"https://api.example.com/me\")\n            .then((res) => res.json())\n            .then((data) => setName(data.name));\n    }, []);\n    if (!name) return <Text>Loading...</Text>;\n    return <Text>Welcome, {name}</Text>;\n};\n\ntest(\"UserGreeting shows the fetched name\", async () => {\n    global.fetch = jest.fn(() =>\n        Promise.resolve({ json: () => Promise.resolve({ name: \"Asha\" }) })\n    ) as any;\n\n    render(<UserGreeting />);\n\n    expect(screen.getByText(\"Loading...\")).toBeTruthy();\n\n    const greeting = await screen.findByText(\"Welcome, Asha\");\n    expect(greeting).toBeTruthy();\n});","questionsCode":"// ================================================================\n// [QUESTIONS] -- Query like a user. Interact like a user. Mock the network.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// render(<Toggleable />);\n// screen.getByText(\"Secret message\");\n//\n// Called IMMEDIATELY after render, with no press first -- does\n// this line throw an error, or return null quietly?            -> ?\n// Which query (getByText vs queryByText) would you use INSTEAD\n// to safely check it's absent?                                 -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   test(\"shake updates count\", () => {\n//       render(<Counter />);\n//       fireEvent.press(screen.getByText(\"increment\"));\n//       expect(screen.getByText(\"Count: 1\"));\n//   });\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: text casing matters for getByText,\n// and is this expect() actually asserting anything?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Test the Login Form (Connecting to Lesson 06/23)\n//\n// PLAN: which queries find the email/password fields and the button?\n//\n// Write a test for a simplified login form (email + password\n// TextInputs, a \"Log In\" Pressable) verifying: typing invalid\n// values and pressing \"Log In\" shows an error Text; typing valid\n// values and pressing it does NOT show that error.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Test a Mocked API List (Connecting to Lesson 10)\n//\n// PLAN: what should the fake fetch response contain, and what\n// should the rendered FlatList show as a result?\n//\n// Build and test a simplified PostList component (lesson 10):\n// mock global.fetch to resolve with 2 fake posts, render the\n// component, and use findByText (it's async) to confirm both post\n// titles eventually appear on screen.\n//\n// Write here:","takeaways":["render(<Component />) -- mounts it in a test environment","getByText/getByPlaceholderText -- throws if not found | queryByText -- returns null if not found | findByText -- async, WAITS for it","fireEvent.press / fireEvent.changeText -- simulate real user actions","jest.fn() can replace global.fetch -- test async components without a real network call"],"nextHint":"lesson_47_android_deployment.tsx -- Deployment section begins","milestone":"TESTING SECTION COMPLETE."},{"num":47,"id":"lesson_47_android_deployment","filename":"lesson_47_android_deployment.tsx","title":"Android Deployment: APK, AAB, and the Play Store","subtitle":"lesson 14 already built a \"preview\" app file. This lesson covers the FULL path to a real Play Store listing, end to end.","section":"Deployment","color":"indigo","mainCode":"// ================================================================\n//   LESSON 47 -- Android Deployment: APK, AAB, and the Play Store\n//   Teaching philosophy: lesson 14 already built a \"preview\" app\n//                        file. This lesson covers the FULL path to\n//                        a real Play Store listing, end to end.\n// ================================================================\n//   Before starting: a Google Play Developer account (one-time\n//   $25 USD registration fee), and eas-cli installed (lesson 14)\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Lesson 14 distinguished build PROFILES: development, preview,\n//   production. This lesson is entirely about the \"production\"\n//   profile and what happens to that file AFTER it's built --\n//   the part lesson 14 deferred.\n//\n//   Two Android file formats matter, and they serve DIFFERENT purposes:\n//\n//   .apk -- a single installable package, ready to run on any\n//           device directly. Good for: manual installs, sharing\n//           outside the Play Store (lesson 14's preview profile).\n//   .aab (Android App Bundle) -- NOT directly installable. You\n//           upload this to the Play Store, and GOOGLE generates\n//           optimized, device-specific APKs from it for each user\n//           (smaller downloads, since a user's exact phone model/\n//           architecture gets only what it needs).\n//\n//   The Play Store REQUIRES .aab for new app submissions -- .apk\n//   alone is no longer accepted for new listings.\n\n\n// ================================================================\n// PART 1 -- Building a Production AAB\n// ================================================================\n//\n//   TRACE: the production build command\n//   Step 1: eas.json's \"production\" profile (lesson 14 PART 5)\n//           is typically configured with android: { buildType: \"app-bundle\" }\n//   Step 2: eas build --platform android --profile production\n//   Step 3: EAS builds in the cloud, signs the app with a managed\n//           signing key (or your own, if configured), and gives you\n//           a download link to the finished .aab\n//\n//   eas build --platform android --profile production\n//\n//   // eas.json (relevant excerpt)\n//   {\n//     \"build\": {\n//       \"production\": {\n//         \"android\": { \"buildType\": \"app-bundle\" }\n//       }\n//     }\n//   }\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you upload an .apk (instead of .aab) to a brand NEW Play\n// Store listing, what do you expect the Play Console to do?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- App Signing: Why It Matters\n// ================================================================\n//\n//   Every Android app is cryptographically SIGNED -- this proves\n//   updates genuinely come from the same developer as the original\n//   install (similar trust reasoning to lesson 22's JWT signatures,\n//   just for app binaries instead of API tokens).\n//\n//   TRACE: why losing your signing key is a serious problem\n//   Step 1: your FIRST production build generates (or uses) a\n//           signing key\n//   Step 2: every FUTURE update must be signed with the SAME key\n//   Step 3: if you lose it, you cannot publish updates to your\n//           EXISTING app listing -- you'd need an entirely new one\n//   Step 4: EAS, by default, manages this key for you SECURELY and\n//           keeps it associated with your project -- you generally\n//           don't need to handle key files manually\n\n\n// ================================================================\n// PART 3 -- Versioning: versionCode and version\n// ================================================================\n//\n//   // app.json\n//   {\n//     \"expo\": {\n//       \"version\": \"1.0.0\",              // human-readable, shown to users\n//       \"android\": {\n//         \"versionCode\": 1                 // MUST increase every submission\n//       }\n//     }\n//   }\n//\n//   TRACE: why TWO different version numbers exist\n//   Step 1: \"version\" (1.0.0, 1.0.1...) -- for HUMANS, shown in the\n//           Play Store listing, follows whatever convention you like\n//   Step 2: \"versionCode\" (1, 2, 3...) -- for the PLAY STORE itself,\n//           a plain integer that MUST strictly increase with every\n//           single submission, or the upload will be REJECTED\n//   Step 3: EAS can auto-increment versionCode for you, if configured\n//           (eas.json's \"autoIncrement\" setting)\n\n\n// ================================================================\n// PART 4 -- Submitting to the Play Store\n// ================================================================\n//\n//   TRACE: the submission flow\n//   Step 1: eas submit --platform android -- uploads your built\n//           .aab directly to the Play Console (using a Google\n//           service account key you set up once)\n//   Step 2: in the Play Console, fill out the STORE LISTING: app\n//           name, description, screenshots, privacy policy URL\n//           (REQUIRED if your app collects any user data -- and\n//           given lessons 22-26's auth flow, yours likely does)\n//   Step 3: choose a release track: Internal testing -> Closed\n//           testing -> Open testing -> Production -- each tier\n//           reaches progressively more real users\n//   Step 4: Google reviews the submission (can take hours to days)\n//           before it goes live on the chosen track\n//\n//   eas submit --platform android\n\n\n// ================================================================\n// PART 5 -- Release Tracks: Why Not Ship Straight to Production\n// ================================================================\n//\n//   Internal testing -- a small, hand-picked list of testers (you,\n//                       teammates) -- fastest to set up, instant access\n//   Closed testing    -- a larger but still invite-only group\n//   Open testing       -- anyone with the link can opt in (a public beta)\n//   Production         -- visible to everyone searching the Play Store\n//\n//   Shipping straight to Production skips the chance to catch\n//   crashes/bugs with a SMALL audience first -- the same caution as\n//   testing locally (lessons 45-46) before trusting code in production.","questionsCode":"// ================================================================\n// [QUESTIONS] -- .aab for the Store. versionCode always increases.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// Your app.json has \"versionCode\": 3, already live on the Play\n// Store. You build and submit a new update, but FORGET to bump it,\n// leaving it at 3.\n//\n// What do you expect the Play Console to do with this submission?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake in this release plan)\n//\n//   1. Build with eas build --platform android --profile production\n//   2. Download the resulting file\n//   3. Create a brand-new Play Store listing\n//   4. Upload the downloaded .apk directly\n//   5. Submit for review\n//\n// Bug -> ?  (which file format does step 1's production profile\n// need to produce, for step 4 to even be accepted?)\n// Fixed plan:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Plan a Staged Rollout\n//\n// PLAN: which track should each stage use, and in what order?\n//\n// You're releasing the Weather Notes app (lesson 13) for the first\n// time. Write out a release plan using AT LEAST 2 different tracks\n// before reaching Production, explaining what you'd be checking\n// for at each stage.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Prepare a Real Submission Checklist\n//\n// PLAN: what does the Play Console require beyond just the binary?\n//\n// List everything you'd need ready BEFORE running eas submit for a\n// real app: required app.json fields, store listing assets, and\n// policy requirements (hint: think about lesson 23's login flow --\n// what does collecting emails/passwords obligate you to provide?).\n//\n// Write here:","takeaways":[".apk -- directly installable | .aab -- required for Play Store submissions, Google generates optimized APKs from it","versionCode -- a plain integer, MUST increase every submission","eas build --profile production, then eas submit --platform android","Release tracks: Internal -> Closed -> Open -> Production -- stage your rollout, don't skip straight to everyone"],"nextHint":"lesson_48_ios_deployment.tsx -- TestFlight and the App Store","milestone":""},{"num":48,"id":"lesson_48_ios_deployment","filename":"lesson_48_ios_deployment.tsx","title":"iOS Deployment: TestFlight and the App Store","subtitle":"same GOAL as lesson 47 -- get a built app in front of real users -- but Apple's process has its own specific gates.","section":"Deployment","color":"indigo","mainCode":"// ================================================================\n//   LESSON 48 -- iOS Deployment: TestFlight and the App Store\n//   Teaching philosophy: same GOAL as lesson 47 -- get a built app\n//                        in front of real users -- but Apple's\n//                        process has its own specific gates.\n// ================================================================\n//   Before starting: an Apple Developer Program account ($99/year),\n//   eas-cli installed (lesson 14)\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Android (lesson 47) let you sideload an .apk directly, no\n//   store needed, even for real users. iOS does NOT allow this in\n//   the same way -- every iOS device that runs your app, even\n//   during TESTING, must be explicitly known to Apple in advance\n//   (a \"provisioning profile\" tied to specific device IDs), or the\n//   app must go through TestFlight. There is no equivalent of\n//   \"just send someone the file and they install it.\"\n//\n//   Apple Developer Program enrollment ($99/year) is required\n//   BEFORE you can build, test on real devices, or submit anything\n//   -- unlike Android's one-time $25 fee.\n\n\n// ================================================================\n// PART 1 -- Building for iOS\n// ================================================================\n//\n//   TRACE: the build command, mirroring lesson 47's Android flow\n//   Step 1: eas build --platform ios --profile production\n//   Step 2: EAS handles the complex parts of iOS signing\n//           automatically (certificates, provisioning profiles) --\n//           historically the most painful part of iOS development,\n//           largely abstracted away here\n//   Step 3: you get a download link to a signed .ipa file (iOS's\n//           equivalent of Android's .apk/.aab)\n//\n//   eas build --platform ios --profile production\n\n// ── PREDICT before running ──────────────────────────────────────\n// Unlike Android, where you can build an .apk and just email it to\n// a friend to install, why can't you do the same with an iOS .ipa\n// file, even for a single tester?                              -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- TestFlight: iOS's Testing Track\n// ================================================================\n//\n//   TestFlight is Apple's OFFICIAL beta-testing app -- it plays a\n//   similar role to lesson 47's \"Internal/Closed/Open testing\"\n//   tracks, but for iOS it's not optional infrastructure -- it's\n//   essentially the ONLY sanctioned way to get a build onto a\n//   real tester's phone outside of the full App Store release.\n//\n//   TRACE: the TestFlight flow\n//   Step 1: eas submit --platform ios -- uploads your .ipa to App\n//           Store Connect (Apple's equivalent of the Play Console)\n//   Step 2: Apple processes the build (a brief automated check)\n//   Step 3: you invite testers by EMAIL (internal testers, up to\n//           100, instant access) or via a PUBLIC LINK (external\n//           testers, up to 10,000, requires a quick Apple review\n//           the FIRST time you use it)\n//   Step 4: testers install the TestFlight app, then your app\n//           THROUGH it -- it auto-updates as you push new builds\n//\n//   eas submit --platform ios\n\n\n// ================================================================\n// PART 3 -- App Store Review: What Apple Actually Checks\n// ================================================================\n//\n//   Apple's review process is notably stricter than Google's, and\n//   covers more than just \"does it crash.\" Common rejection reasons\n//   directly relevant to THIS course's content:\n//   - missing a Privacy Policy URL (REQUIRED if you collect any\n//     data -- lesson 23's login flow definitely qualifies)\n//   - asking for permissions (lesson 12, 36, 38) without a clear\n//     \"purpose string\" explaining WHY -- app.json needs descriptive\n//     text, e.g. NSLocationWhenInUseUsageDescription\n//   - incomplete features, placeholder content, or obvious bugs\n//   - login-gated apps with no way for the reviewer to actually\n//     test it -- provide a demo account if your app requires login\n//\n//   // app.json -- purpose strings Apple requires for permissions\n//   {\n//     \"expo\": {\n//       \"ios\": {\n//         \"infoPlist\": {\n//           \"NSLocationWhenInUseUsageDescription\": \"We use your location to show nearby cities.\",\n//           \"NSCameraUsageDescription\": \"We use your camera to let you set a profile photo.\"\n//         }\n//       }\n//     }\n//   }\n\n\n// ================================================================\n// PART 4 -- Versioning on iOS\n// ================================================================\n//\n//   // app.json\n//   {\n//     \"expo\": {\n//       \"version\": \"1.0.0\",\n//       \"ios\": {\n//         \"buildNumber\": \"1\"        // MUST increase every submission,\n//       }                           // same role as Android's versionCode\n//     }\n//   }\n//\n//   Same TWO-number pattern as lesson 47's Android section --\n//   \"version\" for humans, \"buildNumber\" strictly increasing for\n//   Apple's systems to track distinct submissions.\n\n\n// ================================================================\n// PART 5 -- Submitting to the App Store (Production)\n// ================================================================\n//\n//   TRACE: the final step, after TestFlight testing looks good\n//   Step 1: in App Store Connect, create a new App Store listing\n//           version, attach your already-uploaded build\n//   Step 2: fill in: description, screenshots (REQUIRED for\n//           multiple specific device sizes), Privacy Policy URL,\n//           age rating questionnaire\n//   Step 3: submit for review -- typically 1-3 days, can be longer\n//   Step 4: once approved, you choose to release immediately, on a\n//           specific date, or manually whenever you're ready","questionsCode":"// ================================================================\n// [QUESTIONS] -- TestFlight is the real gate. Purpose strings are required.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// Your app requests camera access (lesson 12/37) but app.json has\n// NO NSCameraUsageDescription set.\n//\n// What do you expect to happen, either during Apple's review, or\n// when the permission prompt actually appears on a real device?  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake in this release plan)\n//\n//   1. Build with eas build --platform ios --profile production\n//   2. Download the .ipa\n//   3. AirDrop the .ipa file to a friend's iPhone to test\n//   4. They tap it expecting it to install, like an Android .apk\n//\n// Bug -> ?  (what's the ACTUAL required path to get a build onto\n// someone else's iPhone for testing?)\n// Fixed plan:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Prepare an App Store Submission Checklist\n//\n// PLAN: which permissions does your app ACTUALLY use, and which\n// purpose strings do they each require?\n//\n// For the Authentication App project (lesson 26), list every\n// app.json field and store-listing asset you'd need ready before\n// submitting: required infoPlist purpose strings (if any), Privacy\n// Policy requirement, and whether a demo account is needed for reviewers.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Plan a TestFlight Rollout\n//\n// PLAN: internal testers first, or external? why that order?\n//\n// Write a staged testing plan for a new app: how many internal\n// testers, what you'd check for before inviting external testers,\n// and what would make you decide it's ready to submit for full\n// App Store review.\n//\n// Write here:","takeaways":["Apple Developer Program ($99/year) required before ANY real-device testing",".ipa -- iOS's build artifact, NOT directly installable like an .apk","TestFlight -- the ONLY sanctioned path to real testers, internal or external","Purpose strings (NSCameraUsageDescription, etc.) -- REQUIRED for every permission your app requests","buildNumber -- must increase every submission, same role as Android's versionCode"],"nextHint":"lesson_49_typescript_mastery.tsx -- Professional Skills begin","milestone":"DEPLOYMENT SECTION COMPLETE."},{"num":49,"id":"lesson_49_typescript_mastery","filename":"lesson_49_typescript_mastery.tsx","title":"TypeScript Mastery: Generics, Unions, Enums, Utilities","subtitle":"lesson 00 taught BASIC types. Every lesson since has used them lightly. This lesson fills in the patterns that show up constantly in real, professional codebases.","section":"Professional Skills","color":"rose","mainCode":"// ================================================================\n//   LESSON 49 -- TypeScript Mastery: Generics, Unions, Enums, Utilities\n//   Teaching philosophy: lesson 00 taught BASIC types. Every lesson\n//                        since has used them lightly. This lesson\n//                        fills in the patterns that show up\n//                        constantly in real, professional codebases.\n// ================================================================\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   You've been writing TypeScript since lesson 00, but mostly\n//   simple annotations (string, number, interfaces). Real codebases\n//   lean on a handful of MORE powerful patterns to avoid duplicated\n//   type definitions and catch entire categories of bugs -- this\n//   lesson is a tour of the ones you'll see constantly, with\n//   examples pulled from patterns ALREADY used earlier in this course.\n\n\n// ================================================================\n// PART 1 -- Generics: Functions/Types That Work With ANY Type\n// ================================================================\n//\n//   You've ALREADY used generics without a deep explanation --\n//   lesson 17's useFetch<T> and lesson 21's apiClient<T> both used\n//   the <T> syntax. Now the full picture:\n//\n//   TRACE: why a generic is needed at all\n//   Step 1: WITHOUT generics, you'd write a SEPARATE function for\n//           each type: fetchUsers(): User[], fetchPosts(): Post[],\n//           all with IDENTICAL logic, just a different return type\n//   Step 2: WITH a generic <T>, ONE function adapts to WHATEVER\n//           type you specify when calling it\n//   Step 3: T is a PLACEHOLDER, filled in at the call site --\n//           similar in spirit to a function parameter, but for TYPES\n\nfunction wrapInArray<T>(value: T): T[] {\n    return [value];\n}\n\nconst numbers = wrapInArray(5);        // T becomes number -> number[]\nconst names = wrapInArray(\"Sarath\");   // T becomes string -> string[]\n\n// Generic interfaces -- exactly lesson 21's ApiResponse pattern:\ninterface ApiResponse<T> {\n    data: T;\n    success: boolean;\n}\n\ninterface User { id: number; name: string; }\n\nconst userResponse: ApiResponse<User> = {\n    data: { id: 1, name: \"Sarath\" },\n    success: true,\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you tried userResponse.data.name = 5 (assigning a NUMBER to a\n// field typed as string), what would TypeScript do?           -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Union Types: \"This OR That\"\n// ================================================================\n//\n//   You've used these already too -- lesson 16's useState<number |\n//   null> and lesson 24's \"GET\" | \"POST\" | ... in RequestOptions.\n//\n//   TRACE: narrowing a union\n//   Step 1: a value typed `string | number` could be EITHER\n//   Step 2: TypeScript won't let you call string-only methods\n//           (like .toUpperCase()) until you NARROW it\n//   Step 3: typeof checks (or other guards) narrow the type WITHIN\n//           that branch -- TypeScript tracks this automatically\n\ntype Id = string | number;\n\nfunction formatId(id: Id): string {\n    if (typeof id === \"number\") {\n        return `#${id.toString().padStart(4, \"0\")}`;   // id is `number` here\n    }\n    return id.toUpperCase();   // id is `string` here -- narrowed automatically\n}\n\n// Discriminated unions -- a VERY common professional pattern, for\n// representing \"one of several possible shapes\":\ntype LoadingState =\n    | { status: \"loading\" }\n    | { status: \"success\"; data: User }\n    | { status: \"error\"; message: string };\n\nfunction renderState(state: LoadingState): string {\n    switch (state.status) {\n        case \"loading\": return \"Loading...\";\n        case \"success\": return `Hello, ${state.data.name}`;   // .data exists ONLY here\n        case \"error\": return `Error: ${state.message}`;        // .message exists ONLY here\n    }\n}\n//\n//   This is the FORMAL version of the loading/error/data pattern\n//   you've used informally since lesson 10 -- here, TypeScript\n//   GUARANTEES you can't accidentally read state.data while\n//   status is \"error\".\n\n\n// ================================================================\n// PART 3 -- Enums: Named Constants (and a Common Alternative)\n// ================================================================\n//\n//   enum OrderStatus {\n//       Pending,\n//       Shipped,\n//       Delivered,\n//   }\n//   const status: OrderStatus = OrderStatus.Shipped;\n//\n//   Many TypeScript style guides (including a lot of modern RN\n//   codebases) PREFER a union of string literals instead -- it\n//   avoids some of enum's quirks (e.g. numeric enums allowing any\n//   number to be assigned) and is easier to log/debug, since the\n//   value IS the readable string:\n\ntype OrderStatusLiteral = \"pending\" | \"shipped\" | \"delivered\";\n\nconst currentStatus: OrderStatusLiteral = \"shipped\";\n\nfunction describeStatus(status: OrderStatusLiteral): string {\n    if (status === \"pending\") return \"Order received\";\n    if (status === \"shipped\") return \"On its way\";\n    return \"Delivered\";\n}\n\n\n// ================================================================\n// PART 4 -- Utility Types: Transforming Existing Types\n// ================================================================\n//\n//   TypeScript ships several built-in HELPERS for deriving a NEW\n//   type from an existing one, instead of retyping it from scratch.\n\ninterface Product { id: string; name: string; price: number; description: string; }\n\n// Partial<T> -- every field becomes OPTIONAL -- perfect for an\n// \"update\" function where only SOME fields might be provided\n// (connects directly to lesson 21's PATCH semantics):\nfunction updateProduct(id: string, changes: Partial<Product>) {\n    // changes might be { price: 100 } -- just one field, all others optional\n}\n\n// Pick<T, Keys> -- builds a type with ONLY the listed fields:\ntype ProductSummary = Pick<Product, \"id\" | \"name\">;\n// equivalent to: { id: string; name: string }\n\n// Omit<T, Keys> -- the OPPOSITE -- everything EXCEPT the listed fields:\ntype ProductWithoutDescription = Omit<Product, \"description\">;\n\n// Record<Keys, ValueType> -- a dict-like type, used already in\n// lesson 21's Record<string, string> for headers:\ntype ProductsById = Record<string, Product>;\n\n\n// ================================================================\n// PART 5 -- Typing API Responses and Navigation (Tying It Together)\n// ================================================================\n//\n//   Combining generics + unions gives you a SAFE shape for\n//   anything fetched (lesson 10/21), and the SAME idea types\n//   Expo Router params (lesson 08) precisely:\n\ntype FetchResult<T> =\n    | { status: \"loading\" }\n    | { status: \"success\"; data: T }\n    | { status: \"error\"; error: string };\n\n// Typed navigation params (extending lesson 08's useLocalSearchParams):\ntype ProductDetailParams = { id: string };\n// const { id } = useLocalSearchParams<ProductDetailParams>();","questionsCode":"// ================================================================\n// [QUESTIONS] -- Generics adapt to any type. Unions narrow with guards.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// const state: LoadingState = { status: \"loading\" };\n// console.log(state.data);\n//\n// Does TypeScript allow this line to compile? Why or why not,\n// given PART 2's discriminated union?                          -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the type error)\n//\n//   function getFirst<T>(items: T[]): T {\n//       return items[0];\n//   }\n//\n//   const first: string = getFirst([1, 2, 3]);\n//\n// Bug -> ?  (what does TypeScript infer T to be here, and why\n// does assigning the result to `string` fail?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Generic API Hook Type\n//\n// PLAN: which 3 states does a fetch operation need, generically?\n//\n// Define a generic type ApiState<T> as a discriminated union with\n// \"idle\" | \"loading\" | \"success\" (carrying data: T) | \"error\"\n// (carrying message: string). Write a function describeApiState\n// that takes an ApiState<User> and returns an appropriate string\n// for each case, using a switch like PART 2's renderState.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Build a Form-Update Type\n//\n// PLAN: which utility type fits an edit-profile form where users\n// only change a FEW fields at a time?\n//\n// Given an interface UserProfile { id: string; name: string; bio:\n// string; avatarUrl: string }, write a function updateProfile(id:\n// string, changes: ???) using the right utility type from PART 4\n// so callers can pass just { bio: \"new bio\" } without errors.\n//\n// Write here:","takeaways":["Generics <T> -- one function/type, works with whatever type you specify","Union types (A | B) -- narrow with typeof or a discriminant field","Discriminated unions -- TypeScript GUARANTEES you check the right shape","String-literal unions are often preferred over numeric enums","Partial<T> / Pick<T,K> / Omit<T,K> / Record<K,V> -- derive types, don't retype"],"nextHint":"lesson_50_git_github.tsx -- version control for real projects","milestone":""},{"num":50,"id":"lesson_50_git_github","filename":"lesson_50_git_github.tsx","title":"Git & GitHub: Version Control for Real Projects","subtitle":"Git tracks SNAPSHOTS of your code over time. GitHub is where those snapshots are shared and reviewed with other people.","section":"Professional Skills","color":"rose","mainCode":"// ================================================================\n//   LESSON 50 -- Git & GitHub: Version Control for Real Projects\n//   Teaching philosophy: Git tracks SNAPSHOTS of your code over\n//                        time. GitHub is where those snapshots are\n//                        shared and reviewed with other people.\n// ================================================================\n//   Before starting: install Git, create a free GitHub account\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Without version control, \"saving your work\" means manually\n//   copying folders -- \"project_v2\", \"project_final\", \"project_\n//   final_ACTUALLY_final\". Git replaces that with a structured\n//   HISTORY: every meaningful change is a labeled SNAPSHOT\n//   (\"commit\") you can return to, compare, or combine with others'\n//   changes -- without ever needing duplicate folders.\n//\n//   Git (the tool, runs locally) vs GitHub (a website hosting Git\n//   repositories online, adding collaboration features like pull\n//   requests) -- Git works completely without GitHub; GitHub adds\n//   the \"share this with other people\" layer on top.\n\n\n// ================================================================\n// PART 1 -- The Core Loop: status, add, commit\n// ================================================================\n//\n//   TRACE: saving a snapshot of your work\n//   Step 1: git status -- shows what's changed since the LAST\n//           snapshot (modified files, new untracked files)\n//   Step 2: git add <file> (or \"git add .” for everything) --\n//           STAGES changes, marking them \"ready to be included\" in\n//           the next snapshot (this is a Git-specific in-between\n//           step most other tools don't have)\n//   Step 3: git commit -m \"message\" -- actually CREATES the\n//           snapshot, permanently, with a description of what changed\n//\n//   git status\n//   git add course_react_native/lesson_50_git_github.tsx\n//   git commit -m \"Add Git & GitHub lesson\"\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you edit a file but only run \"git commit\" WITHOUT running\n// \"git add\" first, does that edit get included in the commit?  -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Connecting to GitHub: clone, push, pull\n// ================================================================\n//\n//   TRACE: starting from an EXISTING GitHub repository\n//   Step 1: git clone <url> -- downloads a FULL copy of a repo\n//           (all files AND its entire history) onto your machine\n//   Step 2: you make changes, git add + git commit locally (PART 1)\n//   Step 3: git push -- uploads your new commits TO GitHub, making\n//           them visible to anyone else with access\n//   Step 4: git pull -- downloads commits OTHERS made, that you\n//           don't have locally yet -- run this BEFORE you start\n//           working, to avoid conflicting with their changes\n//\n//   git clone https://github.com/yourname/weather-notes.git\n//   git push origin main\n//   git pull origin main\n//\n//   \"origin\" is the default NAME Git gives to the remote\n//   (GitHub) location a repo was cloned from -- you'll see it in\n//   almost every push/pull command.\n\n\n// ================================================================\n// PART 3 -- Branches: Working on Something Without Disturbing \"main\"\n// ================================================================\n//\n//   TRACE: why branches exist\n//   Step 1: \"main\" (sometimes \"master\") is usually the STABLE,\n//           working version of your app\n//   Step 2: starting a new feature directly on main risks leaving\n//           it broken halfway through\n//   Step 3: git checkout -b feature/dark-mode -- creates AND\n//           switches to a new branch, a separate line of history\n//   Step 4: you commit freely on this branch -- main stays\n//           untouched the whole time\n//   Step 5: once the feature works, you MERGE it back into main\n//\n//   git checkout -b feature/dark-mode\n//   # ...make changes, commit on this branch...\n//   git checkout main\n//   git merge feature/dark-mode\n\n\n// ================================================================\n// PART 4 -- Merging and Merge Conflicts\n// ================================================================\n//\n//   TRACE: a CLEAN merge (the common case)\n//   Step 1: main hasn't changed since you branched off it\n//   Step 2: git merge feature/dark-mode -- Git applies your\n//           branch's commits on top of main automatically\n//\n//   TRACE: a CONFLICT (when both branches changed the SAME lines)\n//   Step 1: main got OTHER changes while you were working on your branch\n//   Step 2: git merge feature/dark-mode -- Git can't automatically\n//           decide which version is \"correct\" for the overlapping lines\n//   Step 3: Git marks the conflicting section directly in the file:\n//\n//           <<<<<<< HEAD\n//           const theme = \"light\";\n//           =======\n//           const theme = \"system\";\n//           >>>>>>> feature/dark-mode\n//\n//   Step 4: YOU edit the file by hand, choosing (or combining) the\n//           correct final version, delete the <<<<<<< markers, then\n//           git add + git commit to finish the merge\n//\n//   This is NEVER something to \"fix\" by discarding one side\n//   blindly -- read both versions and decide deliberately (the\n//   same care this course's system instructions apply to any\n//   destructive-looking situation).\n\n\n// ================================================================\n// PART 5 -- Pull Requests: Proposing Changes for Review\n// ================================================================\n//\n//   TRACE: the GitHub-specific workflow (not a plain \"git\" command\n//   -- this happens on GitHub's website/CLI, layered on top of Git)\n//   Step 1: push your branch to GitHub: git push origin feature/dark-mode\n//   Step 2: on GitHub, open a Pull Request (PR) -- proposing to\n//           merge your branch into main\n//   Step 3: teammates review the DIFF (the exact lines changed),\n//           leave comments, request changes\n//   Step 4: once approved, the PR is merged -- often through\n//           GitHub's UI rather than a local \"git merge\" command\n//\n//   This review step is WHY teams use branches + PRs instead of\n//   everyone committing straight to main -- it's a checkpoint\n//   before code becomes part of the shared, stable version.","questionsCode":"// ================================================================\n// [QUESTIONS] -- add stages, commit saves, push shares, pull syncs.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// You and a teammate both branched off main yesterday. They've\n// since pushed several commits to main. You finish your feature\n// and run \"git push origin main\" directly, WITHOUT pulling first.\n//\n// What do you expect Git to do, and why?                       -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find the mistake in this workflow)\n//\n//   1. git checkout -b feature/login-screen\n//   2. ...write the login screen, lots of changes...\n//   3. git commit -m \"Add login screen\"\n//   4. git push origin feature/login-screen\n//   5. Open a Pull Request on GitHub\n//\n// Bug -> ?  (one step from the CORE loop, PART 1, is missing\n// entirely -- which one, and what would happen without it?)\n// Fixed workflow:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Practice the Core Loop\n//\n// In a real (even brand new, empty) Git repository: make a small\n// change to any file, run git status, git add, and git commit\n// with a clear message. Then run \"git log\" to see your commit's\n// history entry.\n//\n// Write here what you saw:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Practice a Branch and Merge\n//\n// PLAN: which branch do you start FROM, and which do you merge INTO?\n//\n// Create a branch \"feature/test-branch\", make a small change,\n// commit it, switch back to main, and merge your branch in. Confirm\n// the change now appears on main. Push main to GitHub if you have\n// a remote set up.\n//\n// Write here what you did and the result:","takeaways":["git add (stage) -> git commit (snapshot) -> git push (share to GitHub)","git pull -- sync OTHERS' changes before you start working","Branches -- isolate work-in-progress from the stable \"main\"","Merge conflicts -- Git marks them, YOU resolve them deliberately","Pull Requests -- propose + review changes BEFORE merging into main"],"nextHint":"lesson_51_env_config.tsx -- managing secrets and build variants","milestone":""},{"num":51,"id":"lesson_51_env_config","filename":"lesson_51_env_config.tsx","title":"Environment & Configuration: .env, API URLs, Secrets","subtitle":"\"works on my machine\" usually means config was hardcoded. This lesson separates CONFIG from CODE, the same instinct as lesson 30's \"keep secrets off the device.\"","section":"Professional Skills","color":"rose","mainCode":"// ================================================================\n//   LESSON 51 -- Environment & Configuration: .env, API URLs, Secrets\n//   Teaching philosophy: \"works on my machine\" usually means\n//                        config was hardcoded. This lesson separates\n//                        CONFIG from CODE, the same instinct as\n//                        lesson 30's \"keep secrets off the device.\"\n// ================================================================\n//   Before starting: npx expo install dotenv (often built into\n//   Expo's config system already, via app.config.ts -- see PART 2)\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Every example since lesson 21 hardcoded a URL like\n//   \"https://api.example.com\" directly in the code. Real apps need\n//   DIFFERENT values depending on context:\n//   - your laptop's local backend during development\n//   - a staging server for testing before release\n//   - the real production server for actual users\n//\n//   Hardcoding any ONE of these means manually editing code every\n//   time you switch contexts -- error-prone, and risks accidentally\n//   shipping a build pointed at your laptop's local server.\n//   Environment variables solve this: the SAME code reads a\n//   DIFFERENT value depending on which environment it's running in.\n\n\n// ================================================================\n// PART 1 -- .env Files and EXPO_PUBLIC_ Variables\n// ================================================================\n//\n//   TRACE: how Expo exposes env variables to your app code\n//   Step 1: create a .env file at your project root:\n//\n//           EXPO_PUBLIC_API_URL=https://api.example.com\n//\n//   Step 2: the \"EXPO_PUBLIC_\" prefix is REQUIRED for a variable\n//           to be readable from your app's JS code at all -- this\n//           is a deliberate safety boundary (PART 4 explains why)\n//   Step 3: access it via process.env, exactly like Node.js:\n\nconst apiUrl = process.env.EXPO_PUBLIC_API_URL;\n\nconst fetchData = async () => {\n    const response = await fetch(`${apiUrl}/products`);\n    return response.json();\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// If you name a variable API_URL (without the EXPO_PUBLIC_ prefix)\n// in your .env file, what happens when you try to read\n// process.env.API_URL inside a component?                     -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Different .env Files Per Environment\n// ================================================================\n//\n//   A common convention: multiple .env files, loaded based on\n//   which build you're running.\n//\n//   .env.development   EXPO_PUBLIC_API_URL=http://localhost:3000\n//   .env.staging        EXPO_PUBLIC_API_URL=https://staging-api.example.com\n//   .env.production      EXPO_PUBLIC_API_URL=https://api.example.com\n//\n//   .gitignore  (IMPORTANT -- see PART 4)\n//\n//   These get loaded via your chosen tooling (e.g. a package like\n//   react-native-dotenv, or EAS's own per-profile environment\n//   variable support shown in PART 3) depending on which command/\n//   profile you're running.\n\n\n// ================================================================\n// PART 3 -- EAS Build Profiles With Different Env Variables\n// ================================================================\n//\n//   Connecting directly to lesson 14's build profiles -- each\n//   profile in eas.json can specify its OWN environment variables,\n//   so a \"production\" build automatically points at the real API,\n//   while a \"development\" build points at a local/staging one.\n//\n//   // eas.json\n//   {\n//     \"build\": {\n//       \"development\": {\n//         \"env\": { \"EXPO_PUBLIC_API_URL\": \"http://localhost:3000\" }\n//       },\n//       \"production\": {\n//         \"env\": { \"EXPO_PUBLIC_API_URL\": \"https://api.example.com\" }\n//       }\n//     }\n//   }\n//\n//   TRACE: why this matters for safety\n//   Step 1: WITHOUT this, a developer might forget to manually\n//           change the URL before building for production\n//   Step 2: WITH per-profile env vars, the CORRECT url is baked in\n//           automatically based on which profile you build with\n//   Step 3: eas build --profile production ALWAYS uses the\n//           production URL, with no manual step to forget\n\n\n// ================================================================\n// PART 4 -- Secrets Management: What NEVER Belongs in EXPO_PUBLIC_\n// ================================================================\n//\n//   This is the MOST important idea in this lesson, and it\n//   connects directly to lesson 22 (JWT) and lesson 30 (database\n//   credentials):\n//\n//   EXPO_PUBLIC_ variables get BUNDLED directly into your app's\n//   JavaScript code -- anyone who downloads your app can extract\n//   them by inspecting the bundle. This is FINE for things like a\n//   public API base URL, but CATASTROPHIC for:\n//   - database connection strings (lesson 30's exact warning)\n//   - private API keys that grant write/admin access\n//   - any secret meant to stay server-side only\n//\n//   TRACE: where REAL secrets belong instead\n//   Step 1: real secrets live in your BACKEND's environment\n//           variables (on the server, never shipped in the app)\n//   Step 2: the app only ever holds PUBLIC values (a base URL, a\n//           publishable/public API key explicitly designed to be\n//           exposed) and short-lived USER tokens (lesson 22's JWTs,\n//           stored in SecureStore -- lesson 23 -- not .env)\n//   Step 3: if a key/secret would let someone do real damage if\n//           leaked, it does NOT belong in EXPO_PUBLIC_ anything\n\n\n// ================================================================\n// PART 5 -- .gitignore: Keeping .env Out of Version Control\n// ================================================================\n//\n//   Connecting to lesson 50 -- committing a .env file to GitHub\n//   means it's now in your repository's PERMANENT history, visible\n//   to anyone with access (and very hard to fully remove later,\n//   even after deleting the file in a later commit).\n//\n//   # .gitignore\n//   .env\n//   .env.local\n//   .env.*.local\n//\n//   A SAFE pattern: commit a \".env.example\" file with placeholder\n//   values (e.g. EXPO_PUBLIC_API_URL=https://your-api-here.com) so\n//   teammates know WHAT variables they need, without ever\n//   committing real values.","questionsCode":"// ================================================================\n// [QUESTIONS] -- EXPO_PUBLIC_ vars are bundled, visible, and not secret.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A developer puts EXPO_PUBLIC_DB_PASSWORD=supersecret123 in .env,\n// reasoning \"it's in an env variable, so it's safe.\"\n//\n// Is this actually safe, given PART 4's explanation of what\n// EXPO_PUBLIC_ variables really do?                            -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   // .env\n//   API_URL=https://api.example.com\n//   SECRET_KEY=abc123\n//\n//   // App.tsx\n//   const url = process.env.API_URL;\n//   const key = process.env.SECRET_KEY;\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: one is about whether this value\n// is even readable at all, the other is about whether it SHOULD be)\n// Fixed approach:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Set Up Multi-Environment Config\n//\n// PLAN: which value differs between environments -- and which\n// stays the SAME everywhere?\n//\n// For the Weather Notes app (lesson 13), set up EXPO_PUBLIC_\n// WEATHER_API_BASE for development (pointing at the real wttr.in\n// endpoint, since it's free) and write out what a staging/\n// production split MIGHT look like if this were a paid API requiring\n// different keys per environment.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Audit a Real Project for Leaked Secrets\n//\n// PLAN: what should you search the codebase FOR?\n//\n// In any of your own past projects (or this course's lessons),\n// search for hardcoded URLs, API keys, or tokens directly in code.\n// List what you'd move into EXPO_PUBLIC_ env vars, and what (if\n// anything) you'd realize should move to a BACKEND instead, per\n// PART 4's rule.\n//\n// Write here:","takeaways":["EXPO_PUBLIC_ prefix -- required for a variable to be readable in app code","Different .env files / EAS build profile env vars -- per environment","EXPO_PUBLIC_ variables are BUNDLED and extractable -- never put real secrets there","Real secrets live on the BACKEND, never shipped in the app",".gitignore your .env files -- commit a .env.example instead"],"nextHint":"lesson_52_error_handling_logging.tsx -- handling failures gracefully","milestone":""},{"num":52,"id":"lesson_52_error_handling_logging","filename":"lesson_52_error_handling_logging.tsx","title":"Error Handling & Logging: Failing Gracefully","subtitle":"errors WILL happen in production -- the question is whether your app shows a blank crashed screen, or recovers gracefully.","section":"Professional Skills","color":"rose","mainCode":"// ================================================================\n//   LESSON 52 -- Error Handling & Logging: Failing Gracefully\n//   Teaching philosophy: errors WILL happen in production -- the\n//                        question is whether your app shows a\n//                        blank crashed screen, or recovers gracefully.\n// ================================================================\n//   Before starting: a free Sentry account (for PART 4) -- optional\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   try/catch has appeared informally since lesson 10 -- this\n//   lesson makes the PATTERNS explicit: where errors come from in a\n//   real app, how to stop ONE broken component from crashing the\n//   ENTIRE screen, and how to find out about crashes that happen on\n//   a USER's phone, which you'll never personally see happen.\n\n\n// ================================================================\n// PART 1 -- try/catch Recap and a Custom Error Hierarchy\n// ================================================================\n//\n//   You've used generic try/catch since lesson 10. Real apps often\n//   define SPECIFIC error types, so catch blocks can react\n//   DIFFERENTLY depending on what actually went wrong -- the same\n//   instinct as lesson 22's distinction between a 401 vs other failures.\n//\n//   TRACE: a custom error class\n//   Step 1: class ApiError extends Error -- inherits Error's\n//           standard behavior (.message, stack traces), adds extra fields\n//   Step 2: throw new ApiError(...) -- carries MORE context than a\n//           plain string message\n//   Step 3: catch blocks can check \"err instanceof ApiError\" to\n//           handle API failures differently from, say, a parsing bug\n\nclass ApiError extends Error {\n    statusCode: number;\n    constructor(message: string, statusCode: number) {\n        super(message);\n        this.statusCode = statusCode;\n        this.name = \"ApiError\";\n    }\n}\n\nconst fetchUser = async (id: number) => {\n    const response = await fetch(`https://api.example.com/users/${id}`);\n    if (!response.ok) {\n        throw new ApiError(`Failed to fetch user ${id}`, response.status);\n    }\n    return response.json();\n};\n\nconst loadUser = async (id: number) => {\n    try {\n        return await fetchUser(id);\n    } catch (err) {\n        if (err instanceof ApiError && err.statusCode === 404) {\n            console.log(\"User not found -- showing empty state\");\n            return null;\n        }\n        throw err;   // re-throw anything we don't specifically handle\n    }\n};\n\n// ── PREDICT before running ──────────────────────────────────────\n// Why does the catch block RE-THROW errors it doesn't recognize,\n// instead of silently swallowing every possible error?        -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Error Boundaries: Containing a Crash to ONE Section\n// ================================================================\n//\n//   try/catch only catches errors in code you EXPLICITLY wrapped --\n//   it does NOT catch errors thrown while RENDERING a component\n//   (e.g. a bug like reading user.name when user is unexpectedly\n//   null). Without protection, a render error crashes the ENTIRE\n//   app to a blank white screen. An Error Boundary contains that\n//   crash to just the section that failed.\n//\n//   TRACE: how an Error Boundary works\n//   Step 1: it's a CLASS component (one of the few cases RN/React\n//           still requires a class instead of a function + hooks)\n//   Step 2: getDerivedStateFromError -- React calls this\n//           automatically when a CHILD component throws while rendering\n//   Step 3: render() checks its own error state -- shows a fallback\n//           UI instead of letting the crash propagate further up\n\nimport React from \"react\";\nimport { View, Text, Pressable } from \"react-native\";\n\ninterface ErrorBoundaryState { hasError: boolean; }\n\nclass ErrorBoundary extends React.Component<{ children: React.ReactNode }, ErrorBoundaryState> {\n    state: ErrorBoundaryState = { hasError: false };\n\n    static getDerivedStateFromError(): ErrorBoundaryState {\n        return { hasError: true };\n    }\n\n    componentDidCatch(error: Error) {\n        console.log(\"Caught by ErrorBoundary:\", error.message);\n        // PART 4 -- this is also where you'd report to Sentry\n    }\n\n    render() {\n        if (this.state.hasError) {\n            return (\n                <View style={{ padding: 20 }}>\n                    <Text>Something went wrong on this screen.</Text>\n                    <Pressable onPress={() => this.setState({ hasError: false })}>\n                        <Text>Try Again</Text>\n                    </Pressable>\n                </View>\n            );\n        }\n        return this.props.children;\n    }\n}\n\n// Usage -- wrap a RISKY section, not necessarily the whole app:\n// <ErrorBoundary>\n//     <ProductDetailScreen />\n// </ErrorBoundary>\n\n\n// ================================================================\n// PART 3 -- API Error Handling: Surfacing Useful Messages to Users\n// ================================================================\n//\n//   Connecting to lessons 10/21's loading/error/data pattern --\n//   the GOAL is showing the user something ACTIONABLE, not a raw\n//   technical message.\n\nconst getUserFriendlyMessage = (err: unknown): string => {\n    if (err instanceof ApiError) {\n        if (err.statusCode === 404) return \"We couldn't find that.\";\n        if (err.statusCode === 401) return \"Please log in again.\";\n        if (err.statusCode >= 500) return \"Something went wrong on our end. Try again shortly.\";\n    }\n    if (err instanceof TypeError) return \"Check your internet connection.\";\n    return \"Something unexpected happened.\";\n};\n//\n//   TRACE: why \"err: unknown\" instead of \"err: Error\" or \"err: any\"\n//   Step 1: JavaScript allows throwing ANY value, not just Error\n//           objects -- \"unknown\" forces you to NARROW (instanceof\n//           checks, lesson 49 PART 2) before using it, exactly like\n//           any other union type\n//   Step 2: \"any\" would let you skip narrowing entirely, silently\n//           reintroducing the bugs TypeScript is meant to catch\n\n\n// ================================================================\n// PART 4 -- Crash Reporting: Finding Out About Errors You'll Never See\n// ================================================================\n//\n//   Once an app is on a real user's phone (lessons 47-48), YOU\n//   won't be there to see a crash happen. Crash reporting tools\n//   (Sentry is the most common for RN/Expo) automatically capture\n//   errors and send them to a dashboard you can review later.\n//\n//   // App.tsx, near the top, run once at startup\n//   import * as Sentry from \"@sentry/react-native\";\n//   Sentry.init({ dsn: \"YOUR_SENTRY_DSN\" });\n//\n//   // anywhere you catch an error you still want VISIBILITY into:\n//   try {\n//       await riskyOperation();\n//   } catch (err) {\n//       Sentry.captureException(err);\n//       // ...still show the user a friendly message, PART 3...\n//   }\n//\n//   Combine this with ErrorBoundary's componentDidCatch (PART 2) --\n//   reporting render crashes too, not just caught async errors.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Catch specific errors. Contain render crashes. Report what slips through.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A component renders <Text>{user.profile.bio}</Text> where \"user\"\n// is sometimes null (e.g. before lesson 26's auth check finishes).\n//\n// Without an ErrorBoundary, what happens to the WHOLE app when\n// this line throws, versus WITH an ErrorBoundary wrapping just\n// this screen?                                                  -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   const loadData = async () => {\n//       try {\n//           const data = await fetchUser(1);\n//           return data;\n//       } catch (err) {\n//           console.log(err);\n//       }\n//   };\n//\n// Bug -> ?  (this technically \"works\" -- but what's missing for a\n// REAL app, per PART 3 and PART 4's goals?)\n// Fixed code:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Build a Friendly Error Display\n//\n// PLAN: which error types need DIFFERENT user-facing messages?\n//\n// Using getUserFriendlyMessage, build a screen that attempts a\n// fetch (reuse lesson 10's pattern), and on failure displays the\n// FRIENDLY message (not the raw error), plus a \"Retry\" button that\n// re-attempts the same request.\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Wrap a Risky Screen\n//\n// PLAN: which screen in a past lesson's project (13, 26, or 34)\n// has the most \"could crash if data is unexpected\" risk?\n//\n// Pick one project screen from this course, wrap it in ErrorBoundary,\n// and deliberately introduce a bug that would crash it (e.g. reading\n// a property off something that's null) to confirm the fallback UI\n// shows instead of a blank crash.\n//\n// Write here:","takeaways":["Custom error classes (extends Error) carry MORE context than a string","Error Boundaries catch RENDER crashes -- try/catch does NOT","Always narrow \"unknown\" caught errors before using them","getUserFriendlyMessage -- never show raw technical errors to users","Sentry (or similar) -- the only way to learn about crashes you can't personally reproduce"],"nextHint":"lesson_53_cicd_basics.tsx -- automating builds and deployment","milestone":""},{"num":53,"id":"lesson_53_cicd_basics","filename":"lesson_53_cicd_basics.tsx","title":"CI/CD Basics: Automating Builds and Deployment","subtitle":"this is the CAPSTONE lesson -- it wires together Git (50), Testing (45-46), and Deployment (47-48) into one automatic pipeline, so none of those steps rely on a human remembering to run them by hand.","section":"Professional Skills","color":"rose","mainCode":"// ================================================================\n//   LESSON 53 -- CI/CD Basics: Automating Builds and Deployment\n//   Teaching philosophy: this is the CAPSTONE lesson -- it wires\n//                        together Git (50), Testing (45-46), and\n//                        Deployment (47-48) into one automatic\n//                        pipeline, so none of those steps rely on\n//                        a human remembering to run them by hand.\n// ================================================================\n//   Before starting: a GitHub repository (lesson 50) with this\n//   project pushed to it\n\n// ================================================================\n// BEFORE CODE -- Feel the Problem First\n// ================================================================\n//\n//   Without automation, shipping a change means a human manually\n//   running, IN ORDER, every time: tests (lessons 45-46), a build\n//   (lesson 14/47/48), and a submission. Forgetting ANY step --\n//   especially \"run the tests first\" -- is exactly how broken code\n//   reaches real users.\n//\n//   CI/CD = Continuous Integration / Continuous Deployment:\n//   CI -- automatically run checks (tests, type-checking) on EVERY\n//         change, before it's allowed to merge\n//   CD -- automatically BUILD and/or DEPLOY once those checks pass\n//\n//   GitHub Actions is GitHub's built-in automation system -- it\n//   runs scripts (\"workflows\") in response to events like a push\n//   or a pull request, on GitHub's own servers, not your laptop.\n\n\n// ================================================================\n// PART 1 -- A Basic GitHub Actions Workflow File\n// ================================================================\n//\n//   TRACE: how a workflow gets triggered and run\n//   Step 1: a YAML file in .github/workflows/ describes WHEN to\n//           run (the \"on\" section) and WHAT to run (the \"jobs\" section)\n//   Step 2: GitHub watches for matching events (here: any push, or\n//           any pull request, targeting \"main\")\n//   Step 3: when triggered, GitHub spins up a FRESH virtual machine,\n//           checks out your code, and runs each listed step in order\n//   Step 4: if ANY step fails (e.g. tests fail), the whole workflow\n//           is marked FAILED -- visible directly on the PR (lesson 50)\n//\n//   ---- .github/workflows/test.yml ----\n//\n//   name: Run Tests\n//   on:\n//     push:\n//       branches: [main]\n//     pull_request:\n//       branches: [main]\n//\n//   jobs:\n//     test:\n//       runs-on: ubuntu-latest\n//       steps:\n//         - uses: actions/checkout@v4\n//         - uses: actions/setup-node@v4\n//           with:\n//             node-version: 20\n//         - run: npm install\n//         - run: npx tsc --noEmit          # type-check, lesson 49\n//         - run: npx jest                  # lessons 45-46\n\n// ── PREDICT before running ──────────────────────────────────────\n// A teammate opens a Pull Request (lesson 50 PART 5) with a failing\n// test. What does this workflow's result look like on that PR,\n// and should it be mergeable as-is?                            -> ?\n// ────────────────────────────────────────────────────────────────\n\n\n// ================================================================\n// PART 2 -- Why This Runs on EVERY Pull Request, Not Just main\n// ================================================================\n//\n//   TRACE: catching a problem BEFORE it reaches main\n//   Step 1: a developer opens a PR from their feature branch\n//           (lesson 50 PART 3)\n//   Step 2: the workflow runs automatically, against THEIR\n//           branch's code\n//   Step 3: reviewers see a clear pass/fail status directly on the\n//           PR, before approving or merging\n//   Step 4: broken code is caught and fixed on the BRANCH --\n//           main never sees it at all\n//\n//   This is the automated version of \"always run tests before\n//   merging\" -- removing the chance someone forgets, under deadline\n//   pressure, to run them manually.\n\n\n// ================================================================\n// PART 3 -- EAS Build, Triggered Automatically\n// ================================================================\n//\n//   Connecting to lessons 14/47/48 -- instead of a human running\n//   \"eas build\" by hand, a workflow can trigger it whenever code\n//   lands on main (or a release branch).\n//\n//   ---- .github/workflows/build.yml ----\n//\n//   name: Build App\n//   on:\n//     push:\n//       branches: [main]\n//\n//   jobs:\n//     build:\n//       runs-on: ubuntu-latest\n//       steps:\n//         - uses: actions/checkout@v4\n//         - uses: actions/setup-node@v4\n//           with:\n//             node-version: 20\n//         - run: npm install -g eas-cli\n//         - run: eas build --platform android --profile production --non-interactive\n//           env:\n//             EXPO_TOKEN: ${{ secrets.EXPO_TOKEN }}\n//\n//   \"--non-interactive\" -- TRACE: why this flag matters\n//   Step 1: eas build normally ASKS questions interactively (e.g.\n//           confirming a profile) -- fine on your laptop, impossible\n//           on an automated server with nobody to answer prompts\n//   Step 2: --non-interactive tells it to use only what's already\n//           configured, failing clearly instead of hanging forever\n\n\n// ================================================================\n// PART 4 -- Secrets in CI/CD (Connecting Directly to Lesson 51)\n// ================================================================\n//\n//   ${{ secrets.EXPO_TOKEN }} -- TRACE: where this value actually\n//   lives\n//   Step 1: NEVER write a real token directly into the YAML file\n//           -- it would be committed to Git history (lesson 50/51's\n//           exact warning) and visible to anyone who can read the repo\n//   Step 2: instead, the secret is stored in GitHub's repository\n//           Settings -> Secrets and variables -> Actions -- encrypted,\n//           never shown in logs, never committed anywhere\n//   Step 3: the workflow file only references its NAME --\n//           \"EXPO_TOKEN\" -- GitHub substitutes the real value at\n//           runtime, ON its servers, never exposing it in the YAML itself\n\n\n// ================================================================\n// PART 5 -- A Realistic Full Pipeline (Tying the Course Together)\n// ================================================================\n//\n//   A mature pipeline for an app like the Authentication App\n//   (lesson 26) or Chat App (lesson 34) typically chains stages:\n//\n//   1. On every PR -> run type-check + tests (PART 1) -- FAST feedback\n//   2. On merge to main -> build a \"preview\" profile (lesson 14)\n//      automatically, so testers always have the latest build\n//   3. On a TAGGED release (e.g. git tag v1.2.0) -> build\n//      \"production\" + eas submit (lessons 47-48) -- a deliberate,\n//      named moment of \"this version ships,\" not every single commit\n//\n//   Notice stage 3 is NOT automatic on every push -- shipping to\n//   real users (App Store/Play Store) usually stays a DELIBERATE,\n//   human-triggered step, even in a heavily automated pipeline.","questionsCode":"// ================================================================\n// [QUESTIONS] -- Automate checks on every PR. Keep shipping deliberate.\n// ================================================================\n\n// QUESTION 1 -- Predict (no running yet)\n//\n// A workflow's \"on\" section only lists \"push: branches: [main]\".\n// A developer opens a Pull Request from a feature branch but\n// hasn't merged it yet.\n//\n// Does this workflow run on their PR? What would you need to add\n// to the \"on\" section for it to also run there?                -> ?\n//\n// Predictions:\n\n\n// ---------------------------------------------------------------\n// QUESTION 2 -- Debug (find ALL bugs before running)\n//\n//   name: Build\n//   on: push\n//   jobs:\n//     build:\n//       steps:\n//         - run: eas build --platform android --profile production\n//           env:\n//             EXPO_TOKEN: abc123realtoken456\n//\n// Bug 1 -> ?   Bug 2 -> ?   (hint: one is about a missing\n// --non-interactive flag for an automated environment, the other\n// is the exact mistake PART 4 warns against)\n// Fixed workflow:\n\n\n// ---------------------------------------------------------------\n// QUESTION 3 -- Design a Workflow for This Course's Auth App\n//\n// PLAN: which checks MUST pass before main accepts any change?\n//\n// Write out (in YAML, following PART 1's structure) a workflow\n// that runs on every pull request targeting main, type-checks\n// (tsc --noEmit), and runs the Jest suite (lessons 45-46) for the\n// Authentication App project (lesson 26).\n//\n// Write here:\n\n\n// ---------------------------------------------------------------\n// QUESTION 4 -- Plan the Full Release Pipeline\n//\n// PLAN: which stage is automatic, and which stays a deliberate,\n// human-triggered action?\n//\n// For a real app you'd ship, write out the 3-stage pipeline from\n// PART 5 specifically for it: what runs on every PR, what runs on\n// merge to main, and what specifically TRIGGERS a real Play\n// Store/App Store submission (hint: it should NOT be \"every push\").\n//\n// Write here:","takeaways":["CI -- automatically run tests/type-checks on every push/PR","CD -- automatically build, and OPTIONALLY deploy, once checks pass","GitHub Actions workflows live in .github/workflows/*.yml","Secrets (EXPO_TOKEN, etc.) -- stored in GitHub Settings, NEVER in the YAML file","Keep real Store submissions a DELIBERATE, tagged/manual step -- not triggered by every single commit"],"nextHint":"","milestone":"REACT NATIVE + EXPO COURSE COMPLETE -- lessons 00-53, fundamentals through a fully automated, production-ready pipeline."}];
